def _append_server_timing(name, duration_ms):
    metric_name = re.sub(r'[^A-Za-z0-9_-]+', '-', str(name or '').strip()).strip('-')
    if not metric_name:
        return
    try:
        duration = max(0.0, float(duration_ms or 0))
    except Exception:
        return
    timings = getattr(g, 'server_timings', None)
    if timings is None:
        timings = []
        g.server_timings = timings
    timings.append((metric_name, duration))


def _record_elapsed_server_timing(name, started_at):
    _append_server_timing(name, (time.perf_counter() - started_at) * 1000)


@app.after_request
def debug_401_responses(response):
    if response.status_code == 401:
        auth_hdr = request.headers.get('Authorization', '')
        auth_hdr_trunc = auth_hdr[:20] + '...' if len(auth_hdr) > 20 else auth_hdr
        x_trans = request.headers.get('X-Auth-Transport', '')
        err_code = request.environ.get('JWT_AUTH_ERROR_CODE', 'none')
        cookie_hdr = 'yes' if 'Cookie' in request.headers else 'no'
        logging.error(
            f">>> 401 ERROR: {request.path} | "
            f"Code: {err_code} | "
            f"Trans: {x_trans} | "
            f"AuthHdr: '{auth_hdr_trunc}' | "
            f"Cookies: {cookie_hdr}"
        )
    return response


@app.after_request
def periodic_memory_maintenance(response):
    try:
        _maybe_trim_process_memory('periodic_request')
    except Exception:
        logging.debug("Periodic memory maintenance failed", exc_info=True)
    return response

