def _normalize_origin(origin):
    if not origin:
        return ""
    return str(origin).strip().rstrip("/")


def _is_allowed_origin(origin):
    origin = _normalize_origin(origin)
    if not origin:
        return False
    if origin in ALLOWED_ORIGINS:
        return True
    return origin.startswith("http://localhost:") or origin.startswith("http://127.0.0.1:")


CORS(app, resources={
    r"/api/*": {
        "origins": list(ALLOWED_ORIGINS) + [r"http://localhost:\d+", r"http://127\.0\.0\.1:\d+"],
        "methods": ["GET", "POST", "PUT", "PATCH", "DELETE", "OPTIONS"],
        "allow_headers": ["Content-Type", "X-User-Id", "Authorization", "X-Refresh-Token", "X-Auth-Transport"],
        "supports_credentials": True,
        "max_age": 86400
    }
})

SHIFT_AUCTION_EVENT_HEARTBEAT_SECONDS = 15
SHIFT_AUCTION_EVENT_LISTENER_RETRY_SECONDS = 2
# How many recent events to keep in memory for SSE fan-out. The single PG
# listener fetches new events ONCE and pushes them into this buffer; every
# connected stream then reads from RAM instead of hitting the DB on each
# notification. This converts the old O(streams x events) DB query storm
# (which saturated the connection pool during a live auction) into O(events).
SHIFT_AUCTION_EVENT_BUFFER_MAXLEN = _env_int('SHIFT_AUCTION_EVENT_BUFFER_MAXLEN', 2000, minimum=200)
SHIFT_AUCTION_EVENT_FETCH_LIMIT = 500
shift_auction_event_condition = threading.Condition()
shift_auction_event_signal_id = 0
shift_auction_event_buffer = collections.deque(maxlen=SHIFT_AUCTION_EVENT_BUFFER_MAXLEN)
shift_auction_event_buffer_max_id = 0
shift_auction_event_buffer_ready = False
shift_auction_event_listener_started = False
shift_auction_event_listener_lock = threading.Lock()


def _build_postgres_connection_params():
    return {
        'dbname': os.getenv('POSTGRES_DB'),
        'user': os.getenv('POSTGRES_USER'),
        'password': os.getenv('POSTGRES_PASSWORD'),
        'host': os.getenv('POSTGRES_HOST'),
        'port': os.getenv('POSTGRES_PORT', 5432),
        'keepalives': 1,
        'keepalives_idle': 30,
        'keepalives_interval': 10,
        'keepalives_count': 3,
        'connect_timeout': 5,
    }


def _signal_shift_auction_event_waiters():
    global shift_auction_event_signal_id
    with shift_auction_event_condition:
        shift_auction_event_signal_id += 1
        shift_auction_event_condition.notify_all()


def _get_shift_auction_event_signal_id():
    with shift_auction_event_condition:
        return shift_auction_event_signal_id


def _wait_for_shift_auction_event_signal(last_seen_signal_id, timeout_seconds):
    timeout_seconds = max(0.1, float(timeout_seconds or 0.1))
    with shift_auction_event_condition:
        if shift_auction_event_signal_id <= last_seen_signal_id:
            shift_auction_event_condition.wait(timeout=timeout_seconds)
        return shift_auction_event_signal_id


def _fetch_shift_auction_events_with_cursor(cursor, after_id, limit=SHIFT_AUCTION_EVENT_FETCH_LIMIT):
    """Fetch events after ``after_id`` using a caller-provided cursor.

    Used by the PG listener on its OWN dedicated connection so the event
    fan-out never touches the shared application connection pool.
    """
    cursor.execute(
        """
        SELECT id, event_type, payload, created_at
        FROM shift_auction_test_events
        WHERE id > %s
        ORDER BY id
        LIMIT %s
        """,
        (int(after_id or 0), int(limit)),
    )
    return [
        {
            "id": row[0],
            "event_type": row[1],
            "payload": row[2] or {},
            "created_at": row[3].isoformat() if row[3] else None,
        }
        for row in (cursor.fetchall() or [])
    ]


def _fetch_recent_shift_auction_events_with_cursor(cursor):
    """Warm a new process with the newest buffer window, not the full history."""
    cursor.execute(
        """
        SELECT id, event_type, payload, created_at
        FROM shift_auction_test_events
        ORDER BY id DESC
        LIMIT %s
        """,
        (int(SHIFT_AUCTION_EVENT_BUFFER_MAXLEN),),
    )
    rows = list(cursor.fetchall() or [])
    rows.reverse()
    return [
        {
            "id": row[0],
            "event_type": row[1],
            "payload": row[2] or {},
            "created_at": row[3].isoformat() if row[3] else None,
        }
        for row in rows
    ]


def _publish_shift_auction_events(events):
    """Append freshly fetched events to the in-memory buffer and wake waiters once."""
    global shift_auction_event_signal_id, shift_auction_event_buffer_max_id
    if not events:
        return
    with shift_auction_event_condition:
        appended = False
        for event in events:
            try:
                event_id = int(event.get("id") or 0)
            except Exception:
                event_id = 0
            if event_id <= shift_auction_event_buffer_max_id:
                continue
            shift_auction_event_buffer.append(event)
            shift_auction_event_buffer_max_id = event_id
            appended = True
        if appended:
            shift_auction_event_signal_id += 1
            shift_auction_event_condition.notify_all()


def _read_shift_auction_events_from_buffer(after_id):
    """Return ``(events, covered, signal_id, floor_id)`` after ``after_id``.

    ``covered`` is True when the in-memory buffer is guaranteed to contain the
    full contiguous range after ``after_id`` (so the caller can trust RAM and
    skip the DB). It is False only when the client is further behind than the
    buffer window — then the caller does a one-off DB catch-up.
    """
    after_id = int(after_id or 0)
    with shift_auction_event_condition:
        signal_id = shift_auction_event_signal_id
        if not shift_auction_event_buffer:
            # During listener warm-up, wait for its signal instead of making all
            # newly connected streams hit the shared application DB pool.
            return [], True, signal_id, None
        min_buffered_id = int(shift_auction_event_buffer[0].get("id") or 0)
        covered = (after_id + 1) >= min_buffered_id
        # The buffer is strictly id-ascending, so scan from the tail and stop at
        # the first already-seen id — O(new events) instead of O(buffer length).
        events = []
        for event in reversed(shift_auction_event_buffer):
            if int(event.get("id") or 0) > after_id:
                events.append(event)
            else:
                break
        events.reverse()
    return events, covered, signal_id, min_buffered_id


def _drain_shift_auction_events(cursor):
    """Fetch and broadcast ALL events after the buffer head, paging to exhaustion.

    ``_publish_shift_auction_events`` advances ``shift_auction_event_buffer_max_id``,
    so each iteration re-reads the global and makes monotonic progress. Looping
    until a short page guarantees a large backlog — a reconnect after an outage,
    or a burst of more than ``SHIFT_AUCTION_EVENT_FETCH_LIMIT`` NOTIFYs — is fully
    drained instead of stranding the tail until the next live event arrives.
    """
    while True:
        batch = _fetch_shift_auction_events_with_cursor(cursor, shift_auction_event_buffer_max_id)
        if not batch:
            break
        _publish_shift_auction_events(batch)
        if len(batch) < SHIFT_AUCTION_EVENT_FETCH_LIMIT:
            break


def _initialize_shift_auction_event_buffer(cursor):
    """Load the recent window once and mark the process-local fan-out ready."""
    global shift_auction_event_buffer_ready, shift_auction_event_signal_id
    _publish_shift_auction_events(_fetch_recent_shift_auction_events_with_cursor(cursor))
    with shift_auction_event_condition:
        shift_auction_event_buffer_ready = True
        # Also wake streams when the table is empty and no event was published.
        shift_auction_event_signal_id += 1
        shift_auction_event_condition.notify_all()


def _run_shift_auction_pg_listener():
    while True:
        conn = None
        cursor = None
        try:
            conn = psycopg2.connect(**_build_postgres_connection_params())
            conn.set_session(autocommit=True)
            cursor = conn.cursor()
            cursor.execute(f"LISTEN {SHIFT_AUCTION_TEST_EVENT_NOTIFY_CHANNEL}")
            logging.info("Shift auction event listener connected")

            # A new process needs only the recent window. A reconnect keeps its
            # RAM buffer and drains every missed page to the current head.
            if shift_auction_event_buffer_ready:
                _drain_shift_auction_events(cursor)
            else:
                _initialize_shift_auction_event_buffer(cursor)

            while True:
                readable, _, _ = select.select([conn], [], [], SHIFT_AUCTION_EVENT_HEARTBEAT_SECONDS)
                # Always poll + drain: a NOTIFY can be absorbed into conn.notifies
                # as a side effect of running the events query below, so we must
                # not rely on socket readability alone to detect new events.
                conn.poll()
                got_notify = False
                while conn.notifies:
                    conn.notifies.pop(0)
                    got_notify = True
                if not readable:
                    # Idle heartbeat — keep the connection alive.
                    cursor.execute("SELECT 1")
                    # Executing a query can itself move pending NOTIFYs into
                    # conn.notifies, so poll and drain once more afterwards.
                    conn.poll()
                    while conn.notifies:
                        conn.notifies.pop(0)
                        got_notify = True
                if got_notify:
                    # Fetch to exhaustion once, regardless of how many NOTIFYs
                    # arrived. This also handles bursts larger than one page.
                    _drain_shift_auction_events(cursor)
        except Exception as error:
            logging.warning("Shift auction event listener reconnecting after error: %s", error, exc_info=True)
            _signal_shift_auction_event_waiters()
            time.sleep(SHIFT_AUCTION_EVENT_LISTENER_RETRY_SECONDS)
        finally:
            try:
                if cursor is not None:
                    cursor.close()
            except Exception:
                pass
            try:
                if conn is not None:
                    conn.close()
            except Exception:
                pass


def _ensure_shift_auction_event_listener_started():
    global shift_auction_event_listener_started
    if shift_auction_event_listener_started:
        return
    with shift_auction_event_listener_lock:
        if shift_auction_event_listener_started:
            return
        listener_thread = threading.Thread(
            target=_run_shift_auction_pg_listener,
            name="shift-auction-pg-listener",
            daemon=True
        )
        listener_thread.start()
        shift_auction_event_listener_started = True


def get_gcs_client():
    # Если используется JSON из переменной окружения
    credentials_content = os.getenv('GOOGLE_APPLICATION_CREDENTIALS_CONTENT')
    if credentials_content:
        import json
        from google.oauth2 import service_account
        credentials_info = json.loads(credentials_content)
        credentials = service_account.Credentials.from_service_account_info(credentials_info)
        return gcs_storage.Client(credentials=credentials)
    return gcs_storage.Client()


class AuthError(Exception):
    def __init__(self, code, message):
        super().__init__(message)
        self.code = code
        self.message = message


def _client_ip():
    xff = request.headers.get('X-Forwarded-For', '')
    if xff:
        return xff.split(',')[0].strip()
    return request.remote_addr


def _hash_token(raw_token):
    value = f"{raw_token}:{JWT_TOKEN_PEPPER}"
    return hashlib.sha256(value.encode('utf-8')).hexdigest()


def _refresh_token_matches_session(session, refresh_token_hash):
    current_hash = str(session.get("refresh_token_hash") or '')
    if current_hash and hmac.compare_digest(current_hash, refresh_token_hash):
        return True

    previous_hash = str(session.get("previous_refresh_token_hash") or '')
    if not previous_hash or not hmac.compare_digest(previous_hash, refresh_token_hash):
        return False

    previous_valid_until = session.get("previous_refresh_valid_until")
    if previous_valid_until is None:
        return False
    return previous_valid_until >= datetime.utcnow()


def _normalize_auth_transport(value):
    normalized = str(value or '').strip().lower()
    if normalized in {'cookie', 'bearer'}:
        return normalized
    return None


def _requested_auth_transport(payload=None):
    if isinstance(payload, dict):
        payload_transport = _normalize_auth_transport(payload.get('auth_transport'))
        if payload_transport:
            return payload_transport

    header_transport = _normalize_auth_transport(request.headers.get(JWT_AUTH_TRANSPORT_HEADER_NAME))
    if header_transport:
        return header_transport

    # Fallback for legacy/mobile clients that can lose X-Auth-Transport
    # but still send bearer credentials.
    if _get_bearer_access_token() or _get_refresh_header_token():
        return 'bearer'

    return 'cookie'


def _build_auth_response_payload(user_payload, transport='cookie', access_token=None, refresh_token=None):
    response_payload = {
        "status": "success",
        "user": user_payload,
        "auth_transport": transport,
        **user_payload
    }
    # Keep tokens in JSON body for compatibility with mobile/webview clients
    # that rely on Bearer storage and cannot always persist cookies.
    if access_token:
        response_payload["access_token"] = access_token
    if refresh_token:
        response_payload["refresh_token"] = refresh_token
    return response_payload


def _normalize_login_rate_limit_key(login_value):
    return str(login_value or '').strip().lower()[:256]


def _prune_login_rate_limits_locked(now_ts):
    cutoff = now_ts - max(1, LOGIN_RATE_LIMIT_WINDOW_SECONDS)

    for bucket in (login_rate_limit_failures_by_ip, login_rate_limit_failures_by_login):
        stale_keys = []
        for key, values in bucket.items():
            fresh_values = [value for value in values if value >= cutoff]
            if fresh_values:
                bucket[key] = fresh_values
            else:
                stale_keys.append(key)
        for key in stale_keys:
            bucket.pop(key, None)

    stale_blocks = [key for key, blocked_until in login_rate_limit_blocks.items() if blocked_until <= now_ts]
    for key in stale_blocks:
        login_rate_limit_blocks.pop(key, None)


def _login_rate_limit_remaining_seconds(login_value):
    ip_key = _client_ip() or 'unknown'
    login_key = _normalize_login_rate_limit_key(login_value)
    now_ts = time.time()

    with login_rate_limit_lock:
        _prune_login_rate_limits_locked(now_ts)
        blocked_until = max(
            float(login_rate_limit_blocks.get(('ip', ip_key), 0) or 0),
            float(login_rate_limit_blocks.get(('login', login_key), 0) or 0)
        )

    if blocked_until <= now_ts:
        return 0
    return max(1, int(math.ceil(blocked_until - now_ts)))


def _register_login_rate_limit_failure(login_value):
    ip_key = _client_ip() or 'unknown'
    login_key = _normalize_login_rate_limit_key(login_value)
    now_ts = time.time()

    with login_rate_limit_lock:
        _prune_login_rate_limits_locked(now_ts)
        login_rate_limit_failures_by_ip.setdefault(ip_key, []).append(now_ts)
        login_rate_limit_failures_by_login.setdefault(login_key, []).append(now_ts)

        if len(login_rate_limit_failures_by_ip.get(ip_key, [])) >= max(1, LOGIN_RATE_LIMIT_MAX_FAILURES_PER_IP):
            login_rate_limit_blocks[('ip', ip_key)] = now_ts + max(1, LOGIN_RATE_LIMIT_BLOCK_SECONDS)
        if len(login_rate_limit_failures_by_login.get(login_key, [])) >= max(1, LOGIN_RATE_LIMIT_MAX_FAILURES_PER_LOGIN):
            login_rate_limit_blocks[('login', login_key)] = now_ts + max(1, LOGIN_RATE_LIMIT_BLOCK_SECONDS)


def _clear_login_rate_limit_failures(login_value):
    ip_key = _client_ip() or 'unknown'
    login_key = _normalize_login_rate_limit_key(login_value)
    with login_rate_limit_lock:
        login_rate_limit_failures_by_ip.pop(ip_key, None)
        login_rate_limit_failures_by_login.pop(login_key, None)
        login_rate_limit_blocks.pop(('ip', ip_key), None)
        login_rate_limit_blocks.pop(('login', login_key), None)


def _get_user_payload(user):
    avatar_bucket = None
    avatar_blob_path = None
    avatar_updated_at = None
    gender = None
    role = None
    user_id = None
    name = None
    telegram_id = None
    if isinstance(user, (tuple, list)):
        role = user[3]
        user_id = user[0]
        name = user[2]
        telegram_id = user[1]
        if len(user) >= 20:
            gender = user[13]
            avatar_bucket = user[15]
            avatar_blob_path = user[16]
            avatar_updated_at = user[19]
        elif len(user) >= 17:
            gender = user[16]
            avatar_bucket = user[11]
            avatar_blob_path = user[12]
            avatar_updated_at = user[15]
        elif len(user) >= 16:
            avatar_bucket = user[11]
            avatar_blob_path = user[12]
            avatar_updated_at = user[15]
    elif isinstance(user, dict):
        role = user.get("role")
        user_id = user.get("id")
        name = user.get("name")
        telegram_id = user.get("telegram_id")
        gender = user.get("gender")
        avatar_bucket = user.get("avatar_bucket")
        avatar_blob_path = user.get("avatar_blob_path")
        avatar_updated_at = user.get("avatar_updated_at")
    department_id = None
    department_code = None
    headed_department_id = None
    headed_department_ids = []
    headed_department_code = None
    headed_department_codes = []
    if user_id is not None:
        try:
            department_id, department_code = db.get_user_department(user_id)
            headed_department_id = db.headed_department_id_for_user(user_id)
        except Exception:
            department_id = None
            department_code = None
            headed_department_id = None
        try:
            headed_departments = db.get_headed_departments_for_user(user_id) or []
            headed_department_ids = [
                int(item.get('id'))
                for item in headed_departments
                if isinstance(item, dict) and item.get('id') is not None
            ]
            headed_department_codes = [
                str(item.get('code')).strip().lower()
                for item in headed_departments
                if isinstance(item, dict) and str(item.get('code') or '').strip()
            ]
            headed_department = next(
                (
                    item for item in headed_departments
                    if isinstance(item, dict)
                    and item.get('id') is not None
                    and int(item.get('id')) == int(headed_department_id)
                ),
                None,
            ) if headed_department_id is not None else None
            if headed_department:
                headed_department_code = str(headed_department.get('code') or '').strip().lower() or None
        except Exception:
            headed_department_ids = []
            headed_department_codes = []
            headed_department_code = None
    return {
        "role": role,
        "id": user_id,
        "name": name,
        "telegram_id": telegram_id,
        "gender": gender,
        "department_id": department_id,
        "department_code": department_code,
        "headed_department_id": headed_department_id,
        "headed_department_ids": headed_department_ids,
        "headed_department_code": headed_department_code,
        "headed_department_codes": headed_department_codes,
        "avatar_url": _build_avatar_signed_url(avatar_bucket, avatar_blob_path),
        "avatar_updated_at": avatar_updated_at.isoformat() if hasattr(avatar_updated_at, "isoformat") else avatar_updated_at
    }


def _extract_request_origin():
    origin = _normalize_origin(request.headers.get('Origin'))
    if origin:
        return origin

    referer = (request.headers.get('Referer') or '').strip()
    if not referer:
        return ''

    try:
        parsed = urlparse(referer)
        if parsed.scheme and parsed.netloc:
            return _normalize_origin(f"{parsed.scheme}://{parsed.netloc}")
    except Exception:
        return ''
    return ''


def _is_state_changing_api_request():
    if request.method not in {'POST', 'PUT', 'PATCH', 'DELETE'}:
        return False
    if not request.path.startswith('/api/'):
        return False
    return request.method != 'OPTIONS'


def _validate_user_session_principal(user_id, session_id=None, user=None):
    user = user if user is not None else db.get_user(id=user_id)
    if not user:
        if session_id:
            db.revoke_user_session(session_id=session_id, user_id=user_id)
        raise AuthError("USER_NOT_FOUND", "User not found")

    status_value = ''
    if isinstance(user, (tuple, list)) and len(user) > 11:
        status_value = str(user[11] or '').strip().lower()
    elif isinstance(user, dict):
        status_value = str(user.get('status') or '').strip().lower()

    if status_value in {'fired', 'dismissal'}:
        if session_id:
            db.revoke_user_session(session_id=session_id, user_id=user_id)
        raise AuthError("USER_INACTIVE", "User account is inactive")
    return user


def _set_request_auth_context(user_id, user=None):
    request.environ['HTTP_X_USER_ID'] = str(user_id)
    request.user_id = int(user_id)
    g.user_id = int(user_id)
    if user is not None:
        g.auth_user = user


def _should_touch_user_session(session, ip_address=None, user_agent=None):
    if not session:
        return True
    if JWT_SESSION_TOUCH_INTERVAL_SECONDS <= 0:
        return True
    if ip_address and ip_address != session.get("ip_address"):
        return True
    if user_agent and user_agent != session.get("user_agent"):
        return True
    last_seen_at = session.get("last_seen_at")
    if not last_seen_at:
        return True
    try:
        return (datetime.now() - last_seen_at).total_seconds() >= JWT_SESSION_TOUCH_INTERVAL_SECONDS
    except Exception:
        return True


def _reserve_user_session_touch(session_id, session, ip_address=None, user_agent=None):
    if not _should_touch_user_session(session, ip_address=ip_address, user_agent=user_agent):
        return False
    now = time.monotonic()
    fingerprint = (str(ip_address or ''), str(user_agent or ''))
    with session_touch_gate_lock:
        gate = session_touch_next_due.get(str(session_id))
        if gate:
            next_due_at, previous_fingerprint = gate
            if next_due_at > now and previous_fingerprint == fingerprint:
                return False
        interval_seconds = max(1, JWT_SESSION_TOUCH_INTERVAL_SECONDS or 1)
        session_touch_next_due[str(session_id)] = (now + interval_seconds, fingerprint)
        if len(session_touch_next_due) > 5000:
            expired = [
                key for key, (next_due_at, _fingerprint) in session_touch_next_due.items()
                if next_due_at <= now
            ]
            for key in expired[:2500]:
                session_touch_next_due.pop(key, None)
        return True


def _touch_user_session_background(session_id, user_id, ip_address, user_agent):
    try:
        db.touch_user_session(
            session_id=session_id,
            user_id=user_id,
            ip_address=ip_address,
            user_agent=user_agent
        )
    except Exception:
        app.logger.exception("Failed to touch user session in background")


def _schedule_user_session_touch(session_id, user_id, ip_address, user_agent):
    auth_maintenance_executor.submit(
        _touch_user_session_background,
        session_id,
        user_id,
        ip_address,
        user_agent
    )


def _get_original_request_user_id_header():
    raw_value = request.environ.get('ORIGINAL_X_USER_ID')
    if raw_value is None:
        raw_value = request.headers.get('X-User-Id')
    return str(raw_value or '').strip()


def _validate_authenticated_identity_header():
    authenticated_user_id = getattr(g, 'user_id', None)
    if not authenticated_user_id:
        return None

    original_header = _get_original_request_user_id_header()
    if not original_header:
        return None

    try:
        header_user_id = int(original_header)
    except Exception:
        return jsonify({"error": "Invalid X-User-Id"}), 400

    if header_user_id != int(authenticated_user_id):
        return jsonify({"error": "X-User-Id does not match authenticated user"}), 403
    return None


def _decode_token(token, expected_type, verify_exp=True):
    try:
        payload = jwt.decode(
            token,
            JWT_SECRET,
            algorithms=[JWT_ALGORITHM],
            options={"verify_exp": verify_exp}
        )
    except jwt.ExpiredSignatureError as e:
        raise AuthError("TOKEN_EXPIRED", "JWT token expired") from e
    except jwt.InvalidTokenError as e:
        raise AuthError("INVALID_TOKEN", "Invalid JWT token") from e

    token_type = payload.get("type")
    if token_type != expected_type:
        raise AuthError("INVALID_TOKEN_TYPE", "Invalid token type")
    if not payload.get("sub") or not payload.get("sid"):
        raise AuthError("INVALID_TOKEN", "Malformed JWT token")
    return payload


def _build_access_token(user, session_id):
    now = datetime.now(timezone.utc)
    payload = {
        "sub": str(user[0]),
        "role": user[3],
        "name": user[2],
        "sid": str(session_id),
        "type": "access",
        "iat": int(now.timestamp()),
        "exp": int((now + timedelta(minutes=JWT_ACCESS_TOKEN_MINUTES)).timestamp())
    }
    return jwt.encode(payload, JWT_SECRET, algorithm=JWT_ALGORITHM)


def _build_refresh_token(user_id, session_id):
    now = datetime.now(timezone.utc)
    payload = {
        "sub": str(user_id),
        "sid": str(session_id),
        "type": "refresh",
        "iat": int(now.timestamp()),
        "exp": int((now + timedelta(days=JWT_REFRESH_TOKEN_DAYS)).timestamp())
    }
    return jwt.encode(payload, JWT_SECRET, algorithm=JWT_ALGORITHM)


def _is_mobile_or_embedded_user_agent():
    user_agent = str(request.headers.get('User-Agent') or '').lower()
    if not user_agent:
        return False
    mobile_pattern = r'(android|iphone|ipad|ipod|iemobile|opera mini|mobile|windows phone)'
    embedded_pattern = r'(\bwv\b|; wv\)|fbav|fban|instagram|line/)'
    return re.search(mobile_pattern, user_agent) is not None or re.search(embedded_pattern, user_agent) is not None


def _cookie_options():
    secure = JWT_COOKIE_SECURE
    origin = request.headers.get('Origin', '')
    if origin.startswith("http://localhost:") or origin.startswith("http://127.0.0.1:"):
        secure = False

    samesite = JWT_COOKIE_SAMESITE
    if not secure and str(samesite).lower() == 'none':
        samesite = 'Lax'

    if _is_mobile_or_embedded_user_agent():
        # Older mobile browsers/webviews often mishandle SameSite=None/Partitioned cookies.
        # Keep desktop cross-site protections, but prefer a compatible cookie shape on mobile.
        if str(samesite).lower() == 'none':
            samesite = 'Lax'
        partitioned = False
    else:
        partitioned = bool(JWT_COOKIE_PARTITIONED and secure and str(samesite).lower() == 'none')

    return {
        "httponly": True,
        "secure": secure,
        "samesite": samesite,
        "domain": JWT_COOKIE_DOMAIN,
        "path": "/",
        "partitioned": partitioned
    }


def _serialize_cookie(name, value, max_age, cookie_kwargs, expires=None):
    safe_value = quote(value, safe="!#$%&'()*+-./:<=>?@[]^_`{|}~")
    parts = [f"{name}={safe_value}"]
    parts.append(f"Path={cookie_kwargs['path']}")
    parts.append(f"Max-Age={int(max_age)}")
    if cookie_kwargs.get('domain'):
        parts.append(f"Domain={cookie_kwargs['domain']}")
    if expires:
        parts.append(f"Expires={expires}")
    if cookie_kwargs.get('httponly'):
        parts.append("HttpOnly")
    if cookie_kwargs.get('secure'):
        parts.append("Secure")
    if cookie_kwargs.get('samesite'):
        parts.append(f"SameSite={cookie_kwargs['samesite']}")
    if cookie_kwargs.get('partitioned'):
        parts.append("Partitioned")
    return "; ".join(parts)


def _set_cookie_header(response, name, value, max_age):
    cookie_kwargs = _cookie_options()
    cookie_header = _serialize_cookie(name, value, max_age=max_age, cookie_kwargs=cookie_kwargs)
    response.headers.add("Set-Cookie", cookie_header)


def _clear_cookie_header(response, name):
    cookie_kwargs = _cookie_options()
    cookie_header = _serialize_cookie(
        name,
        '',
        max_age=0,
        cookie_kwargs=cookie_kwargs,
        expires="Thu, 01 Jan 1970 00:00:00 GMT"
    )
    response.headers.add("Set-Cookie", cookie_header)


def _set_auth_cookies(response, access_token, refresh_token):
    _set_cookie_header(response, JWT_ACCESS_COOKIE_NAME, access_token, JWT_ACCESS_TOKEN_MINUTES * 60)
    _set_cookie_header(response, JWT_REFRESH_COOKIE_NAME, refresh_token, JWT_REFRESH_TOKEN_DAYS * 24 * 60 * 60)


def _clear_auth_cookies(response):
    _clear_cookie_header(response, JWT_ACCESS_COOKIE_NAME)
    _clear_cookie_header(response, JWT_REFRESH_COOKIE_NAME)


def _get_cookie_values(cookie_name):
    # request.cookies may behave inconsistently if duplicate cookie names exist.
    # Parse raw Cookie header and keep all occurrences.
    raw_cookie = request.headers.get('Cookie', '') or ''
    values = []
    for chunk in raw_cookie.split(';'):
        part = chunk.strip()
        if not part or '=' not in part:
            continue
        key, val = part.split('=', 1)
        if key.strip() == cookie_name:
            values.append(val.strip())
    if not values:
        fallback = request.cookies.get(cookie_name)
        if fallback:
            values.append(fallback)
    return values


def _get_cookie_value(cookie_name):
    values = _get_cookie_values(cookie_name)
    if not values:
        return None
    return values[-1]


def _get_bearer_access_token():
    auth_header = (request.headers.get('Authorization') or '').strip()
    if not auth_header:
        return None
    parts = auth_header.split(' ', 1)
    if len(parts) != 2 or parts[0].strip().lower() != 'bearer':
        return None
    token = parts[1].strip()
    return token or None


def _get_refresh_header_token():
    token = (request.headers.get(JWT_REFRESH_HEADER_NAME) or '').strip()
    return token or None


def _get_refresh_body_token():
    if request.path != '/api/auth/refresh':
        return None
    data = request.get_json(silent=True) or {}
    token = str(data.get('refresh_token') or '').strip()
    return token or None


def _get_access_token_values():
    tokens = _get_cookie_values(JWT_ACCESS_COOKIE_NAME)
    header_token = _get_bearer_access_token()
    if header_token:
        tokens.append(header_token)
    return tokens


def _get_refresh_token_values():
    tokens = _get_cookie_values(JWT_REFRESH_COOKIE_NAME)
    header_token = _get_refresh_header_token()
    if header_token:
        tokens.append(header_token)
    body_token = _get_refresh_body_token()
    if body_token:
        tokens.append(body_token)
    return tokens


def _authenticate_access_cookie(optional=True, touch_session=True):
    auth_started_at = time.perf_counter()
    access_tokens = _get_access_token_values()
    if not access_tokens:
        if optional:
            return None
        raise AuthError("MISSING_TOKEN", "Missing access token")

    last_error = AuthError("INVALID_TOKEN", "Invalid access token")
    for access_token in reversed(access_tokens):
        try:
            payload = _decode_token(access_token, expected_type="access", verify_exp=True)
            user_id = int(payload["sub"])
            session_id = str(payload["sid"])
            session_started_at = time.perf_counter()
            session, user = db.get_user_session_with_user(session_id=session_id, user_id=user_id)
            _record_elapsed_server_timing("auth-session", session_started_at)
            if not session:
                raise AuthError("SESSION_NOT_FOUND", "Session not found")
            if session["revoked_at"] is not None:
                raise AuthError("SESSION_REVOKED", "Session revoked")
            if session["expires_at"] and session["expires_at"] < datetime.utcnow():
                raise AuthError("SESSION_EXPIRED", "Session expired")
            user = _validate_user_session_principal(user_id=user_id, session_id=session_id, user=user)

            ip_address = _client_ip()
            user_agent = request.headers.get('User-Agent')
            if touch_session and _reserve_user_session_touch(session_id, session, ip_address=ip_address, user_agent=user_agent):
                _schedule_user_session_touch(
                    session_id=session_id,
                    user_id=user_id,
                    ip_address=ip_address,
                    user_agent=user_agent
                )

            _set_request_auth_context(user_id, user=user)
            _record_elapsed_server_timing("auth-access", auth_started_at)
            return payload
        except AuthError as auth_error:
            last_error = auth_error
            continue

    raise last_error


def _authenticate_refresh_cookie(optional=True, rotate_tokens=True, rotate_refresh_token=True):
    auth_started_at = time.perf_counter()
    refresh_tokens = _get_refresh_token_values()
    if not refresh_tokens:
        if optional:
            return None
        raise AuthError("MISSING_REFRESH_TOKEN", "Missing refresh token")

    last_error = AuthError("INVALID_TOKEN", "Invalid refresh token")
    for refresh_token in reversed(refresh_tokens):
        try:
            payload = _decode_token(refresh_token, expected_type="refresh", verify_exp=True)
            user_id = int(payload["sub"])
            session_id = str(payload["sid"])

            session_started_at = time.perf_counter()
            session, user = db.get_user_session_with_user(session_id=session_id, user_id=user_id)
            _record_elapsed_server_timing("auth-session", session_started_at)
            if not session:
                raise AuthError("SESSION_NOT_FOUND", "Session not found")
            if session["revoked_at"] is not None:
                raise AuthError("SESSION_REVOKED", "Session revoked")
            if session["expires_at"] and session["expires_at"] < datetime.utcnow():
                raise AuthError("SESSION_EXPIRED", "Session expired")
            refresh_token_hash = _hash_token(refresh_token)
            if not _refresh_token_matches_session(session, refresh_token_hash):
                raise AuthError("REFRESH_TOKEN_MISMATCH", "Refresh token mismatch")

            user = _validate_user_session_principal(user_id=user_id, session_id=session_id, user=user)

            if rotate_tokens:
                new_access_token = _build_access_token(user, session_id)
                if rotate_refresh_token:
                    new_refresh_token = _build_refresh_token(user_id, session_id)
                    grace_seconds = max(0, int(JWT_REFRESH_PREVIOUS_TOKEN_GRACE_SECONDS))
                    previous_refresh_valid_until = (
                        datetime.utcnow() + timedelta(seconds=grace_seconds)
                        if grace_seconds > 0
                        else None
                    )
                    db.rotate_user_session_token(
                        session_id=session_id,
                        user_id=user_id,
                        refresh_token_hash=_hash_token(new_refresh_token),
                        expires_at=datetime.utcnow() + timedelta(days=JWT_REFRESH_TOKEN_DAYS),
                        previous_refresh_valid_until=previous_refresh_valid_until
                    )
                else:
                    new_refresh_token = refresh_token
                    ip_address = _client_ip()
                    user_agent = request.headers.get('User-Agent')
                    if _reserve_user_session_touch(session_id, session, ip_address=ip_address, user_agent=user_agent):
                        touch_started_at = time.perf_counter()
                        db.touch_user_session(
                            session_id=session_id,
                            user_id=user_id,
                            ip_address=ip_address,
                            user_agent=user_agent
                        )
                        _record_elapsed_server_timing("auth-touch", touch_started_at)
                g.pending_auth_tokens = (new_access_token, new_refresh_token)
            else:
                ip_address = _client_ip()
                user_agent = request.headers.get('User-Agent')
                if _reserve_user_session_touch(session_id, session, ip_address=ip_address, user_agent=user_agent):
                    touch_started_at = time.perf_counter()
                    db.touch_user_session(
                        session_id=session_id,
                        user_id=user_id,
                        ip_address=ip_address,
                        user_agent=user_agent
                    )
                    _record_elapsed_server_timing("auth-touch", touch_started_at)

            _set_request_auth_context(user_id, user=user)
            _record_elapsed_server_timing("auth-refresh", auth_started_at)
            return payload
        except AuthError as auth_error:
            last_error = auth_error
            continue

    raise last_error


def _current_session_id_from_access_token():
    access_token = _get_cookie_value(JWT_ACCESS_COOKIE_NAME) or _get_bearer_access_token()
    if not access_token:
        return None
    try:
        payload = _decode_token(access_token, expected_type="access", verify_exp=False)
        return str(payload.get("sid"))
    except AuthError:
        return None


def _base64url_encode(value: bytes) -> str:
    return base64.urlsafe_b64encode(value).decode('utf-8').rstrip('=')


def _base64url_decode(value: str) -> bytes:
    padding = '=' * (-len(value) % 4)
    return base64.urlsafe_b64decode((value + padding).encode('utf-8'))


def _normalize_user_role(role) -> str:
    role_norm = str(role or '').strip().lower()
    if role_norm == 'supervisor':
        return 'sv'
    if role_norm in ('superadmin', 'super-admin', 'super admin'):
        return 'super_admin'
    return role_norm


ROLE_HIERARCHY = {
    'operator': 10,
    'trainee': 10,
    'trainer': 20,
    'sv': 30,
    'admin': 40,
    'super_admin': 50
}


def _get_role_level(role) -> int:
    return int(ROLE_HIERARCHY.get(_normalize_user_role(role), 0))


def _has_min_role(role, required_role) -> bool:
    required_level = _get_role_level(required_role)
    if required_level <= 0:
        return False
    return _get_role_level(role) >= required_level


def _has_any_role(role, allowed_roles) -> bool:
    role_norm = _normalize_user_role(role)
    if not role_norm:
        return False
    normalized_allowed = {_normalize_user_role(item) for item in (allowed_roles or [])}
    return role_norm in normalized_allowed


def _is_super_admin_role(role) -> bool:
    return _normalize_user_role(role) == 'super_admin'


def _is_admin_role(role) -> bool:
    return _has_min_role(role, 'admin')


def _is_global_admin_requester(role, requester_id=None) -> bool:
    if not _is_admin_role(role):
        return False
    if _is_super_admin_role(role):
        return True
    return _headed_department_id(requester_id) is None


def _is_privileged_role(role: str) -> bool:
    return _has_min_role(role, 'sv')


def _mask_phone_number(phone_number):
    if phone_number is None:
        return None
    raw = str(phone_number).strip()
    if not raw:
        return raw
    digits = re.sub(r'\D', '', raw)
    if not digits:
        return '*' * min(len(raw), 6)
    if len(digits) <= 4:
        return '*' * len(digits)
    return ('*' * (len(digits) - 4)) + digits[-4:]


KZ_PHONE_REGEX = re.compile(r'^\+7\d{10}$')


def _is_valid_kz_phone(phone_number):
    if phone_number is None:
        return True
    value = str(phone_number).strip()
    if not value:
        return True
    return bool(KZ_PHONE_REGEX.match(value))


def _build_sensitive_qr_token(session_id, user_id):
    expires_at = datetime.now(timezone.utc) + timedelta(seconds=SENSITIVE_QR_TTL_SECONDS)
    payload = {
        "sid": str(session_id),
        "uid": int(user_id),
        "exp": int(expires_at.timestamp()),
        "nonce": uuid.uuid4().hex
    }
    payload_json = json.dumps(payload, separators=(',', ':'), sort_keys=True).encode('utf-8')
    payload_b64 = _base64url_encode(payload_json)
    signature = hmac.new(
        SENSITIVE_QR_SECRET.encode('utf-8'),
        payload_b64.encode('utf-8'),
        hashlib.sha256
    ).hexdigest()
    token = f"{payload_b64}.{signature}"
    return token, expires_at


def _decode_sensitive_qr_token(token):
    if not token or '.' not in token:
        raise ValueError("Invalid QR token format")

    payload_b64, signature = token.rsplit('.', 1)
    expected_signature = hmac.new(
        SENSITIVE_QR_SECRET.encode('utf-8'),
        payload_b64.encode('utf-8'),
        hashlib.sha256
    ).hexdigest()

    if not hmac.compare_digest(signature, expected_signature):
        raise ValueError("Invalid QR token signature")

    try:
        payload_raw = _base64url_decode(payload_b64)
        payload = json.loads(payload_raw.decode('utf-8'))
    except Exception as exc:
        raise ValueError("Invalid QR token payload") from exc

    session_id = str(payload.get('sid') or '').strip()
    user_id = payload.get('uid')
    exp_ts = payload.get('exp')

    try:
        user_id = int(user_id)
        exp_ts = int(exp_ts)
    except Exception as exc:
        raise ValueError("Invalid QR token claims") from exc

    if not session_id:
        raise ValueError("Invalid QR token session")

    now_ts = int(datetime.now(timezone.utc).timestamp())
    if exp_ts <= now_ts:
        raise ValueError("QR token expired")

    return {
        "session_id": session_id,
        "user_id": user_id,
        "expires_at": datetime.fromtimestamp(exp_ts, timezone.utc)
    }


def _is_sensitive_access_unlocked(user_id, session_id):
    if not user_id or not session_id:
        return False
    try:
        return db.is_session_sensitive_access_unlocked(session_id=session_id, user_id=user_id)
    except Exception as exc:
        logging.error(f"Failed to check sensitive session access: {exc}")
        return False


def _sanitize_evaluations_for_access(evaluations, reveal_sensitive, hide_hidden_operator_comments=False):
    result = []
    for ev in (evaluations or []):
        if not isinstance(ev, dict):
            result.append(ev)
            continue

        item = dict(ev)
        phone_masked = _mask_phone_number(item.get('phone_number'))
        item['phone_number_masked'] = phone_masked
        if not reveal_sensitive:
            item['phone_number'] = phone_masked
            item['audio_path'] = None
        if hide_hidden_operator_comments and item.get('comment_visible_to_operator') is False:
            item['comment'] = None
        result.append(item)
    return result


def _headed_department_id(requester_id):
    """id отдела, главой которого является пользователь (кэш в g на запрос).

    Возвращает None, если пользователь не глава никакого отдела. Глава отдела
    получает админ-подобный доступ, но строго в рамках своего отдела.
    """
    if not requester_id:
        return None
    # Кэш живёт в контексте Flask-запроса. Когда функцию вызывают вне него —
    # например, из обработчика Telegram-бота в executor-потоке — любое обращение
    # к `g` бросает RuntimeError («Working outside of application context»).
    # В этом случае работаем без кэша, напрямую из БД, чтобы не уронить вызов
    # (иначе RuntimeError всплывал как «запрос уже обработан» при approve/reject).
    cache = None
    try:
        cache = getattr(g, '_headed_dept_cache', None)
        if cache is None:
            cache = {}
            g._headed_dept_cache = cache
    except RuntimeError:
        cache = None
    except Exception:
        cache = None
    if cache is not None and requester_id in cache:
        return cache[requester_id]
    try:
        dept = db.headed_department_id_for_user(requester_id)
    except Exception:
        dept = None
    if cache is not None:
        cache[requester_id] = dept
    return dept


def _department_scope_id_for_requester(requester_id):
    """Department boundary for scoped managers: headed department first, own department second."""
    headed_dept = _headed_department_id(requester_id)
    if headed_dept is not None:
        return headed_dept
    return db.get_user_department_id(requester_id)


def _headed_department_ids(requester_id):
    """All active departments formally headed by the requester (cached per request)."""
    if not requester_id:
        return frozenset()

    cache = None
    try:
        cache = getattr(g, '_headed_dept_ids_cache', None)
        if cache is None:
            cache = {}
            g._headed_dept_ids_cache = cache
    except RuntimeError:
        cache = None
    except Exception:
        cache = None

    if cache is not None and requester_id in cache:
        return cache[requester_id]

    try:
        departments = db.get_headed_departments_for_user(requester_id) or []
        department_ids = frozenset(
            int(item.get('id'))
            for item in departments
            if isinstance(item, dict) and item.get('id') is not None
        )
    except Exception:
        department_ids = frozenset()

    if cache is not None:
        cache[requester_id] = department_ids
    return department_ids


def _is_department_manager_requester(requester_role, requester_id):
    role = _normalize_user_role(requester_role)
    return _is_supervisor_role(role) or _headed_department_id(requester_id) is not None


def _effective_scoped_manager_role(role, requester_id):
    role_norm = _normalize_user_role(role)
    if _headed_department_id(requester_id) is not None and not _is_super_admin_role(role_norm):
        return 'sv'
    return role_norm


def _operator_item_id(item):
    """Извлечь id оператора из элемента списка (dict или кортеж)."""
    if isinstance(item, dict):
        for key in ('id', 'operator_id', 'user_id'):
            if item.get(key) is not None:
                try:
                    return int(item[key])
                except (TypeError, ValueError):
                    pass
        return None
    try:
        return int(item[0])
    except Exception:
        return None


def _authorize_operator_scope(requester, requester_id, operator_id):
    role = _normalize_user_role(requester[3])
    # Видят всех: супер-админ, админы, тренер
    headed_dept_ids = _headed_department_ids(requester_id)
    if headed_dept_ids and not _is_super_admin_role(role):
        operator_department_id = db.get_user_department_id(operator_id)
        try:
            return operator_department_id is not None and int(operator_department_id) in headed_dept_ids
        except (TypeError, ValueError):
            return False
    if _is_global_admin_requester(role, requester_id) or role == 'trainer':
        return True
    if role == 'operator':
        return requester_id == operator_id
    # Супервайзер / глава отдела — только операторы СВОЕГО отдела
    scope = _department_scope_id_for_requester(requester_id)
    if scope is None:
        return False
    return db.get_user_department_id(operator_id) == scope


def _target_user_supervisor_id(target_user):
    try:
        raw_value = target_user[6]
    except Exception:
        raw_value = None
    try:
        return int(raw_value) if raw_value is not None else None
    except Exception:
        return None


def _requester_can_access_target_user(
    requester,
    requester_id,
    target_user,
    *,
    allow_self=False,
    supervisor_target_roles=('operator', 'trainee')
):
    requester_role = _normalize_user_role(requester[3])
    target_role = _normalize_user_role(target_user[3])
    target_user_id = int(target_user[0])

    if allow_self and requester_id == target_user_id:
        return True

    headed_dept_ids = _headed_department_ids(requester_id)
    if headed_dept_ids and not _is_super_admin_role(requester_role):
        if _is_admin_role(target_role):
            return False
        target_department_id = db.get_user_department_id(target_user_id)
        try:
            return target_department_id is not None and int(target_department_id) in headed_dept_ids
        except (TypeError, ValueError):
            return False
    if _is_global_admin_requester(requester_role, requester_id):
        return True
    if _is_supervisor_role(requester_role):
        if target_role not in set(supervisor_target_roles or ()):
            return False
        # A regular supervisor is scoped to their department. If legacy data
        # has no department, keep access only to an explicit direct report.
        scope = _department_scope_id_for_requester(requester_id)
        if scope is None:
            return _target_user_supervisor_id(target_user) == requester_id
        return db.get_user_department_id(target_user_id) == scope
    return False


def _validate_scoped_user_relation_update(requester_role, requester_id, target_user, field, value):
    """Validate direction/supervisor assignments made by a scoped manager."""
    if field not in ('direction_id', 'supervisor_id') or value is None:
        return None
    if _is_global_admin_requester(requester_role, requester_id):
        return None

    target_department_id = db.get_user_department_id(int(target_user[0]))
    if target_department_id is None:
        return ("Target user has no department", 403)

    if field == 'direction_id':
        try:
            requested_direction_id = int(value)
        except (TypeError, ValueError):
            return ("Invalid direction_id", 400)
        active_direction_ids = {
            int(item.get('id'))
            for item in (db.get_directions(department_id=target_department_id) or [])
            if isinstance(item, dict) and item.get('id') is not None
        }
        if requested_direction_id not in active_direction_ids:
            return ("Direction is outside the target user's department or inactive", 403)
        relation_department_id = target_department_id
    else:
        supervisor = db.get_user(id=value)
        if not supervisor or not _is_supervisor_role(supervisor[3]):
            return ("Supervisor not found or has invalid role", 400)
        relation_department_id = db.get_user_department_id(value)
        if relation_department_id is None:
            return ("Supervisor has no department", 400)

    try:
        same_department = int(relation_department_id) == int(target_department_id)
    except (TypeError, ValueError):
        same_department = False
    if not same_department:
        return (f"{field} does not belong to the target user's department", 403)
    return None


def _load_target_user_with_scope(
    requester,
    requester_id,
    target_user_id,
    *,
    allow_self=False,
    supervisor_target_roles=('operator', 'trainee'),
    not_found_message="User not found",
    forbidden_message="Forbidden"
):
    try:
        target_user_id_int = int(target_user_id)
    except (TypeError, ValueError):
        return None, ("Invalid target user id", 400)

    target_user = db.get_user(id=target_user_id_int)
    if not target_user:
        return None, (not_found_message, 404)

    if not _requester_can_access_target_user(
        requester,
        requester_id,
        target_user,
        allow_self=allow_self,
        supervisor_target_roles=supervisor_target_roles
    ):
        return None, (forbidden_message, 403)
    return target_user, None


# Тренеру раздел «Графики работы» открыт только на просмотр и только по двум
# отделам — СЗоВ и Отдел продаж (ОП). Сам доступ выдаётся в
# _resolve_work_schedule_viewer, а состав видимых операторов ограничивается
# этими отделами в _filter_operators_for_requester_scope.
TRAINER_WORK_SCHEDULE_DEPARTMENT_CODES = ('szov', 'op')


def _trainer_work_schedule_member_ids():
    """Множество id сотрудников отделов, доступных тренеру в «Графиках работы»."""
    allowed_codes = set(TRAINER_WORK_SCHEDULE_DEPARTMENT_CODES)
    member_ids = set()
    for dept in (db.get_departments() or []):
        if str(dept.get('code') or '').strip().lower() in allowed_codes:
            member_ids |= db.get_department_member_ids(dept.get('id'))
    return member_ids


def _filter_operators_for_requester_scope(requester, requester_id, operators):
    requester_role = _normalize_user_role(requester[3])
    items = list(operators or [])
    # Видят всех: супер-админ, админы
    if _is_global_admin_requester(requester_role, requester_id):
        return items
    # Глава отдела (любая базовая роль, включая тренера) — операторы своего
    # отдела; для главы нескольких отделов — объединение всех возглавляемых.
    headed_dept_ids = _headed_department_ids(requester_id)
    if headed_dept_ids:
        member_ids = set()
        for department_id in headed_dept_ids:
            member_ids.update(db.get_department_member_ids(department_id) or set())
        return [it for it in items if _operator_item_id(it) in member_ids]
    # Тренер — только просмотр и только операторы отделов СЗоВ и ОП.
    if requester_role == 'trainer':
        member_ids = _trainer_work_schedule_member_ids()
        return [it for it in items if _operator_item_id(it) in member_ids]
    # Супервайзер — только операторы своего отдела.
    if _is_supervisor_role(requester_role):
        scope = _department_scope_id_for_requester(requester_id)
        if scope is None:
            return items
        member_ids = db.get_department_member_ids(scope)
        return [it for it in items if _operator_item_id(it) in member_ids]
    return []


def _resolve_management_requester():
    requester_id, requester, auth_error = _get_authenticated_requester()
    if auth_error:
        return None, None, auth_error
    if not (
        _is_admin_role(requester[3])
        or _is_supervisor_role(requester[3])
        or _headed_department_id(requester_id) is not None
    ):
        return None, None, ("Forbidden", 403)
    return requester_id, requester, None


def _resolve_work_schedule_viewer():
    """Кто может ПРОСМАТРИВАТЬ графики работы.

    Помимо управленцев (админы / супервайзеры / главы отделов, которым доступно
    и редактирование) сюда входит роль «тренер» — но строго в режиме чтения и
    только по отделам СЗоВ и ОП (скоуп задаётся в
    _filter_operators_for_requester_scope). Мутационные эндпоинты графиков
    по-прежнему идут через _resolve_management_requester и тренеру недоступны.
    """
    requester_id, requester, auth_error = _get_authenticated_requester()
    if auth_error:
        return None, None, auth_error
    if (
        _is_admin_role(requester[3])
        or _is_supervisor_role(requester[3])
        or _headed_department_id(requester_id) is not None
        or _normalize_user_role(requester[3]) == 'trainer'
    ):
        return requester_id, requester, None
    return None, None, ("Forbidden", 403)


def _resolve_scoped_operator_for_requester(requester, requester_id, operator_id):
    return _load_target_user_with_scope(
        requester,
        requester_id,
        operator_id,
        allow_self=False,
        supervisor_target_roles=('operator',),
        not_found_message="Operator not found",
        forbidden_message="Forbidden for this operator"
    )


def _ensure_call_access_for_requester(call_operator_id, requester, requester_id):
    role = _normalize_user_role(requester[3])
    headed_dept_ids = _headed_department_ids(requester_id)
    if headed_dept_ids and not _is_super_admin_role(role):
        call_operator_department_id = db.get_user_department_id(call_operator_id)
        try:
            return call_operator_department_id is not None and int(call_operator_department_id) in headed_dept_ids
        except (TypeError, ValueError):
            return False
    if _is_global_admin_requester(role, requester_id):
        return True
    if role == 'operator':
        return requester_id == call_operator_id
    if role == 'sv':
        scope = _department_scope_id_for_requester(requester_id)
        if scope is not None:
            return db.get_user_department_id(call_operator_id) == scope
        operator = db.get_user(id=call_operator_id)
        return bool(operator and operator[3] == 'operator' and operator[6] == requester_id)
    return False


def _build_call_feedback_training_comment(call_id, feedback_comment, delivery_comment):
    return (
        f"ОС по оценке #{call_id}\n"
        f"Обратная связь: {feedback_comment}\n"
        f"Как проведена: {delivery_comment}"
    )


def _rebuild_call_feedback_training_comment(cursor, training_id):
    """Rebuild a training's comment from every feedback linked to it.

    A solo training (one feedback) keeps the legacy single-call format; a
    shared training (batch feedback covering several evaluations of the same
    operator in one session) gets an aggregated per-call breakdown. Returns
    the comment string, or None if no feedback references the training.
    """
    cursor.execute("""
        SELECT call_id, feedback_comment, delivery_comment
        FROM call_feedbacks
        WHERE training_id = %s
        ORDER BY call_id
    """, (training_id,))
    rows = cursor.fetchall()
    if not rows:
        return None
    if len(rows) == 1:
        call_id, feedback_comment, delivery_comment = rows[0]
        return _build_call_feedback_training_comment(
            int(call_id), feedback_comment or '', delivery_comment or ''
        )
    delivery_comment = next((r[2] for r in rows if r[2]), '') or ''
    call_ids = ", ".join(f"#{int(r[0])}" for r in rows)
    lines = [f"ОС по оценкам {call_ids}"]
    lines.extend(f"- #{int(r[0])}: {r[1] or ''}" for r in rows)
    lines.append(f"Как проведена: {delivery_comment}")
    return "\n".join(lines)


def _is_supervisor_role(role: str) -> bool:
    return _normalize_user_role(role) == 'sv'


# Отдел, чьи супервайзеры управляют аукционом смен наравне с главой отдела.
SHIFT_AUCTION_MANAGER_DEPARTMENT_CODE = 'szov'


def _is_shift_auction_manager(requester_id, requester_role) -> bool:
    """Кто может управлять аукционом смен (запуск, контроль, публикация и т.п.).

    Помимо админов — супервайзеры СЗоВ: им открыты те же действия, что и главе
    отдела (admin). Соответствует фронтовому ``canManage`` в ShiftAuctionView.
    """
    role = _normalize_user_role(requester_role)
    if _is_admin_role(role):
        return True
    if _is_supervisor_role(role) and requester_id:
        try:
            _, department_code = db.get_user_department(requester_id)
        except Exception:
            department_code = None
        return str(department_code or '').lower() == SHIFT_AUCTION_MANAGER_DEPARTMENT_CODE
    return False


def _current_almaty_datetime():
    try:
        return datetime.now(ZoneInfo('Asia/Almaty'))
    except Exception:
        return datetime.now()


def _is_supervisor_rate_change_day(now_dt=None) -> bool:
    current_dt = now_dt or _current_almaty_datetime()
    return int(current_dt.day) == 1


def _normalize_management_role(role):
    return _normalize_user_role(role)


def _effective_management_scope(requester, requester_id):
    role = _effective_scoped_manager_role(requester[3], requester_id)
    scope_department_id = None if _is_global_admin_requester(role, requester_id) else _department_scope_id_for_requester(requester_id)
    return role, scope_department_id


def _normalize_int_id_list(values):
    if values is None:
        return []
    if isinstance(values, (list, tuple, set)):
        raw_values = list(values)
    else:
        raw_values = [values]

    result = []
    seen = set()
    for item in raw_values:
        if item is None:
            continue
        if isinstance(item, str) and not item.strip():
            continue
        try:
            ivalue = int(item)
        except (TypeError, ValueError):
            continue
        if ivalue <= 0 or ivalue in seen:
            continue
        seen.add(ivalue)
        result.append(ivalue)
    return result


def _normalize_calibration_score_value(value):
    raw = str(value or '').strip().lower()
    mapping = {
        'correct': 'Correct',
        'ok': 'Correct',
        'n/a': 'N/A',
        'na': 'N/A',
        'n\\a': 'N/A',
        'incorrect': 'Incorrect',
        'deficiency': 'Deficiency',
        'error': 'Error'
    }
    return mapping.get(raw, str(value or 'Correct').strip() or 'Correct')


def _calibration_label_score(value):
    normalized = _normalize_calibration_score_value(value)
    labels = {
        'Correct': 'Корректно',
        'N/A': 'N/A',
        'Incorrect': 'Ошибка',
        'Deficiency': 'Недочет',
        'Error': 'Критич. ошибка'
    }
    return labels.get(normalized, normalized)


def _compute_total_score_from_criteria(criteria, scores):
    criteria = criteria if isinstance(criteria, list) else []
    scores = scores if isinstance(scores, list) else []
    has_critical_error = False
    total = 0.0

    for idx, criterion in enumerate(criteria):
        criterion = criterion if isinstance(criterion, dict) else {}
        score_value = _normalize_calibration_score_value(scores[idx] if idx < len(scores) else 'Correct')
        is_critical = bool(criterion.get('isCritical'))
        if is_critical:
            if score_value == 'Error':
                has_critical_error = True
            continue
        try:
            weight = float(criterion.get('weight') or 0)
        except Exception:
            weight = 0.0
        if score_value in ('Correct', 'N/A'):
            total += weight
        elif score_value == 'Deficiency':
            deficiency = criterion.get('deficiency') if isinstance(criterion.get('deficiency'), dict) else {}
            try:
                total += float(deficiency.get('weight') or 0)
            except Exception:
                pass

    if has_critical_error:
        return 0.0, True
    return round(float(total), 2), False


def _build_calibration_results(criteria, etalon_scores, etalon_comments, evaluations, admin_scores=None, admin_comments=None):
    criteria = criteria if isinstance(criteria, list) else []
    etalon_scores = etalon_scores if isinstance(etalon_scores, list) else []
    etalon_comments = etalon_comments if isinstance(etalon_comments, list) else []
    admin_scores = admin_scores if isinstance(admin_scores, list) else etalon_scores
    admin_comments = admin_comments if isinstance(admin_comments, list) else etalon_comments
    evaluations = evaluations if isinstance(evaluations, list) else []

    eval_count = len(evaluations)
    critical_mismatch = False
    rows = []

    for idx, criterion in enumerate(criteria):
        criterion = criterion if isinstance(criterion, dict) else {}
        is_critical = bool(criterion.get('isCritical'))
        admin_val = _normalize_calibration_score_value(admin_scores[idx] if idx < len(admin_scores) else 'Correct')
        etalon_val = _normalize_calibration_score_value(etalon_scores[idx] if idx < len(etalon_scores) else admin_val)
        # Percent is based on overall agreement between all participants:
        # admin + all supervisors. Etalon is displayed separately and does not
        # affect calibration percent.
        score_counts = {admin_val: 1}
        by_evaluator = []

        for evaluation in evaluations:
            ev_scores = evaluation.get('scores') if isinstance(evaluation.get('scores'), list) else []
            ev_comments = evaluation.get('criterion_comments') if isinstance(evaluation.get('criterion_comments'), list) else []
            ev_val = _normalize_calibration_score_value(ev_scores[idx] if idx < len(ev_scores) else 'Correct')
            score_counts[ev_val] = int(score_counts.get(ev_val, 0)) + 1
            is_match = ev_val == admin_val

            by_evaluator.append({
                "evaluator_id": evaluation.get('evaluator_id'),
                "score": ev_val,
                "score_label": _calibration_label_score(ev_val),
                "comment": (ev_comments[idx] if idx < len(ev_comments) else None) or None,
                "is_match": bool(is_match)
            })

        percent = None
        if eval_count > 0:
            participants_count = 1 + eval_count
            dominant_count = max(score_counts.values()) if score_counts else 0
            percent = round((dominant_count * 100.0) / float(participants_count), 1)
            if is_critical and dominant_count < participants_count:
                critical_mismatch = True
                percent = 0.0

        rows.append({
            "criterion_index": idx,
            "criterion_name": criterion.get('name') or f"Критерий {idx + 1}",
            "is_critical": is_critical,
            "percent": percent,
            "etalon": {
                "score": etalon_val,
                "score_label": _calibration_label_score(etalon_val),
                "comment": (etalon_comments[idx] if idx < len(etalon_comments) else None) or None
            },
            "admin": {
                "score": admin_val,
                "score_label": _calibration_label_score(admin_val),
                "comment": (admin_comments[idx] if idx < len(admin_comments) else None) or None
            },
            "benchmark": {
                "score": etalon_val,
                "score_label": _calibration_label_score(etalon_val),
                "comment": (etalon_comments[idx] if idx < len(etalon_comments) else None) or None
            },
            "by_evaluator": by_evaluator
        })

    overall_percent = None
    if rows and eval_count > 0:
        perc_values = [r.get('percent') for r in rows if r.get('percent') is not None]
        if perc_values:
            overall_percent = round(sum(perc_values) / float(len(perc_values)), 1)
    if critical_mismatch and overall_percent is not None:
        overall_percent = 0.0

    return {
        "criteria_rows": rows,
        "evaluated_count": eval_count,
        "critical_mismatch": critical_mismatch,
        "overall_percent": overall_percent
    }


def _build_signed_audio_url(audio_path):
    if not audio_path:
        return None
    try:
        path_parts = str(audio_path).split('/', 1)
        if len(path_parts) != 2:
            return None
        bucket_name, blob_path = path_parts
        bucket = get_gcs_client().bucket(bucket_name)
        blob = bucket.blob(blob_path)
        if not blob.exists():
            return None
        return blob.generate_signed_url(
            version="v4",
            expiration=timedelta(minutes=15),
            method="GET",
            response_type='audio/mpeg'
        )
    except Exception as e:
        logging.error("Error building signed audio URL: %s", e)
        return None


