def _send_task_completion_attachments_to_telegram(chat_id, task_subject, attachments, task_link=None):
    warnings = []
    if not chat_id or not attachments:
        return warnings

    telegram_url = f"https://api.telegram.org/bot{API_TOKEN}/sendDocument"
    gcs_client = None

    for idx, attachment in enumerate(attachments, start=1):
        try:
            storage_type = str(attachment.get('storage_type') or 'gcs').strip().lower() or 'gcs'
            file_name = (attachment.get('file_name') or f'attachment_{idx}').strip() or f'attachment_{idx}'
            content_type = (attachment.get('content_type') or '').strip() or 'application/octet-stream'

            if storage_type == 'gcs':
                bucket_name = (attachment.get('gcs_bucket') or '').strip()
                blob_path = (attachment.get('gcs_blob_path') or '').strip()
                if not bucket_name or not blob_path:
                    warnings.append(f"Не удалось отправить файл '{file_name}': отсутствуют метаданные хранилища")
                    continue
                if gcs_client is None:
                    gcs_client = get_gcs_client()
                blob = gcs_client.bucket(bucket_name).blob(blob_path)
                if not blob.exists():
                    warnings.append(f"Не удалось отправить файл '{file_name}': файл не найден в хранилище")
                    continue
                file_bytes = blob.download_as_bytes()
            else:
                file_data = attachment.get('file_data')
                if isinstance(file_data, memoryview):
                    file_bytes = file_data.tobytes()
                elif isinstance(file_data, bytearray):
                    file_bytes = bytes(file_data)
                elif isinstance(file_data, bytes):
                    file_bytes = file_data
                else:
                    warnings.append(f"Не удалось отправить файл '{file_name}': неподдерживаемый формат данных")
                    continue

            files = {
                'document': (file_name, file_bytes, content_type)
            }
            data = {
                'chat_id': int(chat_id)
            }
            if idx == 1:
                task_subject_html = _escape_telegram_html(task_subject or 'Без названия', 180)
                if task_link:
                    task_subject_html = (
                        f'<a href="{_escape_telegram_html(task_link, 500)}">'
                        f'{task_subject_html}'
                        '</a>'
                    )
                caption = (
                    "<b>📎 Файлы по задаче</b>\n"
                    f"{task_subject_html}"
                )
                if len(caption) > TELEGRAM_MAX_CAPTION_CHARS:
                    caption = caption[:TELEGRAM_MAX_CAPTION_CHARS]
                if caption:
                    data['caption'] = caption
                    data['parse_mode'] = 'HTML'

            response = requests.post(
                telegram_url,
                files=files,
                data=data,
                timeout=TASK_TELEGRAM_TIMEOUT_SECONDS
            )
            if response.status_code != 200:
                warnings.append(f"Не удалось отправить файл '{file_name}': {_get_telegram_error_text(response)}")
        except Exception as attachment_error:
            warnings.append(f"Не удалось отправить файл '{attachment.get('file_name') or idx}': {attachment_error}")

    return warnings


def _build_avatar_signed_url(bucket_name, blob_path):
    bucket_name = (bucket_name or '').strip()
    blob_path = (blob_path or '').strip()
    if not bucket_name or not blob_path:
        return None
    cache_key = (bucket_name, blob_path)
    now_ts = time.time()
    with AVATAR_SIGNED_URL_CACHE_LOCK:
        cached = AVATAR_SIGNED_URL_CACHE.get(cache_key)
        if cached and cached.get('expires_at', 0) > (now_ts + AVATAR_SIGNED_URL_CACHE_MIN_REMAINING_SECONDS):
            return cached.get('url')
        if cached:
            AVATAR_SIGNED_URL_CACHE.pop(cache_key, None)
    try:
        gcs_client = get_gcs_client()
        bucket = gcs_client.bucket(bucket_name)
        blob = bucket.blob(blob_path)
        signed_url = blob.generate_signed_url(
            version="v4",
            expiration=timedelta(seconds=AVATAR_SIGNED_URL_TTL_SECONDS),
            method="GET"
        )
        expires_at = now_ts + AVATAR_SIGNED_URL_TTL_SECONDS
        with AVATAR_SIGNED_URL_CACHE_LOCK:
            AVATAR_SIGNED_URL_CACHE[cache_key] = {
                "url": signed_url,
                "expires_at": expires_at
            }
            if len(AVATAR_SIGNED_URL_CACHE) > AVATAR_SIGNED_URL_CACHE_MAX_ITEMS:
                stale_keys = [k for k, v in AVATAR_SIGNED_URL_CACHE.items() if v.get('expires_at', 0) <= now_ts]
                for stale_key in stale_keys:
                    AVATAR_SIGNED_URL_CACHE.pop(stale_key, None)
                overflow = len(AVATAR_SIGNED_URL_CACHE) - AVATAR_SIGNED_URL_CACHE_MAX_ITEMS
                if overflow > 0:
                    oldest_keys = sorted(
                        AVATAR_SIGNED_URL_CACHE.items(),
                        key=lambda item: item[1].get('expires_at', 0)
                    )[:overflow]
                    for oldest_key, _ in oldest_keys:
                        AVATAR_SIGNED_URL_CACHE.pop(oldest_key, None)
        return signed_url
    except Exception as e:
        logging.warning(f"Failed to build avatar signed URL for bucket={bucket_name}: {e}")
        return None


def _sanitize_avatar_extension(source_filename, fallback='.webp'):
    safe_name = secure_filename(source_filename or "")
    extension = os.path.splitext(safe_name)[1].lower()
    if not extension or not re.match(r'^\.[a-z0-9]{1,10}$', extension):
        return fallback
    return extension


def _build_avatar_blob_paths(user_id, thumbnail_filename, original_filename=None):
    upload_folder = AVATAR_UPLOAD_FOLDER.strip('/')
    upload_prefix = f"{upload_folder}/" if upload_folder else ""
    thumbnail_ext = _sanitize_avatar_extension(thumbnail_filename, '.webp')
    original_ext = _sanitize_avatar_extension(original_filename or thumbnail_filename, thumbnail_ext)
    date_prefix = datetime.utcnow().strftime('%Y/%m/%d')
    random_id = uuid.uuid4().hex
    base_prefix = f"{upload_prefix}avatars/{int(user_id)}/{date_prefix}/{random_id}"
    return {
        "thumbnail_path": f"{base_prefix}_{AVATAR_THUMBNAIL_SUFFIX}{thumbnail_ext}",
        "original_path": f"{base_prefix}_original{original_ext}"
    }


def _delete_avatar_blobs(bucket_name, *blob_paths):
    bucket_name = (bucket_name or '').strip()
    unique_paths = []
    for item in blob_paths:
        path = (item or '').strip()
        if path and path not in unique_paths:
            unique_paths.append(path)
    if not bucket_name or not unique_paths:
        return
    try:
        client = get_gcs_client()
        bucket = client.bucket(bucket_name)
    except Exception:
        return
    for blob_path in unique_paths:
        try:
            bucket.blob(blob_path).delete()
        except Exception:
            pass


def _resolve_four_you_viewer_user_id():
    return FOUR_YOU_VIEWER_USER_ID if FOUR_YOU_VIEWER_USER_ID > 0 else None


def _four_you_access_for_requester(requester_id, requester):
    requester_role = _normalize_user_role(requester[3] if requester else None)
    requester_id = int(requester_id or 0)
    requester_status = str(requester[11] if requester and len(requester) > 11 else '').strip().lower()
    if requester_status in ('fired', 'dismissal'):
        return False, False
    can_upload = requester_role == 'super_admin' and requester_id == FOUR_YOU_ADMIN_USER_ID
    viewer_user_id = _resolve_four_you_viewer_user_id()
    can_view = can_upload or (viewer_user_id is not None and requester_id == int(viewer_user_id))
    return can_view, can_upload


def _four_you_route_guard(require_upload=False):
    requester_id, requester, auth_error = _get_authenticated_requester()
    if auth_error:
        message, status_code = auth_error
        return None, None, jsonify({"error": message}), status_code
    can_view, can_upload = _four_you_access_for_requester(requester_id, requester)
    if not can_view or (require_upload and not can_upload):
        return None, None, jsonify({"error": "Access denied"}), 403
    return requester_id, can_upload, None, None


def _four_you_bucket_name():
    return (
        (os.getenv('GOOGLE_CLOUD_STORAGE_BUCKET_FOUR_YOU') or '').strip()
        or (os.getenv('GOOGLE_CLOUD_STORAGE_BUCKET_TASKS') or '').strip()
        or (os.getenv('GOOGLE_CLOUD_STORAGE_BUCKET') or '').strip()
    )


def _four_you_convert_image_variants(raw_bytes):
    if Image is None:
        raise RuntimeError("Image processing is unavailable")
    try:
        with Image.open(BytesIO(raw_bytes)) as source:
            source_width, source_height = source.size
            if source_width <= 0 or source_height <= 0 or (source_width * source_height) > FOUR_YOU_MAX_IMAGE_PIXELS:
                raise ValueError("Image dimensions are not allowed")
            source.load()
            image = ImageOps.exif_transpose(source) if ImageOps is not None else source.copy()
            width, height = image.size
            if image.mode not in ('RGB', 'RGBA'):
                has_alpha = 'A' in image.getbands() or 'transparency' in image.info
                image = image.convert('RGBA' if has_alpha else 'RGB')

            resample = Image.Resampling.LANCZOS if hasattr(Image, 'Resampling') else Image.LANCZOS

            def _encode(max_side, quality):
                variant = image.copy()
                if max(variant.size) > max_side:
                    variant.thumbnail((max_side, max_side), resample)
                output = BytesIO()
                variant.save(
                    output,
                    format='WEBP',
                    quality=quality,
                    method=6,
                    optimize=True
                )
                return output.getvalue(), variant.size

            preview_bytes, _ = _encode(840, 80)
            display_bytes, display_size = _encode(1920, 88)
            return preview_bytes, display_bytes, int(display_size[0]), int(display_size[1])
    except (ValueError, RuntimeError):
        raise
    except Exception as error:
        raise ValueError("Unsupported or damaged image") from error


def _four_you_blob_paths():
    folder = FOUR_YOU_UPLOAD_FOLDER.strip('/')
    prefix = f"{folder}/" if folder else ""
    date_prefix = datetime.utcnow().strftime('%Y/%m/%d')
    random_id = uuid.uuid4().hex
    base_path = f"{prefix}{date_prefix}/{random_id}"
    return f"{base_path}_preview.webp", f"{base_path}_display.webp"


def _four_you_image_payload(image_row):
    return {
        "id": image_row.get("id"),
        "preview_url": _build_avatar_signed_url(
            image_row.get("preview_bucket"),
            image_row.get("preview_blob_path")
        ),
        "display_url": _build_avatar_signed_url(
            image_row.get("display_bucket"),
            image_row.get("display_blob_path")
        ),
        "width": int(image_row.get("width") or 0),
        "height": int(image_row.get("height") or 0),
        "created_at": image_row.get("created_at"),
        "annotations": image_row.get("annotations") or {},
        "annotations_updated_at": image_row.get("annotations_updated_at"),
    }


def _delete_four_you_blobs(image_row):
    refs = {
        (str(image_row.get("preview_bucket") or '').strip(), str(image_row.get("preview_blob_path") or '').strip()),
        (str(image_row.get("display_bucket") or '').strip(), str(image_row.get("display_blob_path") or '').strip()),
    }
    client = None
    for bucket_name, blob_path in refs:
        if not bucket_name or not blob_path:
            continue
        try:
            if client is None:
                client = get_gcs_client()
            client.bucket(bucket_name).blob(blob_path).delete()
        except Exception:
            logging.warning("Failed to delete 4 You blob %s/%s", bucket_name, blob_path, exc_info=True)


