def _wazzup_analytics_date(value):
    """'YYYY-MM-DD' или None; всё остальное — ошибка (в SQL идёт как ::date)."""
    value = (value or '').strip()
    if not value:
        return None
    datetime.strptime(value, '%Y-%m-%d')  # ValueError → 400 выше
    return value


