def _get_operator_month_salary_metrics(operator_id, month):
    """Return non-sensitive, month-scoped inputs used by the salary preview."""
    empty_payload = {
        "month": str(month),
        "quality_average": None,
        "quality_evaluation_count": 0,
        "quality_available": False,
    }
    try:
        aggregates = db.get_operator_score_aggregates_for_month(
            month=month,
            operator_ids=[operator_id],
        ) or {}
        aggregate = aggregates.get(int(operator_id)) or {}
        quality_count = int(aggregate.get("call_count") or 0)
        quality_average = aggregate.get("avg_score_raw")
        if quality_average is None:
            quality_average = aggregate.get("avg_score")
        quality_available = quality_count > 0 and quality_average is not None
        return {
            "month": str(month),
            "quality_average": float(quality_average) if quality_available else None,
            "quality_evaluation_count": quality_count,
            "quality_available": quality_available,
        }
    except Exception:
        # Сбой необязательного превью зарплаты не должен скрывать сами часы.
        logging.exception(
            "Failed to load salary quality metrics for operator %s, month %s",
            operator_id,
            month,
        )
        return empty_payload


@app.route('/api/sv/daily_hours', methods=['GET'])
@require_api_key
def sv_daily_hours():
    """
    Возвращает daily_hours за месяц для всех операторов текущего супервайзера.
    Если запрос делает обычный оператор — возвращаем только его daily_hours
    и нечувствительный месячный salary_metrics для превью зарплаты.
    Параметры:
      - month (query param) — YYYY-MM (опционально, по умолчанию текущий месяц)
      - id (query param) — (только для admin) id нужного supervisor
    Заголовки:
      - X-User-Id (обязательно) — id супервайзера/оператора (проверяется роль)
    """
    try:
        month = request.args.get('month') or datetime.now().strftime('%Y-%m')
        try:
            _year, _mon = map(int, str(month).split('-'))
            _month_start = dt_date(_year, _mon, 1)
            _month_end = dt_date(_year, _mon, calendar.monthrange(_year, _mon)[1])
        except Exception:
            return jsonify({"error": "Invalid month format. Use YYYY-MM"}), 400
        # group_id (опц.) — group-aware режим: операторы и метрики по группе за месяц.
        group_param = request.args.get('group_id')
        group_id = int(group_param) if group_param and str(group_param).isdigit() else None
        requester_id, requester, auth_error = _get_authenticated_requester()
        if auth_error:
            message, status_code = auth_error
            return jsonify({"error": message}), status_code

        role = _normalize_user_role(requester[3])
        headed_dept_id = _headed_department_id(requester_id)
        is_global_admin = _is_global_admin_requester(role, requester_id)
        if headed_dept_id is not None and not is_global_admin:
            if group_id is not None:
                _grp = db.get_group(group_id)
                if not (_grp and _grp.get('department_id') == headed_dept_id):
                    return jsonify({"error": "Forbidden: not your department's group"}), 403
                result = db.get_daily_hours_by_group_month(group_id, month)
            else:
                result = db.get_daily_hours_for_all_month(month, department_id=headed_dept_id)
            return jsonify({
                "status": "success",
                "month": result.get("month", month),
                "days_in_month": result.get("days_in_month"),
                "operators": result.get("operators", [])
            }), 200

        if _is_supervisor_role(role):
            user_param = request.args.get('id')
            if user_param and str(user_param).isdigit():
                supervisor_id = int(user_param)
            else:
                supervisor_id = requester_id

            if group_id is not None:
                # СВ может смотреть группы своего отдела (или те, что ведёт).
                # Проверяем по отделу запрашивающего (requester), а не выбранного СВ:
                # иначе проверка всегда проходила бы (группа принадлежит выбранному СВ).
                _grp = db.get_group(group_id)
                _req_dept = db.get_user_department_id(requester_id)
                _allowed = (
                    (_grp and _req_dept is not None and _grp.get('department_id') == _req_dept)
                    or db.supervisor_has_group_access_for_period(
                        requester_id, group_id, _month_start, _month_end
                    )
                )
                if not _allowed:
                    return jsonify({"error": "Forbidden: not your department's group"}), 403
                result = db.get_daily_hours_by_group_month(group_id, month)
            else:
                result = db.get_daily_hours_by_supervisor_month(supervisor_id, month)
            return jsonify({
                "status": "success",
                "month": result.get("month", month),
                "days_in_month": result.get("days_in_month"),
                "operators": result.get("operators", [])
            }), 200

        if role == 'operator':
            result = db.get_daily_hours_for_operator_month(requester_id, month)
            operator_obj = result.get("operator") if isinstance(result, dict) else None
            if operator_obj:
                operator_obj["salary_metrics"] = _get_operator_month_salary_metrics(
                    operator_id=requester_id,
                    month=month,
                )
            return jsonify({
                "status": "success",
                "month": result.get("month", month) if isinstance(result, dict) else month,
                "days_in_month": result.get("days_in_month") if isinstance(result, dict) else None,
                "operators": [operator_obj] if operator_obj else []
            }), 200

        if _is_admin_role(role):
            if group_id is not None:
                # Админ может смотреть любую группу; id супервайзера не требуется.
                result = db.get_daily_hours_by_group_month(group_id, month)
            else:
                user_id = request.args.get('id')
                if not user_id or not str(user_id).isdigit():
                    return jsonify({"error": "Missing or invalid 'id' parameter (supervisor id)"}), 400
                supervisor_id = int(user_id)
                result = db.get_daily_hours_by_supervisor_month(supervisor_id, month)
            operators = result.get("operators") if isinstance(result, dict) else None
            if operators is None:
                single = result.get("operator") if isinstance(result, dict) else None
                operators = [single] if single else []

            return jsonify({
                "status": "success",
                "month": result.get("month", month) if isinstance(result, dict) else month,
                "days_in_month": result.get("days_in_month"),
                "operators": operators
            }), 200

        return jsonify({"error": "Only supervisors, operators and admins can request this endpoint"}), 403

    except Exception as e:
        logging.exception("Error in sv_daily_hours")
        return jsonify({"error": f"Internal server error"}), 500

@app.route('/api/hours/upload_group_day', methods=['POST'])
@require_api_key
def upload_group_day():
    try:
        data = request.get_json()
        if not data:
            return jsonify({"error": "Empty payload"}), 400

        # Парсим базовые поля
        date_str = data.get('date')  # ожидаем YYYY-MM-DD
        if not date_str:
            return jsonify({"error": "Field 'date' is required (YYYY-MM-DD)"}), 400

        try:
            # проверяем формат даты
            day_obj = datetime.strptime(date_str, "%Y-%m-%d").date()
        except Exception:
            return jsonify({"error": "Invalid date format. Use YYYY-MM-DD"}), 400

        default_month = date_str[:7]  # YYYY-MM

        sv_id_payload = data.get('sv_id')  # может быть None
        operators = data.get('operators')
        if not operators or not isinstance(operators, list):
            return jsonify({"error": "Field 'operators' must be a non-empty array"}), 400

        group_id_raw = data.get('group_id')
        selected_group_id = None
        if group_id_raw not in (None, ''):
            try:
                selected_group_id = int(group_id_raw)
            except Exception:
                return jsonify({"error": "Invalid 'group_id' value"}), 400
            if selected_group_id <= 0:
                return jsonify({"error": "Invalid 'group_id' value"}), 400
            if not db.get_group(selected_group_id):
                return jsonify({"error": "Selected group not found"}), 404

        # Получаем id запроса (и проверяем пользователя)
        requester_header = request.headers.get('X-User-Id')
        if not requester_header or not requester_header.isdigit():
            return jsonify({"error": "Invalid or missing X-User-Id"}), 400
        requester_id = int(requester_header)
        requester = db.get_user(id=requester_id)
        if not requester:
            return jsonify({"error": "Requester not found"}), 403

        requester_role = _normalize_user_role(requester[3])  # согласно get_user селекту: u.role в позиции 3

        # Если запрос делает супервайзер — разрешаем только для его id (или если payload sv_id указан, он должен совпадать)
        if _is_supervisor_role(requester_role):
            sv_id = requester_id
        elif _is_admin_role(requester_role):
            if selected_group_id is None and sv_id_payload in (None, ''):
                return jsonify({"error": "Field 'sv_id' is required for admin requests"}), 400
            sv_id = None
            if sv_id_payload not in (None, ''):
                try:
                    sv_id = int(sv_id_payload)
                except Exception:
                    return jsonify({"error": "Invalid 'sv_id' value"}), 400

                supervisor_user = db.get_user(id=sv_id)
                supervisor_role = str(supervisor_user[3] or '').strip().lower() if supervisor_user else ''
                if not supervisor_user or supervisor_role not in ('sv', 'supervisor'):
                    return jsonify({"error": "Selected supervisor not found"}), 404
        else:
            return jsonify({"error": "Unauthorized: only supervisors or admins can upload hours"}), 403

        processed = []
        skipped = []
        errors = []
        processed_operator_ids = set()
        processed_months_by_operator = {}

        for idx, row in enumerate(operators):
            try:
                # Normalize fields
                op_id = row.get('operator_id')
                name = str(row.get('name') or '').strip()

                row_date_str = str(row.get('date') or date_str).strip()
                try:
                    row_day_obj = datetime.strptime(row_date_str, "%Y-%m-%d").date()
                except Exception:
                    skipped.append({"row": idx, "reason": "invalid row date format", "date": row.get('date')})
                    continue

                row_month = str(row.get('month') or row_date_str[:7]).strip()
                if not re.match(r'^\d{4}-\d{2}$', row_month):
                    row_month = row_date_str[:7]

                if selected_group_id is not None and _is_supervisor_role(requester_role):
                    if not db.supervisor_has_group_access_for_period(
                        requester_id, selected_group_id, row_day_obj, row_day_obj
                    ):
                        skipped.append({
                            "row": idx,
                            "reason": "supervisor has no access to selected group on row date",
                            "name": name,
                            "date": row_date_str,
                            "group_id": selected_group_id
                        })
                        continue

                def _optional_float(field_name):
                    if field_name not in row:
                        return None
                    raw_val = row.get(field_name)
                    if raw_val is None or raw_val == '':
                        return None
                    try:
                        return float(raw_val)
                    except Exception:
                        return None

                def _optional_int(field_name):
                    if field_name not in row:
                        return None
                    raw_val = row.get(field_name)
                    if raw_val is None or raw_val == '':
                        return 0
                    try:
                        return max(int(float(raw_val)), 0)
                    except Exception:
                        return 0

                # Поля, которых нет в payload, должны быть сохранены как есть из текущей записи дня.
                # Это позволяет при загрузке файла обновлять только calls, не затирая часы.
                work_time = _optional_float('work_time')
                break_time = _optional_float('break_time')
                talk_time = _optional_float('talk_time')
                calls = _optional_int('calls')
                efficiency = _optional_float('efficiency')
                fine_amount = _optional_float('fine_amount')

                fine_reason_provided = 'fine_reason' in row
                fine_comment_provided = 'fine_comment' in row
                fine_reason = (row.get('fine_reason') if fine_reason_provided else None)
                fine_comment = (row.get('fine_comment') if fine_comment_provided else None)
                if fine_reason is not None:
                    fine_reason = str(fine_reason).strip() or None
                if fine_comment is not None:
                    fine_comment = str(fine_comment).strip() or None

                # защита: принимаем только разрешённые причины (опционально)
                ALLOWED_FINE_REASONS = ['Корп такси', 'Опоздание', 'Прокси карта', 'Не выход', 'Другое']
                if fine_reason and fine_reason not in ALLOWED_FINE_REASONS:
                    # если невалидная причина — помечаем как "Другое" или сохраняем как есть, в примере — нормализуем в 'Другое'
                    fine_reason = 'Другое'
                # accept fines array (new format): list of {amount, reason, comment}
                fines_arr = row.get('fines') if ('fines' in row and isinstance(row.get('fines'), list)) else None
                # accept bonuses array (new format): list of {type, quantity, amount, friend_names, video_links}
                bonuses_arr = row.get('bonuses') if ('bonuses' in row and isinstance(row.get('bonuses'), list)) else None

                # resolve operator_id if not provided
                resolved_operator_id = None
                if op_id:
                    # verify operator exists
                    try:
                        op_id_int = int(op_id)
                        user_row = db.get_user(id=op_id_int)
                        if user_row and (selected_group_id is not None or user_row[3] == 'operator'):  # role == operator in legacy mode
                            if selected_group_id is not None:
                                if not db.operator_in_group_on_date(selected_group_id, op_id_int, row_day_obj):
                                    skipped.append({
                                        "row": idx,
                                        "reason": "operator not in selected group on row date",
                                        "name": name,
                                        "operator_id": op_id,
                                        "date": row_date_str,
                                        "group_id": selected_group_id
                                    })
                                    continue
                                resolved_operator_id = op_id_int
                                # group_id/date membership is authoritative in group-aware mode.
                                # Current users.supervisor_id may already point to the new group.
                            # Ensure operator belongs to the selected/current supervisor.
                            elif user_row[6] != sv_id:  # user_row[6] == supervisor_id in get_user select
                                skipped.append({"row": idx, "reason": "operator not under selected supervisor", "name": name, "operator_id": op_id})
                                continue
                            else:
                                resolved_operator_id = op_id_int
                        else:
                            skipped.append({"row": idx, "reason": "operator_id not found or not operator", "name": name, "operator_id": op_id})
                            continue
                    except Exception:
                        skipped.append({"row": idx, "reason": "invalid operator_id", "value": op_id})
                        continue
                else:
                    # try find by name under sv_id (if sv_id is known)
                    if selected_group_id is not None:
                        user_row = db.find_operator_in_group_by_name(selected_group_id, name, row_day_obj)
                        if user_row:
                            resolved_operator_id = user_row[0]
                    elif sv_id:
                        with db._get_cursor() as cursor:
                            cursor.execute("""
                                SELECT id FROM users
                                WHERE name = %s AND role = 'operator' AND supervisor_id = %s
                                LIMIT 1
                            """, (name, sv_id))
                            res = cursor.fetchone()
                            if res:
                                resolved_operator_id = res[0]
                    # if still not found, try global lookup (supervisor requests only)
                    if not resolved_operator_id:
                        if _is_admin_role(requester_role):
                            skipped.append({"row": idx, "reason": "operator not found under selected supervisor", "name": name})
                            continue
                        with db._get_cursor() as cursor:
                            cursor.execute("""
                                SELECT id FROM users
                                WHERE name = %s AND role = 'operator'
                                LIMIT 1
                            """, (name,))
                            res2 = cursor.fetchone()
                            if res2:
                                # if requester is sv, ensure operator belongs to them
                                if _is_supervisor_role(requester_role):
                                    # check supervisor
                                    with db._get_cursor() as c2:
                                        c2.execute("SELECT supervisor_id FROM users WHERE id = %s", (res2[0],))
                                        sp = c2.fetchone()
                                        if sp and sp[0] == sv_id:
                                            resolved_operator_id = res2[0]
                                        else:
                                            skipped.append({"row": idx, "reason": "operator found but not under this supervisor", "name": name})
                                            continue
                                else:
                                    resolved_operator_id = res2[0]

                if not resolved_operator_id:
                    skipped.append({"row": idx, "reason": "operator not found", "name": name})
                    continue

                # Подтягиваем текущие значения дня, если какое-то поле не передано в payload.
                existing_daily = None
                needs_existing = any(v is None for v in (work_time, break_time, talk_time, calls, efficiency, fine_amount))
                needs_existing = needs_existing or (not fine_reason_provided) or (not fine_comment_provided)
                if needs_existing:
                    with db._get_cursor() as cursor:
                        cursor.execute("""
                            SELECT
                                COALESCE(work_time, 0),
                                COALESCE(break_time, 0),
                                COALESCE(talk_time, 0),
                                COALESCE(calls, 0),
                                COALESCE(efficiency, 0),
                                COALESCE(fine_amount, 0),
                                fine_reason,
                                fine_comment
                            FROM daily_hours
                            WHERE operator_id = %s AND day = %s
                            LIMIT 1
                        """, (resolved_operator_id, row_day_obj))
                        existing_daily = cursor.fetchone()

                existing_work = float(existing_daily[0]) if existing_daily else 0.0
                existing_break = float(existing_daily[1]) if existing_daily else 0.0
                existing_talk = float(existing_daily[2]) if existing_daily else 0.0
                existing_calls = int(existing_daily[3]) if existing_daily else 0
                existing_eff = float(existing_daily[4]) if existing_daily else 0.0
                existing_fine_amount = float(existing_daily[5]) if existing_daily else 0.0
                existing_fine_reason = (existing_daily[6] if existing_daily else None)
                existing_fine_comment = (existing_daily[7] if existing_daily else None)

                work_time = float(existing_work if work_time is None else work_time)
                break_time = float(existing_break if break_time is None else break_time)
                talk_time = float(existing_talk if talk_time is None else talk_time)
                calls = max(int(existing_calls if calls is None else calls), 0)
                efficiency = float(existing_eff if efficiency is None else efficiency)
                fine_amount = float(existing_fine_amount if fine_amount is None else fine_amount)

                if not fine_reason_provided:
                    fine_reason = existing_fine_reason
                if not fine_comment_provided:
                    fine_comment = existing_fine_comment

                # Insert/update daily_hours
                try:
                    logging.info(
                        "Fine data: amount=%s, reason=%s, comment=%s",
                        fine_amount, fine_reason, fine_comment
                    )
                    # use the Database helper (assumes method exists)
                    db.insert_or_update_daily_hours(resolved_operator_id, row_date_str,
                                                    work_time=work_time,
                                                    break_time=break_time,
                                                    talk_time=talk_time,
                                                    calls=calls,
                                                    efficiency=efficiency,
                                                    fine_amount=fine_amount,
                                                    fine_reason=fine_reason,
                                                    fine_comment=fine_comment,
                                                    fines=fines_arr,
                                                    bonuses=bonuses_arr,
                                                    group_id=selected_group_id)

                    # Ручной ввод чат-метрик (если переданы): время ответа/переводы/средняя оценка.
                    # Количество чатов приходит только из отдельных отчётов метрик чатов (A+B),
                    # поэтому daily.calls больше не синхронизируем в chat_manager_daily_metrics.
                    # preserve_missing=True: пустые значения НЕ затирают импортированные (COALESCE).
                    chat_metrics_obj = row.get('chat_metrics')
                    if isinstance(chat_metrics_obj, dict):
                        def _cm_int(raw, default=None):
                            if raw in (None, ''):
                                return default
                            try:
                                return max(0, int(round(float(str(raw).replace(',', '.')))))
                            except Exception:
                                return default

                        def _cm_float(raw):
                            if raw in (None, ''):
                                return None
                            try:
                                v = float(str(raw).replace(',', '.'))
                                return v if v >= 0 else None
                            except Exception:
                                return None

                        metric_payload = {
                            'operator_id': resolved_operator_id,
                            'day': row_date_str,
                        }
                        metric_update_fields = []

                        avg_response_seconds = _cm_float(chat_metrics_obj.get('avg_response_time_seconds'))
                        if avg_response_seconds is not None:
                            metric_payload['avg_response_time_seconds'] = avg_response_seconds
                            metric_update_fields.append('avg_response_time_seconds')

                        transfer_chat_count = _cm_int(chat_metrics_obj.get('transfer_chat_count'), default=None)
                        if transfer_chat_count is not None:
                            metric_payload['transfer_chat_count'] = transfer_chat_count
                            metric_update_fields.append('transfer_chat_count')

                        avg_score = _cm_float(chat_metrics_obj.get('avg_score'))
                        if avg_score is not None:
                            metric_payload['avg_score'] = avg_score
                            # Ручной avg_score должен заменить импортную взвешенную оценку дня.
                            metric_payload['score_sum'] = None
                            metric_payload['score_count'] = None
                            metric_update_fields.extend(['avg_score', 'score_sum', 'score_count'])

                        try:
                            if metric_update_fields:
                                db.save_chat_manager_daily_metrics(
                                    [metric_payload],
                                    imported_by=requester_id,
                                    preserve_missing=True,
                                    update_fields=metric_update_fields
                                )
                        except Exception as _cm_err:
                            logging.warning("upload_group_day: failed to save chat metrics for op %s: %s", resolved_operator_id, _cm_err)

                    processed.append({
                        "row": idx,
                        "operator_id": resolved_operator_id,
                        "name": name,
                        "date": row_date_str,
                        "group_id": selected_group_id
                    })
                    processed_operator_ids.add(resolved_operator_id)
                    processed_months_by_operator.setdefault(resolved_operator_id, set()).add(row_month)
                except Exception as e:
                    errors.append({"row": idx, "operator_id": resolved_operator_id, "error": str(e)})
                    continue

            except Exception as e:
                errors.append({"row": idx, "error": str(e)})
                continue

        # После всех вставок — агрегируем месяц для каждого обработанного оператора
        aggregations = {}
        aggregations_by_month = {}
        for opid in processed_operator_ids:
            months_for_op = sorted(processed_months_by_operator.get(opid) or {default_month})
            aggregations_by_month[opid] = {}
            for month_value in months_for_op:
                try:
                    agg = db.aggregate_month_from_daily(opid, month_value)
                    aggregations_by_month[opid][month_value] = agg
                except Exception as e:
                    aggregations_by_month[opid][month_value] = {"error": str(e)}
            if months_for_op:
                last_month = months_for_op[-1]
                aggregations[opid] = aggregations_by_month[opid].get(last_month)

        return jsonify({
            "status": "success",
            "date": date_str,
            "month": default_month,
            "processed_count": len(processed),
            "processed": processed,
            "skipped_count": len(skipped),
            "skipped": skipped,
            "errors": errors,
            "aggregations": aggregations,
            "aggregations_by_month": aggregations_by_month
        }), 200

    except Exception as e:
        logging.exception("Error in upload_group_day")
        return jsonify({"error": f"Internal server error"}), 500

@app.route('/api/sv/save_table', methods=['POST'])
@require_api_key
def save_table():
    try:
        data = request.get_json()
        required_fields = ['table_url', 'direction_id', 'operators']
        if not data or not all(field in data for field in required_fields):
            return jsonify({"error": "Missing required fields: table_url, direction_id, operators"}), 400

        table_url = data['table_url']
        direction_id = int(data['direction_id'])
        operators = data['operators']  # List of dicts with 'name'

        user_id = int(request.headers.get('X-User-Id'))
        user = db.get_user(id=user_id)
        if not user or user[3] != 'sv':
            return jsonify({"error": "Unauthorized: Only supervisors can save tables"}), 403

        # Validate direction
        directions = db.get_directions()
        if not any(d['id'] == direction_id for d in directions):
            return jsonify({"error": "Invalid direction_id"}), 400

        # Update supervisor's hours table
        db.update_user_table(user_id=user_id, hours_table_url=table_url)

        # Create/update operators with direction and supervisor
        for op in operators:
            db.create_user(
                telegram_id=None,
                name=op['name'],
                role='operator',
                direction_id=direction_id,
                supervisor_id=user_id,
                hours_table_url=table_url
            )

        # Optional: Send Telegram notification to supervisor
        telegram_url = f"https://api.telegram.org/bot{API_TOKEN}/sendMessage"
        payload = {
            "chat_id": user[1],
            "text": f"Таблица часов успешно обновлена и операторы сохранены с направлением ID {direction_id} ✅",
            "parse_mode": "HTML"
        }
        response = requests.post(telegram_url, json=payload, timeout=10)
        if response.status_code != 200:
            logging.error(f"Telegram notification failed: {response.json().get('description')}")

        return jsonify({
            "status": "success",
            "message": "Table updated, operators saved with selected direction"
        }), 200
    except Exception as e:
        logging.error(f"Error saving table: {e}")
        return jsonify({"error": f"Internal server error"}), 500

@app.route('/api/user/change_login', methods=['POST'])
@require_api_key
def change_login():
    try:
        data = request.get_json()
        required_fields = ['user_id', 'new_login']
        if not data or not all(field in data for field in required_fields):
            return jsonify({"error": "Missing required fields (user_id, new_login)"}), 400

        user_id = int(data['user_id'])
        new_login = data['new_login']
        requester_id, requester, auth_error = _get_authenticated_requester()
        if auth_error:
            message, status_code = auth_error
            return jsonify({"error": message}), status_code

        if not new_login or len(new_login) < 4:
            return jsonify({"error": "New login must be at least 4 characters long"}), 400

        # Check if new login is already taken
        if db.get_user_by_login(new_login):
            return jsonify({"error": "Login is already in use"}), 400

        # Fetch target user; requester comes only from the authenticated JWT context.
        target_user = db.get_user(id=user_id)

        if not target_user:
            return jsonify({"error": "User not found"}), 404

        # Authorization checks. A formally assigned department head may manage
        # any non-admin employee in that department regardless of the head's
        # base role; regular admins/SVs retain their previous permissions.
        requester_role = _normalize_user_role(requester[3])
        target_role = _normalize_user_role(target_user[3])
        if requester_id != user_id:
            headed_dept_id = _headed_department_id(requester_id)
            if headed_dept_id is not None and not _is_super_admin_role(requester_role):
                if not _requester_can_access_target_user(
                    requester,
                    requester_id,
                    target_user,
                    allow_self=False,
                    supervisor_target_roles=('operator', 'trainee', 'trainer', 'sv')
                ):
                    return jsonify({"error": "Unauthorized to change this user's login"}), 403
            elif requester_role == 'operator':
                return jsonify({"error": "Operators can only change their own login"}), 403
            elif requester_role == 'sv':
                if target_role != 'operator' or target_user[6] != requester_id:
                    return jsonify({"error": "Supervisors can only change logins for their operators"}), 403
            elif not _is_admin_role(requester_role):
                return jsonify({"error": "Unauthorized to change this user's login"}), 403

        # Update login
        success = db.update_operator_login(user_id, target_user[6] if requester_role in ('sv', 'admin', 'super_admin') else None, new_login)
        if not success:
            return jsonify({"error": "Failed to update login"}), 500

        # Notify user via Telegram
        if target_user[1]:
            telegram_url = f"https://api.telegram.org/bot{API_TOKEN}/sendMessage"
            payload = {
                "chat_id": target_user[1],
                "text": f"Ваш логин был успешно изменён. Новый логин: <b>{new_login}</b>",
                "parse_mode": "HTML"
            }
            response = requests.post(telegram_url, json=payload, timeout=10)
            if response.status_code != 200:
                error_detail = response.json().get('description', 'Unknown error')
                logging.error(f"Telegram API error: {error_detail}")

        return jsonify({"status": "success", "message": f"Login updated for user {target_user[2]}"})

    except Exception as e:
        logging.error(f"Error changing login: {e}")
        return jsonify({"error": f"Internal server error"}), 500

@app.route('/api/user/hours', methods=['GET'])
@require_api_key
def get_user_hours():
    try:
        operator_id = request.args.get('operator_id')
        month = request.args.get('month')
        if not operator_id:
            return jsonify({"error": "Missing operator_id parameter"}), 400
        if not month:
            month = datetime.now().strftime('%Y-%m')

        requester_id, requester, auth_error = _get_authenticated_requester()
        if auth_error:
            message, status_code = auth_error
            return jsonify({"error": message}), status_code

        target_user, scope_error = _load_target_user_with_scope(
            requester,
            requester_id,
            operator_id,
            allow_self=True,
            supervisor_target_roles=('operator',),
            not_found_message="Operator not found",
            forbidden_message="Unauthorized to view this operator's hours"
        )
        if scope_error:
            message, status_code = scope_error
            return jsonify({"error": message}), status_code

        operator_id = int(target_user[0])
        hours_summary = db.get_hours_summary(operator_id=operator_id, month=month)

        if not hours_summary:
            return jsonify({"status": "success", "hours": None}), 200

        # Assuming get_hours_summary returns a list, take the first item
        hours_data = hours_summary[0]

        return jsonify({"status": "success", "hours": hours_data}), 200
    except Exception as e:
        logging.error(f"Error fetching hours data: {e}")
        return jsonify({"error": f"Internal server error"}), 500

@app.route('/api/admin/sv_list', methods=['GET'])
@require_api_key
def get_sv_list():
    try:
        requester_id, requester, auth_error = _get_authenticated_requester()
        if auth_error:
            message, status_code = auth_error
            return jsonify({"error": message}), status_code
        requester_role = _normalize_user_role(requester[3])
        headed_dept_ids = _headed_department_ids(requester_id)
        if not (_is_admin_role(requester_role) or _is_supervisor_role(requester_role) or headed_dept_ids):
            return jsonify({"error": "Only admins, supervisors or department heads can access supervisors list"}), 403

        is_global_admin = _is_global_admin_requester(requester_role, requester_id)
        include_full_profile = is_global_admin or bool(headed_dept_ids)
        with db._get_cursor() as cursor:
            if include_full_profile:
                cursor.execute("""
                    SELECT
                        id,
                        name,
                        hours_table_url,
                        role,
                        hire_date,
                        status,
                        gender,
                        birth_date,
                        avatar_bucket,
                        avatar_blob_path,
                        avatar_updated_at,
                        phone,
                        email,
                        personal_email,
                        instagram,
                        telegram_nick,
                        company_name,
                        employment_type,
                        study_place,
                        study_course,
                        study_completed,
                        study_completion_year,
                        close_contact_1_relation,
                        close_contact_1_full_name,
                        close_contact_1_phone,
                        close_contact_2_relation,
                        close_contact_2_full_name,
                        close_contact_2_phone,
                        card_number,
                        COALESCE(has_proxy, FALSE) as has_proxy,
                        proxy_card_number,
                        proxy_status,
                        internship_in_company,
                        front_office_training,
                        front_office_training_date,
                        taxipro_id,
                        rate,
                        direction_id,
                        supervisor_id,
                        department_id
                    FROM users
                    WHERE LOWER(COALESCE(role, '')) IN ('sv', 'supervisor')
                    ORDER BY name
                """)
                supervisors = cursor.fetchall()
                if headed_dept_ids and not is_global_admin:
                    supervisors = [
                        supervisor for supervisor in supervisors
                        if supervisor[39] is not None and int(supervisor[39]) in headed_dept_ids
                    ]
                sv_data = []
                for sv in supervisors:
                    sv_data.append({
                        "id": sv[0],
                        "name": sv[1],
                        "table": sv[2],
                        "role": _normalize_user_role(sv[3]),
                        "hire_date": sv[4].strftime('%d-%m-%Y') if sv[4] else None,
                        "status": sv[5],
                        "gender": sv[6],
                        "birth_date": sv[7].strftime('%d-%m-%Y') if sv[7] else None,
                        "avatar_url": _build_avatar_signed_url(sv[8], sv[9]),
                        "avatar_updated_at": sv[10].isoformat() if sv[10] else None,
                        "phone": sv[11] or "",
                        "email": sv[12] or "",
                        "personal_email": sv[13] or "",
                        "instagram": sv[14] or "",
                        "telegram_nick": sv[15] or "",
                        "company_name": sv[16] or "",
                        "employment_type": sv[17] or "",
                        "study_place": sv[18] or "",
                        "study_course": sv[19] or "",
                        "study_completed": bool(sv[20]) if sv[20] is not None else False,
                        "study_completion_year": int(sv[21]) if sv[21] is not None else None,
                        "close_contact_1_relation": sv[22] or "",
                        "close_contact_1_full_name": sv[23] or "",
                        "close_contact_1_phone": sv[24] or "",
                        "close_contact_2_relation": sv[25] or "",
                        "close_contact_2_full_name": sv[26] or "",
                        "close_contact_2_phone": sv[27] or "",
                        "card_number": sv[28] or "",
                        "has_proxy": bool(sv[29]) if sv[29] is not None else False,
                        "proxy_card_number": sv[30] or "",
                        "proxy_status": sv[31] or "",
                        "proxy_status_label": PROXY_STATUS_LABELS.get(str(sv[31] or '').strip().lower(), ""),
                        "internship_in_company": bool(sv[32]) if sv[32] is not None else False,
                        "front_office_training": bool(sv[33]) if sv[33] is not None else False,
                        "front_office_training_date": sv[34].strftime('%Y-%m-%d') if sv[34] else None,
                        "taxipro_id": sv[35] or "",
                        "rate": float(sv[36]) if sv[36] is not None else 1.0,
                        "direction_id": sv[37],
                        "supervisor_id": sv[38],
                        "department_id": sv[39]
                    })
            else:
                # Супервайзер видит только супервайзеров СВОЕГО отдела
                # (главы отделов сюда не попадают: им всегда отдаётся полный
                # профиль с фильтром по возглавляемым отделам выше).
                sv_scope_dept = _department_scope_id_for_requester(requester_id)
                if sv_scope_dept is not None:
                    cursor.execute("""
                        SELECT id, name, hours_table_url, role, hire_date, status, avatar_bucket, avatar_blob_path, department_id
                        FROM users
                        WHERE LOWER(COALESCE(role, '')) IN ('sv', 'supervisor')
                          AND department_id = %s
                        ORDER BY name
                    """, (sv_scope_dept,))
                else:
                    cursor.execute("""
                        SELECT id, name, hours_table_url, role, hire_date, status, avatar_bucket, avatar_blob_path, department_id
                        FROM users
                        WHERE LOWER(COALESCE(role, '')) IN ('sv', 'supervisor')
                        ORDER BY name
                    """)
                supervisors = cursor.fetchall()
                sv_data = [
                    {
                        "id": sv[0],
                        "name": sv[1],
                        "table": sv[2],
                        "role": _normalize_user_role(sv[3]),
                        "hire_date": sv[4].strftime('%d-%m-%Y') if sv[4] else None,
                        "status": sv[5],
                        "avatar_url": _build_avatar_signed_url(sv[6], sv[7]),
                        "department_id": sv[8]
                    }
                    for sv in supervisors
                ]

        logging.info(f"Fetched {len(sv_data)} supervisors")
        return jsonify({"status": "success", "sv_list": sv_data})
    except Exception as e:
        logging.error(f"Error fetching SV list: {e}", exc_info=True)
        return jsonify({"error": "Failed to fetch supervisors"}), 500

@app.route('/api/admin/call_feedback_report_setting', methods=['GET', 'POST'])
@require_api_key
def admin_call_feedback_report_setting():
    try:
        requester_id, requester, auth_error = _get_authenticated_requester()
        if auth_error:
            message, status_code = auth_error
            return jsonify({"error": message}), status_code

        requester_role = _normalize_user_role(requester[3])
        is_admin = _is_admin_role(requester_role)
        headed_departments = db.get_headed_departments_for_user(requester_id) or []
        if not is_admin and not headed_departments:
            return jsonify({"error": "Only admins and department heads can manage this setting"}), 403
        report_scope = "global" if is_admin else "department"
        report_department_names = [
            str(item.get('name') or '') for item in headed_departments if item.get('name')
        ]
        report_department_name = ", ".join(report_department_names)

        if request.method == 'GET':
            enabled = db.get_admin_feedback_telegram_report_setting(requester_id)
            if enabled is None:
                return jsonify({"error": "Admin user not found"}), 404
            return jsonify({
                "status": "success",
                "enabled": bool(enabled),
                "telegram_connected": bool(requester[1]),
                "scope": report_scope,
                "department_name": report_department_name or None,
                "department_names": report_department_names,
            }), 200

        data = request.get_json(silent=True) or {}
        raw_enabled = data.get('enabled')
        if isinstance(raw_enabled, bool):
            enabled = raw_enabled
        elif isinstance(raw_enabled, (int, float)):
            enabled = bool(raw_enabled)
        elif isinstance(raw_enabled, str):
            norm = raw_enabled.strip().lower()
            if norm in ('1', 'true', 'yes', 'on'):
                enabled = True
            elif norm in ('0', 'false', 'no', 'off', ''):
                enabled = False
            else:
                return jsonify({"error": "Invalid enabled value"}), 400
        else:
            return jsonify({"error": "enabled is required"}), 400

        updated = db.set_admin_feedback_telegram_report_setting(requester_id, enabled)
        if updated is None:
            return jsonify({"error": "Admin user not found"}), 404

        return jsonify({
            "status": "success",
            "enabled": bool(updated),
            "telegram_connected": bool(requester[1]),
            "scope": report_scope,
            "department_name": report_department_name or None,
            "department_names": report_department_names,
        }), 200

    except Exception:
        logging.exception("Error in /api/admin/call_feedback_report_setting")
        return jsonify({"error": "Internal server error"}), 500


@app.route('/api/admin/call_feedback_report_preview', methods=['POST'])
@require_api_key
def admin_call_feedback_report_preview():
    """Разово сформировать текущий Excel-отчёт и отправить его администратору в Telegram."""
    try:
        requester_id, requester, auth_error = _get_authenticated_requester()
        if auth_error:
            message, status_code = auth_error
            return jsonify({"error": message}), status_code

        requester_role = _normalize_user_role(requester[3])
        is_admin = _is_admin_role(requester_role)
        headed_departments = db.get_headed_departments_for_user(requester_id) or []
        if not is_admin and not headed_departments:
            return jsonify({"error": "Only admins and department heads can request this report"}), 403

        department_ids = None if is_admin else [
            int(item.get('id')) for item in headed_departments if item.get('id') is not None
        ]
        department_names = [
            str(item.get('name') or '') for item in headed_departments if item.get('name')
        ]
        scope_label = 'Все отделы' if is_admin else (', '.join(department_names) or 'Отдел главы')

        telegram_id = requester[1]
        if not telegram_id:
            return jsonify({"error": "Telegram не подключён к профилю"}), 400

        try:
            now_dt = datetime.now(ZoneInfo('Asia/Almaty'))
        except Exception:
            now_dt = datetime.now()

        month = now_dt.strftime('%Y-%m')
        generated_label = now_dt.strftime('%d.%m.%Y %H:%M')
        report_data = db.get_feedback_sla_report_for_month(
            month=month,
            department_ids=department_ids,
            reference_date=now_dt.date()
        ) or {}
        xlsx_bytes = _build_call_feedback_report_xlsx(
            report_data=report_data,
            month=month,
            generated_at=generated_label,
            scope_label=scope_label
        )
        response = _send_call_feedback_report_document(
            chat_id=telegram_id,
            xlsx_bytes=xlsx_bytes,
            month=month,
            generated_label=generated_label,
            preview=True,
            scope_label=scope_label
        )
        if response.status_code != 200:
            logging.warning(
                "Call feedback Excel preview send failed for admin %s: %s",
                requester_id,
                _get_telegram_error_text(response)
            )
            return jsonify({"error": "Не удалось отправить отчёт в Telegram"}), 502

        return jsonify({
            "status": "success",
            "month": month,
            "scope": "global" if is_admin else "department",
            "department_name": None if is_admin else scope_label,
            "message": "Excel-отчёт отправлен в Telegram"
        }), 200
    except Exception:
        logging.exception("Error in /api/admin/call_feedback_report_preview")
        return jsonify({"error": "Internal server error"}), 500


def _parse_boolean_setting(raw_value, field_name='enabled'):
    if isinstance(raw_value, bool):
        return raw_value, None
    if isinstance(raw_value, (int, float)):
        return bool(raw_value), None
    if isinstance(raw_value, str):
        norm = raw_value.strip().lower()
        if norm in ('1', 'true', 'yes', 'on'):
            return True, None
        if norm in ('0', 'false', 'no', 'off', ''):
            return False, None
    return None, f"Invalid {field_name} value"


def _build_call_evaluation_notification_settings_payload(requester_id, requester, is_admin, headed_dept_id):
    setting = db.get_call_evaluation_notify_setting(requester_id)
    if setting is None:
        return None

    if is_admin:
        departments = [
            dept for dept in (db.get_departments() or [])
            if isinstance(dept, dict) and dept.get('is_active') is not False
        ]
        department_id = setting.get('department_id')
        department_name = setting.get('department_name')
        if department_id and not department_name:
            dept = db.get_department_by_id(department_id)
            department_name = (dept or {}).get('name') if isinstance(dept, dict) else None
        enabled = bool(setting.get('enabled') and department_id is not None)
        scope = 'admin'
    else:
        dept = db.get_department_by_id(headed_dept_id) if headed_dept_id else None
        departments = [dept] if isinstance(dept, dict) else []
        department_id = int(headed_dept_id) if headed_dept_id is not None else None
        department_name = (dept or {}).get('name') if isinstance(dept, dict) else None
        enabled = bool(setting.get('enabled') and setting.get('department_id') == department_id)
        scope = 'department'

    return {
        "status": "success",
        "enabled": enabled,
        "telegram_connected": bool(requester[1]) if requester else False,
        "scope": scope,
        "department_id": department_id,
        "department_name": department_name,
        "departments": departments,
    }


@app.route('/api/call_evaluation/notification_settings', methods=['GET', 'PUT', 'OPTIONS'])
@require_api_key
def call_evaluation_notification_settings():
    if request.method == 'OPTIONS':
        return _build_cors_preflight_response()

    try:
        requester_id, requester, auth_error = _get_authenticated_requester()
        if auth_error:
            message, status_code = auth_error
            return jsonify({"error": message}), status_code

        requester_role = _normalize_user_role(requester[3]) if requester else ''
        is_admin = _is_admin_role(requester_role)
        headed_dept_id = db.headed_department_id_for_user(requester_id)
        if not is_admin and headed_dept_id is None:
            return jsonify({"error": "Only admins and department heads can manage evaluation notifications"}), 403

        if request.method == 'GET':
            payload = _build_call_evaluation_notification_settings_payload(
                requester_id, requester, is_admin, headed_dept_id
            )
            if payload is None:
                return jsonify({"error": "User not found"}), 404
            return jsonify(payload), 200

        data = request.get_json(silent=True) or {}
        raw_enabled = data.get('enabled', data.get('call_evaluation_notify_enabled'))
        if raw_enabled is None:
            return jsonify({"error": "enabled is required"}), 400
        enabled, parse_error = _parse_boolean_setting(raw_enabled, 'enabled')
        if parse_error:
            return jsonify({"error": parse_error}), 400

        if is_admin:
            raw_department_id = data.get('department_id', data.get('call_evaluation_notify_department_id'))
            if raw_department_id in (None, '') and enabled:
                current = db.get_call_evaluation_notify_setting(requester_id) or {}
                raw_department_id = current.get('department_id')
            department_id = None
            if raw_department_id not in (None, ''):
                try:
                    department_id = int(raw_department_id)
                except (TypeError, ValueError):
                    return jsonify({"error": "Invalid department_id"}), 400
            if enabled and department_id is None:
                return jsonify({"error": "department_id is required"}), 400
            if department_id is not None:
                department = db.get_department_by_id(department_id)
                if not department or department.get('is_active') is False:
                    return jsonify({"error": "Department not found"}), 404
        else:
            department_id = int(headed_dept_id)
            department = db.get_department_by_id(department_id)
            if not department or department.get('is_active') is False:
                return jsonify({"error": "Department not found"}), 404

        updated = db.set_call_evaluation_notify_setting(
            requester_id,
            bool(enabled),
            department_id
        )
        if updated is None:
            return jsonify({"error": "User not found"}), 404

        payload = _build_call_evaluation_notification_settings_payload(
            requester_id, requester, is_admin, headed_dept_id
        )
        if payload is None:
            return jsonify({"error": "User not found"}), 404
        return jsonify(payload), 200

    except Exception:
        logging.exception("Error in /api/call_evaluation/notification_settings")
        return jsonify({"error": "Internal server error"}), 500

