@app.route('/api/ai/birthday_greeting', methods=['POST'])
@require_api_key
def ai_birthday_greeting():
    try:
        requester_id = getattr(g, 'user_id', None) or request.headers.get('X-User-Id')
        if not requester_id:
            return jsonify({"status": "error", "error": "Missing X-User-Id header"}), 400

        try:
            requester_id = int(requester_id)
        except (ValueError, TypeError):
            return jsonify({"status": "error", "error": "Invalid X-User-Id format"}), 400

        requester = db.get_user(id=requester_id)
        if not requester:
            return jsonify({"status": "error", "error": "User not found"}), 404

        status = str(requester[11] or '').strip().lower()
        if status in ('fired', 'dismissal'):
            return jsonify({"status": "error", "error": "User is not active"}), 403

        birth_date = requester[14]
        if not birth_date:
            return jsonify({"status": "error", "error": "Birth date not set"}), 404

        today = datetime.now().date()
        if birth_date.month != today.month or birth_date.day != today.day:
            return jsonify({"status": "error", "error": "Not birthday"}), 409

        user_payload = {
            "id": requester_id,
            "name": requester[2],
            "role": requester[3],
            "direction": requester[4],
            "gender": requester[13],
            "hire_date": requester[5].strftime('%Y-%m-%d') if requester[5] else None
        }

        try:
            loop = asyncio.get_event_loop()
        except RuntimeError:
            loop = None

        if loop and loop.is_running():
            fut = asyncio.run_coroutine_threadsafe(
                generate_birthday_greeting_with_ai(user_payload=user_payload, for_date=today.isoformat()),
                loop,
            )
            result = fut.result(timeout=120)
        else:
            result = asyncio.run(generate_birthday_greeting_with_ai(user_payload=user_payload, for_date=today.isoformat()))

        if result is None:
            return jsonify({"status": "error", "error": "ai_failed"}), 500

        if isinstance(result, dict) and result.get('error'):
            return jsonify({"status": "error", "error": result}), 200

        return jsonify({"status": "success", "result": result}), 200

    except Exception as e:
        logging.exception("Error in /api/ai/birthday_greeting")
        return jsonify({"status": "error", "error": f"Internal server error"}), 500


@app.route('/api/ai/monthly_feedback', methods=['POST'])
@require_api_key
def ai_monthly_feedback():
    try:
        # Проверка прав - admin, sv и operator (operator только для чтения из кэша)
        requester_id = request.headers.get('X-User-Id')
        if not requester_id:
            return jsonify({"status": "error", "error": "Missing X-User-Id header"}), 400
        
        try:
            requester_id = int(requester_id)
        except (ValueError, TypeError):
            return jsonify({"status": "error", "error": "Invalid X-User-Id format"}), 400
        
        requester = db.get_user(id=requester_id)
        requester_role = _normalize_user_role(requester[3]) if requester else ''
        if not requester or (not _is_admin_role(requester_role) and requester_role not in ('sv', 'operator')):
            return jsonify({"status": "error", "error": "Access denied"}), 403

        is_operator = requester_role == 'operator'

        data = request.get_json() or {}
        operator_id = data.get('operator_id')
        month = data.get('month')

        if operator_id is None or month is None:
            return jsonify({"status": "error", "error": "Missing operator_id or month"}), 400

        try:
            operator_id = int(operator_id)
        except Exception:
            return jsonify({"status": "error", "error": "Invalid operator_id"}), 400

        try:
            datetime.strptime(str(month), "%Y-%m")
        except Exception:
            return jsonify({"status": "error", "error": "Invalid month format. Use YYYY-MM"}), 400

        # Для операторов проверяем только кэш
        if is_operator:
            cached_feedback = db.get_ai_feedback_cache(requester_id, str(month))
            if cached_feedback:
                return jsonify({"status": "success", "result": cached_feedback['feedback_data']}), 200
            else:
                return jsonify({"status": "error", "error": "No cached feedback available"}), 404

        try:
            loop = asyncio.get_event_loop()
        except RuntimeError:
            loop = None

        if loop and loop.is_running():
            fut = asyncio.run_coroutine_threadsafe(
                generate_monthly_feedback_with_ai(operator_id=operator_id, month=str(month)),
                loop,
            )
            result = fut.result(timeout=180)
        else:
            result = asyncio.run(generate_monthly_feedback_with_ai(operator_id=operator_id, month=str(month)))

        if result is None:
            return jsonify({"status": "error", "error": "ai_failed"}), 500

        if isinstance(result, dict) and result.get('error'):
            return jsonify({"status": "error", "error": result}), 200

        return jsonify({"status": "success", "result": result}), 200

    except Exception as e:
        logging.exception("Error in /api/ai/monthly_feedback")
        return jsonify({"status": "error", "error": f"Internal server error"}), 500

@app.route('/api/admin/operators_summary', methods=['GET'])
@require_api_key
def operators_summary():
    try:
        # month required (YYYY-MM)
        month = request.args.get('month')
        if not month:
            return jsonify({"error": "Missing month parameter (YYYY-MM)"}), 400
        from datetime import datetime
        try:
            datetime.strptime(month, "%Y-%m")
        except ValueError:
            return jsonify({"error": "Invalid month format. Use YYYY-MM"}), 400

        # requester identity + role check
        user_id_header = getattr(g, 'user_id', None) or request.headers.get('X-User-Id')
        if not user_id_header:
            return jsonify({"error": "Missing X-User-Id header"}), 400
        try:
            requester_id = int(user_id_header)
        except (ValueError, TypeError):
            return jsonify({"error": "Invalid X-User-Id format"}), 400

        requester = db.get_user(id=requester_id)
        if not requester:
            return jsonify({"error": "Requester not found"}), 404

        # requester role: support tuple/dict user shapes (following your existing pattern)
        role = None
        if isinstance(requester, dict):
            role = requester.get('role')
        else:
            # assume role in pos 3 like in other parts of code
            role = requester[3] if len(requester) > 3 else None
        role = _normalize_user_role(role)

        if not (_is_admin_role(role) or _is_supervisor_role(role)):
            return jsonify({"error": "Forbidden: only admins or supervisors can access"}), 403

        # optional supervisor_id param: admin can request any sv; sv will be forced to their id
        sv_param = request.args.get('supervisor_id')
        supervisor_id = None
        if _is_supervisor_role(role):
            # if requester is SV — restrict to their operators only
            supervisor_id = requester_id
        else:
            # admin: allow optional supervisor filter
            if sv_param:
                try:
                    supervisor_id = int(sv_param)
                except ValueError:
                    return jsonify({"error": "Invalid supervisor_id"}), 400

        operators = db.get_operators_summary_for_month(month=month, supervisor_id=supervisor_id)
        operator_ids_for_feedback = []
        for item in (operators or []):
            try:
                operator_ids_for_feedback.append(int(item.get('id')))
            except Exception:
                continue

        feedback_stats_by_operator = {}
        if operator_ids_for_feedback:
            try:
                feedback_stats_by_operator = db.get_feedback_sla_operator_stats_for_month(
                    month=month,
                    operator_ids=operator_ids_for_feedback
                ) or {}
            except Exception:
                logging.exception("Failed to load feedback SLA stats for operators summary")
                feedback_stats_by_operator = {}

        for item in (operators or []):
            try:
                op_id = int(item.get('id'))
            except Exception:
                op_id = None
            stats = feedback_stats_by_operator.get(op_id, {}) if op_id is not None else {}
            item['feedback_stats'] = stats
            item['feedback_count'] = int(stats.get('feedback_count') or 0)
            item['feedback_overdue_count'] = int(stats.get('overdue_count') or 0)
            item['feedback_pending_count'] = int(stats.get('pending_count') or 0)

        return jsonify({"status": "success", "month": month, "operators": operators}), 200

    except Exception as e:
        logging.exception("Error in /api/admin/operators_summary")
        return jsonify({"error": "Internal server error"}), 500

@app.route('/api/admin/change_sv_table', methods=['POST'])
@require_api_key
def change_sv_table():
    try:
        requester_id, requester, auth_error = _get_authenticated_requester()
        if auth_error:
            message, status_code = auth_error
            return jsonify({"error": message}), status_code
        if not (_is_admin_role(requester[3]) or _is_supervisor_role(requester[3])):
            return jsonify({"error": "Only admins or supervisors can change supervisor tables"}), 403

        data = request.get_json()
        required_fields = ['id', 'table_url']
        if not data or not all(field in data for field in required_fields):
            return jsonify({"error": "Missing required fields"}), 400

        sv_id = int(data['id'])
        table_url = data['table_url']
        
        sheet_name, operators, error = extract_fio_and_links(table_url)
        if error:
            return jsonify({"error": error}), 400
        
        db.update_user_table(sv_id, table_url)
        
        telegram_url = f"https://api.telegram.org/bot{API_TOKEN}/sendMessage"
        payload = {
            "chat_id": db.get_user(id=sv_id)[1],
            "text": f"Таблица успешно обновлена администратором <b>успешно✅</b>",
            "parse_mode": "HTML"
        }
        response = requests.post(telegram_url, json=payload, timeout=10)
        if response.status_code != 200:
            error_detail = response.json().get('description', 'Unknown error')
            logging.error(f"Telegram API error: {error_detail}")
        
        return jsonify({
            "status": "success",
            "message": "Table updated",
            "operators": operators
        })
    except Exception as e:
        logging.error(f"Error updating SV table: {e}")
        return jsonify({"error": f"Internal server error"}), 500

def _normalize_reevaluation_request_role(role):
    role_norm = _normalize_user_role(role)
    if _is_admin_role(role_norm):
        return 'admin'
    return role_norm


def _reevaluation_request_role_label(role):
    role_norm = _normalize_reevaluation_request_role(role)
    labels = {
        'operator': 'оператора',
        'sv': 'супервайзера',
        'admin': 'администратора'
    }
    return labels.get(role_norm, 'сотрудника')


def _get_call_reevaluation_context(call_id):
    with db._get_cursor() as cursor:
        cursor.execute("""
            SELECT
                c.id,
                c.operator_id,
                op.name,
                op.telegram_id,
                op.supervisor_id,
                sv.name,
                sv.telegram_id,
                c.evaluator_id,
                ev.name,
                ev.telegram_id,
                c.month,
                c.phone_number,
                TO_CHAR(c.appeal_date, 'YYYY-MM-DD HH24:MI') AS appeal_date_text,
                c.score,
                c.is_draft,
                c.sv_request,
                c.sv_request_comment,
                c.sv_request_by,
                req.name,
                req.telegram_id,
                c.sv_request_by_role,
                TO_CHAR(c.sv_request_at, 'YYYY-MM-DD HH24:MI') AS sv_request_at_text,
                c.sv_request_approved,
                c.sv_request_approved_by,
                c.sv_request_rejected,
                c.sv_request_rejected_by,
                c.sv_request_reject_comment
            FROM calls c
            JOIN users op ON op.id = c.operator_id
            LEFT JOIN users sv ON sv.id = op.supervisor_id
            LEFT JOIN users ev ON ev.id = c.evaluator_id
            LEFT JOIN users req ON req.id = c.sv_request_by
            WHERE c.id = %s
            LIMIT 1
        """, (call_id,))
        row = cursor.fetchone()

    if not row:
        return None

    return {
        "call_id": int(row[0]),
        "operator_id": int(row[1]),
        "operator_name": row[2],
        "operator_tg_id": row[3],
        "supervisor_id": int(row[4]) if row[4] is not None else None,
        "supervisor_name": row[5],
        "supervisor_tg_id": row[6],
        "evaluator_id": int(row[7]) if row[7] is not None else None,
        "evaluator_name": row[8],
        "evaluator_tg_id": row[9],
        "month": row[10],
        "phone_number": row[11],
        "appeal_date_text": row[12],
        "score": float(row[13]) if row[13] is not None else None,
        "is_draft": bool(row[14]),
        "sv_request": bool(row[15]),
        "sv_request_comment": row[16],
        "sv_request_by": int(row[17]) if row[17] is not None else None,
        "requester_name": row[18],
        "requester_tg_id": row[19],
        "sv_request_by_role": row[20],
        "sv_request_at_text": row[21],
        "sv_request_approved": bool(row[22]),
        "sv_request_approved_by": int(row[23]) if row[23] is not None else None,
        "sv_request_rejected": bool(row[24]),
        "sv_request_rejected_by": int(row[25]) if row[25] is not None else None,
        "sv_request_reject_comment": row[26],
    }


def _build_reevaluation_request_admin_message(call_ctx, requester_name, requester_role, comment):
    performer_name = (
        call_ctx.get('supervisor_name') if requester_role == 'operator' else requester_name
    ) or 'Сотрудник'
    comment_text = str(comment or '').strip() or '—'
    score_text = '—' if call_ctx.get('score') is None else f"{call_ctx.get('score'):.2f}"
    return (
        "⚠️ <b>Запрос на переоценку</b>\n\n"
        f"<b>Источник:</b> от {_escape_telegram_html(_reevaluation_request_role_label(requester_role), 32)}\n"
        f"<b>Call ID:</b> <code>{_escape_telegram_html(call_ctx.get('call_id'), 32)}</code>\n"
        f"<b>Оператор:</b> {_escape_telegram_html(call_ctx.get('operator_name') or '—', 120)}\n"
        f"<b>Супервайзер:</b> {_escape_telegram_html(call_ctx.get('supervisor_name') or '—', 120)}\n"
        f"<b>Запросил:</b> {_escape_telegram_html(requester_name or 'Сотрудник', 120)}\n"
        f"<b>Переоценит:</b> {_escape_telegram_html(performer_name, 120)}\n"
        f"<b>Номер:</b> {_escape_telegram_html(call_ctx.get('phone_number') or '—', 64)}\n"
        f"<b>Дата обращения:</b> {_escape_telegram_html(call_ctx.get('appeal_date_text') or '—', 32)}\n"
        f"<b>Месяц:</b> {_escape_telegram_html(call_ctx.get('month') or '—', 16)}\n"
        f"<b>Оценка:</b> {_escape_telegram_html(score_text, 16)}\n"
        f"<b>Комментарий:</b> {_escape_telegram_html(comment_text, 600)}\n\n"
        "Выберите действие ниже."
    )


def _notify_telegram_about_new_reevaluation_request(call_ctx, requester_name, requester_role, comment):
    if not API_TOKEN:
        return

    try:
        recipients = db.get_call_evaluation_notify_recipients(call_ctx.get('operator_id')) or []
    except Exception as exc:
        logging.error("Failed to load reevaluation notification recipients: %s", exc, exc_info=True)
        recipients = []

    for recipient in recipients:
        admin_chat_id = recipient.get('telegram_id') if isinstance(recipient, dict) else None
        if not admin_chat_id:
            continue
        reply_markup = {
            "inline_keyboard": [[
                {"text": "Одобрить ✅", "callback_data": f"approve_reval:{call_ctx['call_id']}"},
                {"text": "Отклонить ❌", "callback_data": f"reject_reval:{call_ctx['call_id']}"}
            ]]
        }
        try:
            response = _send_telegram_text_message(
                chat_id=admin_chat_id,
                text=_build_reevaluation_request_admin_message(call_ctx, requester_name, requester_role, comment),
                parse_mode='HTML',
                reply_markup=reply_markup
            )
            if response.status_code != 200:
                logging.error(
                    "Failed to send reevaluation request to admin chat: %s",
                    _get_telegram_error_text(response)
                )
        except Exception as exc:
            logging.error("Failed to send telegram reevaluation admin notification: %s", exc)

    if requester_role == 'operator' and call_ctx.get('supervisor_tg_id'):
        supervisor_message = (
            "📨 <b>Новая заявка оператора на переоценку</b>\n\n"
            f"<b>Оператор:</b> {_escape_telegram_html(call_ctx.get('operator_name') or '—', 120)}\n"
            f"<b>Call ID:</b> <code>{_escape_telegram_html(call_ctx.get('call_id'), 32)}</code>\n"
            f"<b>Комментарий:</b> {_escape_telegram_html(comment or '—', 600)}\n\n"
            "Заявка отправлена администратору на согласование. После одобрения вы сможете выполнить переоценку."
        )
        try:
            response = _send_telegram_text_message(chat_id=call_ctx['supervisor_tg_id'], text=supervisor_message, parse_mode='HTML')
            if response.status_code != 200:
                logging.error(
                    "Failed to send reevaluation request notification to supervisor: %s",
                    _get_telegram_error_text(response)
                )
        except Exception as exc:
            logging.error("Failed to notify supervisor about operator reevaluation request: %s", exc)


def _create_reevaluation_request(call_id, requester, requester_id, comment):
    call_ctx = _get_call_reevaluation_context(call_id)
    if not call_ctx:
        raise ValueError("Call not found")
    if call_ctx.get('is_draft'):
        raise ValueError("Reevaluation request is available only for completed evaluations")

    requester_role = _normalize_reevaluation_request_role(requester[3] if requester else None)
    requester_base_role = _normalize_user_role(requester[3] if requester else None)
    is_department_head = (
        _headed_department_id(requester_id) is not None
        and not _is_super_admin_role(requester_base_role)
    )
    if is_department_head:
        if not _ensure_call_access_for_requester(call_ctx.get('operator_id'), requester, requester_id):
            raise PermissionError("Only admins or this department head can request reevaluation")
        requester_role = 'admin'
    elif requester_role == 'operator':
        if int(call_ctx.get('operator_id') or 0) != int(requester_id):
            raise PermissionError("Operators can request reevaluation only for their own calls")
        if not call_ctx.get('supervisor_id'):
            raise ValueError("Supervisor not found for this operator")
    elif requester_role == 'sv':
        if int(call_ctx.get('supervisor_id') or 0) != int(requester_id):
            raise PermissionError("Only the operator's supervisor can request reevaluation")
    elif requester_role != 'admin':
        raise PermissionError("Only operators, supervisors and admins can request reevaluation")

    if call_ctx.get('sv_request') and not call_ctx.get('sv_request_approved') and not call_ctx.get('sv_request_rejected'):
        raise RuntimeError("Reevaluation request is already pending")
    if call_ctx.get('sv_request') and call_ctx.get('sv_request_approved'):
        raise RuntimeError("Reevaluation request is already approved")

    request_comment = str(comment or '').strip()
    with db._get_cursor() as cursor:
        cursor.execute("""
            UPDATE calls
            SET sv_request = TRUE,
                sv_request_comment = %s,
                sv_request_by = %s,
                sv_request_by_role = %s,
                sv_request_at = %s,
                sv_request_approved = FALSE,
                sv_request_approved_by = NULL,
                sv_request_approved_at = NULL,
                sv_request_approve_comment = NULL,
                sv_request_rejected = FALSE,
                sv_request_rejected_by = NULL,
                sv_request_rejected_at = NULL,
                sv_request_reject_comment = NULL
            WHERE id = %s
        """, (request_comment, requester_id, requester_role, datetime.utcnow(), call_id))

    requester_name = requester[2] if requester and len(requester) > 2 else 'Сотрудник'
    _notify_telegram_about_new_reevaluation_request(call_ctx, requester_name, requester_role, request_comment)
    return {
        "call": call_ctx,
        "requester_role": requester_role,
        "requester_name": requester_name
    }


def _resolve_reevaluation_request(call_id, approver_user_id, decision, comment=None):
    decision_norm = str(decision or '').strip().lower()
    if decision_norm in ('approve', 'approved'):
        decision_norm = 'approved'
    elif decision_norm in ('reject', 'rejected'):
        decision_norm = 'rejected'
    else:
        raise ValueError("Invalid reevaluation request decision")

    call_ctx = _get_call_reevaluation_context(call_id)
    if not call_ctx:
        raise ValueError("Call not found")
    if not call_ctx.get('sv_request'):
        raise ValueError("Reevaluation request not found")
    if call_ctx.get('sv_request_approved') or call_ctx.get('sv_request_rejected'):
        raise RuntimeError("Reevaluation request is already resolved")

    approver = db.get_user(id=approver_user_id) if approver_user_id else None
    if not approver:
        raise PermissionError("Approver not found")
    approver_role = _normalize_user_role(approver[3])
    headed_dept_id = _headed_department_id(approver_user_id)
    if not _is_admin_role(approver_role) and headed_dept_id is None:
        raise PermissionError("Only admins or this department head can decide reevaluation requests")
    if not _ensure_call_access_for_requester(call_ctx.get('operator_id'), approver, approver_user_id):
        raise PermissionError("Only admins or this department head can decide reevaluation requests")

    decision_comment = str(comment or '').strip() or None
    with db._get_cursor() as cursor:
        if decision_norm == 'approved':
            cursor.execute("""
                UPDATE calls
                SET sv_request_approved = TRUE,
                    sv_request_approved_by = %s,
                    sv_request_approved_at = %s,
                    sv_request_approve_comment = %s,
                    sv_request_rejected = FALSE,
                    sv_request_rejected_by = NULL,
                    sv_request_rejected_at = NULL,
                    sv_request_reject_comment = NULL
                WHERE id = %s
            """, (approver_user_id, datetime.utcnow(), decision_comment, call_id))
        else:
            cursor.execute("""
                UPDATE calls
                SET sv_request_approved = FALSE,
                    sv_request_approved_by = NULL,
                    sv_request_approved_at = NULL,
                    sv_request_approve_comment = NULL,
                    sv_request_rejected = TRUE,
                    sv_request_rejected_by = %s,
                    sv_request_rejected_at = %s,
                    sv_request_reject_comment = %s
                WHERE id = %s
            """, (approver_user_id, datetime.utcnow(), decision_comment, call_id))

    resolved_ctx = _get_call_reevaluation_context(call_id) or call_ctx
    approver_name = approver[2] if approver and len(approver) > 2 else 'Администратор'
    requester_role = _normalize_reevaluation_request_role(resolved_ctx.get('sv_request_by_role'))

    requester_tg_id = resolved_ctx.get('requester_tg_id')
    if requester_tg_id and API_TOKEN:
        if decision_norm == 'approved':
            if requester_role == 'operator':
                requester_message = (
                    "✅ <b>Ваш запрос на переоценку одобрен</b>\n\n"
                    f"👤 <b>Решение принял:</b> {_escape_telegram_html(approver_name, 120)}\n"
                )
                if decision_comment:
                    requester_message += f"💬 <b>Комментарий:</b> {_escape_telegram_html(decision_comment, 700)}\n"
                requester_message += "🔔 <b>Что дальше:</b> супервайзер уже получил уведомление и сможет перейти к переоценке звонка."
            else:
                performer_name = (
                    resolved_ctx.get('supervisor_name') if requester_role == 'operator' else resolved_ctx.get('requester_name')
                ) or 'Сотрудник'
                requester_message = (
                    "✅ <b>Запрос на переоценку одобрен</b>\n\n"
                    f"🆔 <b>Call ID:</b> <code>{_escape_telegram_html(call_id, 32)}</code>\n"
                    f"👤 <b>Одобрил:</b> {_escape_telegram_html(approver_name, 120)}\n"
                    f"📝 <b>Переоценит:</b> {_escape_telegram_html(performer_name, 120)}"
                )
                if decision_comment:
                    requester_message += f"\n💬 <b>Комментарий:</b> {_escape_telegram_html(decision_comment, 700)}"
        else:
            if requester_role == 'operator':
                requester_message = (
                    "❌ <b>Запрос на переоценку отклонён</b>\n\n"
                    f"👤 <b>Решение принял:</b> {_escape_telegram_html(approver_name, 120)}"
                )
                if decision_comment:
                    requester_message += f"\n💬 <b>Причина:</b> {_escape_telegram_html(decision_comment, 700)}"
                requester_message += "\n\nℹ️ Если нужно, вы можете обсудить это решение с супервайзером."
            else:
                requester_message = (
                    "❌ <b>Запрос на переоценку отклонён</b>\n\n"
                    f"🆔 <b>Call ID:</b> <code>{_escape_telegram_html(call_id, 32)}</code>\n"
                    f"👤 <b>Отклонил:</b> {_escape_telegram_html(approver_name, 120)}"
                )
                if decision_comment:
                    requester_message += f"\n💬 <b>Причина:</b> {_escape_telegram_html(decision_comment, 700)}"
        try:
            response = _send_telegram_text_message(chat_id=requester_tg_id, text=requester_message, parse_mode='HTML')
            if response.status_code != 200:
                logging.error("Failed to notify requester about reevaluation decision: %s", _get_telegram_error_text(response))
        except Exception as exc:
            logging.error("Failed to send reevaluation decision to requester: %s", exc)

    if requester_role == 'operator' and decision_norm == 'rejected' and resolved_ctx.get('supervisor_tg_id') and API_TOKEN:
        supervisor_message = (
            "✅ <b>Запрос оператора на переоценку одобрен</b>\n\n"
            if decision_norm == 'approved'
            else "ℹ️ <b>Запрос оператора на переоценку отклонён</b>\n\n"
        )
        supervisor_message += (
            f"<b>Оператор:</b> {_escape_telegram_html(resolved_ctx.get('operator_name') or '—', 120)}\n"
            f"<b>Call ID:</b> <code>{_escape_telegram_html(call_id, 32)}</code>\n"
            f"<b>Администратор:</b> {_escape_telegram_html(approver_name, 120)}"
        )
        if decision_norm == 'approved':
            supervisor_message += "\n\nМожете выполнить переоценку звонка."
        elif decision_comment:
            supervisor_message += f"\n<b>Причина:</b> {_escape_telegram_html(decision_comment, 700)}"
        try:
            response = _send_telegram_text_message(chat_id=resolved_ctx['supervisor_tg_id'], text=supervisor_message, parse_mode='HTML')
            if response.status_code != 200:
                logging.error("Failed to notify supervisor about reevaluation decision: %s", _get_telegram_error_text(response))
        except Exception as exc:
            logging.error("Failed to send reevaluation decision to supervisor: %s", exc)

    if requester_role == 'operator' and decision_norm == 'approved' and resolved_ctx.get('supervisor_tg_id') and API_TOKEN:
        operator_name = resolved_ctx.get('operator_name') or '—'
        approver_display_name = approver[2] if approver and len(approver) > 2 else 'Администратор'
        phone_number = resolved_ctx.get('phone_number') or '—'
        appeal_date_text = resolved_ctx.get('appeal_date_text') or '—'
        request_created_at = resolved_ctx.get('sv_request_at_text') or '—'
        month_text = resolved_ctx.get('month') or '—'
        current_score = resolved_ctx.get('score')
        score_text = '—' if current_score is None else f"{float(current_score):.2f}"
        evaluator_name = resolved_ctx.get('evaluator_name') or '—'
        requester_name = resolved_ctx.get('requester_name') or operator_name
        supervisor_message = (
            "🔔 <b>Одобрен запрос на переоценку</b>\n\n"
            "Оператору согласовали переоценку. Ниже все детали, чтобы можно было сразу взять звонок в работу.\n\n"
            f"👤 <b>Оператор:</b> {_escape_telegram_html(operator_name, 120)}\n"
            f"🆔 <b>Call ID:</b> <code>{_escape_telegram_html(call_id, 32)}</code>\n"
            f"📞 <b>Телефон:</b> {_escape_telegram_html(phone_number, 64)}\n"
            f"🗓 <b>Дата обращения:</b> {_escape_telegram_html(appeal_date_text, 64)}\n"
            f"📅 <b>Месяц:</b> {_escape_telegram_html(month_text, 16)}\n"
            f"📊 <b>Текущий балл:</b> {_escape_telegram_html(score_text, 16)}\n"
            f"🎧 <b>Текущий оценщик:</b> {_escape_telegram_html(evaluator_name, 120)}\n"
            f"🙋 <b>Запросил:</b> {_escape_telegram_html(requester_name, 120)}\n"
            f"⏱ <b>Дата запроса:</b> {_escape_telegram_html(request_created_at, 64)}\n"
            f"✅ <b>Одобрил администратор:</b> {_escape_telegram_html(approver_display_name, 120)}"
        )
        if resolved_ctx.get('sv_request_comment'):
            supervisor_message += (
                f"\n💬 <b>Комментарий к запросу:</b> "
                f"{_escape_telegram_html(resolved_ctx.get('sv_request_comment'), 700)}"
            )
        if decision_comment:
            supervisor_message += (
                f"\n💬 <b>Комментарий администратора:</b> "
                f"{_escape_telegram_html(decision_comment, 700)}"
            )
        supervisor_message += (
            "\n\n👉 <b>Что дальше:</b> откройте журнал оценок, найдите этот звонок и выполните переоценку."
        )
        try:
            response = _send_telegram_text_message(
                chat_id=resolved_ctx['supervisor_tg_id'],
                text=supervisor_message,
                parse_mode='HTML'
            )
            if response.status_code != 200:
                logging.error(
                    "Failed to send supervisor approval reminder about reevaluation: %s",
                    _get_telegram_error_text(response)
                )
        except Exception as exc:
            logging.error("Failed to send supervisor approval reminder: %s", exc)

    return {
        "decision": decision_norm,
        "call": resolved_ctx,
        "approver_name": approver_name
    }


def _set_reevaluation_decision_comment(call_id, decision, comment):
    """
    Дописать необязательный комментарий к УЖЕ принятому решению по переоценке.

    Используется ботом: решение фиксируется сразу по нажатию кнопки, а комментарий
    (если админ его ввёл) сохраняется отдельным шагом. Возвращает True, если строка
    обновлена (решение всё ещё в том же статусе), иначе False.
    """
    decision_norm = str(decision or '').strip().lower()
    if decision_norm in ('approve', 'approved'):
        comment_column = 'sv_request_approve_comment'
        flag_column = 'sv_request_approved'
    elif decision_norm in ('reject', 'rejected'):
        comment_column = 'sv_request_reject_comment'
        flag_column = 'sv_request_rejected'
    else:
        return False

    decision_comment = str(comment or '').strip() or None
    if decision_comment is None:
        return False

    # comment_column/flag_column берутся только из контролируемых литералов выше,
    # значение комментария передаётся параметром — инъекция исключена.
    with db._get_cursor() as cursor:
        cursor.execute(
            f"UPDATE calls SET {comment_column} = %s WHERE id = %s AND {flag_column} = TRUE",
            (decision_comment, call_id)
        )
        return cursor.rowcount > 0


@app.route('/api/call_evaluation/dispute', methods=['POST'])
@require_api_key
def dispute_call_evaluation():
    try:
        data = request.get_json(silent=True) or {}
        if 'id' not in data or 'dispute_text' not in data:
            return jsonify({"error": "Missing required fields"}), 400

        requester_id, requester, auth_error = _get_authenticated_requester()
        if auth_error:
            message, status_code = auth_error
            return jsonify({"error": message}), status_code

        result = _create_reevaluation_request(
            call_id=int(data['id']),
            requester=requester,
            requester_id=requester_id,
            comment=data.get('dispute_text')
        )
        return jsonify({
            "status": "success",
            "message": "Reevaluation request created",
            "requester_role": result.get("requester_role")
        }), 200

        operator_id = int(data['operator_id'])
        operator = db.get_user(id=operator_id)
        if not operator:
            return jsonify({"error": "Operator not found"}), 404

        supervisor = db.get_user(id=operator[6]) if operator[6] else None
        if not supervisor:
            return jsonify({"error": "Supervisor not found for this operator"}), 404

        # Get call details
        evaluations = db.get_call_evaluations(operator_id, data['month'])
        call = next((e for e in evaluations if e['id'] == data['id']), None)
        if not call:
            return jsonify({"error": "Call evaluation not found"}), 404

        # --- NEW: Try to get audio signed URL ---
        audio_url = None
        if call.get('audio_path'):
            try:
                gcs_client = get_gcs_client()
                path_parts = call['audio_path'].split('/', 1)
                if len(path_parts) == 2:
                    bucket_name, blob_path = path_parts
                    bucket = gcs_client.bucket(bucket_name)
                    blob = bucket.blob(blob_path)
                    if blob.exists():
                        audio_url = blob.generate_signed_url(
                            version="v4",
                            expiration=timedelta(minutes=15),
                            method="GET",
                            response_type='audio/mpeg'
                        )
            except Exception as e:
                logging.error(f"Error generating signed audio URL for dispute: {e}")
        # --- END NEW ---

        # Сообщение для супервайзера
        supervisor_message = (
            f"⚠️ <b>Запрос на пересмотр оценки</b>\n\n"
            f"👤 Оператор: <b>{operator[2]}</b>\n"
            f"📞 Звонок ID: {call['id']}\n"
            f"📱 Номер: {call['phone_number']}\n"
            f"📅 Дата обращения: {' '.join(call['appeal_date'].split('T'))}\n"
            f"📅 Дата оценки: {call['created_at']}\n"
            f"💯 Оценка: {call['score']}\n"
            f"📅 За месяц: {call['month']}\n\n"
            f"📝 <b>Сообщение от оператора:</b>\n"
            f"{data['dispute_text']}"
        )

        # Сообщение для админа
        admin_message = (
            f"⚠️ <b>Запрос на пересмотр оценки</b>\n\n"
            f"💬 Супервайзер: <b>{supervisor[2]}</b>\n"
            f"👤 Оператор: <b>{operator[2]}</b>\n"
            f"📞 Звонок ID: {call['id']}\n"
            f"📅 Дата обращения: {' '.join(call['appeal_date'].split('T'))}\n"
            f"📅 Дата оценки: {call['created_at']}\n"
            f"📱 Номер: {call['phone_number']}\n"
            f"💯 Оценка: {call['score']}\n"
            f"📅 За месяц: {call['month']}\n\n"
            f"📝 <b>Сообщение от оператора:</b>\n"
            f"{data['dispute_text']}"
        )

        telegram_url = f"https://api.telegram.org/bot{API_TOKEN}/sendMessage"
        telegram_audio_url = f"https://api.telegram.org/bot{API_TOKEN}/sendAudio"

        # --- NEW: Send audio if available ---
        def send_telegram_message(chat_id, text, audio_url=None):
            if audio_url:
                payload = {
                    "chat_id": chat_id,
                    "audio": audio_url,
                    "caption": text,
                    "parse_mode": "HTML"
                }
                resp = requests.post(telegram_audio_url, json=payload, timeout=10)
            else:
                payload = {
                    "chat_id": chat_id,
                    "text": text,
                    "parse_mode": "HTML"
                }
                resp = requests.post(telegram_url, json=payload, timeout=10)
            return resp

        # Отправка супервайзеру
        supervisor_response = send_telegram_message(supervisor[1], supervisor_message, audio_url)
        if supervisor_response.status_code != 200:
            error_detail = supervisor_response.json().get('description', 'Unknown error')
            logging.error(f"Telegram API error (supervisor): {error_detail}")
            return jsonify({"error": f"Failed to send dispute message to supervisor: {error_detail}"}), 500

        # Отправка админу
        admin_response = send_telegram_message(os.getenv("ADMIN_ID"), admin_message, audio_url)
        if admin_response.status_code != 200:
            error_detail = admin_response.json().get('description', 'Unknown error')
            logging.error(f"Telegram API error (admin): {error_detail}")
            return jsonify({"error": f"Failed to send dispute message to admin: {error_detail}"}), 500
        # --- END NEW ---

        return jsonify({"status": "success", "message": "Dispute sent to supervisor and admin"})
    except PermissionError as exc:
        return jsonify({"error": str(exc)}), 403
    except ValueError as exc:
        return jsonify({"error": str(exc)}), 400
    except RuntimeError as exc:
        return jsonify({"error": str(exc)}), 409
    except Exception as e:
        logging.error(f"Error processing dispute: {e}")
        return jsonify({"error": f"Internal server error"}), 500

@app.route('/api/hours/send_request', methods=['POST'])
@require_api_key
def send_request():
    try:
        data = request.get_json()
        required_fields = ['date', 'message']
        if not data or not all(field in data for field in required_fields):
            return jsonify({"error": "Missing required fields: date, message"}), 400

        operator_id = int(request.headers.get('X-User-Id'))
        hours = data.get('hours', 0)
        date = data['date']
        message = data['message']

        operator = db.get_user(id=operator_id)
        if not operator:
            return jsonify({"error": "Operator not found"}), 404

        supervisor = db.get_user(id=operator[6]) if operator[6] else None
        if not supervisor:
            return jsonify({"error": "Supervisor not found for this operator"}), 404

        telegram_url = f"https://api.telegram.org/bot{API_TOKEN}/sendMessage"
        payload = {
            "chat_id": supervisor[1],
            "text": (
                f"⚠️ <b>Запрос по рабочим часам</b>\n\n"
                f"👤 Оператор: <b>{operator[2]}</b>\n"
                f"⏰ Часы: <b>{hours} ч</b>\n"
                f"📅 Дата: <b>{date}</b>\n"
                f"📝 <b>Сообщение:</b>\n{message}"
            ),
            "parse_mode": "HTML"
        }
        response = requests.post(telegram_url, json=payload, timeout=10)
        if response.status_code != 200:
            error_detail = response.json().get('description', 'Unknown error')
            logging.error(f"Telegram API error: {error_detail}")
            return jsonify({"error": f"Failed to send request: {error_detail}"}), 500

        return jsonify({"status": "success", "message": "Request sent to supervisor"}), 200
    except Exception as e:
        logging.error(f"Error sending request: {e}")
        return jsonify({"error": f"Internal server error"}), 500

@app.route('/api/admin/add_sv', methods=['POST'])
@require_api_key
def add_sv():
    try:
        requester_id, requester, auth_error = _get_authenticated_requester()
        if auth_error:
            message, status_code = auth_error
            return jsonify({"error": message}), status_code
        if not (_is_admin_role(requester[3]) or _is_supervisor_role(requester[3])):
            return jsonify({"error": "Only admins or supervisors can add supervisors"}), 403

        data = request.get_json()
        required_fields = ['name']  # Removed 'telegram_id' from required fields
        if not data or not all(field in data for field in required_fields):
            return jsonify({"error": "Missing required field: name"}), 400

        name = data['name']
        
        login = f"sv_{str(uuid.uuid4())[:8]}"
        password = str(uuid.uuid4())[:8]  
        
        # Create supervisor with login and hashed_password, telegram_id set to None
        sv_id = db.create_user(
            telegram_id=None,  # Explicitly set to None
            name=name,
            role='sv',
            login=login,
            password=password,
            rate=1.0  # Default rate for SV
        )
        
        return jsonify({
            "status": "success",
            "message": f"SV {name} added",
            "id": sv_id,
            "login": login,  # Return plain login
            "password": password  # Return plain password for admin to share
        })
    except Exception as e:
        logging.error(f"Error adding SV: {e}")
        return jsonify({"error": f"Internal server error"}), 500

@app.route('/api/admin/add_user', methods=['POST'])
@require_api_key
def add_user():
    try:
        data = request.get_json() or {}
        requester_id, requester, auth_error = _get_authenticated_requester()
        if auth_error:
            message, status_code = auth_error
            return jsonify({"error": message}), status_code
        requester_role = _normalize_user_role(requester[3]) if requester else ''
        requester_headed_dept = db.headed_department_id_for_user(requester_id)
        if requester_role not in ('super_admin', 'admin', 'sv') and requester_headed_dept is None:
            return jsonify({"error": "Only admins can add users"}), 403

        name = str(data.get('name') or '').strip()
        if not name:
            return jsonify({"error": "Name cannot be empty"}), 400

        role = _normalize_user_role(data.get('role') or 'operator')
        if role not in ('operator', 'trainee', 'trainer', 'sv', 'admin'):
            return jsonify({"error": "Unsupported role. Allowed: operator, trainee, trainer, sv, admin"}), 400
        if role == 'admin' and requester_role != 'super_admin':
            return jsonify({"error": "Only super admins can create admins"}), 403
        if role == 'sv' and not _is_admin_role(requester_role):
            return jsonify({"error": "Only admins can create supervisors"}), 403
        if (requester_role == 'sv' or requester_headed_dept is not None) and not _is_admin_role(requester_role) and role not in ('operator', 'trainee'):
            return jsonify({"error": "Scoped managers can create only operators or trainees"}), 403

        supervisor_id = None
        direction_id = None

        hire_date = data.get('hire_date')
        if not hire_date:
            return jsonify({"error": "Missing required field: hire_date"}), 400
        try:
            datetime.strptime(hire_date, '%Y-%m-%d')
        except ValueError:
            return jsonify({"error": "Invalid hire_date format. Use YYYY-MM-DD"}), 400

        # Группа оператора: определяет и членство, и супервайзера (СВ группы).
        # supervisor_id как прямой параметр — legacy-фолбэк для старых клиентов.
        target_group = None
        if role in ('operator', 'trainee'):
            group_raw = data.get('group_id')
            if group_raw not in [None, '']:
                try:
                    target_group_id = int(group_raw)
                except (TypeError, ValueError):
                    return jsonify({"error": "Invalid group_id"}), 400
                target_group = db.get_group(target_group_id)
                if not target_group:
                    return jsonify({"error": "Группа не найдена"}), 400
                if target_group.get('status') != 'active':
                    return jsonify({"error": "Группа в архиве — выберите активную группу"}), 400

        if role in ('operator', 'trainee'):
            supervisor_raw = data.get('supervisor_id')
            if supervisor_raw not in [None, '']:
                try:
                    supervisor_id = int(supervisor_raw)
                except (TypeError, ValueError):
                    return jsonify({"error": "Invalid supervisor_id"}), 400
            if role == 'operator' and not data.get('direction_id'):
                return jsonify({"error": "Missing required field: direction_id"}), 400
            if role == 'operator' and not data.get('rate'):
                return jsonify({"error": "Missing required field: rate"}), 400
            if role == 'operator':
                try:
                    direction_id = int(data['direction_id'])
                except (TypeError, ValueError):
                    return jsonify({"error": "Invalid direction_id"}), 400
                try:
                    rate = float(data['rate'])
                except (TypeError, ValueError):
                    return jsonify({"error": "Invalid rate"}), 400
            else:
                direction_id = None
                try:
                    rate = float(data['rate']) if data.get('rate') else 1.0
                except (TypeError, ValueError):
                    return jsonify({"error": "Invalid rate"}), 400
        elif role in ('trainer', 'sv'):
            # Trainers and supervisors are never tied to a direction or supervisor.
            supervisor_id = None
            direction_id = None
            try:
                rate = float(data['rate']) if data.get('rate') else 1.0
            except (TypeError, ValueError):
                return jsonify({"error": "Invalid rate"}), 400
        else:
            # Admins are not tied to direction/supervisor.
            supervisor_id = None
            direction_id = None
            try:
                rate = float(data['rate']) if data.get('rate') else 1.0
            except (TypeError, ValueError):
                return jsonify({"error": "Invalid rate"}), 400

        if requester_role == 'sv':
            # По умолчанию супервайзер — сам СВ, но он может выбрать другого СВ своего отдела.
            if not supervisor_id:
                supervisor_id = requester_id
            # Направление берём выбранное в модалке (оно ограничено отделом СВ);
            # если не выбрано — наследуем направление самого СВ.
            if role == 'operator' and not direction_id:
                requester_direction_name = str(requester[4] or '').strip()
                if requester_direction_name:
                    requester_direction_id = next(
                        (
                            int(item.get('id'))
                            for item in (db.get_directions() or [])
                            if str(item.get('name') or '').strip() == requester_direction_name
                        ),
                        None
                    )
                    if requester_direction_id is not None:
                        direction_id = requester_direction_id

        gender = data.get('gender')
        if gender in [None, '']:
            gender = None
        elif gender not in ['male', 'female']:
            return jsonify({"error": "Invalid gender value"}), 400

        birth_date = data.get('birth_date')
        if birth_date:
            try:
                datetime.strptime(birth_date, '%Y-%m-%d')
            except ValueError:
                return jsonify({"error": "Invalid birth_date format. Use YYYY-MM-DD"}), 400
        else:
            birth_date = None

        phone = str(data.get('phone') or '').strip() or None
        email = str(data.get('email') or '').strip() or None
        if email and '@' not in email:
            return jsonify({"error": "Invalid email value"}), 400
        personal_email = str(data.get('personal_email') or '').strip() or None
        if personal_email and '@' not in personal_email:
            return jsonify({"error": "Invalid personal_email value"}), 400
        instagram = str(data.get('instagram') or '').strip() or None
        telegram_nick = str(data.get('telegram_nick') or '').strip() or None
        company_name = str(data.get('company_name') or '').strip() or None
        study_place = str(data.get('study_place') or '').strip() or None
        study_course = str(data.get('study_course') or '').strip() or None
        study_completion_year_raw = data.get('study_completion_year')
        if study_completion_year_raw in [None, '']:
            study_completion_year = None
        else:
            try:
                study_completion_year = int(study_completion_year_raw)
            except (TypeError, ValueError):
                return jsonify({"error": "Invalid study_completion_year value"}), 400
            if study_completion_year < 1900 or study_completion_year > 2100:
                return jsonify({"error": "study_completion_year must be between 1900 and 2100"}), 400
        close_contact_1_relation = str(data.get('close_contact_1_relation') or '').strip() or None
        close_contact_1_full_name = str(data.get('close_contact_1_full_name') or '').strip() or None
        close_contact_1_phone = str(data.get('close_contact_1_phone') or '').strip() or None
        close_contact_2_relation = str(data.get('close_contact_2_relation') or '').strip() or None
        close_contact_2_full_name = str(data.get('close_contact_2_full_name') or '').strip() or None
        close_contact_2_phone = str(data.get('close_contact_2_phone') or '').strip() or None
        card_number = str(data.get('card_number') or '').strip() or None
        taxipro_id = str(data.get('taxipro_id') or '').strip() or None

        if phone and not _is_valid_kz_phone(phone):
            return jsonify({"error": "Invalid phone format. Use +7XXXXXXXXXX"}), 400
        if close_contact_1_phone and not _is_valid_kz_phone(close_contact_1_phone):
            return jsonify({"error": "Invalid close_contact_1_phone format. Use +7XXXXXXXXXX"}), 400
        if close_contact_2_phone and not _is_valid_kz_phone(close_contact_2_phone):
            return jsonify({"error": "Invalid close_contact_2_phone format. Use +7XXXXXXXXXX"}), 400

        internship_in_company_raw = data.get('internship_in_company')
        if isinstance(internship_in_company_raw, bool):
            internship_in_company = internship_in_company_raw
        elif isinstance(internship_in_company_raw, (int, float)):
            internship_in_company = bool(internship_in_company_raw)
        elif isinstance(internship_in_company_raw, str):
            internship_in_company_value = internship_in_company_raw.strip().lower()
            if internship_in_company_value in ['1', 'true', 'yes', 'y', 'on']:
                internship_in_company = True
            elif internship_in_company_value in ['0', 'false', 'no', 'n', 'off', '']:
                internship_in_company = False
            else:
                return jsonify({"error": "Invalid internship_in_company value"}), 400
        elif internship_in_company_raw is None:
            internship_in_company = False
        else:
            return jsonify({"error": "Invalid internship_in_company value"}), 400

        front_office_training_raw = data.get('front_office_training')
        if isinstance(front_office_training_raw, bool):
            front_office_training = front_office_training_raw
        elif isinstance(front_office_training_raw, (int, float)):
            front_office_training = bool(front_office_training_raw)
        elif isinstance(front_office_training_raw, str):
            front_office_training_value = front_office_training_raw.strip().lower()
            if front_office_training_value in ['1', 'true', 'yes', 'y', 'on']:
                front_office_training = True
            elif front_office_training_value in ['0', 'false', 'no', 'n', 'off', '']:
                front_office_training = False
            else:
                return jsonify({"error": "Invalid front_office_training value"}), 400
        elif front_office_training_raw is None:
            front_office_training = False
        else:
            return jsonify({"error": "Invalid front_office_training value"}), 400

        front_office_training_date = data.get('front_office_training_date')
        if front_office_training_date:
            try:
                datetime.strptime(front_office_training_date, '%Y-%m-%d')
            except ValueError:
                return jsonify({"error": "Invalid front_office_training_date format. Use YYYY-MM-DD"}), 400
        else:
            front_office_training_date = None
        if not front_office_training:
            front_office_training_date = None

        employment_type = str(data.get('employment_type') or '').strip().lower() or None
        if employment_type not in [None, 'gph', 'of', 'smz']:
            return jsonify({"error": "Invalid employment_type value"}), 400

        study_completed_raw = data.get('study_completed')
        if isinstance(study_completed_raw, bool):
            study_completed = study_completed_raw
        elif isinstance(study_completed_raw, (int, float)):
            study_completed = bool(study_completed_raw)
        elif isinstance(study_completed_raw, str):
            study_completed_value = study_completed_raw.strip().lower()
            if study_completed_value in ['1', 'true', 'yes', 'y', 'on']:
                study_completed = True
            elif study_completed_value in ['0', 'false', 'no', 'n', 'off', '']:
                study_completed = False
            else:
                return jsonify({"error": "Invalid study_completed value"}), 400
        elif study_completed_raw is None:
            study_completed = False
        else:
            return jsonify({"error": "Invalid study_completed value"}), 400

        has_proxy_raw = data.get('has_proxy')
        if isinstance(has_proxy_raw, bool):
            has_proxy = has_proxy_raw
        elif isinstance(has_proxy_raw, (int, float)):
            has_proxy = bool(has_proxy_raw)
        elif isinstance(has_proxy_raw, str):
            has_proxy_value = has_proxy_raw.strip().lower()
            if has_proxy_value in ['1', 'true', 'yes', 'y', 'on']:
                has_proxy = True
            elif has_proxy_value in ['0', 'false', 'no', 'n', 'off', '']:
                has_proxy = False
            else:
                return jsonify({"error": "Invalid has_proxy value"}), 400
        elif has_proxy_raw is None:
            has_proxy = False
        else:
            return jsonify({"error": "Invalid has_proxy value"}), 400

        has_driver_license_raw = data.get('has_driver_license')
        if isinstance(has_driver_license_raw, bool):
            has_driver_license = has_driver_license_raw
        elif isinstance(has_driver_license_raw, (int, float)):
            has_driver_license = bool(has_driver_license_raw)
        elif isinstance(has_driver_license_raw, str):
            has_driver_license_value = has_driver_license_raw.strip().lower()
            if has_driver_license_value in ['1', 'true', 'yes', 'y', 'on']:
                has_driver_license = True
            elif has_driver_license_value in ['0', 'false', 'no', 'n', 'off', '']:
                has_driver_license = False
            else:
                return jsonify({"error": "Invalid has_driver_license value"}), 400
        elif has_driver_license_raw is None:
            has_driver_license = False
        else:
            return jsonify({"error": "Invalid has_driver_license value"}), 400

        proxy_card_number = str(data.get('proxy_card_number') or '').strip() or None
        try:
            proxy_status = normalize_proxy_status_value(data.get('proxy_status'))
        except ValueError:
            return jsonify({"error": "Invalid proxy_status value"}), 400
        if role == 'trainee' or not has_proxy:
            has_proxy = False if role == 'trainee' else has_proxy
            proxy_card_number = None

        sip_number = str(data.get('sip_number') or '').strip() or None
        if role != 'operator':
            sip_number = None

        # Отдел: только глобальный админ/супер-админ выбирает любой отдел.
        # СВ и глава отдела (даже с админ-ролью) создают строго в своём отделе —
        # выбор клиента игнорируем, иначе оператор может уйти в чужой отдел/СЗоВ
        # и пропасть из скоупа главы (см. get_admin_users).
        requester_dept_id = requester_headed_dept if requester_headed_dept is not None else db.get_user_department_id(requester_id)
        department_id = None
        if _is_global_admin_requester(requester_role, requester_id):
            department_raw = data.get('department_id')
            if department_raw not in [None, '']:
                try:
                    department_id = int(department_raw)
                except (TypeError, ValueError):
                    return jsonify({"error": "Invalid department_id"}), 400
                if not db.get_department_by_id(department_id):
                    return jsonify({"error": "Department not found"}), 400
        else:
            # СВ / глава отдела — отдел создающего (выбор клиента игнорируем)
            department_id = requester_dept_id

        # Группа: строго из отдела, в котором создаётся сотрудник. Если админ не
        # выбрал отдел явно — сотрудник уходит в отдел группы. СВ берём из группы
        # (переданный supervisor_id игнорируем — источник истины членство в группе).
        if target_group is not None:
            group_dept = target_group.get('department_id')
            if department_id is not None and group_dept is not None and int(group_dept) != int(department_id):
                return jsonify({"error": "Группа не принадлежит выбранному отделу"}), 400
            if department_id is None and group_dept is not None:
                department_id = int(group_dept)
            supervisor_id = db.get_group_active_supervisor_id(target_group['id'])

        # Валидация принадлежности направления и супервайзера выбранному отделу
        # (когда отдел известен явно: для СВ/главы всегда, для админа — если выбрал отдел).
        if department_id is not None:
            if role == 'operator' and direction_id is not None:
                dir_dept = db.get_direction_department_id(direction_id)
                if dir_dept is not None and int(dir_dept) != int(department_id):
                    return jsonify({"error": "Направление не принадлежит выбранному отделу"}), 400
            if supervisor_id is not None:
                sup_dept = db.get_user_department_id(supervisor_id)
                if sup_dept is not None and int(sup_dept) != int(department_id):
                    return jsonify({"error": "Супервайзер не из выбранного отдела"}), 400

        if role == 'trainer':
            login_prefix = 'trainer'
        elif role == 'sv':
            login_prefix = 'sv'
        elif role == 'admin':
            login_prefix = 'admin'
        elif role == 'trainee':
            login_prefix = 'trainee'
        else:
            login_prefix = 'user'
        login = f"{login_prefix}_{str(uuid.uuid4())[:8]}"
        password = str(uuid.uuid4())[:8]

        user_id = db.create_user(
            telegram_id=None,
            name=name,
            role=role,
            hire_date=hire_date,
            supervisor_id=supervisor_id,
            rate=rate,
            direction_id=direction_id,
            login=login,
            password=password,
            gender=gender,
            birth_date=birth_date,
            phone=phone,
            email=email,
            personal_email=personal_email,
            instagram=instagram,
            telegram_nick=telegram_nick,
            company_name=company_name,
            employment_type=employment_type,
            has_proxy=has_proxy,
            proxy_card_number=proxy_card_number,
            proxy_status=proxy_status,
            has_driver_license=has_driver_license,
            sip_number=sip_number,
            study_place=study_place,
            study_course=study_course,
            study_completed=study_completed,
            study_completion_year=study_completion_year,
            close_contact_1_relation=close_contact_1_relation,
            close_contact_1_full_name=close_contact_1_full_name,
            close_contact_1_phone=close_contact_1_phone,
            close_contact_2_relation=close_contact_2_relation,
            close_contact_2_full_name=close_contact_2_full_name,
            close_contact_2_phone=close_contact_2_phone,
            card_number=card_number,
            internship_in_company=internship_in_company,
            front_office_training=front_office_training,
            front_office_training_date=front_office_training_date,
            taxipro_id=taxipro_id,
            department_id=department_id
        )

        # Членство в группе с даты найма; СВ уже проставлен из группы выше,
        # add_operator_to_group синхронизирует его же (идемпотентно).
        if target_group is not None:
            db.add_operator_to_group(
                target_group['id'], user_id,
                start_date=hire_date, assigned_by=requester_id
            )

        changed_by = requester_id
        if role == 'trainer':
            db.update_user(user_id, 'direction_id', None, changed_by=changed_by)
            db.update_user(user_id, 'supervisor_id', None, changed_by=changed_by)

        if role == 'trainer':
            role_label = 'Тренер'
        elif role == 'admin':
            role_label = 'Админ'
        elif role == 'sv':
            role_label = 'Супервайзер'
        elif role == 'trainee':
            role_label = 'Стажер'
        else:
            role_label = 'Оператор'
        return jsonify({
            "status": "success",
            "message": f"{role_label} {name} добавлен",
            "id": user_id,
            "role": role,
            "login": login,
            "password": password
        })
    except Exception as e:
        logging.error(f"Error adding user: {e}")
        return jsonify({"error": f"Internal server error"}), 500

@app.route('/api/admin/directions', methods=['GET'])
@require_api_key
def get_directions():
    try:
        requester_id, requester, auth_error = _get_authenticated_requester()
        if auth_error:
            message, status_code = auth_error
            logging.warning("Directions auth error: %s", message)
            return jsonify({"error": message}), status_code
        role = _normalize_user_role(requester[3])
        headed_dept_ids = _headed_department_ids(requester_id)
        if not (_is_admin_role(role) or _is_supervisor_role(role) or role == 'operator' or headed_dept_ids):
            return jsonify({"error": "Only admins, supervisors, department heads and operators can access directions"}), 403

        # Скоуп по отделу: админ/супер-админ видят все направления (опц. фильтр
        # ?department_id=); глава отдела / супервайзер / оператор — только направления
        # СВОЕГО отдела (изоляция отделов, в т.ч. в настройках перерывов графиков).
        if _is_global_admin_requester(role, requester_id):
            scope_dept = None
            dep_param = request.args.get('department_id')
            if dep_param not in (None, ''):
                try:
                    scope_dept = int(dep_param)
                except (TypeError, ValueError):
                    scope_dept = None
            directions = db.get_directions(department_id=scope_dept)
        elif headed_dept_ids:
            # Глава отдела: объединение направлений всех возглавляемых отделов.
            directions = []
            seen_direction_ids = set()
            for department_id in sorted(headed_dept_ids):
                for direction in (db.get_directions(department_id=department_id) or []):
                    direction_id = direction.get('id') if isinstance(direction, dict) else None
                    if direction_id in seen_direction_ids:
                        continue
                    seen_direction_ids.add(direction_id)
                    directions.append(direction)
        else:
            directions = db.get_directions(department_id=db.get_user_department_id(requester_id))
        # Признак для кнопки «Случайный звонок» в журнале:
        #  - СЗоВ (Oktell): операторская модель;
        #  - TEZ (Binotel): звонковые модели tez_line/tez_op (в модалке — свои min/max длительности).
        # Остальные отделы/модели кнопку не видят. random_call_source управляет UI модалки.
        # «Случайный чат» — два источника: Chat2Desk у чат-менеджеров СЗоВ
        # (ТП чат ТЭЗ живёт в другой системе) и Wazzup у Верификаторов отдела
        # продаж (эпизоды WhatsApp). random_chat_source управляет модалкой.
        # Третий источник — ChatApp у ТП/ОП ТЭЗ: там кнопка висит на «линейном»
        # направлении, а критерии приходят от чатового (random_chat_criteria_direction_id).
        _chatapp_map = _chatapp_direction_map()
        for _d in directions:
            _code = str(_d.get('department_code') or '').strip().lower()
            _model = str(_d.get('calculation_model_code') or '').strip().lower()
            _source = None
            if _model == 'operator' and _code == OKTELL_CALL_DISTRIBUTION_DEPARTMENT_CODE:
                _source = 'oktell'
            elif _code == TEZ_CALL_DISTRIBUTION_DEPARTMENT_CODE and _model in TEZ_RANDOM_CALL_MODELS:
                _source = 'binotel'
            _d['random_call_eligible'] = _source is not None
            _d['random_call_source'] = _source
            _chat_source = None
            # Критерии обычно берутся у направления самого оператора; у ChatApp
            # (ТЭЗ) это не так — см. CHATAPP_CHAT_DIRECTION_MAP.
            _criteria_direction_id = None
            if _model == 'chat_manager' and _code == C2D_RANDOM_CHAT_DEPARTMENT_CODE:
                _chat_source = 'chat2desk'
            elif (_code == WZ_RANDOM_CHAT_DEPARTMENT_CODE
                    and WZ_RANDOM_CHAT_DIRECTION_MARKER in str(_d.get('name') or '').lower()):
                _chat_source = 'wazzup'
            elif _chatapp_map.get(_d.get('id')) is not None:
                _chat_source = 'chatapp'
                _criteria_direction_id = _chatapp_map[_d['id']]
            _d['random_chat_eligible'] = _chat_source is not None
            _d['random_chat_source'] = _chat_source
            _d['random_chat_criteria_direction_id'] = _criteria_direction_id
        return jsonify({
            "status": "success",
            "directions": directions,
            "calculation_models": get_calculation_model_catalog()
        }), 200
    except Exception as e:
        logging.error(f"Error fetching directions: {e}", exc_info=True)
        return jsonify({"error": f"Internal server error"}), 500


@app.route('/api/admin/calculation_models', methods=['GET'])
@require_api_key
def get_calculation_models():
    try:
        requester_id, requester, auth_error = _get_authenticated_requester()
        if auth_error:
            message, status_code = auth_error
            return jsonify({"error": message}), status_code
        role = _normalize_user_role(requester[3])
        if not (_is_admin_role(role) or _is_supervisor_role(role) or role == 'operator'):
            return jsonify({"error": "Forbidden"}), 403
        catalog = get_calculation_model_catalog()
        return jsonify({
            "status": "success",
            "calculation_models": catalog,
            # Реестр метрик на модель: {model_code: [metrics]} — фронт строит
            # столбцы/вкладки учёта часов и отчётов из него (а не из зашитых веток).
            "calculation_model_metrics": {
                item['code']: get_calculation_model_metrics(item['code'])
                for item in catalog
            }
        }), 200
    except Exception as e:
        logging.error(f"Error fetching calculation models: {e}", exc_info=True)
        return jsonify({"error": "Internal server error"}), 500


# ──────────────────────────────── ГРУППЫ: API ────────────────────────────────
def _ensure_group_manager():
    """Авторизация управления группами: админ или глава отдела.
    Возвращает (requester_id, role, None) или (None, None, (resp, code))."""
    requester_id, requester, auth_error = _get_authenticated_requester()
    if auth_error:
        message, status_code = auth_error
        return None, None, (jsonify({"error": message}), status_code)
    role = _normalize_user_role(requester[3])
    headed_dept = db.headed_department_id_for_user(requester_id)
    if not (_is_admin_role(role) or headed_dept is not None):
        return None, None, (jsonify({"error": "Only admins or department heads can manage groups"}), 403)
    return requester_id, role, None


def _ensure_group_in_requester_scope(group_id, requester_id, role):
    """Изоляция отделов: глава отдела управляет только группами своего отдела.
    Глобальный админ/супер-админ — любыми группами. Возвращает (resp, code) при
    отказе, иначе None."""
    if _is_global_admin_requester(role, requester_id):
        return None
    headed_dept = db.headed_department_id_for_user(requester_id)
    grp = db.get_group(group_id)
    if not grp or headed_dept is None or grp.get('department_id') != headed_dept:
        return jsonify({"error": "Forbidden: group is not in your department"}), 403
    return None


@app.route('/api/groups', methods=['GET'])
@require_api_key
def list_groups_endpoint():
    try:
        requester_id, requester, auth_error = _get_authenticated_requester()
        if auth_error:
            message, status_code = auth_error
            return jsonify({"error": message}), status_code
        role = _normalize_user_role(requester[3])
        headed_dept_id = _headed_department_id(requester_id)
        include_archived = str(request.args.get('include_archived', '')).lower() in ('1', 'true', 'yes')
        if headed_dept_id is not None and not _is_super_admin_role(role):
            groups = db.list_groups(include_archived=include_archived, department_id=headed_dept_id)
        elif _is_global_admin_requester(role, requester_id):
            dep = request.args.get('department_id')
            department_id = int(dep) if dep and str(dep).isdigit() else None
            groups = db.list_groups(include_archived=include_archived, department_id=department_id)
        elif _is_supervisor_role(role):
            # СВ видит группы СВОЕГО ОТДЕЛА (а не только те, что ведёт сам).
            sv_dept = db.get_user_department_id(requester_id)
            if sv_dept is not None:
                groups = db.list_groups(include_archived=include_archived, department_id=sv_dept)
            else:
                my_ids = set(db.get_supervisor_group_ids(requester_id))
                groups = [g for g in db.list_groups(include_archived=include_archived) if g['id'] in my_ids]
        else:
            return jsonify({"error": "Forbidden"}), 403
        return jsonify({
            "status": "success",
            "groups": groups,
            "calculation_models": get_calculation_model_catalog(),
        }), 200
    except Exception as e:
        logging.error(f"Error listing groups: {e}", exc_info=True)
        return jsonify({"error": "Internal server error"}), 500


@app.route('/api/admin/snapshots/recompute', methods=['POST'])
@require_api_key
def recompute_month_snapshot_endpoint():
    """Только АДМИН: (пере)заморозить месяц в снимок (тяжёлая операция по ВСЕМ группам всех
    отделов). Идемпотентно. Главам отделов запрещено (эскалация привилегий + нагрузка)."""
    try:
        requester_id, role, guard_err = _ensure_group_manager()
        if guard_err:
            resp, code = guard_err
            return resp, code
        if not _is_global_admin_requester(role, requester_id):
            return jsonify({"error": "Only admins can recompute month snapshots"}), 403
        data = request.get_json(silent=True) or {}
        month = str(data.get('month') or '').strip()
        if not re.match(r'^\d{4}-(0[1-9]|1[0-2])$', month):
            return jsonify({"error": "Field 'month' (YYYY-MM) is required"}), 400
        result = db.recompute_month_snapshot(month)
        logging.info("Snapshot recompute by user %s for %s: %s", requester_id, month, result)
        return jsonify({"status": "success", "result": result}), 200
    except Exception as e:
        logging.error(f"Error recomputing month snapshot: {e}", exc_info=True)
        return jsonify({"error": "Internal server error"}), 500


@app.route('/api/admin/snapshots', methods=['GET'])
@require_api_key
def get_month_snapshot_endpoint():
    """Замороженный снимок месяца (для селектора месяца в GroupsView / проверки)."""
    try:
        requester_id, role, guard_err = _ensure_group_manager()
        if guard_err:
            resp, code = guard_err
            return resp, code
        month = str(request.args.get('month') or '').strip()
        if not re.match(r'^\d{4}-(0[1-9]|1[0-2])$', month):
            return jsonify({"error": "Query param 'month' (YYYY-MM) is required"}), 400
        gid = request.args.get('group_id')
        group_id = int(gid) if gid and str(gid).isdigit() and int(gid) > 0 else None
        # Изоляция отделов: не-админ (глава отдела) видит только группы СВОЕГО отдела.
        if not _is_admin_role(role):
            headed_dept = db.headed_department_id_for_user(requester_id)
            if group_id is None:
                return jsonify({"error": "group_id is required"}), 400
            grp = db.get_group(group_id)
            if not grp or headed_dept is None or grp.get('department_id') != headed_dept:
                return jsonify({"error": "Forbidden: group is not in your department"}), 403
        snap = db.get_month_snapshot(month, group_id=group_id)
        snap["closed"] = db._is_month_closed(month)
        return jsonify({"status": "success", **snap}), 200
    except Exception as e:
        logging.error(f"Error reading month snapshot: {e}", exc_info=True)
        return jsonify({"error": "Internal server error"}), 500


@app.route('/api/admin/groups', methods=['POST'])
@require_api_key
def create_group_endpoint():
    try:
        requester_id, role, guard_err = _ensure_group_manager()
        if guard_err:
            resp, code = guard_err
            return resp, code
        data = request.get_json() or {}
        # Переиспользование архивной группы вместо создания новой.
        reuse_id = data.get('reuse_group_id')
        if reuse_id:
            group = db.reuse_archived_group(int(reuse_id))
            return jsonify({"status": "success", "group": group, "reused": True}), 200
        name = (data.get('name') or '').strip()
        if not name:
            return jsonify({"error": "name is required"}), 400
        direction_id = data.get('direction_id')
        headed_dept = db.headed_department_id_for_user(requester_id)
        department_id = data.get('department_id') if _is_global_admin_requester(role, requester_id) else headed_dept
        # Подсказки: архивные группы того же отдела/направления (если не force).
        if not data.get('force'):
            suggestions = db.get_group_suggestions(department_id=department_id, direction_id=direction_id)
            if suggestions:
                return jsonify({
                    "status": "suggestions",
                    "suggestions": suggestions,
                    "message": "Есть архивные группы — переиспользуйте (reuse_group_id) или создайте новую (force=true)",
                }), 200
        group = db.create_group(
            name=name,
            calculation_model_code=data.get('calculation_model_code'),
            direction_id=direction_id,
            department_id=department_id,
            table_url=data.get('table_url'),
            created_by=requester_id,
        )
        return jsonify({"status": "success", "group": group}), 201
    except Exception as e:
        logging.error(f"Error creating group: {e}", exc_info=True)
        return jsonify({"error": "Internal server error"}), 500


