@app.route('/api/operator/sip_settings', methods=['GET', 'OPTIONS'])
@require_api_key
def operator_sip_settings_endpoint():
    """SIP-настройки залогиненного оператора для регистрации в iCORE Phone."""
    if request.method == 'OPTIONS':
        return _build_cors_preflight_response()
    try:
        requester_id, requester, auth_error = _get_authenticated_requester()
        if auth_error:
            message, status_code = auth_error
            return jsonify({"error": message}), status_code
        sip_number = db.get_user_sip_number(requester_id)
        if not sip_number:
            return jsonify({"error": "SIP-номер не назначен. Обратитесь к руководителю."}), 409
        cfg = db.get_sip_config()
        server = (cfg.get("sip_server") or "").strip()
        base = cfg.get("base_password") or ""
        if not server or not base:
            return jsonify({"error": "Настройки SIP ещё не сконфигурированы."}), 409
        return jsonify({
            "status": "success",
            "settings": {
                "server": server,
                "username": sip_number,
                "password": f"{base}{sip_number}",
                "transport": "UDP",
            }
        }), 200
    except Exception as e:
        logging.error(f"Error in operator sip_settings: {e}", exc_info=True)
        return jsonify({"error": "Internal server error"}), 500


@app.route('/api/operator/status_event', methods=['POST', 'OPTIONS'])
@require_api_key
def operator_status_event_endpoint():
    """Live-пуш события статуса оператора из iCORE Phone (учёт часов в iCORE).

    Оператор шлёт СВОИ события — identity берётся из токена (requester_id),
    поэтому подделать чужого оператора нельзя. Каждое событие несёт
    client_event_id; вставка идемпотентна, поэтому телефон безопасно ретраит
    из офлайн-очереди при разрывах сети без задвоения.

    Тело запроса (JSON):
      status_key      — ключ статуса: готов | перезвон | тренинг | перерыв |
                        занят (в разговоре) | выключен (выход). Обязателен.
      event_at        — ISO-8601 локальное время события (naive, часы оператора).
                        Если не задано — берётся серверное now().
      event_kind      — 'status' | 'action' (по умолчанию выводится из ключа).
      state_note      — необязательная заметка.
      client_event_id — уникальный id события для идемпотентности (<=64).
    """
    if request.method == 'OPTIONS':
        return _build_cors_preflight_response()
    try:
        requester_id, requester, auth_error = _get_authenticated_requester()
        if auth_error:
            message, status_code = auth_error
            return jsonify({"error": message}), status_code

        data = request.get_json(silent=True) or {}
        status_key = str(data.get('status_key') or '').strip()
        if not status_key:
            return jsonify({"error": "status_key is required"}), 400

        event_at_raw = str(data.get('event_at') or '').strip()
        if event_at_raw:
            try:
                event_at_value = datetime.fromisoformat(event_at_raw)
            except Exception:
                return jsonify({"error": "event_at must be an ISO-8601 datetime"}), 400
        else:
            event_at_value = datetime.now()

        result = db.append_operator_status_event(
            operator_id=requester_id,
            event_at=event_at_value,
            status_key=status_key,
            state_note=data.get('state_note'),
            event_kind=data.get('event_kind'),
            client_event_id=data.get('client_event_id'),
        )
        return jsonify({"status": "success", "result": result}), 200
    except ValueError as ve:
        return jsonify({"error": str(ve)}), 400
    except Exception as e:
        logging.error(f"Error in operator status_event: {e}", exc_info=True)
        return jsonify({"error": "Internal server error"}), 500


@app.route('/api/call_distribution/status', methods=['GET', 'OPTIONS'])
@require_api_key
def call_distribution_status():
    """Статус распределения по операторам за месяц: норма / в пуле / оценено / не оценено.
    Только операторская модель (чат-менеджеры исключены). Доступ: админ/глава/СВ."""
    if request.method == 'OPTIONS':
        return _build_cors_preflight_response()
    try:
        requester_id, requester, auth_error = _get_authenticated_requester()
        if auth_error:
            message, status_code = auth_error
            return jsonify({"error": message}), status_code
        role = requester[3]
        is_admin = _is_admin_role(role)
        is_head = _headed_department_id(requester_id) is not None
        is_sv = _is_supervisor_role(role)
        if not (is_admin or is_head or is_sv):
            return jsonify({"error": "Forbidden"}), 403

        month = request.args.get('month') or datetime.now().strftime('%Y-%m')
        if not re.match(r'^\d{4}-\d{2}$', str(month)):
            return jsonify({"error": "month must be in YYYY-MM format"}), 400

        # Изоляция отделов: глава отдела и СВ видят только операторов своего отдела;
        # глобальный админ/супер-админ — всех.
        scope_dept = None if _is_global_admin_requester(role, requester_id) else _department_scope_id_for_requester(requester_id)
        scope_member_ids = db.get_department_member_ids(scope_dept) if scope_dept is not None else None

        # Деление звонков питается из Oktell, а Oktell обслуживает только отдел СЗоВ —
        # поэтому показываем ТОЛЬКО операторов этого отдела (даже супер-админу), иначе в
        # норму/оценки/пул затекают другие отделы (Отдел продаж, Тез КЦ), которых Oktell
        # не касается.
        oktell_dept_id = next(
            (d.get('id') for d in (db.get_departments() or [])
             if str(d.get('code') or '').strip().lower() == OKTELL_CALL_DISTRIBUTION_DEPARTMENT_CODE),
            None
        )
        oktell_member_ids = db.get_department_member_ids(oktell_dept_id) if oktell_dept_id else set()

        # операторская модель (чат-менеджеры исключены)
        ops = []
        for row in (db.get_all_operators() or []):
            try:
                op_id = int(row[0])
            except Exception:
                continue
            if op_id not in oktell_member_ids:
                continue
            if scope_member_ids is not None and op_id not in scope_member_ids:
                continue
            name = str(row[1] or '').strip()
            direction_name = str(row[7] or '').strip() if len(row) > 7 else ''
            calc = str(row[8] or '').strip().lower() if len(row) > 8 else ''
            dkey = ' '.join(direction_name.lower().split())
            if calc == 'chat_manager' or dkey in ('чат менеджер', 'chat manager'):
                continue
            ops.append((op_id, name))

        op_ids = [o[0] for o in ops]
        targets = db.get_operator_call_evaluation_targets_for_month(op_ids, month) or {}
        pool = db.get_imported_calls_status_counts_by_operator(month)
        # «Оценено» берём из РЕАЛЬНОГО журнала оценок (calls), а не только из пула
        # распределения: оператора могли оценить по звонкам вне пула (ручной выбор из
        # журнала), и эти оценки тоже должны отображаться. call_count = оценённые
        # звонки (последняя версия, score IS NOT NULL) — та же логика, что в журнале.
        journal = db.get_operator_score_aggregates_for_month(month, op_ids) or {}

        operators = []
        for op_id, name in ops:
            norm = int((targets.get(op_id) or {}).get('required_calls') or 0)
            pc = pool.get(op_id) or {}
            in_pool = int(pc.get('total') or 0)
            pending = int(pc.get('not_evaluated') or 0)
            evaluated_real = int((journal.get(op_id) or {}).get('call_count') or 0)
            coverage = evaluated_real + pending
            if norm <= 0 and in_pool <= 0 and coverage <= 0:
                continue
            operators.append({
                "operator_id": op_id,
                "name": name,
                "norm": norm,
                "in_pool": in_pool,
                "pool_display": coverage,
                "evaluated": evaluated_real,
                "evaluated_pool": int(pc.get('evaluated') or 0),
                "not_evaluated": pending,
                "pending": pending,
                "coverage": coverage,
                "skipped": int(pc.get('skipped') or 0),
            })
        operators.sort(key=lambda x: x['name'])

        return jsonify({
            "status": "success",
            "month": month,
            "operators": operators,
            "settings": db.get_call_distribution_settings(),
            "can_edit": bool(is_admin or is_head)
        }), 200
    except Exception as e:
        logging.error(f"call_distribution status error: {e}", exc_info=True)
        return jsonify({"error": "Internal server error"}), 500

@app.route('/api/call_evaluation', methods=['POST'])
@require_api_key
def receive_call_evaluation():
    try:
        if not request.form:
            return jsonify({"error": "Missing form data"}), 400

        requester_id, requester, auth_error = _get_authenticated_requester()
        if auth_error:
            message, status_code = auth_error
            return jsonify({"error": message}), status_code

        requester_role = _normalize_user_role(requester[3])
        requester_headed_dept = _headed_department_id(requester_id)
        if not (_is_admin_role(requester_role) or _is_supervisor_role(requester_role) or requester_headed_dept is not None):
            return jsonify({"error": "Only admins, supervisors and department heads can submit evaluations"}), 403

        required_fields = ['evaluator', 'operator', 'phone_number', 'appeal_date', 'score', 'comment', 'month', 'is_draft']
        missing_fields = [field for field in required_fields if field not in request.form]
        if missing_fields:
            return jsonify({"error": f"Missing required fields: {', '.join(missing_fields)}"}), 400

        evaluator_name = request.form['evaluator']
        operator_name = request.form['operator']
        phone_number = request.form['phone_number']
        appeal_date = request.form['appeal_date']
        score = float(request.form['score'])
        comment = request.form['comment']
        month = request.form['month'] or datetime.now().strftime('%Y-%m')
        is_draft = request.form['is_draft'].lower() == 'true'
        comment_visible_to_operator_raw = str(request.form.get('comment_visible_to_operator', 'true')).strip().lower()
        comment_visible_to_operator = comment_visible_to_operator_raw in ('1', 'true', 'yes', 'on')
        question_resolved_raw = str(request.form.get('question_resolved', 'false')).strip().lower()
        question_resolved = question_resolved_raw in ('1', 'true', 'yes', 'on')
        resolved_first_contact = None
        if question_resolved:
            resolved_first_contact_raw = str(request.form.get('resolved_first_contact', 'false')).strip().lower()
            resolved_first_contact = resolved_first_contact_raw in ('1', 'true', 'yes', 'on')
        scores = json.loads(request.form.get('scores', '[]'))
        criterion_comments = json.loads(request.form.get('criterion_comments', '[]'))
        direction_id = request.form.get('direction')
        previous_version_id = request.form.get('previous_version_id')
        is_correction = request.form.get('is_correction', 'false').lower() == 'true'

        evaluator = db.get_user(name=evaluator_name)
        operator = db.get_user(name=operator_name)
        if not evaluator or not operator:
            return jsonify({"error": "Evaluator or operator not found"}), 404
        if not _ensure_call_access_for_requester(operator[0], requester, requester_id):
            return jsonify({"error": "Forbidden for this operator"}), 403

        # Оценка чата Chat2Desk (ЧМ СЗоВ): к записи журнала прикладывается снапшот
        # переписки и цитаты; цитаты сверяются с текстом сообщений дословно.
        c2d_snapshot_id = request.form.get('c2d_snapshot_id')
        chat_quotes = None
        if c2d_snapshot_id not in (None, ''):
            try:
                c2d_snapshot_id = int(c2d_snapshot_id)
            except (TypeError, ValueError):
                return jsonify({"error": "c2d_snapshot_id must be an integer"}), 400
            chat_snapshot = db.get_c2d_snapshot(snapshot_id=c2d_snapshot_id)
            if not chat_snapshot:
                return jsonify({"error": "Снапшот чата не найден"}), 404
            if chat_snapshot.get('operator_id') is not None and \
                    int(chat_snapshot['operator_id']) != int(operator[0]):
                return jsonify({"error": "Снапшот чата принадлежит другому чат-менеджеру"}), 400
            try:
                raw_quotes = json.loads(request.form.get('chat_quotes') or '[]')
            except ValueError:
                return jsonify({"error": "chat_quotes must be valid JSON"}), 400
            chat_quotes, quotes_error = _c2d_eval_normalize_quotes(
                raw_quotes, chat_snapshot.get('messages'))
            if quotes_error:
                return jsonify({"error": quotes_error}), 400
        else:
            c2d_snapshot_id = None
        if is_correction and previous_version_id:
            try:
                previous_call = db.get_call_by_id(int(previous_version_id))
            except (TypeError, ValueError):
                previous_call = None
            if not previous_call:
                return jsonify({"error": "Previous evaluation not found"}), 404
            if not _ensure_call_access_for_requester(previous_call.get("operator_id"), requester, requester_id):
                return jsonify({"error": "Forbidden for this previous evaluation"}), 403
        if is_correction:
            # admins всегда могут делать переоценки
            if _is_admin_role(requester_role) or requester_headed_dept is not None:
                allowed = True
            else:
                # non-admin может переоценивать ТОЛЬКО если:
                # - передан previous_version_id
                # - previous call exists AND sv_request == TRUE AND sv_request_approved == TRUE
                # - и sv_request_by == requester_id (т.е. именно этот СВ отправил запрос)
                allowed = False
                if previous_version_id:
                    try:
                        prev_id = int(previous_version_id)
                    except Exception:
                        prev_id = None
                    if prev_id:
                        try:
                            with db._get_cursor() as cursor:
                                cursor.execute(
                                    """
                                    SELECT
                                        sv_request,
                                        sv_request_approved,
                                        sv_request_by,
                                        sv_request_by_role,
                                        operator_id
                                    FROM calls
                                    WHERE id = %s
                                    """,
                                    (prev_id,)
                                )
                                prev = cursor.fetchone()
                        except Exception as e:
                            logging.error(f"Error checking previous call for re-eval permissions: {e}")
                            prev = None

                        if prev:
                            sv_request_flag = bool(prev[0])
                            sv_request_approved_flag = bool(prev[1])
                            sv_request_by_id = prev[2]
                            sv_request_by_role = _normalize_reevaluation_request_role(prev[3])
                            prev_operator_id = int(prev[4]) if prev[4] is not None else None
                            if sv_request_flag and sv_request_approved_flag:
                                if sv_request_by_role == 'sv' and sv_request_by_id == requester_id:
                                    allowed = True
                                elif sv_request_by_role == 'operator' and prev_operator_id:
                                    prev_operator = db.get_user(id=prev_operator_id)
                                    if prev_operator and int(prev_operator[6] or 0) == int(requester_id):
                                        allowed = True

            if not allowed:
                return jsonify({"error": "Only admins or the approved supervisor can perform re-evaluations"}), 403


        audio_path = None
        audio_data = None
        blob_path = None
        bucket_name = None
        has_new_audio = False

        if 'audio_file' in request.files:
            file = request.files['audio_file']
            if file and file.filename:
                has_new_audio = True
                try:
                    audio_data = file.read()
                except Exception as e:
                    logging.error(f"Error reading audio file: {e}")
                    return jsonify({"error": "Failed to process audio file"}), 500
                filename = secure_filename(f"{uuid.uuid4()}.mp3")
                bucket_name = os.getenv('GOOGLE_CLOUD_STORAGE_BUCKET')
                upload_folder = os.getenv('UPLOAD_FOLDER', 'Uploads/')
                blob_path = f"{upload_folder}{filename}"
                audio_path = "my-app-audio-uploads/" + blob_path

        elif is_correction and previous_version_id:
            try:
                with db._get_cursor() as cursor:
                    cursor.execute("SELECT audio_path FROM calls WHERE id = %s", (previous_version_id,))
                    result = cursor.fetchone()
                    if result and result[0]:
                        audio_path = result[0]
            except Exception as e:
                logging.error(f"Error retrieving audio_path from previous version: {e}")
                return jsonify({"error": "Failed to retrieve audio from previous version"}), 500

        evaluation_id = db.add_call_evaluation(
            evaluator_id=evaluator[0],
            operator_id=operator[0],
            phone_number=phone_number,
            score=score,
            comment=comment,
            comment_visible_to_operator=comment_visible_to_operator,
            month=month,
            audio_path=audio_path,
            is_draft=is_draft,
            scores=scores,
            criterion_comments=criterion_comments,
            direction_id=direction_id,
            is_correction=is_correction,
            previous_version_id=previous_version_id if previous_version_id else None,
            appeal_date=appeal_date,
            question_resolved=question_resolved,
            resolved_first_contact=resolved_first_contact,
            c2d_snapshot_id=c2d_snapshot_id,
            chat_quotes=chat_quotes
        )

        if has_new_audio or (not is_draft and audio_path):
            threading.Thread(target=background_upload_and_notify, args=(
                audio_data, bucket_name, blob_path, evaluation_id, is_draft,
                evaluator[2], operator[2], month, phone_number, score, comment,
                is_correction, previous_version_id, audio_path if not has_new_audio else None,
                appeal_date, operator[0]
            )).start()
        elif not is_draft:
            threading.Thread(target=send_telegram_notification, args=(
                evaluator[2], operator[2], month, phone_number, score, comment,
                is_correction, previous_version_id, None, appeal_date, operator[0]
            )).start()

        return jsonify({"status": "success", "evaluation_id": evaluation_id}), 200
    except Exception as e:
        logging.error(f"Error processing call evaluation: {e}")
        return jsonify({"error": f"Internal server error"}), 500

def background_upload_and_notify(audio_data, bucket_name, blob_path, evaluation_id, is_draft,
                                 evaluator_name, operator_name, month, phone_number, score, comment,
                                 is_correction, previous_version_id, existing_audio_path, appeal_date,
                                 operator_id=None):
    audio_path = existing_audio_path or ("my-app-audio-uploads/" + blob_path if blob_path else None)
    upload_success = False
    if audio_data:
        try:
            client = get_gcs_client()
            bucket = client.bucket(bucket_name)
            blob = bucket.blob(blob_path)
            blob.upload_from_string(audio_data, content_type='audio/mpeg')
            upload_success = True
        except Exception as e:
            logging.error(f"Error uploading file to GCS in background: {e}")
            try:
                with db._get_connection() as conn:
                    with conn.cursor() as cursor:
                        cursor.execute("UPDATE calls SET audio_path = NULL WHERE id = %s", (evaluation_id,))
                        conn.commit()
            except Exception as update_e:
                logging.error(f"Error updating DB after failed upload: {update_e}")
            audio_path = None
    if not is_draft:
        send_telegram_notification(evaluator_name, operator_name, month, phone_number, score, comment,
                                   is_correction, previous_version_id, audio_path if (upload_success or existing_audio_path) else None, appeal_date,
                                   operator_id)

def send_telegram_notification(evaluator_name, operator_name, month, phone_number, score, comment, is_correction, previous_version_id, audio_path, appeal_date, operator_id=None):
    try:
        API_TOKEN = os.getenv('BOT_TOKEN')
        if not API_TOKEN:
            return
        try:
            recipients = db.get_call_evaluation_notify_recipients(operator_id) or []
        except Exception as recipient_error:
            logging.error(f"Failed to load call evaluation notification recipients: {recipient_error}", exc_info=True)
            recipients = []
        if not recipients:
            return

        message = (
            f"👤 Оценивающий: <b>{evaluator_name}</b>\n"
            f"📋 Оператор: <b>{operator_name}</b>\n"
            f"📄 За месяц: <b>{month}</b>\n"
            f"📱 Номер телефона: <b>{phone_number}</b>\n"
            f"📅 Дата обращения: <b>{' '.join(appeal_date.split('T'))}</b>\n"
            f"💯 Оценка: <b>{score}</b>\n"
        )
        if is_correction:
            message += f"🔄 <b>Переоценка звонка (ID предыдущей версии: {previous_version_id})</b>\n"
        if score < 100 and comment:
            message += f"\n💬 Комментарий: \n{comment}\n"

        audio_signed_url = None
        if audio_path:
            try:
                client = get_gcs_client()
                path_parts = audio_path.split('/', 1)
                if len(path_parts) == 2:
                    bucket_name, blob_path = path_parts
                    bucket = client.bucket(bucket_name)
                    blob = bucket.blob(blob_path)
                    if blob.exists():
                        expiration = datetime.utcnow() + timedelta(minutes=15)
                        audio_signed_url = blob.generate_signed_url(
                            expiration=expiration,
                            method='GET',
                            version='v4'
                        )
            except Exception as e:
                logging.error(f"Error generating signed URL for audio: {e}")

        telegram_url = f"https://api.telegram.org/bot{API_TOKEN}/sendAudio" if audio_signed_url else f"https://api.telegram.org/bot{API_TOKEN}/sendMessage"
        payload = {
            "parse_mode": "HTML"
        }
        if audio_signed_url:
            payload["audio"] = audio_signed_url
            payload["caption"] = f"📞 <b>{'Переоценка звонка' if is_correction else 'Оценка звонка'}</b>\n" + message
        else:
            payload["text"] = f"💬 <b>{'Переоценка чата' if is_correction else 'Оценка чата'}</b>\n" + message

        for recipient in recipients:
            chat_id = recipient.get('telegram_id') if isinstance(recipient, dict) else None
            if not chat_id:
                continue
            recipient_payload = dict(payload)
            recipient_payload["chat_id"] = chat_id
            response = requests.post(telegram_url, json=recipient_payload, timeout=10)
            if response.status_code != 200:
                try:
                    error_detail = response.json().get('description', 'Unknown error')
                except Exception:
                    error_detail = response.text or 'Unknown error'
                logging.error(f"Telegram API error for {chat_id}: {error_detail}")
    except Exception as e:
        logging.error(f"Error sending Telegram notification: {e}")

@app.route('/api/admin/add_operator', methods=['POST'])
@require_api_key
def add_operator():
    try:
        requester_id, requester, auth_error = _get_authenticated_requester()
        if auth_error:
            message, status_code = auth_error
            return jsonify({"error": message}), status_code
        if not (_is_admin_role(requester[3]) or _is_supervisor_role(requester[3])):
            return jsonify({"error": "Only admins or supervisors can add operators"}), 403

        data = request.get_json()
        required_fields = ['name', 'telegram_id', 'supervisor_id']
        if not data or not all(field in data for field in required_fields):
            return jsonify({"error": "Missing required fields"}), 400

        name = data['name']
        telegram_id = int(data['telegram_id'])
        supervisor_id = int(data['supervisor_id'])
        
        # Проверяем существование пользователя
        if db.get_user(telegram_id=telegram_id):
            return jsonify({"error": "Operator with this Telegram ID already exists"}), 400
        
        # Создаем оператора
        operator_id = db.create_user(
            telegram_id=telegram_id,
            name=name,
            role='operator',
            supervisor_id=supervisor_id
        )
        
        telegram_url = f"https://api.telegram.org/bot{API_TOKEN}/sendMessage"
        payload = {
            "chat_id": telegram_id,
            "text": f"Вы добавлены как оператор в команду <b>успешно✅</b>",
            "parse_mode": "HTML"
        }
        response = requests.post(telegram_url, json=payload, timeout=10)
        if response.status_code != 200:
            error_detail = response.json().get('description', 'Unknown error')
            logging.error(f"Telegram API error: {error_detail}")
        
        return jsonify({"status": "success", "message": f"Operator {name} added", "id": operator_id})
    except Exception as e:
        logging.error(f"Error adding operator: {e}")
        return jsonify({"error": f"Internal server error"}), 500

@app.route('/api/user/toggle_active', methods=['POST'])
@require_api_key
def toggle_user_active():
    try:
        data = request.get_json()
        if not data or 'status' not in data:
            return jsonify({"error": "Missing status field"}), 400

        new_status = data['status']
        allowed_statuses = {"active", "break", "training", "inactive", "tech","iesigning"}
        if new_status not in allowed_statuses:
            return jsonify({"error": f"Invalid status. Allowed: {', '.join(allowed_statuses)}"}), 400

        user_id = int(request.headers.get('X-User-Id'))
        user = db.get_user(id=user_id)
        if not user:
            return jsonify({"error": "Unauthurized"}), 403

        # здесь предполагаем, что user[10] хранит BOOLEAN (is_active)
        current_active = user[10]
        new_active_bool = True if new_status == "active" else False

        # если статус active ↔ True/False не меняется — нет смысла обновлять
        if current_active == new_active_bool:
            # но дополнительно можно проверить, не был ли изменён текстовый статус (например break/training)
            last_log_status = db.get_last_activity_status(user_id)  # нужна функция в db
            if last_log_status == new_status:
                return jsonify({"status": "unchanged", "message": "Status is already set to the requested value"})

        # обновляем users.is_active (bool)
        success = db.set_user_active(user_id, new_status)
        if not success:
            return jsonify({"error": "Failed to update user active flag"}), 500

        # записываем строковый статус в логи
        log_success = db.log_activity(user_id, new_status)
        if not log_success:
            logging.warning("User active flag updated but logging failed")
            return jsonify({
                "status": "partial_success",
                "message": "User active flag updated, but logging failed"
            }), 500

        return jsonify({"status": "success", "message": f"Status updated to '{new_status}'"}), 200

    except Exception as e:
        logging.error(f"Error toggling status: {e}")
        return jsonify({"error": f"Internal server error"}), 500


