@app.route('/api/report/monthly_hours', methods=['GET'])
@require_api_key
def get_monthly_report_hours():
    try:
        supervisor_id = request.args.get('supervisor_id')
        group_param = request.args.get('group_id')
        group_id = int(group_param) if group_param and str(group_param).isdigit() else None
        month = request.args.get('month')
        if not month or not MONTH_RE.match(month):
            return jsonify({"error": "month required in format YYYY-MM"}), 400
        _report_year, _report_mon = map(int, month.split('-'))
        _report_start = dt_date(_report_year, _report_mon, 1)
        _report_end = dt_date(_report_year, _report_mon, calendar.monthrange(_report_year, _report_mon)[1])

        requester_id, requester, auth_error = _get_authenticated_requester()
        if auth_error:
            message, status_code = auth_error
            return jsonify({"error": message}), status_code

        role = _normalize_user_role(requester[3])
        headed_dept_id = _headed_department_id(requester_id)
        effective_role, scope_department_id = _effective_management_scope(requester, requester_id)
        if not (_is_admin_role(role) or _is_supervisor_role(role) or headed_dept_id is not None):
            return jsonify({"error": "Unauthorized to access this report"}), 403
        generate_all = False

        if group_id is not None:
            # Отчёт строго в рамках группы за месяц: все операторы — одной модели расчёта,
            # поэтому листы выбираются корректно (чат-группа → без «Звонки»/«Эффективность»).
            # СВ может выгружать только группы своего отдела (или те, что ведёт); админ — любые.
            if not _is_global_admin_requester(role, requester_id):
                _grp = db.get_group(group_id)
                _sv_dept = scope_department_id
                _allowed = (
                    (_grp and _sv_dept is not None and _grp.get('department_id') == _sv_dept)
                    or db.supervisor_has_group_access_for_period(
                        requester_id, group_id, _report_start, _report_end
                    )
                )
                if not _allowed:
                    return jsonify({"error": "Forbidden: not your department's group"}), 403
            supervisor_id = None
        elif not supervisor_id:
            generate_all = True
        else:
            try:
                supervisor_id = int(supervisor_id)
            except ValueError:
                return jsonify({"error": "supervisor_id must be integer"}), 400
            if not _is_global_admin_requester(role, requester_id):
                target_supervisor, scope_error = _load_target_user_with_scope(
                    requester,
                    requester_id,
                    supervisor_id,
                    allow_self=True,
                    supervisor_target_roles=('sv', 'supervisor'),
                    not_found_message="Supervisor not found",
                    forbidden_message="Forbidden: supervisor is outside your department"
                )
                if scope_error:
                    message, status_code = scope_error
                    return jsonify({"error": message}), status_code
                if _normalize_user_role(target_supervisor[3]) != 'sv':
                    return jsonify({"error": "Supervisor not found"}), 404

        logging.info("Начало генерации отчета: supervisor_id=%s group_id=%s month=%s generate_all=%s", supervisor_id, group_id, month, generate_all)

        try:
            if generate_all:
                operators = db.get_daily_hours_for_all_month(
                    month,
                    department_id=None if _is_global_admin_requester(role, requester_id) else scope_department_id
                )
            elif group_id is not None:
                operators = db.get_daily_hours_by_group_month(group_id, month)
            else:
                operators = db.get_daily_hours_by_supervisor_month(supervisor_id, month)
        except Exception as e:
            logging.exception("Ошибка получения operators из db")
            return jsonify({"error": "Ошибка получения операторов"}), 500

        # Перешедший оператор показывается ОДНОЙ строкой (не дробим на под-строки «ФИО · Группа»).
        # В отчёте ПО ГРУППЕ (group_id задан) билдер берёт дни оператора в ЭТОЙ группе из
        # group_segments и показывает по ним данные, а дни, когда он был в ДРУГОЙ группе, помечает
        # «др.» и не учитывает в итогах — поэтому метрики разных моделей не смешиваются и не
        # пропадают (в каждой группе виден свой сегмент). В отчёте по СВ/общем (group_id нет) —
        # одна строка с полным месяцем, как раньше (legacy).

        try:
            if generate_all:
                trainings_list_raw = db.get_trainings(None, month)
            else:
                trainings_list_raw = db.get_trainings(supervisor_id, month)
        except Exception as e:
            logging.exception("Ошибка получения trainings из db")
            trainings_list_raw = []

        try:
            y, m = map(int, month.split('-'))
            month_last_day = calendar.monthrange(y, m)[1]
            date_from = f"{month}-01"
            date_to = f"{month}-{str(month_last_day).zfill(2)}"
            technical_result = db.get_operator_technical_issues(
                requester_id=requester_id,
                requester_role=effective_role,
                date_from=date_from,
                date_to=date_to,
                limit=5000,
                offset=0,
                scope_department_id=scope_department_id
            )
            technical_items_raw = technical_result.get('items', []) if isinstance(technical_result, dict) else []
        except Exception:
            logging.exception("Ошибка получения technical issues из db")
            technical_items_raw = []

        visible_operator_ids = set()
        try:
            operators_list_for_scope = operators.get("operators", []) if isinstance(operators, dict) else []
            visible_operator_ids = {
                int(op.get("operator_id"))
                for op in operators_list_for_scope
                if op and op.get("operator_id") is not None
            }
        except Exception:
            visible_operator_ids = set()

        if visible_operator_ids:
            trainings_list = [
                item for item in trainings_list_raw
                if int(item.get("operator_id") or 0) in visible_operator_ids
            ]
            technical_items = []
            for item in technical_items_raw:
                try:
                    if int(item.get("operator_id")) in visible_operator_ids:
                        technical_items.append(item)
                except Exception:
                    continue
        else:
            trainings_list = trainings_list_raw if generate_all else []
            technical_items = technical_items_raw if generate_all else []

        trainings_map = build_trainings_map(trainings_list)
        technical_issues_map = build_technical_issues_map(technical_items)

        try:
            y, m = map(int, month.split('-'))
            month_last_day = calendar.monthrange(y, m)[1]
            date_from = f"{month}-01"
            date_to = f"{month}-{str(month_last_day).zfill(2)}"
            offline_result = db.get_operator_offline_activities(
                requester_id=requester_id,
                requester_role=effective_role,
                date_from=date_from,
                date_to=date_to,
                supervisor_id=supervisor_id if not generate_all else None,
                limit=5000,
                offset=0,
                scope_department_id=scope_department_id
            )
            offline_items_raw = offline_result.get('items', []) if isinstance(offline_result, dict) else []
        except Exception:
            logging.exception("Ошибка получения offline activities из db")
            offline_items_raw = []

        if visible_operator_ids:
            offline_items = []
            for item in offline_items_raw:
                try:
                    if int(item.get("operator_id")) in visible_operator_ids:
                        offline_items.append(item)
                except Exception:
                    continue
        else:
            offline_items = offline_items_raw if generate_all else []

        offline_activities_map = build_offline_activities_map(offline_items)
        try:
            operators_list_for_practice = operators.get("operators", []) if isinstance(operators, dict) else []
            for op in operators_list_for_practice:
                try:
                    op_id = int(op.get("operator_id"))
                except Exception:
                    continue
                by_day = op.get("offline_activities_by_day") if isinstance(op, dict) else None
                if not isinstance(by_day, dict):
                    continue
                for day_key, day_items in by_day.items():
                    try:
                        day_num = int(day_key)
                    except Exception:
                        continue
                    for item in (day_items if isinstance(day_items, list) else []):
                        if not isinstance(item, dict):
                            continue
                        is_practice_shift = (
                            item.get("source") == "work_shift"
                            or item.get("shift_type") == "office_practice"
                            or item.get("is_practice_shift") is True
                        )
                        if not is_practice_shift:
                            continue
                        offline_activities_map.setdefault(op_id, {}).setdefault(day_num, []).append(item)
        except Exception:
            logging.exception("Ошибка добавления практики в офисе в offline activities map")

        if generate_all:
            filename, content = db.generate_excel_report_all_operators_from_view(
                operators,
                trainings_map,
                technical_issues_map,
                month,
                offline_activities_map=offline_activities_map
            )
        else:
            filename, content = db.generate_excel_report_from_view(
                operators,
                trainings_map,
                technical_issues_map,
                month,
                offline_activities_map=offline_activities_map,
                report_group_id=group_id
            )
            
        if not filename or not content:
            logging.error("Генерация отчёта вернула пустой результат")
            return jsonify({"error": "Failed to generate report"}), 500

        return send_file(
            BytesIO(content),
            as_attachment=True,
            download_name=filename,
            mimetype='application/vnd.openxmlformats-officedocument.spreadsheetml.sheet'
        )

    except Exception as e:
        logging.exception("Error generating monthly report")
        return jsonify({"error": f"Internal server error"}), 500


@app.route('/api/trainings', methods=['GET'])
@require_api_key
def get_trainings():
    try:
        requester_id, requester, auth_error = _get_authenticated_requester()
        if auth_error:
            message, status_code = auth_error
            logging.warning(f"Trainings auth error: {message}")
            return jsonify({"error": message}), status_code

        month = request.args.get('month')
        period_start = None
        period_end = None
        if month:
            try:
                parsed_month = datetime.strptime(month, '%Y-%m')
                period_start = dt_date(parsed_month.year, parsed_month.month, 1)
                period_end = dt_date(
                    parsed_month.year,
                    parsed_month.month,
                    calendar.monthrange(parsed_month.year, parsed_month.month)[1]
                )
            except ValueError:
                logging.warning(f"Invalid month format: {month}")
                return jsonify({"error": "Invalid month format. Use YYYY-MM"}), 400
        else:
            today = datetime.now().date()
            period_start = today
            period_end = today

        group_param = request.args.get('group_id')
        group_id = int(group_param) if group_param and str(group_param).isdigit() else None

        role = _normalize_user_role(requester[3])
        headed_dept_id = _headed_department_id(requester_id)
        if not (_is_admin_role(role) or role in ('sv', 'operator') or headed_dept_id is not None):
            logging.warning(f"Unauthorized role: {role}")
            return jsonify({"error": "Unauthorized"}), 403

        query = """
            SELECT
                t.id,
                t.operator_id,
                t.training_date,
                t.start_time,
                t.end_time,
                t.reason,
                t.comment,
                t.created_at,
                cb.name as created_by_name,
                t.count_in_hours
            FROM trainings t
            JOIN users u ON t.operator_id = u.id
            LEFT JOIN users cb ON t.created_by = cb.id
        """
        where_clauses = []
        params = []

        if month:
            where_clauses.append("TO_CHAR(t.training_date, 'YYYY-MM') = %s")
            params.append(month)

        if group_id is not None:
            group = db.get_group(group_id)
            if not group:
                return jsonify({"error": "Group not found"}), 404
            if headed_dept_id is not None and not _is_global_admin_requester(role, requester_id):
                if group.get('department_id') != headed_dept_id:
                    return jsonify({"error": "Forbidden: not your department's group"}), 403
            elif _is_supervisor_role(role):
                # СВ может смотреть группы своего отдела (как в /api/sv/daily_hours),
                # либо те, что ведёт сам в выбранном периоде.
                _req_dept = db.get_user_department_id(requester_id)
                _same_dept = _req_dept is not None and group.get('department_id') == _req_dept
                if not (_same_dept or db.supervisor_has_group_access_for_period(requester_id, group_id, period_start, period_end)):
                    return jsonify({"error": "Forbidden: not your group"}), 403
            elif role == 'operator':
                return jsonify({"error": "Unsupported target role"}), 400

            where_clauses.append("""
                EXISTS (
                    SELECT 1
                    FROM group_operator_memberships gom
                    WHERE gom.operator_id = t.operator_id
                      AND gom.group_id = %s
                      AND gom.start_date <= t.training_date
                      AND (gom.end_date IS NULL OR gom.end_date >= t.training_date)
                )
            """)
            params.append(group_id)
        elif headed_dept_id is not None and not _is_global_admin_requester(role, requester_id):
            where_clauses.append("u.department_id = %s")
            params.append(headed_dept_id)
        elif role == 'operator':
            where_clauses.append("t.operator_id = %s")
            params.append(requester_id)
        else:
            user_param = request.args.get('id')
            if user_param:
                if not str(user_param).isdigit():
                    return jsonify({"error": "Invalid id parameter"}), 400
                target_user = db.get_user(id=int(user_param))
                if not target_user:
                    return jsonify({"error": "User not found"}), 404
                target_role = _normalize_user_role(target_user[3])
                if target_role == 'sv':
                    where_clauses.append("u.supervisor_id = %s")
                    params.append(int(target_user[0]))
                elif target_role == 'operator':
                    where_clauses.append("t.operator_id = %s")
                    params.append(int(target_user[0]))
                else:
                    return jsonify({"error": "Unsupported target role"}), 400
            elif _is_supervisor_role(role):
                where_clauses.append("u.supervisor_id = %s")
                params.append(requester_id)

        if where_clauses:
            query += " WHERE " + " AND ".join(where_clauses)
        query += " ORDER BY t.training_date DESC, t.start_time DESC"

        with db._get_cursor() as cursor:
            cursor.execute(query, params)
            trainings = [
                {
                    "id": row[0],
                    "operator_id": row[1],
                    "date": row[2].strftime('%Y-%m-%d'),
                    "start_time": row[3].strftime('%H:%M'),
                    "end_time": row[4].strftime('%H:%M'),
                    "reason": row[5],
                    "comment": row[6],
                    "created_at": row[7].strftime('%Y-%m-%d %H:%M'),
                    "created_by_name": row[8] if row[8] else "System",
                    "count_in_hours": bool(row[9])
                }
                for row in cursor.fetchall()
            ]

        logging.info(f"Trainings fetched for role {role}, month: {month}, by user {requester_id}")
        return jsonify({"status": "success", "trainings": trainings}), 200
    except Exception as e:
        logging.error(f"Error fetching trainings: {e}", exc_info=True)
        return jsonify({"error": f"Internal server error"}), 500

def _training_time_to_minutes(value):
    try:
        if hasattr(value, 'hour') and hasattr(value, 'minute'):
            return int(value.hour) * 60 + int(value.minute)
        parsed = datetime.strptime(str(value), '%H:%M')
        return parsed.hour * 60 + parsed.minute
    except Exception:
        return None

def _training_intervals_overlap(left_start, left_end, right_start, right_end):
    ls = _training_time_to_minutes(left_start)
    le = _training_time_to_minutes(left_end)
    rs = _training_time_to_minutes(right_start)
    re = _training_time_to_minutes(right_end)
    if None in (ls, le, rs, re):
        return False
    if le <= ls:
        le += 24 * 60
    if re <= rs:
        re += 24 * 60
    return max(ls, rs) < min(le, re)

def _find_overlapping_training(operator_id, training_date, start_time, end_time, exclude_training_id=None):
    with db._get_cursor() as cursor:
        cursor.execute("""
            SELECT id, start_time, end_time
            FROM trainings
            WHERE operator_id = %s
              AND training_date = %s
              AND (%s IS NULL OR id <> %s)
        """, (operator_id, training_date, exclude_training_id, exclude_training_id))
        rows = cursor.fetchall() or []
    for row in rows:
        if _training_intervals_overlap(start_time, end_time, row[1], row[2]):
            return {
                "id": row[0],
                "start_time": row[1].strftime('%H:%M') if hasattr(row[1], 'strftime') else str(row[1]),
                "end_time": row[2].strftime('%H:%M') if hasattr(row[2], 'strftime') else str(row[2])
            }
    return None

def _parse_optional_group_id(value):
    if value in (None, ''):
        return None, None
    try:
        group_id = int(value)
    except Exception:
        return None, ("Invalid group_id", 400)
    if group_id <= 0:
        return None, ("Invalid group_id", 400)
    return group_id, None

def _training_group_scope_error(requester, requester_id, group_id, operator_id, training_date):
    if group_id is None:
        return None
    group = db.get_group(group_id)
    if not group:
        return ("Group not found", 404)

    role = _normalize_user_role(requester[3])
    headed_dept_id = _headed_department_id(requester_id)
    if headed_dept_id is not None and not _is_admin_role(role):
        if group.get('department_id') != headed_dept_id:
            return ("Forbidden: not your department's group", 403)
    elif _is_supervisor_role(role):
        if not db.supervisor_has_group_access_for_period(requester_id, group_id, training_date, training_date):
            return ("Forbidden: not your group", 403)
    elif not _is_admin_role(role):
        return ("Forbidden", 403)

    if not db.operator_in_group_on_date(group_id, operator_id, training_date):
        return ("Operator not in selected group on training date", 403)
    return None

@app.route('/api/trainings', methods=['POST'])
@require_api_key
def add_training():
    try:
        data = request.get_json(silent=True) or {}
        required_fields = ['date', 'start_time', 'end_time', 'reason']
        if not data or not all(field in data for field in required_fields):
            logging.warning(f"Missing required fields in add_training: {data}")
            return jsonify({"error": "Missing required fields"}), 400

        raw_operator_ids = _normalize_int_id_list(data.get('operator_ids'))
        if raw_operator_ids:
            is_batch_request = True
            operator_ids = raw_operator_ids
        else:
            is_batch_request = False
            operator_ids = _normalize_int_id_list(data.get('operator_id'))

        if not operator_ids:
            logging.warning("Missing operator_id/operator_ids in add_training: %s", data)
            return jsonify({"error": "operator_id or operator_ids is required"}), 400

        requester_id, requester, auth_error = _get_authenticated_requester()
        if auth_error:
            message, status_code = auth_error
            return jsonify({"error": message}), status_code
        if not _is_admin_role(requester[3]) and not _is_supervisor_role(requester[3]) and _headed_department_id(requester_id) is None:
            logging.warning(f"Unauthorized attempt to add training by user {requester_id}")
            return jsonify({"error": "Unauthorized"}), 403

        group_id, group_id_error = _parse_optional_group_id(data.get('group_id'))
        if group_id_error:
            message, status_code = group_id_error
            return jsonify({"error": message}), status_code

        try:
            datetime.strptime(data['date'], '%Y-%m-%d')
            datetime.strptime(data['start_time'], '%H:%M')
            datetime.strptime(data['end_time'], '%H:%M')
        except ValueError:
            logging.warning(f"Invalid date/time format in add_training: {data}")
            return jsonify({"error": "Invalid date or time format"}), 400

        allowed_reasons = [
            "Обратная связь", "Собрание", "Тех. сбой", "Мотивационная беседа",
            "Дисциплинарный тренинг", "Тренинг по качеству. Разбор ошибок",
            "Тренинг по качеству. Объяснение МШ", "Тренинг по продукту",
            "Мониторинг", "Практика в офисе таксопарка", "Другое"
        ]
        if data['reason'] not in allowed_reasons:
            logging.warning(f"Invalid training reason: {data['reason']}")
            return jsonify({"error": "Invalid training reason"}), 400

        if not is_batch_request:
            if group_id is not None:
                operator = db.get_user(id=int(operator_ids[0]))
                if not operator:
                    return jsonify({"error": "Operator not found"}), 404
                group_scope_error = _training_group_scope_error(
                    requester, requester_id, group_id, int(operator[0]), data['date']
                )
                if group_scope_error:
                    message, status_code = group_scope_error
                    logging.warning("Blocked group training creation: requester=%s operator=%s group=%s error=%s", requester_id, operator_ids[0], group_id, message)
                    return jsonify({"error": message}), status_code
            else:
                operator, scope_error = _load_target_user_with_scope(
                    requester,
                    requester_id,
                    operator_ids[0],
                    allow_self=False,
                    supervisor_target_roles=('operator',),
                    not_found_message="Operator not found",
                    forbidden_message="Forbidden for this operator"
                )
                if scope_error:
                    message, status_code = scope_error
                    logging.warning("Blocked training creation: requester=%s operator=%s error=%s", requester_id, operator_ids[0], message)
                    return jsonify({"error": message}), status_code

            overlapping_training = _find_overlapping_training(
                int(operator[0]),
                data['date'],
                data['start_time'],
                data['end_time']
            )
            if overlapping_training:
                return jsonify({
                    "status": "overlap",
                    "error": "Training overlaps with an existing training for this operator",
                    "overlap": True,
                    "training": overlapping_training
                }), 409

            training_id = db.add_training(
                operator_id=int(operator[0]),
                training_date=data['date'],
                start_time=data['start_time'],
                end_time=data['end_time'],
                reason=data['reason'],
                comment=data.get('comment'),
                created_by=requester_id,
                count_in_hours=data.get("count_in_hours", True)
            )
            logging.info("Training added: ID %s for operator %s", training_id, operator_ids[0])
            return jsonify({"status": "success", "id": training_id}), 201

        created_ids = []
        scoped_operator_ids = []
        errors = []

        for raw_operator_id in operator_ids:
            try:
                if group_id is not None:
                    operator = db.get_user(id=int(raw_operator_id))
                    if not operator:
                        errors.append({
                            "operator_id": int(raw_operator_id),
                            "error": "Operator not found",
                            "status_code": 404
                        })
                        continue
                    group_scope_error = _training_group_scope_error(
                        requester, requester_id, group_id, int(operator[0]), data['date']
                    )
                    if group_scope_error:
                        message, status_code = group_scope_error
                        logging.warning(
                            "Blocked group batch training creation: requester=%s operator=%s group=%s error=%s",
                            requester_id,
                            raw_operator_id,
                            group_id,
                            message
                        )
                        errors.append({
                            "operator_id": int(raw_operator_id),
                            "error": str(message),
                            "status_code": int(status_code)
                        })
                        continue
                else:
                    operator, scope_error = _load_target_user_with_scope(
                        requester,
                        requester_id,
                        raw_operator_id,
                        allow_self=False,
                        supervisor_target_roles=('operator',),
                        not_found_message="Operator not found",
                        forbidden_message="Forbidden for this operator"
                    )
                    if scope_error:
                        message, status_code = scope_error
                        logging.warning(
                            "Blocked batch training creation: requester=%s operator=%s error=%s",
                            requester_id,
                            raw_operator_id,
                            message
                        )
                        errors.append({
                            "operator_id": int(raw_operator_id),
                            "error": str(message),
                            "status_code": int(status_code)
                        })
                        continue

                scoped_operator_id = int(operator[0])
                overlapping_training = _find_overlapping_training(
                    scoped_operator_id,
                    data['date'],
                    data['start_time'],
                    data['end_time']
                )
                if overlapping_training:
                    errors.append({
                        "operator_id": int(raw_operator_id),
                        "error": "Training overlaps with an existing training for this operator",
                        "status_code": 409,
                        "overlap": True,
                        "training": overlapping_training
                    })
                    continue

                training_id = db.add_training(
                    operator_id=scoped_operator_id,
                    training_date=data['date'],
                    start_time=data['start_time'],
                    end_time=data['end_time'],
                    reason=data['reason'],
                    comment=data.get('comment'),
                    created_by=requester_id,
                    count_in_hours=data.get("count_in_hours", True)
                )
                scoped_operator_ids.append(scoped_operator_id)
                created_ids.append(training_id)
            except Exception as operator_error:
                logging.error(
                    "Error adding batch training for requester=%s operator=%s: %s",
                    requester_id,
                    raw_operator_id,
                    operator_error,
                    exc_info=True
                )
                errors.append({
                    "operator_id": int(raw_operator_id),
                    "error": "Internal server error",
                    "status_code": 500
                })

        if not created_ids:
            status_code = errors[0].get("status_code", 400) if errors else 400
            if errors and any(item.get("status_code") != status_code for item in errors):
                status_code = 400
            return jsonify({
                "status": "error",
                "error": errors[0]["error"] if errors else "Failed to create trainings",
                "errors": errors,
                "created_count": 0,
                "operator_ids": scoped_operator_ids
            }), status_code

        response_payload = {
            "status": "success" if not errors else "partial_success",
            "ids": created_ids,
            "created_count": len(created_ids),
            "operator_ids": scoped_operator_ids,
            "errors": errors
        }
        logging.info(
            "Batch training request processed: requester=%s created=%s failed=%s",
            requester_id,
            len(created_ids),
            len(errors)
        )
        return jsonify(response_payload), (201 if not errors else 207)
    except Exception as e:
        logging.error(f"Error adding training: {e}", exc_info=True)
        return jsonify({"error": f"Internal server error"}), 500

@app.route('/api/trainings/<int:training_id>', methods=['PUT'])
@require_api_key
def update_training(training_id):
    try:
        data = request.get_json()
        if not data:
            logging.warning("No data provided for update_training")
            return jsonify({"error": "No data provided"}), 400

        requester_id, requester, auth_error = _get_authenticated_requester()
        if auth_error:
            message, status_code = auth_error
            return jsonify({"error": message}), status_code
        if not _is_admin_role(requester[3]) and not _is_supervisor_role(requester[3]) and _headed_department_id(requester_id) is None:
            logging.warning(f"Unauthorized attempt to update training {training_id} by user {requester_id}")
            return jsonify({"error": "Unauthorized"}), 403

        with db._get_cursor() as cursor:
            cursor.execute("""
                SELECT created_by, operator_id, training_date, start_time, end_time FROM trainings WHERE id = %s
            """, (training_id,))
            training = cursor.fetchone()
            if not training:
                logging.warning(f"Training not found: {training_id}")
                return jsonify({"error": "Training not found"}), 404

        group_id, group_id_error = _parse_optional_group_id(data.get('group_id'))
        if group_id_error:
            message, status_code = group_id_error
            return jsonify({"error": message}), status_code

        if group_id is not None:
            effective_scope_date = data.get('date') or training[2].strftime('%Y-%m-%d')
            try:
                datetime.strptime(effective_scope_date, '%Y-%m-%d')
            except ValueError:
                logging.warning(f"Invalid date format: {effective_scope_date}")
                return jsonify({"error": "Invalid date format"}), 400
            operator = db.get_user(id=int(training[1]))
            if not operator:
                return jsonify({"error": "Operator not found"}), 404
            group_scope_error = _training_group_scope_error(
                requester, requester_id, group_id, int(training[1]), effective_scope_date
            )
            if group_scope_error:
                message, status_code = group_scope_error
                return jsonify({"error": message}), status_code
        else:
            operator, scope_error = _load_target_user_with_scope(
                requester,
                requester_id,
                training[1],
                allow_self=False,
                supervisor_target_roles=('operator',),
                not_found_message="Operator not found",
                forbidden_message="Forbidden for this operator"
            )
            if scope_error:
                message, status_code = scope_error
                return jsonify({"error": message}), status_code

        if 'date' in data:
            try:
                datetime.strptime(data['date'], '%Y-%m-%d')
            except ValueError:
                logging.warning(f"Invalid date format: {data['date']}")
                return jsonify({"error": "Invalid date format"}), 400
        if 'start_time' in data:
            try:
                datetime.strptime(data['start_time'], '%H:%M')
            except ValueError:
                logging.warning(f"Invalid start_time format: {data['start_time']}")
                return jsonify({"error": "Invalid start time format"}), 400
        if 'end_time' in data:
            try:
                datetime.strptime(data['end_time'], '%H:%M')
            except ValueError:
                logging.warning(f"Invalid end_time format: {data['end_time']}")
                return jsonify({"error": "Invalid end time format"}), 400
        if 'reason' in data:
            allowed_reasons = [
                "Обратная связь", "Собрание", "Тех. сбой", "Мотивационная беседа",
                "Дисциплинарный тренинг", "Тренинг по качеству. Разбор ошибок",
                "Тренинг по качеству. Объяснение МШ", "Тренинг по продукту",
                "Мониторинг", "Практика в офисе таксопарка", "Другое"
            ]
            if data['reason'] not in allowed_reasons:
                logging.warning(f"Invalid training reason: {data['reason']}")
                return jsonify({"error": "Invalid training reason"}), 400

        effective_date = data.get('date') or training[2].strftime('%Y-%m-%d')
        effective_start = data.get('start_time') or training[3].strftime('%H:%M')
        effective_end = data.get('end_time') or training[4].strftime('%H:%M')
        overlapping_training = _find_overlapping_training(
            training[1],
            effective_date,
            effective_start,
            effective_end,
            exclude_training_id=training_id
        )
        if overlapping_training:
            return jsonify({
                "status": "overlap",
                "error": "Training overlaps with an existing training for this operator",
                "overlap": True,
                "training": overlapping_training
            }), 409

        success = db.update_training(
            training_id=training_id,
            training_date=data.get('date'),
            start_time=data.get('start_time'),
            end_time=data.get('end_time'),
            reason=data.get('reason'),
            comment=data.get('comment'),
            count_in_hours=data.get('count_in_hours') 
        )
        if not success:
            logging.warning(f"Failed to update training {training_id}")
            return jsonify({"error": "Failed to update training"}), 500

        logging.info(f"Training updated: ID {training_id} for operator {operator[0]}")
        return jsonify({"status": "success", "message": "Training updated"}), 200
    except Exception as e:
        logging.error(f"Error updating training {training_id}: {e}", exc_info=True)
        return jsonify({"error": f"Internal server error"}), 500

