@app.route('/api/technical_issues/export_excel', methods=['GET'])
@require_api_key
def export_technical_issues_excel():
    try:
        requester_id = getattr(g, 'user_id', None) or request.headers.get('X-User-Id')
        if not requester_id:
            return jsonify({"error": "Unauthorized"}), 401
        requester_id = int(requester_id)

        requester = db.get_user(id=requester_id)
        if not requester:
            return jsonify({"error": "User not found"}), 404

        requester_role = _normalize_management_role(requester[3])
        effective_role, scope_department_id = _effective_management_scope(requester, requester_id)
        if not (_is_admin_role(requester_role) or _is_supervisor_role(requester_role) or _headed_department_id(requester_id) is not None):
            return jsonify({"error": "Only admin and sv can export technical issues"}), 403

        issue_date = (request.args.get('date') or '').strip() or None
        date_from = (request.args.get('date_from') or '').strip() or None
        date_to = (request.args.get('date_to') or '').strip() or None
        operator_id = (request.args.get('operator_id') or '').strip() or None
        reason = (request.args.get('reason') or '').strip() or None
        workplace_number = (request.args.get('workplace_number') or request.args.get('workplace') or '').strip() or None

        result = db.get_operator_technical_issues(
            requester_id=requester_id,
            requester_role=effective_role,
            issue_date=issue_date,
            date_from=date_from,
            date_to=date_to,
            operator_id=operator_id,
            reason=reason,
            workplace_number=workplace_number,
            limit=5000,
            offset=0,
            scope_department_id=scope_department_id
        )
        rows = result.get('items') or []

        wb = Workbook()
        ws = wb.active
        ws.title = 'Тех причины'

        headers = [
            'Дата проблемы',
            'Время начала',
            'Время окончания',
            'Оператор',
            'Рабочее место',
            'Для супервайзера',
            'Направление оператора',
            'Техническая причина',
            'Комментарий',
            'Выбранные направления',
            'Добавил',
            'Дата фиксации'
        ]
        for col_idx, title in enumerate(headers, start=1):
            cell = ws.cell(row=1, column=col_idx, value=title)
            cell.font = cell.font.copy(bold=True)

        for row_idx, item in enumerate(rows, start=2):
            selected_directions = ', '.join(item.get('selected_direction_names') or [])
            ws.cell(row=row_idx, column=1, value=item.get('date') or '')
            ws.cell(row=row_idx, column=2, value=item.get('start_time') or '')
            ws.cell(row=row_idx, column=3, value=item.get('end_time') or '')
            ws.cell(row=row_idx, column=4, value=item.get('operator_name') or '')
            ws.cell(row=row_idx, column=5, value=item.get('workplace_number') or '')
            ws.cell(row=row_idx, column=6, value='Да' if item.get('for_supervisor') else 'Нет')
            ws.cell(row=row_idx, column=7, value=item.get('direction_name') or '')
            ws.cell(row=row_idx, column=8, value=item.get('reason') or '')
            ws.cell(row=row_idx, column=9, value=item.get('comment') or '')
            ws.cell(row=row_idx, column=10, value=selected_directions)
            ws.cell(row=row_idx, column=11, value=item.get('created_by_name') or '')
            ws.cell(row=row_idx, column=12, value=item.get('created_at') or '')

        for column_cells in ws.columns:
            max_len = 0
            for cell in column_cells:
                try:
                    max_len = max(max_len, len(str(cell.value or '')))
                except Exception:
                    continue
            ws.column_dimensions[column_cells[0].column_letter].width = min(max(max_len + 2, 12), 60)

        filename = f"technical_issues_{datetime.now().strftime('%Y%m%d_%H%M%S')}.xlsx"
        output = BytesIO()
        wb.save(output)
        output.seek(0)

        return send_file(
            output,
            as_attachment=True,
            download_name=filename,
            mimetype='application/vnd.openxmlformats-officedocument.spreadsheetml.sheet'
        )
    except ValueError as e:
        return jsonify({"error": str(e)}), 400
    except Exception as e:
        logging.error(f"Error exporting technical issues: {e}", exc_info=True)
        return jsonify({"error": f"Internal server error"}), 500


# ==================== Work Schedules API ====================

WORK_SCHEDULE_EXCEL_SHIFT_RE = re.compile(
    r'(?P<sh>\d{1,2})(?:[:/](?P<sm>\d{1,2}))?\s*\*\s*(?P<eh>\d{1,2})(?:[:/](?P<em>\d{1,2}))?'
)


def _normalize_schedule_excel_name_key(value):
    return re.sub(r'\s+', ' ', str(value or '').strip()).replace('ё', 'е').replace('Ё', 'Е').lower()


def _parse_schedule_excel_header_date(cell):
    value = cell.value
    if value is None:
        return None

    # openpyxl для xlsx чаще всего уже возвращает datetime/date при is_date=True
    if getattr(cell, 'is_date', False):
        if isinstance(value, datetime):
            return value.date()
        if isinstance(value, dt_date):
            return value

    if isinstance(value, datetime):
        return value.date()
    if isinstance(value, dt_date):
        return value

    text = str(value).strip()
    if not text:
        return None
    for fmt in ('%d.%m.%Y', '%d.%m.%y', '%Y-%m-%d'):
        try:
            return datetime.strptime(text, fmt).date()
        except Exception:
            continue
    return None


def _format_schedule_excel_compact_time(hhmm):
    try:
        hh, mm = str(hhmm).split(':', 1)
        h = int(hh)
        m = int(mm)
    except Exception:
        return str(hhmm or '')
    if m == 0:
        return str(h)
    return f"{h}/{m:02d}"


def _parse_schedule_excel_cell_value(raw_value):
    """
    Возвращает:
      {'kind': 'empty'}
      {'kind': 'day_off'}
      {'kind': 'shifts', 'shifts': [{'start': 'HH:MM', 'end': 'HH:MM'}, ...]}
      {'kind': 'invalid', 'error': '...'}
    """
    if raw_value is None:
        return {'kind': 'empty'}

    text = str(raw_value).strip()
    if not text:
        return {'kind': 'empty'}

    lowered = text.lower()
    shift_matches = list(WORK_SCHEDULE_EXCEL_SHIFT_RE.finditer(text))

    if not shift_matches and 'выходн' in lowered:
        return {'kind': 'day_off'}

    shifts = []
    seen = set()
    for m in shift_matches:
        try:
            sh = int(m.group('sh'))
            sm = int(m.group('sm') or 0)
            eh = int(m.group('eh'))
            em = int(m.group('em') or 0)
        except Exception:
            continue

        if not (0 <= sh <= 23 and 0 <= eh <= 23 and 0 <= sm <= 59 and 0 <= em <= 59):
            return {'kind': 'invalid', 'error': f'Некорректное время: {m.group(0)}'}

        start = f"{sh:02d}:{sm:02d}"
        end = f"{eh:02d}:{em:02d}"
        key = (start, end)
        if key in seen:
            continue
        seen.add(key)
        shifts.append({'start': start, 'end': end})

    if shifts:
        return {'kind': 'shifts', 'shifts': shifts}

    if 'выходн' in lowered:
        return {'kind': 'day_off'}

    return {'kind': 'invalid', 'error': 'Ячейка не похожа на смену или "Выходной"'}


STATUS_IMPORT_MAX_FILE_SIZE_MB = max(1, int(os.getenv('STATUS_IMPORT_MAX_FILE_SIZE_MB', '12')))
STATUS_IMPORT_MAX_FILE_SIZE_BYTES = STATUS_IMPORT_MAX_FILE_SIZE_MB * 1024 * 1024
STATUS_IMPORT_MAX_SOURCE_ROWS = max(1, int(os.getenv('STATUS_IMPORT_MAX_SOURCE_ROWS', '120000')))
STATUS_IMPORT_INVALID_ROWS_PREVIEW_LIMIT = max(1, int(os.getenv('STATUS_IMPORT_INVALID_ROWS_PREVIEW_LIMIT', '30')))
STATUS_IMPORT_LOCK = threading.Lock()
CHAT_MANAGER_METRICS_IMPORT_LOCK = threading.Lock()


def _status_import_secure_filename_and_ext(raw_filename, fallback_filename='statuses.csv'):
    original_filename = str(raw_filename or '').strip()
    fallback = str(fallback_filename or 'statuses.csv').strip() or 'statuses.csv'
    original_ext = os.path.splitext(original_filename)[1].lower()

    safe_name = secure_filename(original_filename or fallback)
    safe_ext = os.path.splitext(str(safe_name or '').lower())[1]
    if original_ext and not safe_ext:
        fallback_root = os.path.splitext(fallback)[0].strip() or 'statuses'
        safe_name = secure_filename(f"{fallback_root}{original_ext}") or f"statuses{original_ext}"
        safe_ext = os.path.splitext(str(safe_name or '').lower())[1]

    if not safe_name:
        safe_name = secure_filename(fallback) or fallback
        safe_ext = os.path.splitext(str(safe_name or '').lower())[1]

    return safe_name, safe_ext


def _status_import_normalize_key(value):
    return ' '.join(str(value or '').strip().lower().split())


def _status_import_normalize_header(value):
    return re.sub(r'[\s_-]+', '', str(value or '').replace('\ufeff', '').strip().lower())


# Казахские буквы, которых нет в русском, нередко расходятся в написании имён между
# системами (Oktell/OTP/Chat2Desk): «Мадиұлы»/«Мадиулы», «Әсел»/«Асел». Сводим их к
# ближайшим русским, чтобы одно и то же имя матчилось независимо от раскладки.
_KZ_TO_RU_FOLD = str.maketrans({
    'ә': 'а', 'ғ': 'г', 'қ': 'к', 'ң': 'н', 'ө': 'о',
    'ұ': 'у', 'ү': 'у', 'һ': 'х', 'і': 'и',
})


def _status_import_normalize_operator_name(value):
    text = re.sub(r'\s+', ' ', str(value or '').strip()).replace('ё', 'е').replace('Ё', 'Е').lower()
    text = text.translate(_KZ_TO_RU_FOLD)
    # Имена в БД и Chat2Desk нередко расходятся на конечный мягкий/твёрдый знак
    # («Асель»/«Асел», «Игорь»/«Игор»), поэтому срезаем «ь»/«ъ» в конце
    # каждого слова — чтобы оба варианта матчились как один оператор.
    return re.sub(r'[ьъ]+(?=\s|$)', '', text)


def _status_import_operator_name_variants(value):
    normalized = _status_import_normalize_operator_name(value)
    if not normalized:
        return []
    tokens = re.findall(r"[a-zа-яёәғқңөұүһі]+", normalized, flags=re.IGNORECASE)
    variants = {normalized}
    if len(tokens) >= 2:
        variants.add(f"{tokens[0]} {tokens[1]}")
        variants.add(f"{tokens[1]} {tokens[0]}")
    if len(tokens) >= 3:
        variants.add(f"{tokens[0]} {tokens[1]} {tokens[2]}")
        variants.add(f"{tokens[1]} {tokens[0]} {tokens[2]}")
        variants.add(f"{tokens[1]} {tokens[0]}")
    return [item for item in variants if item]


def _status_import_dedupe_operator_infos(infos):
    seen = {}
    for info in (infos or []):
        try:
            oid = int(info.get('id'))
        except Exception:
            continue
        if oid not in seen:
            seen[oid] = info
    return list(seen.values())


def _status_import_resolve_operator_matches(operator_name, operator_lookup):
    """Сопоставляет имя из источника с операторами OTP.

    Tier 1 — точное полное имя (как было раньше): сохраняет прежнее поведение,
    никаких регрессий по уже совпадавшим именам.
    Tier 2 — если полное имя не нашлось, пробуем «Фамилия Имя» (и в обратном
    порядке). Это лечит расхождения, ломавшие матчинг: разное число токенов
    (ФИО vs Фамилия+Имя) и разные формы отчества (-кызы/-овна, -улы/-ович),
    которые не влияют на фамилию и имя. Tier 2 срабатывает только при
    однозначном совпадении, иначе строка остаётся «не найдена/неоднозначна».
    """
    norm = _status_import_normalize_operator_name(operator_name)
    exact = _status_import_dedupe_operator_infos(operator_lookup.get(norm))
    if exact:
        return exact  # ровно 1 -> матч; >1 -> неоднозначно (как и раньше)
    tokens = re.findall(r"[a-zа-яёәғқңөұүһі]+", norm, flags=re.IGNORECASE)
    fallback = []
    if len(tokens) >= 2:
        for key in (f"{tokens[0]} {tokens[1]}", f"{tokens[1]} {tokens[0]}"):
            fallback.extend(operator_lookup.get(key) or [])
    return _status_import_dedupe_operator_infos(fallback)


CHAT2DESK_STATUS_EVENT_MAP = {
    'status.online': ('online', 'Online'),
    'status.holiday': ('holiday', 'Закрытие чатов'),
    'status.break': ('break', 'Обеденный перерыв'),
    'status.busy': ('busy', 'Busy'),
    'status.study': ('study', 'Тренинг'),
    'status.training': ('study', 'Тренинг'),
    # Новый экспорт Chat2Desk отдает те же статусы без префикса `status.`.
    'online': ('online', 'Online'),
    'holiday': ('holiday', 'Закрытие чатов'),
    'break': ('break', 'Обеденный перерыв'),
    'busy': ('busy', 'Busy'),
    'study': ('study', 'Тренинг'),
    'training': ('study', 'Тренинг'),
    'tech.break': ('тех причина', 'Тех причина'),
    'status.tech.break': ('тех причина', 'Тех причина'),
    'tech_break': ('тех причина', 'Тех причина'),
    'status.tech_break': ('тех причина', 'Тех причина'),
    'login': ('login', 'Вход в систему'),
    'logout': ('logout', 'Выход из системы'),
}


# События, которые приходят из Chat2Desk, но в учёте чат-менеджеров их нужно
# полностью игнорировать (не превращать в logout и не сохранять сегмент).
CHAT2DESK_IGNORED_STATUS_EVENTS = {
    'offline',
    'status.offline',
}


CHAT2DESK_ACTION_EVENT_MAP = {
    'transfer.chat': ('transfer chat', 'Передача чата'),
    'take.chat': ('take chat', 'Взятие чата'),
}


def _status_import_parse_datetime(value):
    text = str(value or '').strip()
    if not text:
        return None
    formats = (
        '%d.%m.%Y %H:%M:%S',
        '%d.%m.%Y %H:%M',
        '%d/%m/%Y %H:%M:%S',
        '%d/%m/%Y %H:%M',
        '%Y-%m-%d %H:%M:%S',
        '%Y-%m-%d %H:%M',
        '%Y/%m/%d %H:%M:%S',
        '%Y/%m/%d %H:%M',
        '%Y-%m-%dT%H:%M:%S',
        '%Y-%m-%dT%H:%M',
        # Формат посегментной выгрузки TEZ: "HH:MM DD-MM-YYYY".
        '%H:%M %d-%m-%Y',
        '%H:%M:%S %d-%m-%Y',
        '%H:%M %d.%m.%Y',
        '%H:%M:%S %d.%m.%Y'
    )
    for fmt in formats:
        try:
            return datetime.strptime(text, fmt)
        except Exception:
            continue
    return None


def _status_import_resolve_break_note_label(state_note_raw):
    note_key = _status_import_normalize_key(state_note_raw)
    if not note_key:
        return 'Перерыв'
    compact_note_key = re.sub(r'[\s._-]+', '', note_key)
    if note_key == 'вышел':
        return 'Вышел'
    # "Авто" в рамках "Перерыв" трактуем как обычный перерыв.
    if note_key == 'авто':
        return 'Перерыв'
    if note_key == 'перезвон':
        return 'Перезвон'
    if compact_note_key == 'техпричина':
        return 'Тех причина'
    if note_key == 'тренинг':
        return 'Тренинг'
    return str(state_note_raw or '').strip() or 'Перерыв'


def _status_import_resolve_display_state(state_name_raw, state_note_raw):
    base_name = str(state_name_raw or '').strip()
    base_key = _status_import_normalize_key(base_name)
    event_key = re.sub(r'[\s_]+', '.', base_key)
    event_key = re.sub(r'\.+', '.', event_key).strip('.')
    if base_key in CHAT2DESK_IGNORED_STATUS_EVENTS or event_key in CHAT2DESK_IGNORED_STATUS_EVENTS:
        return {
            'label': base_name or '—',
            'key': '',
            'base_key': base_key,
            'base_name': base_name,
            'kind': 'ignore'
        }
    matched_status = CHAT2DESK_STATUS_EVENT_MAP.get(base_key) or CHAT2DESK_STATUS_EVENT_MAP.get(event_key)
    if matched_status:
        status_key, label = matched_status
        return {
            'label': label,
            'key': status_key,
            'base_key': base_key,
            'base_name': base_name,
            'kind': 'status'
        }
    matched_action = CHAT2DESK_ACTION_EVENT_MAP.get(base_key) or CHAT2DESK_ACTION_EVENT_MAP.get(event_key)
    if matched_action:
        status_key, label = matched_action
        return {
            'label': label,
            'key': status_key,
            'base_key': base_key,
            'base_name': base_name,
            'kind': 'action'
        }
    if base_key == 'перерыв':
        label = _status_import_resolve_break_note_label(state_note_raw)
        return {
            'label': label,
            'key': _status_import_normalize_key(label),
            'base_key': base_key,
            'base_name': base_name,
            'kind': 'status'
        }
    return {
        'label': base_name or '—',
        'key': base_key,
        'base_key': base_key,
        'base_name': base_name,
        'kind': 'status'
    }


def _status_import_split_segment_by_day(start_dt, end_dt):
    if not isinstance(start_dt, datetime) or not isinstance(end_dt, datetime):
        return []
    if end_dt <= start_dt:
        return []

    result = []
    cursor = start_dt
    while cursor < end_dt:
        day_start = cursor.replace(hour=0, minute=0, second=0, microsecond=0)
        day_end = day_start + timedelta(days=1)
        seg_end = min(end_dt, day_end)
        duration_sec = int((seg_end - cursor).total_seconds())
        if duration_sec > 0:
            result.append({
                'date': cursor.date(),
                'start': cursor,
                'end': seg_end,
                'duration_sec': duration_sec
            })
        cursor = seg_end
    return result


def _status_import_build_operator_lookup(exclude_chat_managers=False, restrict_to_ids=None):
    """Строит lookup «имя -> оператор(ы)» для матчинга строк импорта/синка.

    restrict_to_ids — если задан, в lookup попадают ТОЛЬКО операторы с этими id.
    Синк Oktell передаёт сюда набор операторов, у которых в периоде есть хотя бы
    один день с операторской моделью (включая тех, кто сейчас числится
    чат-менеджером, но был оператором до перехода), а дни фильтруются отдельно по
    модели на каждый день (см. _oktell_operator_model_gate)."""
    restrict = None
    if restrict_to_ids is not None:
        restrict = {int(v) for v in restrict_to_ids if v is not None}
    lookup = {}
    for row in (db.get_all_operators() or []):
        try:
            operator_id = int(row[0])
        except Exception:
            continue
        if restrict is not None and operator_id not in restrict:
            continue
        operator_name = str(row[1] or '').strip()
        direction_name = str(row[7] or '').strip() if len(row) > 7 else ''
        calculation_model_code = str(row[8] or '').strip().lower() if len(row) > 8 else ''
        direction_key = ' '.join(direction_name.lower().split())
        is_chat_manager = (
            calculation_model_code == 'chat_manager'
            or direction_key in ('чат менеджер', 'chat manager')
        )
        if exclude_chat_managers and is_chat_manager:
            continue
        operator_info = {
            'id': operator_id,
            'name': operator_name,
            'direction_name': direction_name,
            'calculation_model_code': calculation_model_code
        }
        for key in _status_import_operator_name_variants(operator_name):
            lookup.setdefault(key, [])
            if not any(int(item.get('id')) == operator_id for item in lookup[key]):
                lookup[key].append(operator_info)
    return lookup


def _status_import_build_status_events(row_iter, operator_lookup, invalid_rows_preview_limit=None,
                                       operator_day_filter=None):
    """Единый конвейер построения событий/сегментов статусов операторов из УЖЕ
    разобранных строк — без промежуточного CSV.

    `row_iter` — итерируемое из dict с ключами:
        row_num, operator_name, state_name, state_note, time_change.

    `operator_day_filter` — необязательный предикат (operator_id, 'YYYY-MM-DD') ->
    bool. Если задан, события за дни, для которых он вернул False, отбрасываются.
    Синк Oktell передаёт сюда проверку «в этот день оператор был в группе с
    операторской моделью», чтобы статусы за дни после перехода человека в
    чат-менеджеры (или иной не-операторской модели) не записывались.

    Через этот core идут и ручная загрузка (CSV/XLSX -> строки -> core), и живые
    выгрузки (Oktell и последующие интеграции), чтобы все источники использовали одну
    логику матчинга операторов и сборки сегментов. Возвращает тот же сводный dict.
    """
    preview_limit_value = STATUS_IMPORT_INVALID_ROWS_PREVIEW_LIMIT
    if invalid_rows_preview_limit is not None:
        try:
            preview_limit_value = max(1, int(invalid_rows_preview_limit))
        except Exception:
            preview_limit_value = STATUS_IMPORT_INVALID_ROWS_PREVIEW_LIMIT

    source_rows = 0
    valid_events = 0
    invalid_rows_count = 0
    invalid_rows_preview = []
    events_by_operator = {}
    source_order_stats = {}
    action_events_count = 0
    ignored_events_count = 0
    skipped_non_operator_day = 0
    chat_metrics_by_operator_day = {}

    def _push_invalid(row_num, reason, operator_name, source_state_name, state_note, time_change):
        nonlocal invalid_rows_count
        invalid_rows_count += 1
        if len(invalid_rows_preview) >= preview_limit_value:
            return
        invalid_rows_preview.append({
            'row': int(row_num),
            'reason': str(reason or '').strip() or 'Некорректная строка',
            'operator_name': str(operator_name or '').strip(),
            'state_name': str(source_state_name or '').strip(),
            'state_note': str(state_note or '').strip(),
            'time_change': str(time_change or '').strip()
        })

    for row in row_iter:
        source_rows += 1
        row_num = int(row.get('row_num') or (source_rows + 1))
        operator_name = str(row.get('operator_name') or '').strip()
        source_state_name = str(row.get('state_name') or '').strip()
        state_note = str(row.get('state_note') or '').strip()
        time_change = str(row.get('time_change') or '').strip()

        if not operator_name and not source_state_name and not state_note and not time_change:
            continue

        if not operator_name or not source_state_name or not time_change:
            _push_invalid(row_num, 'Отсутствуют обязательные поля', operator_name, source_state_name, state_note, time_change)
            continue

        ts = _status_import_parse_datetime(time_change)
        if not ts:
            _push_invalid(row_num, 'Некорректный формат TimeChange', operator_name, source_state_name, state_note, time_change)
            continue

        valid_events += 1

        operator_matches = _status_import_resolve_operator_matches(operator_name, operator_lookup)
        if len(operator_matches) != 1:
            _push_invalid(
                row_num,
                'Оператор не найден' if len(operator_matches) == 0 else 'Найдено несколько операторов с таким именем',
                operator_name, source_state_name, state_note, time_change
            )
            continue

        resolved = _status_import_resolve_display_state(source_state_name, state_note)
        event_kind = str(resolved.get('kind') or 'status')
        if event_kind == 'ignore':
            ignored_events_count += 1
            continue
        operator_info = operator_matches[0]
        operator_id = int(operator_info['id'])
        if operator_day_filter is not None and not operator_day_filter(operator_id, ts.date().strftime('%Y-%m-%d')):
            # Этот день не относится к операторской модели для данного оператора
            # (например, после перехода в чат-менеджеры) — статусы за него не пишем.
            skipped_non_operator_day += 1
            continue
        status_key = resolved.get('key') or _status_import_normalize_key(source_state_name)
        if event_kind == 'action':
            action_events_count += 1
            if status_key == 'transfer chat':
                metric_key = (operator_id, ts.date().strftime('%Y-%m-%d'))
                metric_row = chat_metrics_by_operator_day.setdefault(metric_key, {
                    'operator_id': operator_id,
                    'operator_name': operator_info.get('name') or operator_name,
                    'day': ts.date().strftime('%Y-%m-%d'),
                    'transfer_chat_count': 0,
                    'source': 'chat2desk_events'
                })
                metric_row['transfer_chat_count'] = int(metric_row.get('transfer_chat_count') or 0) + 1

        order_stats = source_order_stats.setdefault(operator_id, {'asc': 0, 'desc': 0, 'last_ts': None})
        prev_ts = order_stats.get('last_ts')
        if isinstance(prev_ts, datetime):
            diff = (ts - prev_ts).total_seconds()
            if diff > 0:
                order_stats['asc'] = int(order_stats.get('asc') or 0) + 1
            elif diff < 0:
                order_stats['desc'] = int(order_stats.get('desc') or 0) + 1
        order_stats['last_ts'] = ts

        events_by_operator.setdefault(operator_id, []).append({
            'operator_id': operator_id,
            'event_at': ts,
            'status_key': status_key,
            'state_note': state_note,
            'source_row': int(row_num),
            'event_kind': event_kind
        })

    open_tail_events = 0
    zero_or_negative_transitions = 0
    segments = []
    events_for_db = []
    now_dt = datetime.now()

    for operator_id, events_list in events_by_operator.items():
        if not events_list:
            continue

        order_stats = source_order_stats.get(int(operator_id)) or {}
        prefer_desc = int(order_stats.get('desc') or 0) > int(order_stats.get('asc') or 0)
        if len(events_list) > 1:
            events_list.sort(
                key=lambda ev: (
                    ev['event_at'],
                    -int(ev.get('source_row') or 0) if prefer_desc else int(ev.get('source_row') or 0)
                )
            )

        events_for_db.extend(events_list)
        segment_events_list = [ev for ev in events_list if str(ev.get('event_kind') or 'status') != 'action']
        if not segment_events_list:
            continue

        for idx in range(len(segment_events_list) - 1):
            cur = segment_events_list[idx]
            nxt = segment_events_list[idx + 1]
            cur_ts = cur['event_at']
            next_ts = nxt['event_at']
            if next_ts <= cur_ts:
                zero_or_negative_transitions += 1
                continue

            for part in _status_import_split_segment_by_day(cur_ts, next_ts):
                segments.append({
                    'operator_id': int(operator_id),
                    'status_date': part['date'].strftime('%Y-%m-%d'),
                    'start_at': part['start'],
                    'end_at': part['end'],
                    'duration_sec': int(part['duration_sec']),
                    'status_key': cur.get('status_key'),
                    'state_note': cur.get('state_note')
                })

        last_event = segment_events_list[-1]
        last_event_at = last_event.get('event_at')
        tail_anchor_dt = last_event_at
        if isinstance(last_event_at, datetime) and (now_dt - last_event_at) <= timedelta(hours=48):
            tail_anchor_dt = now_dt
        if (
            isinstance(last_event_at, datetime)
            and isinstance(tail_anchor_dt, datetime)
            and tail_anchor_dt > last_event_at
        ):
            for part in _status_import_split_segment_by_day(last_event_at, tail_anchor_dt):
                segments.append({
                    'operator_id': int(operator_id),
                    'status_date': part['date'].strftime('%Y-%m-%d'),
                    'start_at': part['start'],
                    'end_at': part['end'],
                    'duration_sec': int(part['duration_sec']),
                    'status_key': last_event.get('status_key'),
                    'state_note': last_event.get('state_note')
                })

        open_tail_events += 1

    return {
        'source_rows': int(source_rows),
        'valid_events': int(valid_events),
        'matched_events': len(events_for_db),
        'invalid_rows_count': int(invalid_rows_count),
        'invalid_rows_preview': invalid_rows_preview,
        'parse_errors_count': 0,
        'operators_count': len(events_by_operator),
        'action_events_count': int(action_events_count),
        'ignored_events_count': int(ignored_events_count),
        'skipped_non_operator_day': int(skipped_non_operator_day),
        'open_tail_events': int(open_tail_events),
        'zero_or_negative_transitions': int(zero_or_negative_transitions),
        'events': events_for_db,
        'segments': segments,
        'chat_metrics': list(chat_metrics_by_operator_day.values())
    }


def _status_import_parse_csv(csv_text, operator_lookup, max_source_rows=None, invalid_rows_preview_limit=None):
    if not isinstance(csv_text, str):
        raise ValueError("CSV text is required")

    try:
        dialect = csv.Sniffer().sniff(csv_text[:4096], delimiters=';,\t')
    except Exception:
        dialect = csv.excel()
        dialect.delimiter = ';'

    reader = csv.reader(StringIO(csv_text), dialect)
    header = None
    for candidate_header in reader:
        if any(str(cell or '').strip() for cell in candidate_header):
            header = candidate_header
            break
    if not header:
        raise ValueError("Файл пустой")

    normalized_header = [_status_import_normalize_header(h) for h in header]

    def _find_col(candidates):
        for candidate in candidates:
            if candidate in normalized_header:
                return normalized_header.index(candidate)
        return None

    operator_col = _find_col([
        'operatorname', 'operator', 'name', 'employee', 'manager', 'agent', 'user',
        'fio', 'fullname', 'оператор', 'сотрудник', 'фио', 'имя', 'менеджер',
        'чатменеджер', 'чатменеджеры'
    ])
    state_col = _find_col([
        'statename', 'state', 'status', 'statusname', 'action', 'event', 'eventname',
        'статус', 'состояние', 'действие', 'событие'
    ])
    time_col = _find_col([
        'timechange', 'datetime', 'date', 'eventdate', 'createdat', 'changedat', 'timestamp',
        'датавремя', 'времяизменения', 'датаизменения'
    ])
    date_col = _find_col(['date', 'day', 'дата', 'день'])
    time_of_day_col = _find_col(['time', 'время'])
    note_col = _find_col(['statenote', 'statusnote', 'note'])

    if operator_col is None or state_col is None or (time_col is None and (date_col is None or time_of_day_col is None)):
        raise ValueError("CSV должен содержать колонки OperatorName;StateName;TimeChange")

    max_rows_value = None
    if max_source_rows is not None:
        try:
            max_rows_value = int(max_source_rows)
        except Exception:
            max_rows_value = None
        if max_rows_value is not None and max_rows_value <= 0:
            max_rows_value = None

    def _cell(cols, idx):
        if idx is None:
            return ''
        if idx < 0 or idx >= len(cols):
            return ''
        return str(cols[idx] or '').strip()

    def _row_iter():
        seen = 0
        for row_num, cols in enumerate(reader, start=2):
            seen += 1
            if max_rows_value is not None and seen > max_rows_value:
                raise OverflowError(f"Лимит строк CSV превышен ({max_rows_value})")
            time_change = _cell(cols, time_col)
            date_value = _cell(cols, date_col)
            time_value = _cell(cols, time_of_day_col)
            if not time_change and date_col is not None and time_of_day_col is not None:
                time_change = f"{date_value} {time_value}".strip()
            # Совместимость со старым поведением: если выбранный TimeChange не парсится,
            # а пара дата+время парсится — используем её.
            if date_col is not None and time_of_day_col is not None:
                combined = f"{date_value} {time_value}".strip()
                if (combined and combined != time_change
                        and _status_import_parse_datetime(time_change) is None
                        and _status_import_parse_datetime(combined) is not None):
                    time_change = combined
            yield {
                'row_num': row_num,
                'operator_name': _cell(cols, operator_col),
                'state_name': _cell(cols, state_col),
                'state_note': _cell(cols, note_col),
                'time_change': time_change,
            }

    return _status_import_build_status_events(
        _row_iter(),
        operator_lookup,
        invalid_rows_preview_limit=invalid_rows_preview_limit
    )


def _xlsx_cell_ref_to_index(ref):
    letters = ''.join(ch for ch in str(ref or '') if ch.isalpha())
    index = 0
    for ch in letters.upper():
        index = index * 26 + (ord(ch) - ord('A') + 1)
    return max(0, index - 1)


def _status_import_xlsx_rows(raw_bytes):
    if not raw_bytes:
        raise ValueError("XLSX file is required")
    ns = {'x': 'http://schemas.openxmlformats.org/spreadsheetml/2006/main'}
    with ZipFile(BytesIO(raw_bytes)) as archive:
        names = set(archive.namelist())
        shared_strings = []
        if 'xl/sharedStrings.xml' in names:
            shared_root = ET.fromstring(archive.read('xl/sharedStrings.xml'))
            for item in shared_root.findall('x:si', ns):
                parts = [node.text or '' for node in item.findall('.//x:t', ns)]
                shared_strings.append(''.join(parts))

        sheet_name = 'xl/worksheets/sheet1.xml'
        if sheet_name not in names:
            sheet_candidates = sorted(name for name in names if name.startswith('xl/worksheets/sheet') and name.endswith('.xml'))
            if not sheet_candidates:
                raise ValueError("XLSX does not contain worksheets")
            sheet_name = sheet_candidates[0]

        sheet_root = ET.fromstring(archive.read(sheet_name))
        rows = []
        for row in sheet_root.findall('.//x:sheetData/x:row', ns):
            values = []
            for cell in row.findall('x:c', ns):
                col_index = _xlsx_cell_ref_to_index(cell.attrib.get('r'))
                while len(values) <= col_index:
                    values.append('')
                cell_type = cell.attrib.get('t')
                value_node = cell.find('x:v', ns)
                if cell_type == 'inlineStr':
                    text_parts = [node.text or '' for node in cell.findall('.//x:t', ns)]
                    values[col_index] = ''.join(text_parts).strip()
                    continue
                if value_node is None:
                    values[col_index] = ''
                    continue
                raw_value = value_node.text or ''
                if cell_type == 's':
                    try:
                        values[col_index] = shared_strings[int(raw_value)].strip()
                    except Exception:
                        values[col_index] = raw_value.strip()
                else:
                    values[col_index] = raw_value.strip()
            if any(str(value or '').strip() for value in values):
                rows.append(values)
    return rows


def _status_import_parse_xlsx(raw_bytes, operator_lookup, max_source_rows=None, invalid_rows_preview_limit=None):
    rows = _status_import_xlsx_rows(raw_bytes)
    if not rows:
        raise ValueError("Файл пустой")
    buf = StringIO()
    writer = csv.writer(buf, delimiter=';', quotechar='"', lineterminator='\n')
    writer.writerows(rows)
    return _status_import_parse_csv(
        buf.getvalue(),
        operator_lookup,
        max_source_rows=max_source_rows,
        invalid_rows_preview_limit=invalid_rows_preview_limit
    )


# ──────────────────────────────────────────────────────────────────────────
# ПОСЕГМЕНТНАЯ ВЫГРУЗКА СТАТУСОВ TEZ.
# Формат: одна строка = готовый интервал
#   internal number;employee name;started at;stopped at;seconds in status;status
# Статусы: active / work in crm = работа, break in work = перерыв, inactive = офлайн (выход).
# В отличие от событийного Chat2Desk-импорта, здесь есть явные start/stop, поэтому
# сегменты строим напрямую (а не между событиями) — иначе терялся бы последний
# сегмент и операторы с единственной строкой за период.
# ВАЖНО: inactive («выход из системы») СОХРАНЯЕМ как сегмент (kind='status'),
# чтобы офлайн-интервалы были видны на таймлайне; в рабочие часы он всё равно не
# попадает — статус-профиль TEZ не относит 'inactive' к work/break.
# ──────────────────────────────────────────────────────────────────────────
TEZ_STATUS_IMPORT_MAP = {
    'active': ('active', 'work'),
    'work in crm': ('work in crm', 'work'),
    'работа в crm': ('work in crm', 'work'),
    'break in work': ('break in work', 'break'),
    'inactive': ('inactive', 'status'),
}


def _status_import_resolve_tez_status(raw_status):
    key = _status_import_normalize_key(raw_status)
    mapped = TEZ_STATUS_IMPORT_MAP.get(key)
    if mapped:
        return {'key': mapped[0], 'kind': mapped[1]}
    # Неизвестный статус не теряем: сохраняем как обычный сегмент, но в рабочие
    # часы он не попадёт (статус-профиль TEZ его не относит к work/break).
    return {'key': key, 'kind': 'status'}


def _status_import_header_is_tez(normalized_header):
    cols = set(normalized_header or [])
    return (
        'internalnumber' in cols
        and 'startedat' in cols
        and 'stoppedat' in cols
        and 'status' in cols
    )


def _status_import_parse_tez_rows(rows, operator_lookup, max_source_rows=None, invalid_rows_preview_limit=None):
    """Посегментный парсер выгрузки статусов TEZ.

    `rows` — итерируемое списков ячеек (первая непустая строка — заголовок).
    Возвращает тот же контракт, что и `_status_import_build_status_events`
    (`events`/`segments` + счётчики), чтобы `db.save_operator_status_import`
    и авто-пересчёт часов работали без изменений.
    """
    preview_limit_value = STATUS_IMPORT_INVALID_ROWS_PREVIEW_LIMIT
    if invalid_rows_preview_limit is not None:
        try:
            preview_limit_value = max(1, int(invalid_rows_preview_limit))
        except Exception:
            preview_limit_value = STATUS_IMPORT_INVALID_ROWS_PREVIEW_LIMIT

    max_rows_value = None
    if max_source_rows is not None:
        try:
            max_rows_value = int(max_source_rows)
        except Exception:
            max_rows_value = None
        if max_rows_value is not None and max_rows_value <= 0:
            max_rows_value = None

    row_list = list(rows)
    header = None
    header_index = 0
    for i, candidate in enumerate(row_list):
        if any(str(cell or '').strip() for cell in candidate):
            header = candidate
            header_index = i
            break
    if not header:
        raise ValueError("Файл пустой")

    normalized_header = [_status_import_normalize_header(h) for h in header]

    def _find_col(candidates):
        for candidate in candidates:
            if candidate in normalized_header:
                return normalized_header.index(candidate)
        return None

    operator_col = _find_col(['employeename', 'operatorname', 'employee', 'name', 'fio', 'фио', 'сотрудник', 'оператор'])
    start_col = _find_col(['startedat', 'startat', 'start', 'начало'])
    stop_col = _find_col(['stoppedat', 'stopat', 'stop', 'endat', 'end', 'конец'])
    status_col = _find_col(['status', 'statusname', 'state', 'статус', 'состояние'])

    if operator_col is None or start_col is None or stop_col is None or status_col is None:
        raise ValueError("CSV TEZ должен содержать колонки employee name;started at;stopped at;status")

    def _cell(cols, idx):
        if idx is None or idx < 0 or idx >= len(cols):
            return ''
        return str(cols[idx] or '').strip()

    source_rows = 0
    valid_events = 0
    invalid_rows_count = 0
    invalid_rows_preview = []
    ignored_events_count = 0
    zero_or_negative_transitions = 0
    events_by_operator = {}
    segments_by_operator = {}
    matched_operator_ids = set()

    def _push_invalid(row_num, reason, operator_name, status_name, started, stopped):
        nonlocal invalid_rows_count
        invalid_rows_count += 1
        if len(invalid_rows_preview) >= preview_limit_value:
            return
        invalid_rows_preview.append({
            'row': int(row_num),
            'reason': str(reason or '').strip() or 'Некорректная строка',
            'operator_name': str(operator_name or '').strip(),
            'state_name': str(status_name or '').strip(),
            'state_note': '',
            'time_change': f"{started} → {stopped}".strip()
        })

    seen = 0
    for offset, cols in enumerate(row_list[header_index + 1:]):
        if not any(str(cell or '').strip() for cell in cols):
            continue
        seen += 1
        if max_rows_value is not None and seen > max_rows_value:
            raise OverflowError(f"Лимит строк CSV превышен ({max_rows_value})")
        source_rows += 1
        row_num = header_index + 2 + offset

        operator_name = _cell(cols, operator_col)
        status_name = _cell(cols, status_col)
        started_raw = _cell(cols, start_col)
        stopped_raw = _cell(cols, stop_col)

        if not operator_name or not status_name or not started_raw or not stopped_raw:
            _push_invalid(row_num, 'Отсутствуют обязательные поля', operator_name, status_name, started_raw, stopped_raw)
            continue

        start_dt = _status_import_parse_datetime(started_raw)
        end_dt = _status_import_parse_datetime(stopped_raw)
        if not start_dt or not end_dt:
            _push_invalid(row_num, 'Некорректный формат даты/времени', operator_name, status_name, started_raw, stopped_raw)
            continue

        valid_events += 1

        # Матчинг по ФИО: один внутренний (sip) номер может принадлежать разным
        # операторам в разное время, поэтому матчим по имени сотрудника из выгрузки.
        operator_matches = _status_import_resolve_operator_matches(operator_name, operator_lookup)
        if len(operator_matches) != 1:
            _push_invalid(
                row_num,
                'Оператор не найден' if len(operator_matches) == 0 else 'Найдено несколько операторов с таким именем',
                operator_name, status_name, started_raw, stopped_raw
            )
            continue
        operator_info = operator_matches[0]

        resolved = _status_import_resolve_tez_status(status_name)
        status_key = resolved['key']
        kind = resolved['kind']

        if kind == 'ignore':
            ignored_events_count += 1
            continue
        if end_dt <= start_dt:
            zero_or_negative_transitions += 1
            continue

        operator_id = int(operator_info['id'])
        matched_operator_ids.add(operator_id)

        events_by_operator.setdefault(operator_id, []).append({
            'operator_id': operator_id,
            'event_at': start_dt,
            'status_key': status_key,
            'state_note': '',
            'source_row': int(row_num),
            'event_kind': 'status'
        })

        for part in _status_import_split_segment_by_day(start_dt, end_dt):
            segments_by_operator.setdefault(operator_id, []).append({
                'operator_id': operator_id,
                'status_date': part['date'].strftime('%Y-%m-%d'),
                'start_at': part['start'],
                'end_at': part['end'],
                'duration_sec': int(part['duration_sec']),
                'status_key': status_key,
                'state_note': ''
            })

    events_for_db = []
    for op_id, ev_list in events_by_operator.items():
        ev_list.sort(key=lambda ev: (ev['event_at'], int(ev.get('source_row') or 0)))
        events_for_db.extend(ev_list)
    segments = []
    for op_id, seg_list in segments_by_operator.items():
        segments.extend(seg_list)

    return {
        'source_rows': int(source_rows),
        'valid_events': int(valid_events),
        'matched_events': len(events_for_db),
        'invalid_rows_count': int(invalid_rows_count),
        'invalid_rows_preview': invalid_rows_preview,
        'parse_errors_count': 0,
        'operators_count': len(matched_operator_ids),
        'action_events_count': 0,
        'ignored_events_count': int(ignored_events_count),
        'open_tail_events': 0,
        'zero_or_negative_transitions': int(zero_or_negative_transitions),
        'events': events_for_db,
        'segments': segments,
        'chat_metrics': []
    }


def _status_import_parse_tez_csv(csv_text, operator_lookup, max_source_rows=None, invalid_rows_preview_limit=None):
    if not isinstance(csv_text, str):
        raise ValueError("CSV text is required")
    try:
        dialect = csv.Sniffer().sniff(csv_text[:4096], delimiters=';,\t')
    except Exception:
        dialect = csv.excel()
        dialect.delimiter = ';'
    reader = csv.reader(StringIO(csv_text), dialect)
    return _status_import_parse_tez_rows(
        reader,
        operator_lookup,
        max_source_rows=max_source_rows,
        invalid_rows_preview_limit=invalid_rows_preview_limit
    )


def _status_import_csv_text_is_tez(csv_text):
    """Определить по заголовку, что CSV — посегментная выгрузка TEZ."""
    if not isinstance(csv_text, str) or not csv_text.strip():
        return False
    try:
        dialect = csv.Sniffer().sniff(csv_text[:4096], delimiters=';,\t')
    except Exception:
        dialect = csv.excel()
        dialect.delimiter = ';'
    reader = csv.reader(StringIO(csv_text), dialect)
    for candidate in reader:
        if any(str(cell or '').strip() for cell in candidate):
            normalized = [_status_import_normalize_header(h) for h in candidate]
            return _status_import_header_is_tez(normalized)
    return False


def _tez_status_sync_importer(csv_text):
    """Колбэк для ежедневной авто-синхронизации статусов TEZ из Binotel:
    парсит CSV (формат TEZ) и сохраняет события/сегменты в БД тем же путём, что
    и ручная загрузка. Чат-менеджеры из матчинга исключены (как в ручном импорте)."""
    operator_lookup = _status_import_build_operator_lookup(exclude_chat_managers=True)
    parsed = _status_import_parse_tez_csv(
        csv_text,
        operator_lookup,
        max_source_rows=STATUS_IMPORT_MAX_SOURCE_ROWS,
        invalid_rows_preview_limit=STATUS_IMPORT_INVALID_ROWS_PREVIEW_LIMIT,
    )
    if not parsed.get('events'):
        return {
            "message": "Нет валидных событий",
            "matched_events": 0,
            "invalid_rows_count": int(parsed.get('invalid_rows_count') or 0),
        }
    return db.save_operator_status_import(
        events=parsed.get('events') or [],
        segments=parsed.get('segments') or [],
        imported_by=None,
        summary={
            'source_rows': int(parsed.get('source_rows') or 0),
            'valid_events': int(parsed.get('valid_events') or 0),
            'invalid_rows_count': int(parsed.get('invalid_rows_count') or 0),
            'meta': {'api': 'tez_status_sync', 'source': 'binotel'},
        },
    )


# Отметки Clockster (face-терминал) синкаются только для отдела продаж:
# приход = рабочий статус операторского профиля, уход = офлайн.
CLOCKSTER_SYNC_DEPARTMENT_CODE = (os.getenv('CLOCKSTER_SYNC_DEPARTMENT_CODE') or 'op').strip().lower() or 'op'
CLOCKSTER_MARK_IN_STATE = 'Готов'
CLOCKSTER_MARK_OUT_STATE = 'Выключен'


def _clockster_department_id():
    return next(
        (d.get('id') for d in (db.get_departments() or [])
         if str(d.get('code') or '').strip().lower() == CLOCKSTER_SYNC_DEPARTMENT_CODE),
        None
    )


def _clockster_attendance_sync_importer(rows, date_start=None, date_end=None):
    """Колбэк синка Clockster: отметки прихода/ухода → события статусов.

    Матчинг по ФИО ограничен сотрудниками отдела продаж: в Clockster
    отмечается весь офис, а импорт статусов работает как replace по
    оператору+датам — без ограничения отметки, скажем, СВ СЗоВ стёрли бы его
    Oktell-статусы. Приход = «Готов», уход = «Выключен»: сегменты между
    событиями строит стандартный rebuild, часы/опоздания/штрафы считает
    авто-агрегация по сменам графика (модели направлений ОП: часы + штрафы).

    Терминал Clockster один на вход и выход, тип отметки система угадывает и
    ошибается — поэтому поверх сырых отметок применяются ручные правки
    (attendance_mark_overrides: delete/set_kind/add), сделанные в модалке
    таймлайна дня. Так ре-синк воспроизводит правки, а не откатывает их.
    """
    dept_id = _clockster_department_id()
    if not dept_id:
        return {
            "message": f"Отдел '{CLOCKSTER_SYNC_DEPARTMENT_CODE}' не найден",
            "matched_events": 0,
        }
    member_ids = db.get_department_member_ids(dept_id)
    operator_lookup = _status_import_build_operator_lookup(restrict_to_ids=member_ids)

    # Окно оверрайдов: аргументы синка, иначе — по датам самих отметок.
    window_from = _oktell_parse_date(date_start)
    window_to = _oktell_parse_date(date_end)
    row_dates = [row['event_at'].date() for row in (rows or []) if isinstance(row.get('event_at'), datetime)]
    if window_from is None:
        window_from = min(row_dates) if row_dates else datetime.now().date()
    if window_to is None:
        window_to = max(row_dates) if row_dates else datetime.now().date()
    overrides = db.list_attendance_mark_overrides(member_ids, window_from, window_to)
    override_map = {(item['operator_id'], item['event_at']): item for item in overrides}

    def _state_for_kind(kind_value):
        return CLOCKSTER_MARK_IN_STATE if kind_value == 'in' else CLOCKSTER_MARK_OUT_STATE

    events = []
    unmatched_counts = {}
    consumed_overrides = set()
    for row in (rows or []):
        name = str(row.get('employee_name') or '').strip()
        event_at = row.get('event_at')
        if not name or not isinstance(event_at, datetime):
            continue
        matches = _status_import_resolve_operator_matches(name, operator_lookup)
        if len(matches) != 1:
            # Не наш отдел или незаведённый сотрудник — просто копим для сводки.
            unmatched_counts[name] = unmatched_counts.get(name, 0) + 1
            continue
        operator_id = int(matches[0]['id'])
        kind = 'in' if int(row.get('status') or 0) == 1 else 'out'
        override = override_map.get((operator_id, event_at))
        if override is not None:
            consumed_overrides.add((operator_id, event_at))
            if override['action'] == 'delete':
                continue
            if override['action'] in ('set_kind', 'add') and override.get('mark_kind'):
                kind = override['mark_kind']
        events.append({
            'operator_id': operator_id,
            'event_at': event_at,
            'state_name': _state_for_kind(kind),
            'state_note': 'clockster',
        })

    # Руками добавленные отметки (которых нет в Clockster) — отдельными событиями.
    for item in overrides:
        key = (item['operator_id'], item['event_at'])
        if item['action'] != 'add' or key in consumed_overrides:
            continue
        events.append({
            'operator_id': item['operator_id'],
            'event_at': item['event_at'],
            'state_name': _state_for_kind(item.get('mark_kind') or 'in'),
            'state_note': 'clockster-manual',
        })

    if not events:
        return {
            "message": "Нет отметок по сотрудникам отдела продаж",
            "matched_events": 0,
            "unmatched_names_count": len(unmatched_counts),
        }
    summary = db.save_operator_status_import(
        events=events,
        segments=[],
        imported_by=None,
        summary={
            'source_rows': len(rows or []),
            'valid_events': len(events),
            'invalid_rows_count': sum(unmatched_counts.values()),
            'meta': {
                'api': 'clockster_attendance_sync',
                'source': 'clockster',
                'unmatched_names': sorted(unmatched_counts)[:30],
            },
        },
    )
    # «Приход» без парной отметки ухода закрываем сами (иначе статус «готов»
    # течёт в следующие сутки и тянет за собой несуществующие часы).
    auto_closed = db.normalize_attendance_marks(
        sorted({int(item['operator_id']) for item in events}), window_from, window_to
    )
    summary['unmatched_names_count'] = len(unmatched_counts)
    summary['auto_closed_marks'] = int(auto_closed.get('auto_closed') or 0)
    return summary


def _chat_metrics_parse_date(value, default_date=None):
    text = str(value or '').strip()
    if not text and default_date:
        text = str(default_date or '').strip()
    if not text:
        return None
    parsed_dt = _status_import_parse_datetime(text)
    if isinstance(parsed_dt, datetime):
        return parsed_dt.date()
    for fmt in ('%Y-%m-%d', '%d.%m.%Y', '%d/%m/%Y', '%Y/%m/%d'):
        try:
            return datetime.strptime(text, fmt).date()
        except Exception:
            continue
    return None


def _chat_metrics_parse_number(value):
    if value is None:
        return None
    text = str(value).strip().replace('\xa0', '').replace(' ', '')
    if not text:
        return None
    try:
        return float(text.replace(',', '.'))
    except Exception:
        return None


def _chat_metrics_parse_duration_seconds(value, unit_hint='seconds'):
    text = str(value or '').strip()
    if not text:
        return None
    if ':' in text:
        try:
            parts = [float(part.replace(',', '.')) for part in text.split(':')]
        except Exception:
            parts = []
        if len(parts) == 3:
            return parts[0] * 3600.0 + parts[1] * 60.0 + parts[2]
        if len(parts) == 2:
            return parts[0] * 60.0 + parts[1]
    value_num = _chat_metrics_parse_number(text)
    if value_num is None:
        return None
    hint = str(unit_hint or '').lower()
    if hint in ('minutes', 'minute', 'min'):
        return value_num * 60.0
    return value_num


def _chat_metrics_import_parse_csv(csv_text, operator_lookup, default_date=None, max_source_rows=None, invalid_rows_preview_limit=None):
    if not isinstance(csv_text, str):
        raise ValueError("CSV text is required")

    try:
        dialect = csv.Sniffer().sniff(csv_text[:4096], delimiters=';,\t')
    except Exception:
        dialect = csv.excel()
        dialect.delimiter = ';'

    reader = csv.reader(StringIO(csv_text), dialect)
    header = None
    for candidate_header in reader:
        if any(str(cell or '').strip() for cell in candidate_header):
            header = candidate_header
            break
    if not header:
        raise ValueError("Файл пустой")

    normalized_header = [_status_import_normalize_header(h) for h in header]

    def _find_col(candidates):
        for candidate in candidates:
            if candidate in normalized_header:
                return normalized_header.index(candidate)
        return None

    def _find_first_contains(tokens):
        for idx, header_key in enumerate(normalized_header):
            if all(token in header_key for token in tokens):
                return idx
        return None

    def _first_non_none(*values):
        for value in values:
            if value is not None:
                return value
        return None

    operator_col = _find_col([
        'operatorname', 'operator', 'name', 'employee', 'manager', 'agent', 'user',
        'fio', 'fullname', 'оператор', 'сотрудник', 'фио', 'имя', 'менеджер',
        'чатменеджер', 'чатменеджеры'
    ])
    date_col = _find_col(['date', 'day', 'period', 'дата', 'день', 'период'])
    chats_col = _find_col([
        'chats', 'chatscount', 'chatcount', 'totalchats', 'dialogs', 'dialogscount',
        'conversations', 'conversationcount', 'обращения', 'чаты', 'колвочатов',
        'количествочатов', 'диалоги', 'колводиалогов'
    ])
    if chats_col is None:
        chats_col = _first_non_none(_find_first_contains(['chat']), _find_first_contains(['чат']))
    avg_score_col = _find_col([
        'avgscore', 'averagescore', 'score', 'rating', 'avgrating',
        'средняяоценка', 'среднийбалл', 'оценка', 'рейтинг'
    ])
    avg_response_seconds_col = _find_col([
        'avgresponsetimeseconds', 'averageresponsetimeseconds', 'responsetimeseconds',
        'firstresponsetimeseconds', 'среднеевремяответасек', 'времяответасек'
    ])
    avg_response_minutes_col = _find_col([
        'avgresponsetimeminutes', 'averageresponsetimeminutes', 'responsetimeminutes',
        'firstresponsetimeminutes', 'среднеевремяответамин', 'времяответамин'
    ])
    avg_response_col = None
    avg_response_unit = 'seconds'
    if avg_response_seconds_col is not None:
        avg_response_col = avg_response_seconds_col
        avg_response_unit = 'seconds'
    elif avg_response_minutes_col is not None:
        avg_response_col = avg_response_minutes_col
        avg_response_unit = 'minutes'
    else:
        avg_response_col = _first_non_none(
            _find_col(['avgresponsetime', 'averageresponsetime', 'responsetime', 'firstresponsetime']),
            _find_first_contains(['ответ'])
        )
        if avg_response_col is not None:
            header_key = normalized_header[avg_response_col]
            avg_response_unit = 'minutes' if ('min' in header_key or 'мин' in header_key) else 'seconds'

    transfer_col = _find_col([
        'transferchat', 'transferchatcount', 'transfers', 'transfercount',
        'передачачата', 'передачичата', 'передачи', 'колвопередач'
    ])
    if transfer_col is None:
        transfer_col = _first_non_none(_find_first_contains(['transfer']), _find_first_contains(['передач']))

    if operator_col is None:
        raise ValueError("CSV должен содержать колонку оператора/менеджера")
    if date_col is None and not default_date:
        raise ValueError("CSV должен содержать колонку даты или параметр date=YYYY-MM-DD")
    if chats_col is None and avg_score_col is None and avg_response_col is None and transfer_col is None:
        raise ValueError("CSV должен содержать хотя бы одну метрику: чаты, оценка, время ответа или передачи")

    max_rows_value = None
    if max_source_rows is not None:
        try:
            max_rows_value = int(max_source_rows)
        except Exception:
            max_rows_value = None
        if max_rows_value is not None and max_rows_value <= 0:
            max_rows_value = None

    preview_limit_value = STATUS_IMPORT_INVALID_ROWS_PREVIEW_LIMIT
    if invalid_rows_preview_limit is not None:
        try:
            preview_limit_value = max(1, int(invalid_rows_preview_limit))
        except Exception:
            preview_limit_value = STATUS_IMPORT_INVALID_ROWS_PREVIEW_LIMIT

    def _cell(cols, idx):
        if idx is None or idx < 0 or idx >= len(cols):
            return ''
        return str(cols[idx] or '').strip()

    metrics = []
    source_rows = 0
    invalid_rows_count = 0
    invalid_rows_preview = []

    def _push_invalid(row_num, reason, operator_name, date_value):
        nonlocal invalid_rows_count
        invalid_rows_count += 1
        if len(invalid_rows_preview) >= preview_limit_value:
            return
        invalid_rows_preview.append({
            'row': int(row_num),
            'reason': str(reason or '').strip() or 'Некорректная строка',
            'operator_name': str(operator_name or '').strip(),
            'date': str(date_value or '').strip()
        })

    for row_num, cols in enumerate(reader, start=2):
        source_rows += 1
        if max_rows_value is not None and source_rows > max_rows_value:
            raise OverflowError(f"Лимит строк CSV превышен ({max_rows_value})")

        operator_name = _cell(cols, operator_col)
        date_value = _cell(cols, date_col)
        if not operator_name and not date_value and not any(str(cell or '').strip() for cell in cols):
            continue

        day_obj = _chat_metrics_parse_date(date_value, default_date=default_date)
        if not operator_name or day_obj is None:
            _push_invalid(row_num, 'Отсутствует оператор или дата', operator_name, date_value or default_date)
            continue

        operator_key = _status_import_normalize_operator_name(operator_name)
        operator_matches = operator_lookup.get(operator_key) or []
        if len(operator_matches) != 1:
            _push_invalid(
                row_num,
                'Оператор не найден' if len(operator_matches) == 0 else 'Найдено несколько операторов с таким именем',
                operator_name,
                date_value or default_date
            )
            continue

        chats_value = _chat_metrics_parse_number(_cell(cols, chats_col))
        transfer_value = _chat_metrics_parse_number(_cell(cols, transfer_col))
        avg_score_value = _chat_metrics_parse_number(_cell(cols, avg_score_col))
        avg_response_seconds = _chat_metrics_parse_duration_seconds(_cell(cols, avg_response_col), avg_response_unit)

        metrics.append({
            'operator_id': int(operator_matches[0]['id']),
            'operator_name': operator_matches[0].get('name') or operator_name,
            'day': day_obj.strftime('%Y-%m-%d'),
            'chats_count': int(round(chats_value or 0)),
            'avg_score': avg_score_value,
            'avg_response_time_seconds': avg_response_seconds,
            'transfer_chat_count': int(round(transfer_value or 0)),
            'source_row': int(row_num)
        })

    return {
        'source_rows': int(source_rows),
        'matched_rows': len(metrics),
        'invalid_rows_count': int(invalid_rows_count),
        'invalid_rows_preview': invalid_rows_preview,
        'metrics': metrics
    }


# ============================================================================
# Многоформатный импорт метрик чат-менеджеров. Тип отчёта определяется по набору
# колонок (на клиенте — для предпросмотра, на сервере — как источник истины):
#   score          — средняя оценка: operator_name, created_at, rating_scale_score
#                    → храним score_sum + score_count за день, среднее = sum/count
#   response_time  — время ответа: operator_name, request_start, reaction_time (сек)
#                    → дневное среднее (после фильтра «наплыва» по request_start)
#   whatsapp_chats — кол-во чатов: «ФИО создателя», «Дата и время обращения»,
#                    «Звонок или Чат» → считаем строки Whatsapp по дате обращения
#   name_requests  — кол-во чатов: Name, Requests → значение Requests на дату загрузки
# Каждый отчёт перезаписывает ТОЛЬКО свою метрику (частичный upsert).
# ============================================================================

CHAT_REPORT_TYPE_SCORE = 'score'
CHAT_REPORT_TYPE_RESPONSE = 'response_time'
CHAT_REPORT_TYPE_WHATSAPP = 'whatsapp_chats'
CHAT_REPORT_TYPE_NAME_REQUESTS = 'name_requests'
CHAT_REPORT_TYPE_COMBINED = 'combined'

CHAT_REPORT_TYPE_LABELS = {
    CHAT_REPORT_TYPE_SCORE: 'Средняя оценка',
    CHAT_REPORT_TYPE_RESPONSE: 'Среднее время ответа',
    CHAT_REPORT_TYPE_WHATSAPP: 'Количество чатов (Whatsapp)',
    CHAT_REPORT_TYPE_NAME_REQUESTS: 'Количество чатов (Name/Requests)',
    CHAT_REPORT_TYPE_COMBINED: 'Комбинированный отчёт',
}

CHAT_REPORT_TYPE_FIELDS = {
    CHAT_REPORT_TYPE_SCORE: {'score_sum', 'score_count', 'avg_score'},
    CHAT_REPORT_TYPE_RESPONSE: {'avg_response_time_seconds'},
    CHAT_REPORT_TYPE_WHATSAPP: {'whatsapp_chats_count'},
    CHAT_REPORT_TYPE_NAME_REQUESTS: {'name_requests_chats_count'},
}


def _chat_report_name_tokens(value):
    norm = _status_import_normalize_operator_name(value)
    return re.findall(r"[a-zа-яёәғқңөұүһі]+", norm, flags=re.IGNORECASE)


def _chat_report_build_operator_token_index():
    """[{id, name, tokens}] для фуззи-сопоставления (в т.ч. сокращённых имён Name/Requests)."""
    index = []
    for row in (db.get_all_operators() or []):
        try:
            op_id = int(row[0])
        except Exception:
            continue
        name = str(row[1] or '').strip()
        toks = _chat_report_name_tokens(name)
        if toks:
            index.append({'id': op_id, 'name': name, 'tokens': toks})
    return index


def _chat_report_tokens_match(report_tokens, op_tokens):
    """Каждый report-токен сопоставляется РАЗНОМУ op-токену (равен ИЛИ префикс op-токена).
    Покрывает сокращения: «Омар Идр» → оператор «Омар» + фамилия на «Идр…»."""
    if not report_tokens:
        return False
    used = [False] * len(op_tokens)

    def assign(i):
        if i == len(report_tokens):
            return True
        rt = report_tokens[i]
        order = sorted(range(len(op_tokens)), key=lambda j: 0 if op_tokens[j] == rt else 1)
        for j in order:
            if used[j]:
                continue
            if op_tokens[j] == rt or op_tokens[j].startswith(rt):
                used[j] = True
                if assign(i + 1):
                    return True
                used[j] = False
        return False

    return assign(0)


def _chat_report_resolve_operator(raw_name, operator_lookup, operator_token_index):
    """(operator_id, name) или (None, None). Сначала точный lookup (ловит перестановки ФИО),
    затем фуззи по токенам с префиксами (сокращения). Требует РОВНО одного кандидата."""
    name = str(raw_name or '').strip()
    if not name:
        return None, None
    key = _status_import_normalize_operator_name(name)
    matches = operator_lookup.get(key) or []
    if len(matches) == 1:
        return int(matches[0]['id']), (matches[0].get('name') or name)
    if len(matches) > 1:
        return None, None
    report_tokens = _chat_report_name_tokens(name)
    if not report_tokens:
        return None, None
    hits = [op for op in operator_token_index if _chat_report_tokens_match(report_tokens, op['tokens'])]
    uniq_ids = {op['id'] for op in hits}
    if len(uniq_ids) == 1:
        return int(hits[0]['id']), hits[0]['name']
    return None, None


def _chat_report_detect_types(normalized_header):
    nh = [str(h or '') for h in (normalized_header or [])]

    def has(sub):
        return any(sub in h for h in nh)

    detected = []
    if has('ratingscalescore') or (has('rating') and has('scale') and has('score')):
        detected.append(CHAT_REPORT_TYPE_SCORE)
    if has('reactiontime') and (has('requeststart') or has('requestend')):
        detected.append(CHAT_REPORT_TYPE_RESPONSE)
    if any(('звонок' in h and 'чат' in h) for h in nh):
        detected.append(CHAT_REPORT_TYPE_WHATSAPP)
    if not detected and has('requests') and has('name'):
        detected.append(CHAT_REPORT_TYPE_NAME_REQUESTS)
    return detected


def _chat_report_detect_type(normalized_header):
    report_types = _chat_report_detect_types(normalized_header)
    if len(report_types) > 1:
        return CHAT_REPORT_TYPE_COMBINED
    return report_types[0] if report_types else None


def _chat_report_parse_dt(value):
    text = str(value or '').strip()
    if not text:
        return None
    try:
        return datetime.fromisoformat(text)
    except Exception:
        pass
    return _status_import_parse_datetime(text)


def _chat_report_parse_surge_windows(raw):
    """raw: JSON-строка или список {start,end} (ISO datetime). → [(start_dt, end_dt)]."""
    if not raw:
        return []
    data = raw
    if isinstance(raw, str):
        try:
            data = json.loads(raw)
        except Exception:
            return []
    windows = []
    for item in (data or []):
        if not isinstance(item, dict):
            continue
        start_dt = _chat_report_parse_dt(item.get('start'))
        end_dt = _chat_report_parse_dt(item.get('end'))
        if start_dt is not None and end_dt is not None:
            if end_dt < start_dt:
                start_dt, end_dt = end_dt, start_dt
            windows.append((start_dt, end_dt))
    return windows


def _chat_report_in_surge(dt_value, windows):
    if dt_value is None or not windows:
        return False
    return any(start <= dt_value <= end for start, end in windows)


def _chat_report_rows_from_bytes(raw_bytes, filename):
    """(header, data_rows) из CSV или XLSX. header/строки — списки строк."""
    name = str(filename or '').lower()
    if name.endswith('.xlsx') or name.endswith('.xlsm'):
        rows = _status_import_xlsx_rows(raw_bytes)
    else:
        csv_text = None
        for enc in ('utf-8-sig', 'cp1251'):
            try:
                csv_text = raw_bytes.decode(enc)
                break
            except Exception:
                continue
        if csv_text is None:
            raise ValueError("Не удалось декодировать файл (ожидается UTF-8 или CP1251)")
        try:
            dialect = csv.Sniffer().sniff(csv_text[:4096], delimiters=';,\t')
        except Exception:
            dialect = csv.excel()
            dialect.delimiter = ';'
        rows = [list(r) for r in csv.reader(StringIO(csv_text), dialect)]
    header = None
    data_rows = []
    for r in rows:
        if header is None:
            if any(str(c or '').strip() for c in r):
                header = [str(c or '').strip() for c in r]
            continue
        data_rows.append(r)
    if not header:
        raise ValueError("Файл пустой")
    return header, data_rows


def _chat_report_parse(header, data_rows, operator_lookup, operator_token_index,
                       default_date=None, surge_windows=None, preview_limit=None):
    """Определяет тип отчёта по колонкам и считает дневные метрики. Возвращает None,
    если формат не распознан (тогда вызывающий откатывается к универсальному парсеру)."""
    normalized_header = [_status_import_normalize_header(h) for h in (header or [])]
    report_types = _chat_report_detect_types(normalized_header)
    if not report_types:
        return None
    report_type = report_types[0] if len(report_types) == 1 else CHAT_REPORT_TYPE_COMBINED

    def find_idx(*candidates):
        for cand in candidates:
            for i, h in enumerate(normalized_header):
                if h == cand:
                    return i
        for cand in candidates:
            for i, h in enumerate(normalized_header):
                if cand in h:
                    return i
        return None

    def find_contains_all(tokens):
        for i, h in enumerate(normalized_header):
            if all(t in h for t in tokens):
                return i
        return None

    def cell(cols, idx):
        if idx is None or idx < 0 or idx >= len(cols):
            return ''
        return str(cols[idx] or '').strip()

    preview_limit_value = STATUS_IMPORT_INVALID_ROWS_PREVIEW_LIMIT
    if preview_limit is not None:
        try:
            preview_limit_value = max(1, int(preview_limit))
        except Exception:
            preview_limit_value = STATUS_IMPORT_INVALID_ROWS_PREVIEW_LIMIT

    unmatched_names = {}
    unmatched_seen = set()

    def note_unmatched(raw, row_index=None):
        key = str(raw or '').strip() or '(пусто)'
        seen_key = (key, row_index) if row_index is not None else None
        if seen_key is not None:
            if seen_key in unmatched_seen:
                return
            unmatched_seen.add(seen_key)
        unmatched_names[key] = unmatched_names.get(key, 0) + 1

    def nonempty(cols):
        return any(str(c or '').strip() for c in cols)

    source_rows = sum(1 for cols in (data_rows or []) if nonempty(cols))
    metrics_by_key = {}
    update_fields = set()
    excluded_surge = None

    def metric_for(op_id, day_str):
        return metrics_by_key.setdefault((op_id, day_str), {
            'operator_id': op_id,
            'day': day_str,
        })

    if CHAT_REPORT_TYPE_SCORE in report_types:
        op_idx = find_idx('operatorname', 'operator', 'fio', 'фио', 'оператор', 'имя')
        date_idx = find_idx('createdat', 'дата', 'date', 'day')
        if date_idx is None:
            date_idx = find_contains_all(['creat'])
        score_idx = find_idx('ratingscalescore')
        if score_idx is None:
            score_idx = find_contains_all(['scale', 'score'])
        if op_idx is None or score_idx is None:
            raise ValueError("Отчёт оценок: нужны колонки оператора и rating_scale_score")
        score_agg = {}
        for row_index, cols in enumerate(data_rows or []):
            if not nonempty(cols):
                continue
            raw_name = cell(cols, op_idx)
            day = _chat_metrics_parse_date(cell(cols, date_idx), default_date=default_date)
            score = _chat_metrics_parse_number(cell(cols, score_idx))
            if not raw_name or day is None or score is None:
                if raw_name:
                    note_unmatched(raw_name, row_index)
                continue
            op_id, _ = _chat_report_resolve_operator(raw_name, operator_lookup, operator_token_index)
            if op_id is None:
                note_unmatched(raw_name, row_index)
                continue
            bucket = score_agg.setdefault((op_id, day.strftime('%Y-%m-%d')), {'score_sum': 0.0, 'score_count': 0})
            bucket['score_sum'] += float(score)
            bucket['score_count'] += 1
        for (op_id, day_str), v in score_agg.items():
            metric = metric_for(op_id, day_str)
            metric['score_sum'] = round(v['score_sum'], 4)
            metric['score_count'] = int(v['score_count'])
            metric['avg_score'] = round(v['score_sum'] / v['score_count'], 4) if v['score_count'] else None
        update_fields.update(CHAT_REPORT_TYPE_FIELDS[CHAT_REPORT_TYPE_SCORE])

    if CHAT_REPORT_TYPE_RESPONSE in report_types:
        op_idx = find_idx('operatorname', 'operator', 'fio', 'фио', 'оператор')
        start_idx = find_idx('requeststart')
        if start_idx is None:
            start_idx = find_contains_all(['request', 'start'])
        rt_idx = find_idx('reactiontime')
        if rt_idx is None:
            rt_idx = find_contains_all(['reaction'])
        if op_idx is None or start_idx is None or rt_idx is None:
            raise ValueError("Отчёт времени ответа: нужны operator_name, request_start, reaction_time")
        windows = _chat_report_parse_surge_windows(surge_windows)
        excluded_surge = 0
        response_agg = {}
        for row_index, cols in enumerate(data_rows or []):
            if not nonempty(cols):
                continue
            raw_name = cell(cols, op_idx)
            start_dt = _chat_report_parse_dt(cell(cols, start_idx))
            reaction = _chat_metrics_parse_number(cell(cols, rt_idx))
            if not raw_name or start_dt is None or reaction is None:
                if raw_name:
                    note_unmatched(raw_name, row_index)
                continue
            if _chat_report_in_surge(start_dt, windows):
                excluded_surge += 1
                continue
            op_id, _ = _chat_report_resolve_operator(raw_name, operator_lookup, operator_token_index)
            if op_id is None:
                note_unmatched(raw_name, row_index)
                continue
            bucket = response_agg.setdefault((op_id, start_dt.date().strftime('%Y-%m-%d')), {'sum': 0.0, 'count': 0})
            bucket['sum'] += float(reaction)
            bucket['count'] += 1
        for (op_id, day_str), v in response_agg.items():
            if v['count'] <= 0:
                continue
            metric = metric_for(op_id, day_str)
            metric['avg_response_time_seconds'] = round(v['sum'] / v['count'], 2)
        update_fields.update(CHAT_REPORT_TYPE_FIELDS[CHAT_REPORT_TYPE_RESPONSE])

    if CHAT_REPORT_TYPE_WHATSAPP in report_types:
        op_idx = find_contains_all(['создател'])
        if op_idx is None:
            op_idx = find_idx('фиосоздателя', 'operatorname', 'operator', 'fio', 'фио')
        date_idx = find_contains_all(['обращени'])
        if date_idx is None:
            date_idx = find_idx('дата', 'date', 'day')
        if date_idx is None:
            date_idx = find_contains_all(['создан'])
        chan_idx = None
        for i, h in enumerate(normalized_header):
            if 'звонок' in h and 'чат' in h:
                chan_idx = i
                break
        if op_idx is None or chan_idx is None:
            raise ValueError("Отчёт чатов: нужны «ФИО создателя» и «Звонок или Чат»")
        whatsapp_agg = {}
        for row_index, cols in enumerate(data_rows or []):
            if not nonempty(cols):
                continue
            channel = _status_import_normalize_header(cell(cols, chan_idx))
            if 'whatsapp' not in channel:
                continue  # считаем только Whatsapp
            raw_name = cell(cols, op_idx)
            day = _chat_metrics_parse_date(cell(cols, date_idx), default_date=default_date)
            if not raw_name or day is None:
                if raw_name:
                    note_unmatched(raw_name, row_index)
                continue
            op_id, _ = _chat_report_resolve_operator(raw_name, operator_lookup, operator_token_index)
            if op_id is None:
                note_unmatched(raw_name, row_index)
                continue
            bucket = whatsapp_agg.setdefault((op_id, day.strftime('%Y-%m-%d')), {'chats': 0})
            bucket['chats'] += 1
        for (op_id, day_str), v in whatsapp_agg.items():
            metric = metric_for(op_id, day_str)
            metric['chats_count'] = int(v['chats'])
            metric['whatsapp_chats_count'] = int(v['chats'])
            if report_type == CHAT_REPORT_TYPE_WHATSAPP:
                metric['source_report_type'] = CHAT_REPORT_TYPE_WHATSAPP
        update_fields.update(CHAT_REPORT_TYPE_FIELDS[CHAT_REPORT_TYPE_WHATSAPP])

    if CHAT_REPORT_TYPE_NAME_REQUESTS in report_types:
        day = _chat_metrics_parse_date(None, default_date=default_date)
        if day is None:
            raise ValueError("Для отчёта Name/Requests укажите дату загрузки (date=YYYY-MM-DD)")
        name_idx = find_idx('name', 'имя', 'оператор', 'fio', 'фио')
        req_idx = find_idx('requests', 'request')
        if req_idx is None:
            req_idx = find_contains_all(['request']) or find_idx('чаты', 'count', 'колво')
        if name_idx is None or req_idx is None:
            raise ValueError("Отчёт Name/Requests: нужны колонки Name и Requests")
        day_str = day.strftime('%Y-%m-%d')
        name_agg = {}
        for row_index, cols in enumerate(data_rows or []):
            if not nonempty(cols):
                continue
            raw_name = cell(cols, name_idx)
            requests_val = _chat_metrics_parse_number(cell(cols, req_idx))
            if not raw_name or requests_val is None:
                if raw_name:
                    note_unmatched(raw_name, row_index)
                continue
            op_id, _ = _chat_report_resolve_operator(raw_name, operator_lookup, operator_token_index)
            if op_id is None:
                note_unmatched(raw_name, row_index)
                continue
            bucket = name_agg.setdefault((op_id, day_str), {'chats': 0})
            bucket['chats'] += int(round(requests_val))
        for (op_id, day_key), v in name_agg.items():
            metric = metric_for(op_id, day_key)
            metric['chats_count'] = int(v['chats'])
            metric['name_requests_chats_count'] = int(v['chats'])
            if report_type == CHAT_REPORT_TYPE_NAME_REQUESTS:
                metric['source_report_type'] = CHAT_REPORT_TYPE_NAME_REQUESTS
        update_fields.update(CHAT_REPORT_TYPE_FIELDS[CHAT_REPORT_TYPE_NAME_REQUESTS])

    metrics = sorted(metrics_by_key.values(), key=lambda item: (item.get('day') or '', int(item.get('operator_id') or 0)))
    unmatched_sorted = sorted(unmatched_names.items(), key=lambda kv: (-kv[1], kv[0]))
    if report_type == CHAT_REPORT_TYPE_COMBINED:
        detected_label = 'Комбинированный отчёт: ' + ', '.join(
            CHAT_REPORT_TYPE_LABELS.get(t, t) for t in report_types
        )
    else:
        detected_label = CHAT_REPORT_TYPE_LABELS.get(report_type, report_type)
    result = {
        'detected_type': report_type,
        'detected_label': detected_label,
        'detected_types': report_types,
        'update_fields': sorted(update_fields),
        'metrics': metrics,
        'source_rows': int(source_rows),
        'matched_rows': len(metrics),
        'unmatched_count': int(sum(unmatched_names.values())),
        'unmatched_preview': [{'name': name, 'rows': count} for name, count in unmatched_sorted[:preview_limit_value]],
    }
    if excluded_surge is not None:
        result['excluded_surge_rows'] = int(excluded_surge)
    return result


CHAT2DESK_STATISTICS_REPORT_REPLIES = 'operator_replies'
CHAT2DESK_STATISTICS_REPORT_REQUEST_STATS = 'request_stats'
CHAT2DESK_STATISTICS_REPORT_RATING = 'rating'
CHAT2DESK_STATISTICS_REPORT_OPERATOR_STATS = 'operator_stats'
CHAT2DESK_STATISTICS_REPORT_OPERATOR_EVENTS = 'operator_events'


def _chat2desk_api_token():
    token = (os.getenv('CHAT2DESK_API_TOKEN') or CHAT2DESK_API_TOKEN or '').strip()
    if not token:
        return ''
    token = token.strip().strip('"').strip("'").strip()
    if token.lower().startswith('authorization:'):
        token = token.split(':', 1)[1].strip()
    if token.lower().startswith('bearer '):
        token = token[7:].strip()
    return token.strip().strip('"').strip("'").strip()


def _chat2desk_authorization_header():
    token = _chat2desk_api_token()
    if not token:
        return ''
    scheme = (os.getenv('CHAT2DESK_AUTH_SCHEME') or CHAT2DESK_AUTH_SCHEME or 'raw').strip()
    if not scheme or scheme.lower() in {'raw', 'none', 'token'}:
        return token
    if scheme.lower() == 'bearer':
        return f"Bearer {token}"
    return f"{scheme} {token}".strip()


def _chat2desk_api_base_url():
    return (os.getenv('CHAT2DESK_API_BASE_URL') or CHAT2DESK_API_BASE_URL or 'https://api-02.chat2desk.kz').strip().rstrip('/')


def _chat2desk_sync_enabled():
    return _env_bool('CHAT2DESK_SYNC_ENABLED', CHAT2DESK_SYNC_ENABLED)


def _chat2desk_status_sync_enabled():
    return _env_bool('CHAT2DESK_STATUS_SYNC_ENABLED', CHAT2DESK_STATUS_SYNC_ENABLED)


def _chat2desk_sync_timezone():
    tz_name = (os.getenv('CHAT2DESK_SYNC_TIMEZONE') or CHAT2DESK_SYNC_TIMEZONE or 'Asia/Almaty').strip() or 'Asia/Almaty'
    try:
        return ZoneInfo(tz_name)
    except Exception:
        logging.warning("Invalid CHAT2DESK_SYNC_TIMEZONE=%s, fallback to Asia/Almaty", tz_name)
        return ZoneInfo('Asia/Almaty')


def _chat2desk_parse_datetime(value, target_tz=None):
    if value in (None, ''):
        return None
    if isinstance(value, datetime):
        parsed = value
    elif isinstance(value, (int, float)):
        try:
            parsed = datetime.fromtimestamp(value, tz=target_tz or _chat2desk_sync_timezone())
        except Exception:
            return None
    else:
        text = str(value or '').strip()
        if not text:
            return None
        parsed = None
        try:
            parsed = datetime.fromisoformat(text.replace('Z', '+00:00'))
        except Exception:
            parsed = _chat_report_parse_dt(text)
        if parsed is None:
            return None

    if getattr(parsed, 'tzinfo', None) is not None:
        try:
            parsed = parsed.astimezone(target_tz or _chat2desk_sync_timezone())
        except Exception:
            pass
        parsed = parsed.replace(tzinfo=None)
    return parsed


def _chat2desk_metric_day(value, default_day, target_tz=None):
    parsed = _chat2desk_parse_datetime(value, target_tz=target_tz)
    if isinstance(parsed, datetime):
        return parsed.date().strftime('%Y-%m-%d')
    day = _chat_metrics_parse_date(default_day)
    return day.strftime('%Y-%m-%d') if day else None


def _chat2desk_row_first(row, *keys):
    if not isinstance(row, dict):
        return None
    for key in keys:
        if key in row and row.get(key) not in (None, ''):
            return row.get(key)
    lower_map = {
        str(k).strip().lower(): v
        for k, v in row.items()
        if v not in (None, '')
    }
    for key in keys:
        value = lower_map.get(str(key).strip().lower())
        if value not in (None, ''):
            return value
    return None


def _chat2desk_row_is_nonempty(row):
    if isinstance(row, dict):
        return any(str(value or '').strip() for value in row.values())
    return bool(row)


def _chat2desk_extract_response_rows(payload):
    if isinstance(payload, list):
        return payload
    if not isinstance(payload, dict):
        return []
    for key in ('data', 'statistics', 'items', 'result', 'results'):
        value = payload.get(key)
        if isinstance(value, list):
            return value
    return []


def _chat2desk_extract_total(payload):
    if not isinstance(payload, dict):
        return None
    candidates = []
    for container_key in ('meta', 'pagination'):
        container = payload.get(container_key)
        if isinstance(container, dict):
            candidates.extend([container.get('total'), container.get('total_count'), container.get('count')])
    candidates.extend([payload.get('total'), payload.get('total_count')])
    for raw in candidates:
        try:
            value = int(raw)
            if value >= 0:
                return value
        except Exception:
            continue
    return None


def _chat2desk_api_error_message(response, report, day_str):
    status_code = getattr(response, 'status_code', None)
    raw_text = str(getattr(response, 'text', '') or '').strip()
    payload = None
    try:
        payload = response.json()
    except Exception:
        payload = None

    detail_parts = []
    if isinstance(payload, dict):
        for key in ('message', 'errors', 'error'):
            value = payload.get(key)
            if value not in (None, ''):
                detail_parts.append(str(value))
    if not detail_parts and raw_text:
        detail_parts.append(raw_text)
    detail = '; '.join(detail_parts).strip()
    detail_lower = detail.lower()

    if int(status_code or 0) == 403 and 'token' in detail_lower:
        return (
            f"Chat2Desk отклонил CHAT2DESK_API_TOKEN для отчёта {report} за {day_str}. "
            "Проверьте, что в env указан API Token из Chat2Desk без лишних символов и что токен активен."
        )

    if len(detail) > 500:
        detail = detail[:500] + '...'
    suffix = f": {detail}" if detail else ''
    return f"Chat2Desk statistics {report} {day_str} failed: HTTP {status_code}{suffix}"


def _chat2desk_statistics_get(report, day_str, max_pages=None):
    authorization = _chat2desk_authorization_header()
    if not authorization:
        raise RuntimeError("CHAT2DESK_API_TOKEN is not set")

    limit = _env_int('CHAT2DESK_API_PAGE_LIMIT', CHAT2DESK_API_PAGE_LIMIT, minimum=1, maximum=200)
    timeout = _env_int('CHAT2DESK_API_TIMEOUT_SECONDS', CHAT2DESK_API_TIMEOUT_SECONDS, minimum=5, maximum=300)
    url = f"{_chat2desk_api_base_url()}/v1/statistics"
    headers = {
        'Authorization': authorization,
        'Accept': 'application/json',
    }

    rows = []
    offset = 0
    # max_pages=None — поведение по умолчанию (как было, потолок 1000). Явный max_pages
    # позволяет вызывающему листать день целиком (потолок 10000) — нужно для отчётов,
    # где обрезка самых старых строк искажает данные (см. operator_events). Естественный
    # выход по короткой странице/total ниже всё равно останавливает раньше потолка.
    if max_pages is None:
        max_pages = _env_int('CHAT2DESK_API_MAX_PAGES', CHAT2DESK_API_MAX_PAGES, minimum=1, maximum=1000)
    else:
        try:
            max_pages = max(1, min(int(max_pages), 10000))
        except Exception:
            max_pages = _env_int('CHAT2DESK_API_MAX_PAGES', CHAT2DESK_API_MAX_PAGES, minimum=1, maximum=1000)
    for _page_number in range(max_pages):
        params = {
            'report': report,
            'date': day_str,
            'limit': limit,
            'offset': offset,
        }
        response = requests.get(url, headers=headers, params=params, timeout=timeout)
        if response.status_code >= 400:
            raise RuntimeError(_chat2desk_api_error_message(response, report, day_str))
        try:
            payload = response.json()
        except Exception as exc:
            raise RuntimeError(f"Chat2Desk statistics {report} {day_str} returned invalid JSON") from exc

        page_rows = _chat2desk_extract_response_rows(payload)
        if not page_rows:
            break
        rows.extend(page_rows)

        total = _chat2desk_extract_total(payload)
        offset += len(page_rows)
        if len(page_rows) < limit:
            break
        if total is not None and offset >= total:
            break
    else:
        logging.warning(
            "Chat2Desk statistics %s %s stopped after CHAT2DESK_API_MAX_PAGES=%s",
            report,
            day_str,
            max_pages
        )

    return rows


def _chat2desk_operator_display_name(operator_payload):
    if not isinstance(operator_payload, dict):
        return ''
    first_name = str(operator_payload.get('first_name') or '').strip()
    last_name = str(operator_payload.get('last_name') or '').strip()
    full_name = ' '.join(part for part in (first_name, last_name) if part).strip()
    if full_name:
        return full_name
    return str(operator_payload.get('name') or operator_payload.get('email') or '').strip()


def _chat2desk_operator_by_id(operator_id):
    operator_key = str(operator_id or '').strip()
    if not operator_key:
        return None
    if operator_key in CHAT2DESK_OPERATOR_LOOKUP_CACHE:
        return CHAT2DESK_OPERATOR_LOOKUP_CACHE[operator_key]

    authorization = _chat2desk_authorization_header()
    if not authorization:
        CHAT2DESK_OPERATOR_LOOKUP_CACHE[operator_key] = None
        return None

    timeout = _env_int('CHAT2DESK_API_TIMEOUT_SECONDS', CHAT2DESK_API_TIMEOUT_SECONDS, minimum=5, maximum=300)
    url = f"{_chat2desk_api_base_url()}/v1/operators/{operator_key}"
    try:
        response = requests.get(
            url,
            headers={'Authorization': authorization, 'Accept': 'application/json'},
            timeout=timeout
        )
        if response.status_code >= 400:
            logging.warning("Chat2Desk operator lookup %s failed: HTTP %s", operator_key, response.status_code)
            CHAT2DESK_OPERATOR_LOOKUP_CACHE[operator_key] = None
            return None
        payload = response.json()
    except Exception:
        logging.exception("Chat2Desk operator lookup %s failed", operator_key)
        CHAT2DESK_OPERATOR_LOOKUP_CACHE[operator_key] = None
        return None

    data = payload.get('data') if isinstance(payload, dict) else None
    if not isinstance(data, dict):
        data = payload if isinstance(payload, dict) else None
    CHAT2DESK_OPERATOR_LOOKUP_CACHE[operator_key] = data
    return data


def _chat2desk_rating_operator_name(row):
    raw_name = _chat2desk_row_first(row, 'operator_name', 'score_operator_name', 'operator', 'name')
    if str(raw_name or '').strip():
        return str(raw_name or '').strip()
    operator_id = _chat2desk_row_first(row, 'operator_id')
    operator_payload = _chat2desk_operator_by_id(operator_id)
    return _chat2desk_operator_display_name(operator_payload)


def _chat2desk_rating_source_key(row, metric_day, score):
    parts = [
        _chat2desk_row_first(row, 'rating_id'),
        _chat2desk_row_first(row, 'valuation_request_id'),
        _chat2desk_row_first(row, 'request_id'),
        _chat2desk_row_first(row, 'operator_id'),
        _chat2desk_row_first(row, 'created_at', 'request_start', 'date') or metric_day,
        score,
    ]
    seed = '|'.join(str(part or '').strip() for part in parts)
    if not seed.strip('|'):
        seed = json.dumps(row, ensure_ascii=False, sort_keys=True, default=str)
    return uuid.uuid5(uuid.NAMESPACE_URL, f"chat2desk-rating:{seed}").hex


def _chat2desk_low_rating_payload(row, op_id, operator_name, metric_day, score):
    created_at_value = _chat2desk_row_first(row, 'created_at', 'request_start', 'date')
    return {
        'source': 'chat2desk_rating',
        'source_key': _chat2desk_rating_source_key(row, metric_day, score),
        'operator_id': int(op_id),
        'operator_name': operator_name,
        'phone_number': _chat2desk_row_first(row, 'phone'),
        'taxi_park': _chat2desk_row_first(row, 'channel_name'),
        'rated_at': created_at_value,
        'day': metric_day,
        'score': float(score),
        'raw_payload': dict(row),
    }


def _chat2desk_build_metrics_from_statistics_rows(day_str, reply_rows, rating_rows,
                                                  operator_lookup, operator_token_index,
                                                  operator_stats_rows=None,
                                                  surge_windows=None, preview_limit=None,
                                                  request_stats_rows=None):
    preview_limit_value = STATUS_IMPORT_INVALID_ROWS_PREVIEW_LIMIT
    if preview_limit is not None:
        try:
            preview_limit_value = max(1, int(preview_limit))
        except Exception:
            preview_limit_value = STATUS_IMPORT_INVALID_ROWS_PREVIEW_LIMIT

    target_tz = _chat2desk_sync_timezone()
    windows = _chat_report_parse_surge_windows(surge_windows)
    # Время ответа считаем по отчёту request_stats (одна строка на заявку, привязана
    # к фактическому обработчику с настоящим reaction_time). operator_replies для этого
    # непригоден: он даёт строку на каждый сегмент оператора и меряет reaction_time от
    # исходного прихода заявки, поэтому переданная/подхваченная позже заявка вешает на
    # оператора многочасовой «ответ» и завышает среднее в десятки раз. Если request_stats
    # не передан (старые вызовы/тесты) — откатываемся на reply_rows.
    using_request_stats = request_stats_rows is not None
    response_source_rows = request_stats_rows if using_request_stats else reply_rows
    metrics_by_key = {}
    unmatched_names = {}
    unmatched_seen = set()
    excluded_surge = 0
    low_ratings = []
    source_rows = sum(1 for row in (response_source_rows or []) if _chat2desk_row_is_nonempty(row))
    source_rows += sum(1 for row in (rating_rows or []) if _chat2desk_row_is_nonempty(row))
    source_rows += sum(1 for row in (operator_stats_rows or []) if _chat2desk_row_is_nonempty(row))

    def metric_for(op_id, metric_day):
        return metrics_by_key.setdefault((int(op_id), metric_day), {
            'operator_id': int(op_id),
            'day': metric_day,
        })

    def note_unmatched(raw, row_key=None):
        key = str(raw or '').strip() or '(empty)'
        seen_key = (key, row_key) if row_key is not None else None
        if seen_key is not None:
            if seen_key in unmatched_seen:
                return
            unmatched_seen.add(seen_key)
        unmatched_names[key] = unmatched_names.get(key, 0) + 1

    response_agg = {}
    for row_index, row in enumerate(response_source_rows or []):
        if not isinstance(row, dict) or not _chat2desk_row_is_nonempty(row):
            continue
        raw_name = _chat2desk_row_first(row, 'operator_name', 'operator', 'name')
        start_value = _chat2desk_row_first(row, 'request_start', 'reply_start', 'created_at')
        start_dt = _chat2desk_parse_datetime(start_value, target_tz=target_tz)
        # Только reaction_time: так же, как считает веб-отчёт request_stats. На working_reaction_time
        # не откатываемся — иначе в среднее попадут строки, которых нет в отчёте-эталоне.
        reaction = _chat_metrics_parse_number(_chat2desk_row_first(row, 'reaction_time'))
        if not raw_name or start_dt is None or reaction is None:
            if raw_name:
                note_unmatched(raw_name, f"response:{row_index}")
            continue
        if _chat_report_in_surge(start_dt, windows):
            excluded_surge += 1
            continue
        op_id, _ = _chat_report_resolve_operator(raw_name, operator_lookup, operator_token_index)
        if op_id is None:
            note_unmatched(raw_name, f"response:{row_index}")
            continue
        metric_day = start_dt.date().strftime('%Y-%m-%d')
        bucket = response_agg.setdefault((op_id, metric_day), {'sum': 0.0, 'count': 0})
        bucket['sum'] += float(reaction)
        bucket['count'] += 1

    score_agg = {}
    for row_index, row in enumerate(rating_rows or []):
        if not isinstance(row, dict) or not _chat2desk_row_is_nonempty(row):
            continue
        raw_name = _chat2desk_rating_operator_name(row)
        score = _chat_metrics_parse_number(_chat2desk_row_first(row, 'rating_scale_score', 'score', 'rating'))
        metric_day = _chat2desk_metric_day(
            _chat2desk_row_first(row, 'created_at', 'request_start', 'date'),
            day_str,
            target_tz=target_tz
        )
        if not raw_name or score is None or not metric_day:
            if raw_name:
                note_unmatched(raw_name, f"rating:{row_index}")
            continue
        op_id, _ = _chat_report_resolve_operator(raw_name, operator_lookup, operator_token_index)
        if op_id is None:
            note_unmatched(raw_name, f"rating:{row_index}")
            continue
        bucket = score_agg.setdefault((op_id, metric_day), {'score_sum': 0.0, 'score_count': 0})
        bucket['score_sum'] += float(score)
        bucket['score_count'] += 1
        if float(score) < 4:
            low_ratings.append(_chat2desk_low_rating_payload(row, op_id, raw_name, metric_day, score))

    chat_count_agg = {}
    for row_index, row in enumerate(operator_stats_rows or []):
        if not isinstance(row, dict) or not _chat2desk_row_is_nonempty(row):
            continue
        raw_name = _chat2desk_row_first(row, 'operator_name', 'operator', 'name')
        chats_value = _chat_metrics_parse_number(_chat2desk_row_first(row, 'requests_took_part'))
        metric_day = _chat2desk_metric_day(
            _chat2desk_row_first(row, 'date', 'created_at'),
            day_str,
            target_tz=target_tz
        )
        if not raw_name or chats_value is None or not metric_day:
            if raw_name:
                note_unmatched(raw_name, f"operator_stats:{row_index}")
            continue
        op_id, _ = _chat_report_resolve_operator(raw_name, operator_lookup, operator_token_index)
        if op_id is None:
            note_unmatched(raw_name, f"operator_stats:{row_index}")
            continue
        bucket = chat_count_agg.setdefault((op_id, metric_day), {'chats_count': 0})
        bucket['chats_count'] += int(round(chats_value))

    update_fields = set()
    for (op_id, metric_day), bucket in chat_count_agg.items():
        metric = metric_for(op_id, metric_day)
        metric['chats_count'] = int(bucket.get('chats_count') or 0)
    if chat_count_agg:
        update_fields.add('chats_count')

    response_metric_keys = set()
    for (op_id, metric_day), bucket in response_agg.items():
        if bucket['count'] <= 0:
            continue
        metric = metric_for(op_id, metric_day)
        metric['avg_response_time_seconds'] = round(bucket['sum'] / bucket['count'], 2)
        response_metric_keys.add((op_id, metric_day))
    if using_request_stats:
        # request_stats is authoritative for response time. If an operator is present in
        # operator_stats for the day but has no valid reaction_time in request_stats, the
        # stored response time must be cleared instead of preserving an older import.
        for op_id, metric_day in chat_count_agg.keys():
            if (op_id, metric_day) not in response_metric_keys:
                metric = metric_for(op_id, metric_day)
                metric['avg_response_time_seconds'] = None
        update_fields.update(CHAT_REPORT_TYPE_FIELDS[CHAT_REPORT_TYPE_RESPONSE])
    elif response_agg:
        update_fields.update(CHAT_REPORT_TYPE_FIELDS[CHAT_REPORT_TYPE_RESPONSE])

    for (op_id, metric_day), bucket in score_agg.items():
        if bucket['score_count'] <= 0:
            continue
        metric = metric_for(op_id, metric_day)
        metric['score_sum'] = round(bucket['score_sum'], 4)
        metric['score_count'] = int(bucket['score_count'])
        metric['avg_score'] = round(bucket['score_sum'] / bucket['score_count'], 4)
    if score_agg:
        update_fields.update(CHAT_REPORT_TYPE_FIELDS[CHAT_REPORT_TYPE_SCORE])

    detected_parts = []
    if chat_count_agg:
        detected_parts.append('chats_count')
    if response_agg:
        detected_parts.append(CHAT_REPORT_TYPE_RESPONSE)
    if score_agg:
        detected_parts.append(CHAT_REPORT_TYPE_SCORE)

    if len(detected_parts) > 1:
        detected_type = CHAT_REPORT_TYPE_COMBINED
        detected_types = detected_parts
        detected_label_parts = [
            'Кол-во чатов' if t == 'chats_count' else CHAT_REPORT_TYPE_LABELS[t]
            for t in detected_types
        ]
        detected_label = 'Chat2Desk API: ' + ', '.join(detected_label_parts)
    elif chat_count_agg:
        detected_type = 'chats_count'
        detected_types = ['chats_count']
        detected_label = 'Chat2Desk API: Кол-во чатов'
    elif response_agg:
        detected_type = CHAT_REPORT_TYPE_RESPONSE
        detected_types = [CHAT_REPORT_TYPE_RESPONSE]
        detected_label = f"Chat2Desk API: {CHAT_REPORT_TYPE_LABELS[CHAT_REPORT_TYPE_RESPONSE]}"
    elif score_agg:
        detected_type = CHAT_REPORT_TYPE_SCORE
        detected_types = [CHAT_REPORT_TYPE_SCORE]
        detected_label = f"Chat2Desk API: {CHAT_REPORT_TYPE_LABELS[CHAT_REPORT_TYPE_SCORE]}"
    else:
        detected_type = CHAT_REPORT_TYPE_COMBINED
        detected_types = []
        detected_label = 'Chat2Desk API'

    metrics = sorted(metrics_by_key.values(), key=lambda item: (item.get('day') or '', int(item.get('operator_id') or 0)))
    unmatched_sorted = sorted(unmatched_names.items(), key=lambda kv: (-kv[1], kv[0]))
    return {
        'detected_type': detected_type,
        'detected_label': detected_label,
        'detected_types': detected_types,
        'update_fields': sorted(update_fields),
        'metrics': metrics,
        'source_rows': int(source_rows),
        'matched_rows': len(metrics),
        'unmatched_count': int(sum(unmatched_names.values())),
        'unmatched_preview': [{'name': name, 'rows': count} for name, count in unmatched_sorted[:preview_limit_value]],
        'low_ratings': low_ratings,
        'low_rating_count': len(low_ratings),
        'excluded_surge_rows': int(excluded_surge),
        'api_rows': {
            CHAT2DESK_STATISTICS_REPORT_REPLIES: len(reply_rows or []),
            CHAT2DESK_STATISTICS_REPORT_REQUEST_STATS: len(request_stats_rows or []),
            CHAT2DESK_STATISTICS_REPORT_RATING: len(rating_rows or []),
            CHAT2DESK_STATISTICS_REPORT_OPERATOR_STATS: len(operator_stats_rows or []),
        },
    }


def _chat2desk_saved_surge_windows_for_day(day_obj):
    try:
        result = db.get_chat_metric_surge_windows(day_obj.strftime('%Y-%m'))
        if isinstance(result, dict):
            return result.get('windows') or []
    except Exception:
        logging.exception("Failed to load chat metric surge windows for %s", day_obj.strftime('%Y-%m'))
    return []


def _chat2desk_build_daily_metrics(day_str, operator_lookup, operator_token_index, surge_windows=None):
    # Время ответа берём из request_stats (см. _chat2desk_build_metrics_from_statistics_rows).
    # operator_replies больше не тянем — он давал завышенное среднее.
    request_stats_rows = _chat2desk_statistics_get(CHAT2DESK_STATISTICS_REPORT_REQUEST_STATS, day_str)
    rating_rows = _chat2desk_statistics_get(CHAT2DESK_STATISTICS_REPORT_RATING, day_str)
    operator_stats_rows = _chat2desk_statistics_get(CHAT2DESK_STATISTICS_REPORT_OPERATOR_STATS, day_str)
    report = _chat2desk_build_metrics_from_statistics_rows(
        day_str,
        None,
        rating_rows,
        operator_lookup,
        operator_token_index,
        operator_stats_rows=operator_stats_rows,
        surge_windows=surge_windows,
        preview_limit=STATUS_IMPORT_INVALID_ROWS_PREVIEW_LIMIT,
        request_stats_rows=request_stats_rows
    )
    # Те же строки идут в c2d_requests (раздел «Оценка чатов ЧМ») — без
    # дополнительных запросов к API.
    report['request_stats_rows'] = request_stats_rows
    return report


def _chat2desk_build_request_rows(day_str, request_stats_rows, operator_lookup, operator_token_index):
    """Нормализует строки request_stats для db.save_c2d_requests: числа/даты/оператор.
    Строки без request_id пропускаются; без сматченного оператора — сохраняются
    (operator_id NULL), в выборку случайного чата они не попадают."""
    target_tz = _chat2desk_sync_timezone()

    def as_int(value):
        parsed = _chat_metrics_parse_number(value)
        return int(parsed) if parsed is not None else None

    rows = []
    for row in (request_stats_rows or []):
        if not isinstance(row, dict):
            continue
        request_id = as_int(row.get('request_id'))
        if not request_id:
            continue
        start_dt = _chat2desk_parse_datetime(row.get('request_start'), target_tz=target_tz)
        end_dt = _chat2desk_parse_datetime(row.get('request_end'), target_tz=target_tz)
        raw_name = _chat2desk_row_first(row, 'operator_name', 'operator', 'name')
        op_id = None
        if raw_name:
            op_id, _ = _chat_report_resolve_operator(raw_name, operator_lookup, operator_token_index)
        rating = _chat_metrics_parse_number(row.get('rating_scale_score'))
        rows.append({
            'request_id': request_id,
            'day': (start_dt.date() if start_dt else _chat_metrics_parse_date(day_str)),
            'request_start': start_dt,
            'request_end': end_dt,
            'request_time': as_int(row.get('request_time')),
            'reaction_time': as_int(row.get('reaction_time')),
            'request_type': str(row.get('request_type') or '').strip() or None,
            'transport': str(row.get('transport') or '').strip() or None,
            'channel_id': as_int(row.get('channel_id')),
            'channel_name': str(row.get('channel_name') or '').strip() or None,
            'client_id': as_int(row.get('client_id')),
            'client_name': str(row.get('client_name') or '').strip() or None,
            'client_phone': str(row.get('phone') or '').strip() or None,
            'c2d_operator_id': as_int(row.get('operator_id')),
            'c2d_operator_name': str(raw_name or '').strip() or None,
            'operator_id': int(op_id) if op_id is not None else None,
            'incoming_messages': as_int(row.get('incoming_messages')),
            'outgoing_messages': as_int(row.get('outgoing_messages')),
            'rating_score': float(rating) if rating is not None else None,
            'rating_text': str(row.get('rating_text') or '').strip() or None,
        })
    return rows


def _chat2desk_build_status_import_from_operator_events(day_str, event_rows, operator_lookup, preview_limit=None):
    parsed_day = _chat_metrics_parse_date(day_str)
    if parsed_day is None:
        raise ValueError("day_str must be in YYYY-MM-DD format")

    buf = StringIO()
    writer = csv.writer(buf, delimiter=';', quotechar='"', lineterminator='\n')
    writer.writerow(['OperatorName', 'StateName', 'TimeChange', 'StateNote'])
    for row in (event_rows or []):
        if not isinstance(row, dict):
            writer.writerow(['', '', '', ''])
            continue
        operator_name = _chat2desk_row_first(row, 'operator_name', 'operator', 'name')
        event_name = _chat2desk_row_first(row, 'event', 'state_name', 'state', 'status_name', 'status')
        event_at = _chat2desk_row_first(row, 'created_at', 'time_change', 'changed_at', 'timestamp', 'date')
        state_note = _chat2desk_row_first(row, 'state_note', 'status_note', 'note') or ''
        writer.writerow([
            str(operator_name or '').strip(),
            str(event_name or '').strip(),
            str(event_at or '').strip(),
            str(state_note or '').strip()
        ])

    parsed = _status_import_parse_csv(
        buf.getvalue(),
        operator_lookup,
        max_source_rows=STATUS_IMPORT_MAX_SOURCE_ROWS,
        invalid_rows_preview_limit=preview_limit
    )
    parsed['api_rows'] = {
        CHAT2DESK_STATISTICS_REPORT_OPERATOR_EVENTS: len(event_rows or [])
    }
    parsed['source'] = 'chat2desk_operator_events'
    parsed['day'] = parsed_day.strftime('%Y-%m-%d')
    return parsed


def _chat2desk_sync_target_days(day=None, date_from=None, date_to=None):
    if day is not None:
        parsed_day = _chat_metrics_parse_date(day)
        if parsed_day is None:
            raise ValueError("day must be in YYYY-MM-DD format")
        return [parsed_day]

    if date_from is not None or date_to is not None:
        start_day = _chat_metrics_parse_date(date_from)
        end_day = _chat_metrics_parse_date(date_to or date_from)
        if start_day is None or end_day is None:
            raise ValueError("date_from and date_to must be in YYYY-MM-DD format")
        if end_day < start_day:
            raise ValueError("date_to must be greater than or equal to date_from")
        days_count = (end_day - start_day).days + 1
        if days_count > 31:
            raise ValueError("Chat2Desk sync period cannot exceed 31 days")
        return [start_day + timedelta(days=offset) for offset in range(days_count)]

    today = datetime.now(_chat2desk_sync_timezone()).date()
    days_back = _env_int('CHAT2DESK_SYNC_DAYS_BACK', CHAT2DESK_SYNC_DAYS_BACK, minimum=1, maximum=31)
    return [today - timedelta(days=offset) for offset in range(days_back, 0, -1)]


def sync_chat2desk_daily_metrics(day=None, date_from=None, date_to=None, triggered_by='scheduler', force=False, imported_by=None):
    if not force and not _chat2desk_sync_enabled():
        logging.info("Chat2Desk daily metrics sync skipped: disabled")
        return {'status': 'skipped', 'reason': 'disabled'}
    if not _chat2desk_api_token():
        logging.warning("Chat2Desk daily metrics sync skipped: CHAT2DESK_API_TOKEN is not set")
        return {'status': 'skipped', 'reason': 'missing_token'}

    if not CHAT_MANAGER_METRICS_IMPORT_LOCK.acquire(blocking=False):
        logging.warning("Chat2Desk daily metrics sync skipped: metrics import is already running")
        return {'status': 'skipped', 'reason': 'locked'}

    started = time.time()
    day_results = []
    try:
        operator_lookup = _status_import_build_operator_lookup()
        operator_token_index = _chat_report_build_operator_token_index()
        target_days = _chat2desk_sync_target_days(day, date_from=date_from, date_to=date_to)

        for day_obj in target_days:
            day_str = day_obj.strftime('%Y-%m-%d')
            try:
                surge_windows = _chat2desk_saved_surge_windows_for_day(day_obj)
                report = _chat2desk_build_daily_metrics(
                    day_str,
                    operator_lookup,
                    operator_token_index,
                    surge_windows=surge_windows
                )
                metrics = report.get('metrics') or []
                update_fields = report.get('update_fields') or []
                save_summary = {'batch_id': None, 'processed': 0}
                if metrics and update_fields:
                    save_summary = db.save_chat_manager_daily_metrics(
                        metrics=metrics,
                        imported_by=imported_by,
                        update_fields=update_fields
                    )
                low_rating_summary = {'processed': 0}
                low_ratings = report.get('low_ratings') or []
                if low_ratings:
                    low_rating_summary = db.save_chat_manager_low_ratings(
                        low_ratings=low_ratings,
                        imported_by=imported_by,
                        source_batch_id=(save_summary or {}).get('batch_id')
                    )
                # Заявки — в c2d_requests для раздела «Оценка чатов ЧМ» (упавшее
                # сохранение не валит синк метрик).
                c2d_requests_saved = 0
                try:
                    c2d_requests_saved = db.save_c2d_requests(
                        _chat2desk_build_request_rows(
                            day_str,
                            report.get('request_stats_rows'),
                            operator_lookup,
                            operator_token_index
                        )
                    )
                except Exception:
                    logging.exception("c2d requests save failed for %s", day_str)
                day_results.append({
                    'day': day_str,
                    'status': 'success',
                    'source_rows': int(report.get('source_rows') or 0),
                    'matched_rows': int(report.get('matched_rows') or 0),
                    'processed': int((save_summary or {}).get('processed') or 0),
                    'low_rating_count': int(report.get('low_rating_count') or 0),
                    'low_rating_saved': int((low_rating_summary or {}).get('processed') or 0),
                    'c2d_requests_saved': int(c2d_requests_saved or 0),
                    'unmatched_count': int(report.get('unmatched_count') or 0),
                    'excluded_surge_rows': int(report.get('excluded_surge_rows') or 0),
                    'update_fields': update_fields,
                    'api_rows': report.get('api_rows') or {},
                    'batch_id': (save_summary or {}).get('batch_id'),
                    'unmatched_operators': report.get('unmatched_preview') or [],
                })
                logging.info(
                    "Chat2Desk daily metrics sync %s: rows=%s matched=%s processed=%s fields=%s surge_excluded=%s",
                    day_str,
                    int(report.get('source_rows') or 0),
                    int(report.get('matched_rows') or 0),
                    int((save_summary or {}).get('processed') or 0),
                    ','.join(update_fields),
                    int(report.get('excluded_surge_rows') or 0)
                )
            except Exception as exc:
                logging.exception("Chat2Desk daily metrics sync failed for %s", day_str)
                day_results.append({
                    'day': day_str,
                    'status': 'failed',
                    'error': str(exc)
                })

        has_failed = any(item.get('status') == 'failed' for item in day_results)
        return {
            'status': 'partial_failed' if has_failed else 'success',
            'triggered_by': triggered_by,
            'days': day_results,
            'elapsed_seconds': round(time.time() - started, 2)
        }
    finally:
        try:
            CHAT_MANAGER_METRICS_IMPORT_LOCK.release()
        except Exception:
            pass


def sync_chat2desk_operator_statuses(day=None, date_from=None, date_to=None, triggered_by='manual', force=False, imported_by=None):
    if not force and not _chat2desk_sync_enabled():
        logging.info("Chat2Desk operator statuses sync skipped: disabled")
        return {'status': 'skipped', 'reason': 'disabled'}
    if not _chat2desk_api_token():
        logging.warning("Chat2Desk operator statuses sync skipped: CHAT2DESK_API_TOKEN is not set")
        return {'status': 'skipped', 'reason': 'missing_token'}

    if not STATUS_IMPORT_LOCK.acquire(blocking=False):
        logging.warning("Chat2Desk operator statuses sync skipped: status import is already running")
        return {'status': 'skipped', 'reason': 'locked'}

    started = time.time()
    day_results = []
    try:
        operator_lookup = _status_import_build_operator_lookup()
        target_days = _chat2desk_sync_target_days(day, date_from=date_from, date_to=date_to)

        for day_obj in target_days:
            day_str = day_obj.strftime('%Y-%m-%d')
            try:
                event_rows = _chat2desk_statistics_get(
                    CHAT2DESK_STATISTICS_REPORT_OPERATOR_EVENTS,
                    day_str,
                    max_pages=_env_int(
                        'CHAT2DESK_STATUS_API_MAX_PAGES',
                        CHAT2DESK_STATUS_API_MAX_PAGES,
                        minimum=1,
                        maximum=10000
                    )
                )
                parsed = _chat2desk_build_status_import_from_operator_events(
                    day_str,
                    event_rows,
                    operator_lookup,
                    preview_limit=STATUS_IMPORT_INVALID_ROWS_PREVIEW_LIMIT
                )
                save_summary = {
                    'batch_id': None,
                    'source_rows': int(parsed.get('source_rows') or 0),
                    'valid_events': int(parsed.get('valid_events') or 0),
                    'matched_events': 0,
                    'segments_saved': 0,
                    'deleted_events': 0,
                    'deleted_segments': 0,
                    'invalid_rows_count': int(parsed.get('invalid_rows_count') or 0),
                    'parse_errors_count': int(parsed.get('parse_errors_count') or 0),
                    'operators_count': 0,
                    'open_tail_events': int(parsed.get('open_tail_events') or 0),
                    'zero_or_negative_transitions': int(parsed.get('zero_or_negative_transitions') or 0),
                    'date_from': None,
                    'date_to': None,
                }
                status_events_for_save = [
                    event
                    for event in (parsed.get('events') or [])
                    if str(event.get('event_kind') or 'status') != 'action'
                ]
                if status_events_for_save:
                    save_summary = db.save_operator_status_import(
                        events=status_events_for_save,
                        segments=parsed.get('segments') or [],
                        imported_by=imported_by,
                        summary={
                            'source_rows': int(parsed.get('source_rows') or 0),
                            'valid_events': int(parsed.get('valid_events') or 0),
                            'invalid_rows_count': int(parsed.get('invalid_rows_count') or 0),
                            'parse_errors_count': int(parsed.get('parse_errors_count') or 0),
                            'open_tail_events': int(parsed.get('open_tail_events') or 0),
                            'zero_or_negative_transitions': int(parsed.get('zero_or_negative_transitions') or 0),
                            'action_events_count': int(parsed.get('action_events_count') or 0),
                            'ignored_events_count': int(parsed.get('ignored_events_count') or 0),
                            'meta': {
                                'api': 'sync_statuses_chat2desk',
                                'source': 'chat2desk_operator_events',
                                'report': CHAT2DESK_STATISTICS_REPORT_OPERATOR_EVENTS,
                                'day': day_str,
                            }
                        }
                    )

                chat_metrics_summary = {'processed': 0}
                if parsed.get('chat_metrics'):
                    transfer_metrics = []
                    for metric in (parsed.get('chat_metrics') or []):
                        if not isinstance(metric, dict):
                            continue
                        transfer_metrics.append({
                            'operator_id': metric.get('operator_id'),
                            'day': metric.get('day'),
                            'transfer_chat_count': metric.get('transfer_chat_count'),
                            'source': 'chat2desk_events'
                        })
                    chat_metrics_summary = db.save_chat_manager_daily_metrics(
                        metrics=transfer_metrics,
                        imported_by=imported_by,
                        preserve_missing=True,
                        update_fields=['transfer_chat_count']
                    )

                day_results.append({
                    'day': day_str,
                    'status': 'success',
                    'source_rows': int(parsed.get('source_rows') or 0),
                    'valid_events': int(parsed.get('valid_events') or 0),
                    'matched_events': int((save_summary or {}).get('matched_events') or 0),
                    'segments_saved': int((save_summary or {}).get('segments_saved') or 0),
                    'deleted_events': int((save_summary or {}).get('deleted_events') or 0),
                    'deleted_segments': int((save_summary or {}).get('deleted_segments') or 0),
                    'invalid_rows_count': int(parsed.get('invalid_rows_count') or 0),
                    'parse_errors_count': int(parsed.get('parse_errors_count') or 0),
                    'operators_count': int((save_summary or {}).get('operators_count') or 0),
                    'open_tail_events': int(parsed.get('open_tail_events') or 0),
                    'zero_or_negative_transitions': int(parsed.get('zero_or_negative_transitions') or 0),
                    'action_events_count': int(parsed.get('action_events_count') or 0),
                    'ignored_events_count': int(parsed.get('ignored_events_count') or 0),
                    'api_rows': parsed.get('api_rows') or {},
                    'batch_id': (save_summary or {}).get('batch_id'),
                    'date_from': (save_summary or {}).get('date_from'),
                    'date_to': (save_summary or {}).get('date_to'),
                    'invalid_rows_preview': parsed.get('invalid_rows_preview') or [],
                    'chat_metrics': chat_metrics_summary,
                })
                logging.info(
                    "Chat2Desk operator statuses sync %s: rows=%s matched=%s segments=%s invalid=%s",
                    day_str,
                    int(parsed.get('source_rows') or 0),
                    int((save_summary or {}).get('matched_events') or 0),
                    int((save_summary or {}).get('segments_saved') or 0),
                    int(parsed.get('invalid_rows_count') or 0)
                )
            except Exception as exc:
                logging.exception("Chat2Desk operator statuses sync failed for %s", day_str)
                day_results.append({
                    'day': day_str,
                    'status': 'failed',
                    'error': str(exc)
                })

        has_failed = any(item.get('status') == 'failed' for item in day_results)
        return {
            'status': 'partial_failed' if has_failed else 'success',
            'triggered_by': triggered_by,
            'days': day_results,
            'elapsed_seconds': round(time.time() - started, 2)
        }
    finally:
        try:
            STATUS_IMPORT_LOCK.release()
        except Exception:
            pass


# === Oktell operator statuses (телефония) =======================================================
# Тянем переключения статусов из БД Oktell по HTTP /query (один SELECT, readonly, постранично по
# Enumerator из-за лимита прокси в 1000 строк) и прогоняем через тот же конвейер, что и ручная
# CSV-загрузка: Oktell -> CSV-текст -> _status_import_parse_csv -> db.save_operator_status_import.
# Только операторы (exclude_chat_managers=True). Chat2Desk — отдельное направление, не трогаем.

def _oktell_sync_enabled():
    return bool(OKTELL_SYNC_ENABLED)


def _oktell_api_ready():
    return bool(OKTELL_API_URL) and bool(OKTELL_API_TOKEN)


def _oktell_parse_date(value):
    text = str(value or '').strip()
    if not text:
        return None
    try:
        return datetime.strptime(text, '%Y-%m-%d').date()
    except Exception:
        return None


def _oktell_operator_model_gate(range_from, range_to, operator_ids):
    """Строит «операторско-дневной» гейт для синка Oktell.

    Для каждого дня периода резолвит модель расчёта оператора, действующую в этот
    день (группа, активная в день -> groups.calculation_model_code; при отсутствии
    членства fallback на текущее направление — db.get_operator_calculation_models_as_of).

    Возвращает (operator_model_op_ids, is_operator_model_day):
      - operator_model_op_ids: множество операторов, у которых в периоде есть хотя бы
        один день с операторской (не чат-менеджерской) моделью. Это набор для
        restrict_to_ids в lookup: туда попадают и те, кто СЕЙЧАС числится
        чат-менеджером, но в этот период был оператором (сценарий перехода).
      - is_operator_model_day(operator_id, 'YYYY-MM-DD') -> bool: был ли оператор в
        этот день на операторской модели. Этим фильтруются конкретные дни, чтобы
        чат-дни перешедшего сотрудника не синхронизировались как операторские.
    """
    op_ids = sorted({int(v) for v in (operator_ids or []) if v is not None})
    model_by_day = {}
    operator_model_op_ids = set()
    day = range_from
    while day <= range_to:
        day_iso = day.strftime('%Y-%m-%d')
        day_map = db.get_operator_calculation_models_as_of(op_ids, day) if op_ids else {}
        model_by_day[day_iso] = day_map
        for op_id, code in day_map.items():
            if code and code != CALCULATION_MODEL_CHAT_MANAGER:
                operator_model_op_ids.add(int(op_id))
        day += timedelta(days=1)

    def _is_operator_model_day(operator_id, day_iso):
        code = (model_by_day.get(day_iso) or {}).get(int(operator_id))
        return bool(code) and code != CALCULATION_MODEL_CHAT_MANAGER

    return operator_model_op_ids, _is_operator_model_day


def _oktell_query(sql):
    """Один read-only SELECT к прокси Oktell. Возвращает список dict (rows)."""
    if not _oktell_api_ready():
        raise RuntimeError("OKTELL_IP/OKTELL_API_TOKEN is not set")
    resp = requests.post(
        OKTELL_API_URL,
        json={"sql": sql},
        headers={"X-API-Key": OKTELL_API_TOKEN},
        timeout=OKTELL_API_TIMEOUT_SECONDS,
    )
    if resp.status_code != 200:
        raise RuntimeError(f"Oktell proxy HTTP {resp.status_code}: {resp.text[:300]}")
    payload = resp.json()
    return payload.get('rows') or []


def _oktell_status_page_sql(date_from_compact, date_to_excl_compact, cursor):
    # Один SELECT, keyset по Enumerator. Прокси режет на 1000 строк -> листаем по курсору.
    return (
        "SELECT TOP 1000 "
        "oi.Name AS OperatorName, "
        "CASE h.State "
        "WHEN 0 THEN N'Выключен' WHEN 1 THEN N'Готов' WHEN 2 THEN N'Перерыв' "
        "WHEN 3 THEN N'Нет на месте' WHEN 5 THEN N'Занят' WHEN 6 THEN N'Зарезервировано' "
        "WHEN 7 THEN N'Без телефона' "
        "ELSE N'Неизвестно (' + CAST(h.State AS nvarchar(10)) + N')' END AS StateName, "
        "COALESCE(ls.Name, ist.Name, NULLIF(LTRIM(RTRIM(h.Info)), N'')) AS StateNote, "
        "CONVERT(varchar(19), h.TimeChange, 120) AS TimeChange, "
        "h.Enumerator AS Enumerator "
        "FROM oktell.dbo.A_UserStateHistory h "
        "JOIN oktell_cc_temp.dbo.A_Cube_CC_Cat_OperatorInfo oi ON oi.Id = h.UserId "
        "LEFT JOIN oktell_settings.dbo.A_TaskManager_CardLunchStates ls ON ls.Id = h.ICode "
        "LEFT JOIN oktell.dbo.A_UserStateInfoTypes ist ON ist.Id = h.ICode "
        f"WHERE h.TimeChange >= '{date_from_compact}' AND h.TimeChange < '{date_to_excl_compact}' "
        f"AND h.Enumerator > {int(cursor)} "
        "ORDER BY h.Enumerator"
    )


def _oktell_fetch_status_rows(range_from, range_to):
    """range_from/range_to — date (включительно). Постранично тянет строки статусов из Oktell."""
    date_from_compact = range_from.strftime('%Y%m%d')
    date_to_excl_compact = (range_to + timedelta(days=1)).strftime('%Y%m%d')
    rows = []
    cursor = -1
    pages = 0
    while pages < OKTELL_API_MAX_PAGES:
        page = _oktell_query(_oktell_status_page_sql(date_from_compact, date_to_excl_compact, cursor))
        if not page:
            break
        rows.extend(page)
        pages += 1
        try:
            cursor = max(int(r.get('Enumerator')) for r in page)
        except Exception:
            break
        if len(page) < OKTELL_API_PAGE_SIZE:
            break
    return rows, pages


def _oktell_sync_target_days(day=None, date_from=None, date_to=None):
    """Возвращает список date (включительно). day переопределяет диапазон. По умолчанию — вчера."""
    if day:
        d = _oktell_parse_date(day)
        if d is None:
            raise ValueError("date must be in YYYY-MM-DD format")
        return [d]
    if date_from or date_to:
        start = _oktell_parse_date(date_from or date_to)
        end = _oktell_parse_date(date_to or date_from)
        if start is None or end is None:
            raise ValueError("date_from and date_to must be in YYYY-MM-DD format")
        if end < start:
            raise ValueError("date_to must be greater than or equal to date_from")
        span = (end - start).days + 1
        if span > OKTELL_SYNC_MAX_RANGE_DAYS:
            raise ValueError(f"Период синхронизации Oktell не может быть больше {OKTELL_SYNC_MAX_RANGE_DAYS} дней")
        return [start + timedelta(days=i) for i in range(span)]
    today = datetime.now().date()
    return [today - timedelta(days=1)]


def sync_oktell_operator_statuses(day=None, date_from=None, date_to=None, triggered_by='scheduler', force=False, imported_by=None):
    if not force and not _oktell_sync_enabled():
        logging.info("Oktell operator statuses sync skipped: disabled")
        return {'status': 'skipped', 'reason': 'disabled'}
    if not _oktell_api_ready():
        logging.warning("Oktell operator statuses sync skipped: OKTELL_IP/OKTELL_API_TOKEN is not set")
        return {'status': 'skipped', 'reason': 'missing_token'}

    # Резолвим диапазон до захвата лока, чтобы ошибки валидации не держали лок.
    target_days = _oktell_sync_target_days(day, date_from=date_from, date_to=date_to)
    range_from = target_days[0]
    range_to = target_days[-1]

    if not STATUS_IMPORT_LOCK.acquire(blocking=False):
        logging.warning("Oktell operator statuses sync skipped: status import is already running")
        return {'status': 'skipped', 'reason': 'locked'}

    started = time.time()
    try:
        # Операторско-дневной гейт: тянем и сохраняем статусы только за дни, когда
        # оператор был в группе с операторской моделью. Так сотрудник, перешедший в
        # чат-менеджеры (напр. с 8-го числа), всё ещё корректно синкается за свои
        # операторские дни до перехода, а его чат-дни не трогаются.
        all_op_ids = [int(r[0]) for r in (db.get_all_operators() or []) if r and r[0] is not None]
        operator_model_op_ids, is_operator_model_day = _oktell_operator_model_gate(
            range_from, range_to, all_op_ids
        )
        operator_lookup = _status_import_build_operator_lookup(restrict_to_ids=operator_model_op_ids)
        rows, pages = _oktell_fetch_status_rows(range_from, range_to)

        def _oktell_row_iter():
            # Кормим строки Oktell напрямую в общий core статус-импорта — без
            # промежуточного CSV. Тот же путь смогут переиспользовать будущие
            # интеграции, которые раньше шли через загрузку CSV.
            for idx, r in enumerate(rows):
                yield {
                    'row_num': idx + 2,
                    'operator_name': r.get('OperatorName'),
                    'state_name': r.get('StateName'),
                    'state_note': r.get('StateNote'),
                    'time_change': r.get('TimeChange'),
                }

        parsed = _status_import_build_status_events(
            _oktell_row_iter(),
            operator_lookup,
            invalid_rows_preview_limit=STATUS_IMPORT_INVALID_ROWS_PREVIEW_LIMIT,
            operator_day_filter=is_operator_model_day,
        )
        events_for_save = parsed.get('events') or []
        save_summary = {
            'batch_id': None,
            'source_rows': int(parsed.get('source_rows') or 0),
            'valid_events': int(parsed.get('valid_events') or 0),
            'matched_events': 0,
            'segments_saved': 0,
            'deleted_events': 0,
            'deleted_segments': 0,
            'invalid_rows_count': int(parsed.get('invalid_rows_count') or 0),
            'parse_errors_count': int(parsed.get('parse_errors_count') or 0),
            'operators_count': 0,
            'open_tail_events': int(parsed.get('open_tail_events') or 0),
            'zero_or_negative_transitions': int(parsed.get('zero_or_negative_transitions') or 0),
            'date_from': None,
            'date_to': None,
        }
        if events_for_save:
            save_summary = db.save_operator_status_import(
                events=events_for_save,
                segments=parsed.get('segments') or [],
                imported_by=imported_by,
                summary={
                    'source_rows': int(parsed.get('source_rows') or 0),
                    'valid_events': int(parsed.get('valid_events') or 0),
                    'invalid_rows_count': int(parsed.get('invalid_rows_count') or 0),
                    'parse_errors_count': int(parsed.get('parse_errors_count') or 0),
                    'open_tail_events': int(parsed.get('open_tail_events') or 0),
                    'zero_or_negative_transitions': int(parsed.get('zero_or_negative_transitions') or 0),
                    'action_events_count': int(parsed.get('action_events_count') or 0),
                    'meta': {
                        'api': 'sync_statuses_oktell',
                        'source': 'oktell_operator_events',
                        'date_from': range_from.strftime('%Y-%m-%d'),
                        'date_to': range_to.strftime('%Y-%m-%d'),
                        'oktell_rows': len(rows),
                        'pages': int(pages),
                        'skipped_non_operator_day': int(parsed.get('skipped_non_operator_day') or 0),
                    }
                }
            )

        logging.info(
            "Oktell operator statuses sync %s..%s: oktell_rows=%s matched=%s segments=%s invalid=%s pages=%s",
            range_from.strftime('%Y-%m-%d'), range_to.strftime('%Y-%m-%d'),
            len(rows),
            int((save_summary or {}).get('matched_events') or 0),
            int((save_summary or {}).get('segments_saved') or 0),
            int(parsed.get('invalid_rows_count') or 0),
            pages,
        )
        return {
            'status': 'success',
            'triggered_by': triggered_by,
            'date_from': range_from.strftime('%Y-%m-%d'),
            'date_to': range_to.strftime('%Y-%m-%d'),
            'oktell_rows': len(rows),
            'pages': int(pages),
            'import': save_summary,
            'skipped_non_operator_day': int(parsed.get('skipped_non_operator_day') or 0),
            'invalid_rows_preview': parsed.get('invalid_rows_preview') or [],
            'elapsed_seconds': round(time.time() - started, 2),
        }
    except Exception as exc:
        logging.exception("Oktell operator statuses sync failed")
        return {
            'status': 'failed',
            'triggered_by': triggered_by,
            'date_from': range_from.strftime('%Y-%m-%d'),
            'date_to': range_to.strftime('%Y-%m-%d'),
            'error': str(exc),
            'elapsed_seconds': round(time.time() - started, 2),
        }
    finally:
        try:
            STATUS_IMPORT_LOCK.release()
        except Exception:
            pass


# === Oktell: количество звонков по операторам (Учёт часов -> Звонки) =============================
# Плоский (single SELECT) аналог отчёта «Кол-во звонков операторов, группировка по датам».
# Считаем обработанные звонки на оператора за день и пишем ТОЛЬКО в daily_hours.calls
# (часы/перерывы не трогаем). Операторы матчатся по имени, чат-менеджеры исключаются.
OKTELL_CALLS_SYNC_LOCK = threading.Lock()


def _oktell_calls_sync_enabled():
    return bool(OKTELL_CALLS_SYNC_ENABLED)


def _oktell_calls_target_days(day=None, date_from=None, date_to=None):
    """Список date (включительно). day переопределяет диапазон. По умолчанию — вчера.
    Лимит периода — OKTELL_CALLS_MAX_RANGE_DAYS (до месяца)."""
    if day:
        d = _oktell_parse_date(day)
        if d is None:
            raise ValueError("date must be in YYYY-MM-DD format")
        return [d]
    if date_from or date_to:
        start = _oktell_parse_date(date_from or date_to)
        end = _oktell_parse_date(date_to or date_from)
        if start is None or end is None:
            raise ValueError("date_from and date_to must be in YYYY-MM-DD format")
        if end < start:
            raise ValueError("date_to must be greater than or equal to date_from")
        span = (end - start).days + 1
        if span > OKTELL_CALLS_MAX_RANGE_DAYS:
            raise ValueError(f"Период синхронизации звонков Oktell не может быть больше {OKTELL_CALLS_MAX_RANGE_DAYS} дней")
        return [start + timedelta(days=i) for i in range(span)]
    today = datetime.now().date()
    return [today - timedelta(days=1)]


def _oktell_call_count_sql(date_from_compact, date_to_excl_compact):
    return (
        "SELECT oi.Name AS OperatorName, "
        "CONVERT(varchar(10), os.DateStart, 23) AS CallDate, "
        "COUNT(*) AS CallCount "
        "FROM oktell_cc_temp.dbo.A_Cube_CC_OperatorStates os "
        "INNER JOIN oktell_cc_temp.dbo.A_Cube_CC_Cat_OperatorInfo oi ON oi.Id = os.IdOperator "
        "INNER JOIN oktell_cc_temp.dbo.A_Cube_CC_Cat_Task tk ON tk.Id = os.IdTask "
        "WHERE os.State IN (6, 14) AND os.CallResult IS NOT NULL "
        f"AND os.DateStart >= '{date_from_compact}' AND os.DateStart < '{date_to_excl_compact}' "
        "GROUP BY oi.Name, CONVERT(varchar(10), os.DateStart, 23)"
    )


def _oktell_fetch_call_counts(range_from, range_to):
    """Список dict {OperatorName, CallDate, CallCount} за период. Тянем окнами по
    OKTELL_CALLS_CHUNK_DAYS дней; если окно упёрлось в лимит прокси (1000 строк) —
    до-тягиваем его по одному дню, чтобы не потерять данные."""
    rows = []

    def _window(a, b):
        page = _oktell_query(_oktell_call_count_sql(
            a.strftime('%Y%m%d'), (b + timedelta(days=1)).strftime('%Y%m%d')))
        if len(page) >= OKTELL_API_PAGE_SIZE and a < b:
            d = a
            while d <= b:
                rows.extend(_oktell_query(_oktell_call_count_sql(
                    d.strftime('%Y%m%d'), (d + timedelta(days=1)).strftime('%Y%m%d'))))
                d += timedelta(days=1)
        else:
            rows.extend(page)

    cur = range_from
    while cur <= range_to:
        chunk_end = min(range_to, cur + timedelta(days=OKTELL_CALLS_CHUNK_DAYS - 1))
        _window(cur, chunk_end)
        cur = chunk_end + timedelta(days=1)
    return rows


def sync_oktell_operator_calls(day=None, date_from=None, date_to=None, triggered_by='scheduler', force=False, imported_by=None):
    """Синхронизирует кол-во звонков операторов из Oktell в daily_hours.calls.
    Только операторы (чат-менеджеры исключаются матчингом по имени). Меняет ТОЛЬКО calls."""
    if not force and not _oktell_calls_sync_enabled():
        logging.info("Oktell calls sync skipped: disabled")
        return {'status': 'skipped', 'reason': 'disabled'}
    if not _oktell_api_ready():
        logging.warning("Oktell calls sync skipped: OKTELL_IP/OKTELL_API_TOKEN is not set")
        return {'status': 'skipped', 'reason': 'missing_token'}

    target_days = _oktell_calls_target_days(day, date_from=date_from, date_to=date_to)
    range_from = target_days[0]
    range_to = target_days[-1]

    if not OKTELL_CALLS_SYNC_LOCK.acquire(blocking=False):
        logging.warning("Oktell calls sync skipped: another calls sync is already running")
        return {'status': 'skipped', 'reason': 'locked'}

    started = time.time()
    try:
        # Операторско-дневной гейт: звонки пишем в daily_hours.calls только за дни,
        # когда оператор был в группе с операторской моделью. Перешедший в
        # чат-менеджеры сотрудник синкается за свои операторские дни до перехода,
        # его чат-дни не трогаются.
        all_op_ids = [int(r[0]) for r in (db.get_all_operators() or []) if r and r[0] is not None]
        operator_model_op_ids, is_operator_model_day = _oktell_operator_model_gate(
            range_from, range_to, all_op_ids
        )
        operator_lookup = _status_import_build_operator_lookup(restrict_to_ids=operator_model_op_ids)
        rows = _oktell_fetch_call_counts(range_from, range_to)

        source_rows = len(rows)
        matched_operators = set()
        updated = 0
        unmatched = 0
        skipped_non_operator_day = 0
        unmatched_preview = []
        for r in rows:
            operator_name = str(r.get('OperatorName') or '').strip()
            day_str = str(r.get('CallDate') or '').strip()
            try:
                calls_count = int(r.get('CallCount') or 0)
            except Exception:
                calls_count = 0
            if not operator_name or not day_str:
                continue
            matches = _status_import_resolve_operator_matches(operator_name, operator_lookup)
            if len(matches) != 1:
                unmatched += 1
                if len(unmatched_preview) < STATUS_IMPORT_INVALID_ROWS_PREVIEW_LIMIT:
                    unmatched_preview.append({
                        'operator_name': operator_name,
                        'day': day_str,
                        'calls': calls_count,
                        'reason': 'Оператор не найден' if not matches else 'Найдено несколько операторов с таким именем',
                    })
                continue
            operator_id = int(matches[0]['id'])
            if not is_operator_model_day(operator_id, day_str):
                # День не операторский для этого оператора — звонки не пишем.
                skipped_non_operator_day += 1
                continue
            db.upsert_daily_calls(operator_id, day_str, calls_count)
            matched_operators.add(operator_id)
            updated += 1

        logging.info(
            "Oktell calls sync %s..%s: source_rows=%s updated=%s operators=%s unmatched=%s skipped_non_operator_day=%s",
            range_from.strftime('%Y-%m-%d'), range_to.strftime('%Y-%m-%d'),
            source_rows, updated, len(matched_operators), unmatched, skipped_non_operator_day
        )
        return {
            'status': 'success',
            'triggered_by': triggered_by,
            'date_from': range_from.strftime('%Y-%m-%d'),
            'date_to': range_to.strftime('%Y-%m-%d'),
            'source_rows': source_rows,
            'updated': updated,
            'operators_count': len(matched_operators),
            'unmatched': unmatched,
            'skipped_non_operator_day': skipped_non_operator_day,
            'unmatched_preview': unmatched_preview,
            'elapsed_seconds': round(time.time() - started, 2),
        }
    except Exception as exc:
        logging.exception("Oktell calls sync failed")
        return {
            'status': 'failed',
            'triggered_by': triggered_by,
            'date_from': range_from.strftime('%Y-%m-%d'),
            'date_to': range_to.strftime('%Y-%m-%d'),
            'error': str(exc),
            'elapsed_seconds': round(time.time() - started, 2),
        }
    finally:
        try:
            OKTELL_CALLS_SYNC_LOCK.release()
        except Exception:
            pass


# === Oktell: часовая статистика входящих звонков (Расчёт ресурсов) ==============================
# Плоский (single SELECT) аналог отчёта «Статистика входящих почасово, группировка по датам» над
# oktell.dbo.Call_Systems_hst (route='incoming'). Время — в секундах (resource_fte принимает их).
# Кормим строки напрямую в resource_fte_service.import_resource_days (без промежуточного CSV).
OKTELL_RESOURCE_SYNC_LOCK = threading.Lock()
_OKTELL_GREETING_ABANDON = 'Бросили трубку на приветствии'
_OKTELL_FAILED_CALL = 'Неудачный звонок'


def _oktell_resource_sync_enabled():
    return bool(OKTELL_RESOURCE_SYNC_ENABLED)


def _oktell_resource_target_days(day=None, date_from=None, date_to=None):
    if day:
        d = _oktell_parse_date(day)
        if d is None:
            raise ValueError("date must be in YYYY-MM-DD format")
        return [d]
    if date_from or date_to:
        start = _oktell_parse_date(date_from or date_to)
        end = _oktell_parse_date(date_to or date_from)
        if start is None or end is None:
            raise ValueError("date_from and date_to must be in YYYY-MM-DD format")
        if end < start:
            raise ValueError("date_to must be greater than or equal to date_from")
        span = (end - start).days + 1
        if span > OKTELL_RESOURCE_MAX_RANGE_DAYS:
            raise ValueError(f"Период синхронизации ресурсов Oktell не может быть больше {OKTELL_RESOURCE_MAX_RANGE_DAYS} дней")
        return [start + timedelta(days=i) for i in range(span)]
    today = datetime.now().date()
    return [today - timedelta(days=1)]


def _oktell_resource_hourly_sql(date_from_compact, date_to_excl_compact):
    grt = _OKTELL_GREETING_ABANDON.replace("'", "''")
    fail = _OKTELL_FAILED_CALL.replace("'", "''")
    return (
        "SELECT CONVERT(varchar(10), t.dt_insert, 23) AS report_date, "
        "DATEPART(HOUR, t.dt_insert) AS hour, "
        f"SUM(CASE WHEN t.result_call <> N'{grt}' AND t.call_result IN (13,19,5) THEN 1 ELSE 0 END) AS received_calls, "
        f"SUM(CASE WHEN t.result_call <> N'{grt}' AND t.call_result IN (5) THEN 1 ELSE 0 END) AS accepted_calls, "
        f"SUM(CASE WHEN t.result_call <> N'{grt}' AND t.call_result IN (5) THEN t.total_length ELSE 0 END) AS talk_time_seconds, "
        f"SUM(CASE WHEN t.result_call <> N'{grt}' AND t.call_result IN (5) THEN t.LenQueue ELSE 0 END) AS success_wait_seconds, "
        f"SUM(CASE WHEN t.result_call <> N'{grt}' AND t.call_result IN (13,19,5) THEN t.total_length ELSE 0 END) AS total_time_seconds, "
        f"SUM(CASE WHEN t.result_call = N'{grt}' THEN 1 ELSE 0 END) AS greeting_abandoned, "
        f"SUM(CASE WHEN t.result_call = N'{grt}' THEN t.total_length ELSE 0 END) AS greeting_time_seconds, "
        f"SUM(CASE WHEN t.call_result IN (13,19) AND t.result_call NOT IN (N'{grt}', N'{fail}') THEN 1 ELSE 0 END) AS queue_abandoned, "
        f"SUM(CASE WHEN t.call_result IN (13,19) AND t.result_call NOT IN (N'{grt}', N'{fail}') THEN t.total_length ELSE 0 END) AS queue_wait_seconds, "
        f"SUM(CASE WHEN t.call_result IN (13,19) AND t.result_call NOT IN (N'{grt}', N'{fail}') THEN t.LenQueue ELSE 0 END) AS lost_lenqueue_seconds "
        "FROM oktell.dbo.Call_Systems_hst t "
        f"WHERE t.dt_insert >= '{date_from_compact}' AND t.dt_insert < '{date_to_excl_compact}' "
        f"AND t.taxi_park <> '' AND t.route = 'incoming' AND t.result_call <> N'{fail}' "
        "GROUP BY CONVERT(varchar(10), t.dt_insert, 23), DATEPART(HOUR, t.dt_insert)"
    )


def _oktell_fetch_resource_hours(range_from, range_to):
    """Список dict (одна строка = дата+час) за период. Тянем окнами по
    OKTELL_RESOURCE_CHUNK_DAYS дней; при упоре в лимит прокси (1000) — по одному дню."""
    rows = []

    def _window(a, b):
        page = _oktell_query(_oktell_resource_hourly_sql(
            a.strftime('%Y%m%d'), (b + timedelta(days=1)).strftime('%Y%m%d')))
        if len(page) >= OKTELL_API_PAGE_SIZE and a < b:
            d = a
            while d <= b:
                rows.extend(_oktell_query(_oktell_resource_hourly_sql(
                    d.strftime('%Y%m%d'), (d + timedelta(days=1)).strftime('%Y%m%d'))))
                d += timedelta(days=1)
        else:
            rows.extend(page)

    cur = range_from
    while cur <= range_to:
        chunk_end = min(range_to, cur + timedelta(days=OKTELL_RESOURCE_CHUNK_DAYS - 1))
        _window(cur, chunk_end)
        cur = chunk_end + timedelta(days=1)
    return rows


def _oktell_resource_row(raw):
    """Сырые суммы Oktell -> канонический почасовой dict для daily_resource_hours
    (как у _parse_resource_csv_row; средние = сумма/счётчик, как в исходном отчёте)."""
    def _i(v):
        try:
            return int(v or 0)
        except Exception:
            return 0

    def _sec(v):
        try:
            return int(round(float(v or 0)))
        except Exception:
            return 0

    received = max(0, _i(raw.get('received_calls')))
    accepted = max(0, _i(raw.get('accepted_calls')))
    lost = max(0, received - accepted)
    talk = _sec(raw.get('talk_time_seconds'))
    success_wait = _sec(raw.get('success_wait_seconds'))
    total_time = _sec(raw.get('total_time_seconds'))
    greeting_ab = max(0, _i(raw.get('greeting_abandoned')))
    greeting_time = _sec(raw.get('greeting_time_seconds'))
    queue_ab = max(0, _i(raw.get('queue_abandoned')))
    queue_wait = _sec(raw.get('queue_wait_seconds'))
    try:
        lost_lenqueue = float(raw.get('lost_lenqueue_seconds') or 0)
    except Exception:
        lost_lenqueue = 0.0
    avg_wait_den = accepted + queue_ab
    return {
        'hour': max(0, min(23, _i(raw.get('hour')))),
        'received_calls': received,
        'accepted_calls': accepted,
        'lost_calls': lost,
        'no_answer_rate': (lost / received) if received > 0 else 0,
        'talk_time_seconds': talk,
        'avg_talk_seconds': (talk / accepted) if accepted > 0 else 0,
        'success_wait_seconds': success_wait,
        'avg_success_wait_seconds': (success_wait / accepted) if accepted > 0 else 0,
        'total_time_seconds': total_time,
        'greeting_abandoned': greeting_ab,
        'greeting_time_seconds': greeting_time,
        'queue_abandoned': queue_ab,
        'queue_wait_seconds': queue_wait,
        'avg_lost_wait_seconds': (lost_lenqueue / queue_ab) if queue_ab > 0 else 0,
        'avg_wait_seconds': ((success_wait + queue_wait) / avg_wait_den) if avg_wait_den > 0 else 0,
        'raw_payload': {
            'source': 'oktell_call_systems_hst',
            'report_date': raw.get('report_date'),
            'hour': raw.get('hour'),
            'received_calls': received,
            'accepted_calls': accepted,
            'talk_time_seconds': talk,
        },
    }


def sync_oktell_resource_hours(day=None, date_from=None, date_to=None, triggered_by='scheduler', force=False, user_id=None):
    """Синхронизирует часовую статистику входящих из Oktell в daily_resource_hours и
    пересчитывает прогноз ресурсов (через resource_fte_service.import_resource_days)."""
    if not force and not _oktell_resource_sync_enabled():
        logging.info("Oktell resource sync skipped: disabled")
        return {'status': 'skipped', 'reason': 'disabled'}
    if not _oktell_api_ready():
        logging.warning("Oktell resource sync skipped: OKTELL_IP/OKTELL_API_TOKEN is not set")
        return {'status': 'skipped', 'reason': 'missing_token'}

    target_days = _oktell_resource_target_days(day, date_from=date_from, date_to=date_to)
    range_from = target_days[0]
    range_to = target_days[-1]

    if not OKTELL_RESOURCE_SYNC_LOCK.acquire(blocking=False):
        logging.warning("Oktell resource sync skipped: another resource sync is already running")
        return {'status': 'skipped', 'reason': 'locked'}

    started = time.time()
    try:
        raw_rows = _oktell_fetch_resource_hours(range_from, range_to)
        days_map = {}
        for raw in raw_rows:
            rd = str(raw.get('report_date') or '').strip()
            if not rd:
                continue
            days_map.setdefault(rd, []).append(_oktell_resource_row(raw))
        days = [
            {'report_date': rd, 'rows': rows, 'source_row_count': len(rows)}
            for rd, rows in sorted(days_map.items())
        ]
        total_hours = sum(len(d['rows']) for d in days)
        uploaded_dates = []
        if days:
            result = import_resource_days(
                db, days,
                filename='oktell_sync',
                headers=list(OKTELL_RESOURCE_FIELDS),
                mapped_headers=None,
                user_id=user_id,
            )
            uploaded_dates = result.get('uploaded_dates') or []
        logging.info(
            "Oktell resource sync %s..%s: days=%s hours=%s",
            range_from.strftime('%Y-%m-%d'), range_to.strftime('%Y-%m-%d'), len(days), total_hours
        )
        return {
            'status': 'success',
            'triggered_by': triggered_by,
            'date_from': range_from.strftime('%Y-%m-%d'),
            'date_to': range_to.strftime('%Y-%m-%d'),
            'days_count': len(days),
            'hours_count': total_hours,
            'uploaded_dates': uploaded_dates,
            'elapsed_seconds': round(time.time() - started, 2),
        }
    except Exception as exc:
        logging.exception("Oktell resource sync failed")
        return {
            'status': 'failed',
            'triggered_by': triggered_by,
            'date_from': range_from.strftime('%Y-%m-%d'),
            'date_to': range_to.strftime('%Y-%m-%d'),
            'error': str(exc),
            'elapsed_seconds': round(time.time() - started, 2),
        }
    finally:
        try:
            OKTELL_RESOURCE_SYNC_LOCK.release()
        except Exception:
            pass


# === Oktell: «Биллинг Oktell» (Расчет ресурсов) ==================================================
# Живой отчёт по входящим в разрезе день x таксопарк из oktell.dbo.Call_Systems_hst
# (формулы = отчёт «Статистика входящих» .xmlr; SL = обслужено за N сек / обслужено).
# Ничего не сохраняем: каждый запрос UI считается напрямую в Oktell.
OKTELL_BILLING_SL_DEFAULT_SECONDS = int(os.getenv('OKTELL_BILLING_SL_SECONDS', '20'))

_OKTELL_BILLING_METRICS = (
    'arrived', 'served', 'lost', 'served_sl', 'greet_drop',
    'talk_seconds', 'wait_ok_seconds', 'wait_lost_seconds', 'total_seconds',
)


def _oktell_billing_parse_time(value):
    """'HH:MM' -> минуты от полуночи (0..1439), иначе None."""
    text = str(value or '').strip()
    match = re.fullmatch(r'([01]?\d|2[0-3]):([0-5]\d)', text)
    if not match:
        return None
    return int(match.group(1)) * 60 + int(match.group(2))


def _oktell_billing_minute_filter(minute_from, minute_to, column='t.dt_insert'):
    if int(minute_from) > 0 or int(minute_to) < 1439:
        return (
            f"AND (DATEPART(HOUR, {column}) * 60 + DATEPART(MINUTE, {column})) "
            f"BETWEEN {int(minute_from)} AND {int(minute_to)} "
        )
    return ''


def _oktell_billing_sql(date_from_compact, date_to_excl_compact, minute_from, minute_to, sl_seconds, group_by='park'):
    grt = _OKTELL_GREETING_ABANDON.replace("'", "''")
    fail = _OKTELL_FAILED_CALL.replace("'", "''")
    minute_filter = _oktell_billing_minute_filter(minute_from, minute_to)
    line_select = ''
    line_join = ''
    line_group = ''
    if group_by == 'line':
        # Набранная SIP-линия: лег ConnectionType=4 (снаружи в IVR) той же цепочки.
        # Цепочки бывают с несколькими легами ct=4 (повторные заходы в IVR) — дедуп через MIN;
        # разные номера внутри одной цепочки — единичные случаи (2 за неделю), MIN детерминирован.
        # Окно по TimeStart расширено на день назад: звонок может начаться до полуночи.
        conn_from = (datetime.strptime(date_from_compact, '%Y%m%d') - timedelta(days=1)).strftime('%Y%m%d')
        line_select = "COALESCE(c.line_number, N'') AS line_number, "
        line_join = (
            "LEFT JOIN (SELECT IdChain, MIN(ANumberDialed) AS line_number "
            "FROM oktell.dbo.A_Stat_Connections_1x1 "
            f"WHERE ConnectionType = 4 AND TimeStart >= '{conn_from}' AND TimeStart < '{date_to_excl_compact}' "
            "GROUP BY IdChain) c ON c.IdChain = TRY_CAST(t.chainid AS uniqueidentifier) "
        )
        line_group = ", COALESCE(c.line_number, N'')"
    return (
        "SELECT CONVERT(varchar(10), t.dt_insert, 23) AS report_date, "
        "t.taxi_park AS taxi_park, "
        f"{line_select}"
        f"SUM(CASE WHEN t.result_call <> N'{grt}' AND t.call_result IN (13,19,5) THEN 1 ELSE 0 END) AS arrived, "
        f"SUM(CASE WHEN t.result_call <> N'{grt}' AND t.call_result IN (5) THEN 1 ELSE 0 END) AS served, "
        f"SUM(CASE WHEN t.result_call <> N'{grt}' AND t.call_result IN (5) AND t.LenQueue <= {int(sl_seconds)} THEN 1 ELSE 0 END) AS served_sl, "
        f"SUM(CASE WHEN t.result_call = N'{grt}' THEN 1 ELSE 0 END) AS greet_drop, "
        f"SUM(CASE WHEN t.result_call <> N'{grt}' AND t.call_result IN (5) THEN t.total_length ELSE 0 END) AS talk_seconds, "
        f"SUM(CASE WHEN t.result_call <> N'{grt}' AND t.call_result IN (5) THEN t.LenQueue ELSE 0 END) AS wait_ok_seconds, "
        f"SUM(CASE WHEN t.call_result IN (13,19) AND t.result_call NOT IN (N'{grt}', N'{fail}') THEN t.LenQueue ELSE 0 END) AS wait_lost_seconds, "
        f"SUM(CASE WHEN t.result_call <> N'{grt}' AND t.call_result IN (13,19,5) THEN t.total_length ELSE 0 END) AS total_seconds "
        "FROM oktell.dbo.Call_Systems_hst t "
        f"{line_join}"
        f"WHERE t.dt_insert >= '{date_from_compact}' AND t.dt_insert < '{date_to_excl_compact}' "
        f"AND t.taxi_park <> '' AND t.route = 'incoming' AND t.result_call <> N'{fail}' "
        f"{minute_filter}"
        f"GROUP BY CONVERT(varchar(10), t.dt_insert, 23), t.taxi_park{line_group}"
    )


def _oktell_fetch_billing_rows(range_from, range_to, minute_from, minute_to, sl_seconds, group_by='park'):
    """Строки (день x таксопарк [x линия]) за период. Окна по OKTELL_RESOURCE_CHUNK_DAYS дней;
    при упоре в лимит прокси (1000 строк) — по одному дню. Запросы строго последовательные."""
    rows = []

    def _window(a, b):
        page = _oktell_query(_oktell_billing_sql(
            a.strftime('%Y%m%d'), (b + timedelta(days=1)).strftime('%Y%m%d'),
            minute_from, minute_to, sl_seconds, group_by))
        if len(page) >= OKTELL_API_PAGE_SIZE and a < b:
            d = a
            while d <= b:
                rows.extend(_oktell_query(_oktell_billing_sql(
                    d.strftime('%Y%m%d'), (d + timedelta(days=1)).strftime('%Y%m%d'),
                    minute_from, minute_to, sl_seconds, group_by)))
                d += timedelta(days=1)
        else:
            rows.extend(page)

    cur = range_from
    while cur <= range_to:
        chunk_end = min(range_to, cur + timedelta(days=OKTELL_RESOURCE_CHUNK_DAYS - 1))
        _window(cur, chunk_end)
        cur = chunk_end + timedelta(days=1)
    return rows


def _oktell_billing_int(value):
    try:
        return int(value or 0)
    except Exception:
        return 0


def _oktell_billing_sec(value):
    try:
        return int(round(float(value or 0)))
    except Exception:
        return 0


def _oktell_billing_build_report(raw_rows, include_line=False):
    """Сырые строки (день x таксопарк [x линия]) -> {days, parks, totals}. Суммы в целых
    секундах; проценты/средние считает фронтенд из сырых счётчиков."""
    def _blank():
        return {key: 0 for key in _OKTELL_BILLING_METRICS}

    def _merge(target, row):
        for key in _OKTELL_BILLING_METRICS:
            target[key] += row[key]

    days_map = {}
    parks_map = {}
    totals = _blank()
    for raw in raw_rows:
        report_date = str(raw.get('report_date') or '').strip()
        park = str(raw.get('taxi_park') or '').strip()
        if not report_date or not park:
            continue
        key = (park, str(raw.get('line_number') or '').strip()) if include_line else (park, '')
        arrived = max(0, _oktell_billing_int(raw.get('arrived')))
        served = max(0, _oktell_billing_int(raw.get('served')))
        row = {
            'arrived': arrived,
            'served': served,
            'lost': max(0, arrived - served),
            'served_sl': max(0, _oktell_billing_int(raw.get('served_sl'))),
            'greet_drop': max(0, _oktell_billing_int(raw.get('greet_drop'))),
            'talk_seconds': _oktell_billing_sec(raw.get('talk_seconds')),
            'wait_ok_seconds': _oktell_billing_sec(raw.get('wait_ok_seconds')),
            'wait_lost_seconds': _oktell_billing_sec(raw.get('wait_lost_seconds')),
            'total_seconds': _oktell_billing_sec(raw.get('total_seconds')),
        }
        day_parks = days_map.setdefault(report_date, {})
        _merge(day_parks.setdefault(key, _blank()), row)
        _merge(parks_map.setdefault(key, _blank()), row)
        _merge(totals, row)

    def _sorted_parks(parks):
        items = []
        for (park, line), metrics in parks.items():
            item = {'park': park, **metrics}
            if include_line:
                item['line'] = line
            items.append(item)
        items.sort(key=lambda item: (-item['arrived'], item['park'], item.get('line') or ''))
        return items

    days = []
    for report_date in sorted(days_map):
        park_rows = _sorted_parks(days_map[report_date])
        day_totals = _blank()
        for item in park_rows:
            for key in _OKTELL_BILLING_METRICS:
                day_totals[key] += item[key]
        days.append({'date': report_date, 'parks': park_rows, 'totals': day_totals})

    return {'days': days, 'parks': _sorted_parks(parks_map), 'totals': totals}


# --- «Биллинг Oktell»: построчная детализация звонков -------------------------------------------
# Одна строка = один входящий звонок. Снимок по максимальному Id фиксирует выборку при переходе
# между страницами, чтобы новые звонки текущего дня не сдвигали уже просмотренные строки.
def _oktell_billing_detail_source_sql(date_from_compact, date_to_excl_compact,
                                      minute_from, minute_to, max_call_id=None):
    grt = _OKTELL_GREETING_ABANDON.replace("'", "''")
    fail = _OKTELL_FAILED_CALL.replace("'", "''")
    minute_filter = _oktell_billing_minute_filter(minute_from, minute_to)
    id_filter = f"AND t.Id <= {int(max_call_id)} " if max_call_id is not None else ''
    return (
        "FROM oktell.dbo.Call_Systems_hst t "
        f"WHERE t.dt_insert >= '{date_from_compact}' AND t.dt_insert < '{date_to_excl_compact}' "
        f"AND t.taxi_park <> '' AND t.route = 'incoming' AND t.result_call <> N'{fail}' "
        f"AND (t.result_call = N'{grt}' OR (t.result_call <> N'{grt}' AND t.call_result IN (5,13,19))) "
        f"{id_filter}{minute_filter}"
    )


def _oktell_billing_detail_select_sql():
    return (
        "t.Id AS call_id, "
        "t.dt_insert AS occurred_at, "
        "t.taxi_park AS taxi_park, "
        "COALESCE(t.[number], N'') AS driver_number, "
        "t.chainid AS chain_id, t.result_call AS result_call, "
        "t.call_result AS call_result, t.total_length AS total_length"
    )


def _oktell_billing_detail_line_apply_sql(call_alias, date_from_compact, date_to_excl_compact):
    conn_from = (datetime.strptime(date_from_compact, '%Y%m%d') - timedelta(days=1)).strftime('%Y%m%d')
    return (
        "OUTER APPLY (SELECT TOP 1 s.ANumberDialed AS line_number, s.AOutNumber AS caller_number "
        "FROM oktell.dbo.A_Stat_Connections_1x1 s "
        f"WHERE s.IdChain = TRY_CAST({call_alias}.chain_id AS uniqueidentifier) "
        "AND s.ConnectionType = 4 "
        f"AND s.TimeStart >= '{conn_from}' AND s.TimeStart < '{date_to_excl_compact}' "
        "ORDER BY s.TimeStart ASC, s.Id ASC) c "
    )


def _oktell_billing_detail_page_sql(date_from_compact, date_to_excl_compact,
                                    minute_from, minute_to, page, per_page, snapshot_id=None):
    grt = _OKTELL_GREETING_ABANDON.replace("'", "''")
    page = max(1, int(page))
    per_page = max(1, min(100, int(per_page)))
    row_from = (page - 1) * per_page + 1
    row_to = row_from + per_page - 1
    source_sql = _oktell_billing_detail_source_sql(
        date_from_compact, date_to_excl_compact, minute_from, minute_to, snapshot_id)
    select_sql = _oktell_billing_detail_select_sql()
    return (
        "SELECT q.call_id, CONVERT(varchar(19), q.occurred_at, 120) AS occurred_at, "
        "q.taxi_park, COALESCE(c.line_number, N'') AS line_number, "
        "COALESCE(NULLIF(q.driver_number, N''), NULLIF(c.caller_number, N''), N'') AS driver_number, "
        f"CASE WHEN q.result_call = N'{grt}' THEN 1 ELSE 0 END AS ivr_drop, "
        f"CASE WHEN q.result_call <> N'{grt}' AND q.call_result IN (13,19) THEN 1 ELSE 0 END AS queue_drop, "
        f"CASE WHEN q.result_call <> N'{grt}' AND q.call_result = 5 THEN q.total_length ELSE 0 END AS talk_seconds, "
        "q.total_count, q.snapshot_id "
        "FROM (SELECT ranked.* FROM (SELECT "
        f"{select_sql}, "
        "COUNT(*) OVER() AS total_count, MAX(t.Id) OVER() AS snapshot_id, "
        "ROW_NUMBER() OVER (ORDER BY t.dt_insert DESC, t.Id DESC) AS row_num "
        f"{source_sql}"
        ") ranked "
        f"WHERE ranked.row_num BETWEEN {row_from} AND {row_to}) q "
        f"{_oktell_billing_detail_line_apply_sql('q', date_from_compact, date_to_excl_compact)}"
        "ORDER BY q.row_num"
    )


def _oktell_billing_detail_export_page_sql(date_from_compact, date_to_excl_compact,
                                           minute_from, minute_to, max_call_id=None,
                                           page_size=None):
    grt = _OKTELL_GREETING_ABANDON.replace("'", "''")
    size = max(1, min(int(page_size or OKTELL_API_PAGE_SIZE), int(OKTELL_API_PAGE_SIZE)))
    source_sql = _oktell_billing_detail_source_sql(
        date_from_compact, date_to_excl_compact, minute_from, minute_to, max_call_id)
    return (
        "SELECT p.call_id, CONVERT(varchar(19), p.occurred_at, 120) AS occurred_at, "
        "p.taxi_park, COALESCE(c.line_number, N'') AS line_number, "
        "COALESCE(NULLIF(p.driver_number, N''), NULLIF(c.caller_number, N''), N'') AS driver_number, "
        f"CASE WHEN p.result_call = N'{grt}' THEN 1 ELSE 0 END AS ivr_drop, "
        f"CASE WHEN p.result_call <> N'{grt}' AND p.call_result IN (13,19) THEN 1 ELSE 0 END AS queue_drop, "
        f"CASE WHEN p.result_call <> N'{grt}' AND p.call_result = 5 THEN p.total_length ELSE 0 END AS talk_seconds "
        f"FROM (SELECT TOP {size} {_oktell_billing_detail_select_sql()} "
        f"{source_sql}"
        "ORDER BY t.Id DESC) p "
        f"{_oktell_billing_detail_line_apply_sql('p', date_from_compact, date_to_excl_compact)}"
        "ORDER BY p.call_id DESC"
    )


def _oktell_billing_detail_row(raw):
    return {
        'id': max(0, _oktell_billing_int(raw.get('call_id'))),
        'occurred_at': str(raw.get('occurred_at') or '').strip(),
        'park': str(raw.get('taxi_park') or '').strip(),
        'line': str(raw.get('line_number') or '').strip(),
        'driver_number': str(raw.get('driver_number') or '').strip(),
        'ivr_drop': 1 if _oktell_billing_int(raw.get('ivr_drop')) else 0,
        'queue_drop': 1 if _oktell_billing_int(raw.get('queue_drop')) else 0,
        'talk_seconds': max(0, _oktell_billing_sec(raw.get('talk_seconds'))),
    }


def _oktell_billing_build_detail_page(raw_rows, page, per_page, snapshot_id=None):
    rows = [_oktell_billing_detail_row(raw) for raw in (raw_rows or [])]
    first_raw = (raw_rows or [None])[0]
    total = max(0, _oktell_billing_int(first_raw.get('total_count'))) if first_raw else 0
    resolved_snapshot = snapshot_id
    if resolved_snapshot is None and first_raw:
        candidate = _oktell_billing_int(first_raw.get('snapshot_id'))
        resolved_snapshot = candidate if candidate > 0 else None
    page = max(1, int(page))
    per_page = max(1, int(per_page))
    total_pages = (total + per_page - 1) // per_page if total else 0
    return {
        'rows': rows,
        'snapshot_id': resolved_snapshot,
        'pagination': {
            'page': page,
            'per_page': per_page,
            'total': total,
            'total_pages': total_pages,
        },
    }


def _oktell_fetch_billing_detail_page(range_from, range_to, minute_from, minute_to,
                                      page, per_page, snapshot_id=None):
    return _oktell_query(_oktell_billing_detail_page_sql(
        range_from.strftime('%Y%m%d'), (range_to + timedelta(days=1)).strftime('%Y%m%d'),
        minute_from, minute_to, page, per_page, snapshot_id))


def _oktell_fetch_billing_detail_export_rows(range_from, range_to, minute_from, minute_to):
    """Полная построчная выборка для Excel. Листаем по уникальному Id, поэтому лимит
    прокси в 1000 строк не обрезает день или месячный период."""
    date_from = range_from.strftime('%Y%m%d')
    date_to_excl = (range_to + timedelta(days=1)).strftime('%Y%m%d')
    page_size = int(OKTELL_API_PAGE_SIZE)
    max_call_id = None
    rows = []
    while True:
        raw_page = _oktell_query(_oktell_billing_detail_export_page_sql(
            date_from, date_to_excl, minute_from, minute_to, max_call_id, page_size))
        if not raw_page:
            break
        page_ids = [
            _oktell_billing_int(item.get('call_id'))
            for item in raw_page
            if _oktell_billing_int(item.get('call_id')) > 0
        ]
        if not page_ids:
            raise RuntimeError('Oktell billing detail page has no call_id cursor')
        rows.extend(_oktell_billing_detail_row(item) for item in raw_page)
        next_max_call_id = min(page_ids) - 1
        if max_call_id is not None and next_max_call_id >= max_call_id:
            raise RuntimeError('Oktell billing detail cursor did not advance')
        max_call_id = next_max_call_id
        if len(raw_page) < page_size:
            break
    return rows


# --- «Биллинг Oktell»: разрез по операторам ------------------------------------------------------
# Обслужено/время разговора — из Call_Systems_hst (как в парковых таблицах, оператор = id_operator);
# постобработка/удержание/ожидание/пауза — из oktell_cc_temp.dbo.A_Cube_CC_OperatorStates
# (коды: 3 распределение, 6 разговор, 7 постобработка, 9 ожидание, 10 пауза, 12 резерв, 33 удержание).
_OKTELL_BILLING_OPERATOR_METRICS = (
    'served', 'talk_seconds', 'talk_in_seconds', 'talk_out_seconds', 'postproc_seconds',
    'hold_seconds', 'wait_seconds', 'pause_seconds', 'dial_seconds',
)


def _oktell_billing_operator_calls_sql(date_from_compact, date_to_excl_compact, minute_from, minute_to):
    grt = _OKTELL_GREETING_ABANDON.replace("'", "''")
    fail = _OKTELL_FAILED_CALL.replace("'", "''")
    minute_filter = _oktell_billing_minute_filter(minute_from, minute_to)
    return (
        "SELECT CONVERT(varchar(10), t.dt_insert, 23) AS report_date, "
        "oi.Name AS operator_name, "
        "COUNT(*) AS served, "
        "SUM(t.total_length) AS talk_seconds "
        "FROM oktell.dbo.Call_Systems_hst t "
        "JOIN oktell_cc_temp.dbo.A_Cube_CC_Cat_OperatorInfo oi ON oi.Id = TRY_CAST(t.id_operator AS uniqueidentifier) "
        f"WHERE t.dt_insert >= '{date_from_compact}' AND t.dt_insert < '{date_to_excl_compact}' "
        "AND t.taxi_park <> '' AND t.route = 'incoming' "
        f"AND t.result_call NOT IN (N'{grt}', N'{fail}') AND t.call_result IN (5) "
        f"{minute_filter}"
        "GROUP BY CONVERT(varchar(10), t.dt_insert, 23), oi.Name"
    )


def _oktell_billing_operator_states_sql(date_from_compact, date_to_excl_compact, minute_from, minute_to):
    minute_filter = _oktell_billing_minute_filter(minute_from, minute_to, column='s.DateTimeStart')
    return (
        "SELECT CONVERT(varchar(10), s.DateStart, 23) AS report_date, "
        "oi.Name AS operator_name, "
        "SUM(CASE WHEN s.State = 6 AND s.IsOutput = 0 THEN s.LenTime ELSE 0 END) AS talk_in_seconds, "
        "SUM(CASE WHEN s.State = 6 AND s.IsOutput = 1 THEN s.LenTime ELSE 0 END) AS talk_out_seconds, "
        "SUM(CASE WHEN s.State = 7 THEN s.LenTime ELSE 0 END) AS postproc_seconds, "
        "SUM(CASE WHEN s.State = 33 THEN s.LenTime ELSE 0 END) AS hold_seconds, "
        "SUM(CASE WHEN s.State = 9 THEN s.LenTime ELSE 0 END) AS wait_seconds, "
        "SUM(CASE WHEN s.State = 10 THEN s.LenTime ELSE 0 END) AS pause_seconds, "
        "SUM(CASE WHEN s.State IN (3,12) THEN s.LenTime ELSE 0 END) AS dial_seconds "
        "FROM oktell_cc_temp.dbo.A_Cube_CC_OperatorStates s "
        "JOIN oktell_cc_temp.dbo.A_Cube_CC_Cat_OperatorInfo oi ON oi.Id = s.IdOperator "
        f"WHERE s.DateTimeStart >= '{date_from_compact}' AND s.DateTimeStart < '{date_to_excl_compact}' "
        f"{minute_filter}"
        "GROUP BY CONVERT(varchar(10), s.DateStart, 23), oi.Name"
    )


def _oktell_fetch_billing_operator_rows(range_from, range_to, minute_from, minute_to):
    """Пары списков (calls_rows, states_rows) за период; чанки как у паркового отчёта,
    два последовательных запроса на чанк."""
    calls_rows = []
    states_rows = []

    def _window(target, sql_builder, a, b):
        page = _oktell_query(sql_builder(
            a.strftime('%Y%m%d'), (b + timedelta(days=1)).strftime('%Y%m%d'),
            minute_from, minute_to))
        if len(page) >= OKTELL_API_PAGE_SIZE and a < b:
            d = a
            while d <= b:
                target.extend(_oktell_query(sql_builder(
                    d.strftime('%Y%m%d'), (d + timedelta(days=1)).strftime('%Y%m%d'),
                    minute_from, minute_to)))
                d += timedelta(days=1)
        else:
            target.extend(page)

    cur = range_from
    while cur <= range_to:
        chunk_end = min(range_to, cur + timedelta(days=OKTELL_RESOURCE_CHUNK_DAYS - 1))
        _window(calls_rows, _oktell_billing_operator_calls_sql, cur, chunk_end)
        _window(states_rows, _oktell_billing_operator_states_sql, cur, chunk_end)
        cur = chunk_end + timedelta(days=1)
    return calls_rows, states_rows


def _oktell_billing_build_operator_report(calls_rows, states_rows):
    """Слияние звонков и состояний по (день, оператор) -> {days, operators, totals}.
    Технические учётки (supervisor/admin: нет ни звонков, ни разговоров) отбрасываются."""
    def _blank():
        return {key: 0 for key in _OKTELL_BILLING_OPERATOR_METRICS}

    def _merge(target, row):
        for key in _OKTELL_BILLING_OPERATOR_METRICS:
            target[key] += row[key]

    days_map = {}

    def _entry(report_date, operator):
        return days_map.setdefault(report_date, {}).setdefault(operator, _blank())

    for raw in calls_rows:
        report_date = str(raw.get('report_date') or '').strip()
        operator = str(raw.get('operator_name') or '').strip()
        if not report_date or not operator:
            continue
        entry = _entry(report_date, operator)
        entry['served'] += max(0, _oktell_billing_int(raw.get('served')))
        entry['talk_seconds'] += _oktell_billing_sec(raw.get('talk_seconds'))

    state_keys = ('talk_in_seconds', 'talk_out_seconds', 'postproc_seconds', 'hold_seconds',
                  'wait_seconds', 'pause_seconds', 'dial_seconds')
    for raw in states_rows:
        report_date = str(raw.get('report_date') or '').strip()
        operator = str(raw.get('operator_name') or '').strip()
        if not report_date or not operator:
            continue
        entry = _entry(report_date, operator)
        for key in state_keys:
            entry[key] += _oktell_billing_sec(raw.get(key))

    def _is_real_operator(metrics):
        return metrics['served'] > 0 or metrics['talk_in_seconds'] > 0 or metrics['talk_out_seconds'] > 0

    operators_map = {}
    totals = _blank()
    days = []
    for report_date in sorted(days_map):
        rows = [
            {'operator': operator, **metrics}
            for operator, metrics in days_map[report_date].items()
            if _is_real_operator(metrics)
        ]
        if not rows:
            continue
        rows.sort(key=lambda item: (-item['served'], -item['talk_in_seconds'], item['operator']))
        day_totals = _blank()
        for item in rows:
            for key in _OKTELL_BILLING_OPERATOR_METRICS:
                day_totals[key] += item[key]
            _merge(operators_map.setdefault(item['operator'], _blank()), item)
        _merge(totals, day_totals)
        days.append({'date': report_date, 'operators': rows, 'totals': day_totals})

    operators = [{'operator': operator, **metrics} for operator, metrics in operators_map.items()]
    operators.sort(key=lambda item: (-item['served'], -item['talk_in_seconds'], item['operator']))
    return {'days': days, 'operators': operators, 'totals': totals}


