async def _is_admin_user(tg_id):
    """Проверка админа: сначала сравнение с переменной admin, затем fallback — проверка в БД."""
    try:
        if os.getenv("ADMIN_ID") is not None and str(tg_id) == str(os.getenv("ADMIN_ID")):
            return True

        # fallback: проверить в users по telegram_id и role='admin'
        loop = asyncio.get_event_loop()
        def _check():
            with db._get_cursor() as cur:
                cur.execute("""
                    SELECT u.role, d.id
                    FROM users u
                    LEFT JOIN departments d ON d.head_user_id = u.id
                    WHERE u.telegram_id = %s
                    LIMIT 1
                """, (tg_id,))
                row = cur.fetchone()
                if not row:
                    return False
                return bool(_is_admin_role(row[0]) or row[1] is not None)
        return await loop.run_in_executor(None, _check)
    except Exception as e:
        logging.exception("Error checking admin: %s", e)
        return False


async def _resolve_call_reevaluation_request_for_telegram(call_id, approver_tg_id, decision, comment=None):
    loop = asyncio.get_event_loop()

    def _resolve():
        approver = db.get_user(telegram_id=approver_tg_id)
        approver_user_id = approver[0] if approver else None
        return _resolve_reevaluation_request(call_id, approver_user_id, decision, comment=comment)

    return await loop.run_in_executor(None, _resolve)


async def _apply_call_reevaluation_comment_for_telegram(call_id, decision, comment):
    """Сохранить необязательный комментарий к уже принятому решению (в executor-потоке)."""
    loop = asyncio.get_event_loop()
    return await loop.run_in_executor(
        None, _set_reevaluation_decision_comment, call_id, decision, comment
    )


async def _get_call_reevaluation_status_for_telegram(call_id):
    """Вернуть текущий статус запроса на переоценку для проверки перед вводом комментария."""
    loop = asyncio.get_event_loop()
    return await loop.run_in_executor(None, _get_call_reevaluation_context, call_id)


async def _prompt_reevaluation_decision_comment(cq, call_id, decision, state):
    """
    Общий обработчик нажатия approve/reject из Telegram.

    Решение фиксируется СРАЗУ по нажатию кнопки (call_id берётся из callback_data,
    поэтому при пачке заявок ничего не теряется и не путается). После этого
    предлагаем по желанию дописать комментарий — он применяется к уже принятому
    решению отдельным шагом и не может «потерять» само решение.
    """
    # Быстрая проверка статуса — чтобы сразу дать понятный ответ на кнопку.
    try:
        ctx = await _get_call_reevaluation_status_for_telegram(call_id)
    except Exception as e:
        logging.exception("Ошибка получения статуса запроса на переоценку: %s", e)
        await cq.answer("Ошибка сервера", show_alert=True)
        return
    if not ctx or not ctx.get('sv_request'):
        await cq.answer("Запрос не найден", show_alert=True)
        return
    if ctx.get('sv_request_approved') or ctx.get('sv_request_rejected'):
        await cq.answer("Запрос уже обработан", show_alert=True)
        # Снимаем устаревшие кнопки, чтобы по ним больше не нажимали.
        try:
            if cq.message:
                await cq.bot.edit_message_reply_markup(
                    chat_id=cq.message.chat.id, message_id=cq.message.message_id, reply_markup=None
                )
        except Exception as e:
            logging.debug("Не удалось убрать reply_markup у обработанного запроса: %s", e)
        return

    try:
        await cq.answer()
    except Exception as e:
        logging.debug("Не удалось ответить на callback: %s", e)

    # Убираем inline-кнопки исходного сообщения, чтобы не нажали повторно.
    try:
        if cq.message:
            await cq.bot.edit_message_reply_markup(
                chat_id=cq.message.chat.id, message_id=cq.message.message_id, reply_markup=None
            )
    except Exception as e:
        logging.debug("Не удалось убрать reply_markup: %s", e)

    # Фиксируем решение немедленно (атомарно по нажатию кнопки).
    resolved = await _finalize_reevaluation_decision(cq.from_user.id, call_id, decision, None, cq.bot)
    logging.info("Call %s %s by tg_user %s (resolved=%s)", call_id, decision, cq.from_user.id, resolved)
    if not resolved:
        # _finalize уже сообщил администратору, что пошло не так.
        return

    # Решение применено. Предлагаем по желанию дописать комментарий.
    await state.set_state(ReevalDecision.waiting_comment.state)
    await state.update_data(reval_call_id=call_id, reval_decision=decision)

    decision_label = "одобрению" if decision == 'approved' else "отклонению"
    skip_markup = InlineKeyboardMarkup().add(
        InlineKeyboardButton("Пропустить ➡️", callback_data="reval_skip_comment")
    )
    try:
        await cq.bot.send_message(
            cq.from_user.id,
            f"💬 При необходимости добавьте комментарий к <b>{decision_label}</b> "
            f"(Call ID {call_id}) или нажмите «Пропустить».",
            parse_mode='HTML',
            reply_markup=skip_markup
        )
    except Exception as e:
        logging.debug("Не удалось предложить комментарий к решению: %s", e)
        # Решение уже зафиксировано — просто завершаем без комментария.
        await state.finish()


async def _finalize_reevaluation_decision(approver_tg_id, call_id, decision, comment, bot_instance):
    """
    Зафиксировать решение по запросу на переоценку и уведомить администратора.
    Возвращает True при успехе, False — если решение зафиксировать не удалось
    (об этом администратору уже отправлено сообщение).
    """
    try:
        await _resolve_call_reevaluation_request_for_telegram(call_id, approver_tg_id, decision, comment=comment)
    except ValueError:
        await bot_instance.send_message(approver_tg_id, "❗️ Запрос не найден.")
        return False
    except RuntimeError:
        await bot_instance.send_message(approver_tg_id, "ℹ️ Запрос уже был обработан.")
        return False
    except PermissionError as e:
        await bot_instance.send_message(approver_tg_id, f"Access denied: {str(e)}")
        return False
    except Exception as e:
        logging.exception("Ошибка при фиксации решения по переоценке: %s", e)
        await bot_instance.send_message(approver_tg_id, "❗️ Ошибка сервера при сохранении решения.")
        return False

    if decision == 'approved':
        text = f"✅ Запрос на переоценку (Call ID {call_id}) одобрен."
    else:
        text = f"❌ Запрос на переоценку (Call ID {call_id}) отклонён."
    if comment:
        text += f"\n💬 Комментарий: {comment}"
    try:
        await bot_instance.send_message(approver_tg_id, text)
    except Exception as e:
        logging.debug("Не удалось отправить подтверждение администратору: %s", e)
    return True

async def _approve_call_and_get_notify_row(call_id, approver_tg_id):
    """
    Пометить звонок одобренным и вернуть данные для уведомлений:
    (sv_request_by, sv_tg, evaluator_id, eval_tg)
    """
    loop = asyncio.get_event_loop()

    def _update():
        with db._get_cursor() as cur:
            # получить internal user id админа (если есть)
            cur.execute("SELECT id FROM users WHERE telegram_id = %s LIMIT 1", (approver_tg_id,))
            row = cur.fetchone()
            approver_user_id = row[0] if row else None

            cur.execute("""
                UPDATE calls
                SET sv_request_approved = TRUE,
                    sv_request_approved_by = %s,
                    sv_request_approved_at = %s
                WHERE id = %s
            """, (approver_user_id, datetime.utcnow(), call_id))

            cur.execute("""
                SELECT c.sv_request_by, u_super.telegram_id AS sv_tg, c.evaluator_id, u_eval.telegram_id AS eval_tg
                FROM calls c
                LEFT JOIN users u_super ON u_super.id = c.sv_request_by
                LEFT JOIN users u_eval ON u_eval.id = c.evaluator_id
                WHERE c.id = %s
            """, (call_id,))
            return cur.fetchone()

    result = await loop.run_in_executor(None, _update)
    return result  # None или кортеж (sv_request_by, sv_tg, evaluator_id, eval_tg)

async def _approve_call_and_get_notify_row(call_id, approver_tg_id):
    await _resolve_call_reevaluation_request_for_telegram(call_id, approver_tg_id, 'approved')
    return None


@dp.callback_query_handler(lambda c: c.data and c.data.startswith('approve_reval:'))
async def handle_approve_reval(callback_query: types.CallbackQuery, state: FSMContext):
    """
    Обработка approve_reval:{call_id}.
    Первый шаг двухшагового сценария: проверяем админа и просим необязательный
    комментарий к одобрению (см. _prompt_reevaluation_decision_comment). Само решение
    фиксируется после ввода комментария или нажатия «Пропустить».
    """
    cq = callback_query
    user = cq.from_user
    data = cq.data

    # извлечь call_id
    try:
        _, call_id_str = data.split(':', 1)
        call_id = int(call_id_str)
    except Exception:
        await cq.answer("Неверный идентификатор звонка", show_alert=True)
        return

    # проверить, что нажал админ
    try:
        is_admin = await _is_admin_user(user.id)
    except Exception as e:
        logging.exception("Ошибка проверки администратора: %s", e)
        is_admin = False

    if not is_admin:
        await cq.answer("Только администратор может одобрять переоценку", show_alert=True)
        return

    await _prompt_reevaluation_decision_comment(cq, call_id, 'approved', state)


