def _lms_build_pdf_from_html(html_markup):
    global LMS_CERTIFICATE_HTML_ENGINE_WARNED
    markup = str(html_markup or "").strip()
    if not markup:
        return None

    if WeasyHTML is not None:
        try:
            rendered = WeasyHTML(string=markup, base_url=os.getcwd()).write_pdf()
            if rendered:
                return rendered
        except Exception:
            logging.exception("WeasyPrint certificate render failed")

    if LMS_CERTIFICATE_USE_XHTML2PDF and Xhtml2PdfPisa is not None:
        try:
            out = BytesIO()
            result = Xhtml2PdfPisa.CreatePDF(src=markup, dest=out, encoding='utf-8')
            if not getattr(result, 'err', 0):
                rendered = out.getvalue()
                if rendered:
                    return rendered
        except Exception:
            logging.exception("xhtml2pdf certificate render failed")

    if not LMS_CERTIFICATE_HTML_ENGINE_WARNED:
        if WeasyHTML is None and (not LMS_CERTIFICATE_USE_XHTML2PDF or Xhtml2PdfPisa is None):
            logging.warning(
                "LMS certificate HTML->PDF engines are unavailable (weasyprint/xhtml2pdf). "
                "Install dependencies and restart backend to get copyable designed certificates."
            )
            LMS_CERTIFICATE_HTML_ENGINE_WARNED = True

    return None


def _lms_store_certificate_pdf_payload(certificate_number, issued_at, pdf_bytes):
    storage_type = 'db'
    pdf_data = pdf_bytes
    gcs_bucket = None
    gcs_blob_path = None

    if LMS_CERTIFICATE_STORAGE == 'gcs':
        bucket_name = _lms_bucket_name()
        if bucket_name:
            try:
                safe_number = str(certificate_number or '').strip() or f"lms-cert-{secrets.token_hex(6)}"
                dt_value = issued_at if isinstance(issued_at, datetime) else _lms_now()
                client = get_gcs_client()
                bucket = client.bucket(bucket_name)
                blob_path = (
                    f"lms/certificates/{dt_value.strftime('%Y/%m/%d')}/"
                    f"{safe_number}.pdf"
                )
                blob = bucket.blob(blob_path)
                blob.upload_from_string(pdf_bytes, content_type='application/pdf')
                storage_type = 'gcs'
                pdf_data = None
                gcs_bucket = bucket_name
                gcs_blob_path = blob_path
            except Exception:
                storage_type = 'db'
                pdf_data = pdf_bytes
                gcs_bucket = None
                gcs_blob_path = None

    return storage_type, pdf_data, gcs_bucket, gcs_blob_path


def _lms_update_certificate_pdf_tx(cursor, certificate_id, certificate_number, issued_at, pdf_bytes, metadata):
    storage_type, pdf_data, gcs_bucket, gcs_blob_path = _lms_store_certificate_pdf_payload(
        certificate_number=certificate_number,
        issued_at=issued_at,
        pdf_bytes=pdf_bytes
    )
    cursor.execute("""
        UPDATE lms_certificates
        SET pdf_storage_type = %s,
            pdf_data = %s,
            gcs_bucket = %s,
            gcs_blob_path = %s,
            metadata = %s::jsonb
        WHERE id = %s
    """, (
        storage_type,
        pdf_data,
        gcs_bucket,
        gcs_blob_path,
        json.dumps(metadata or {}, ensure_ascii=False),
        int(certificate_id)
    ))
    return {
        "storage_type": storage_type,
        "pdf_data": pdf_data,
        "gcs_bucket": gcs_bucket,
        "gcs_blob_path": gcs_blob_path
    }


@lru_cache(maxsize=128)
def _lms_certificate_font(size, bold=False):
    if ImageFont is None:
        return None

    try:
        point_size = max(6, int(size))
    except Exception:
        point_size = 12

    env_key = "LMS_CERTIFICATE_FONT_BOLD" if bold else "LMS_CERTIFICATE_FONT_REGULAR"
    env_font = (os.getenv(env_key) or "").strip()
    candidates = [env_font] if env_font else []
    if bold:
        candidates.extend([
            "C:\\Windows\\Fonts\\Montserrat-Bold.ttf",
            "C:\\Windows\\Fonts\\arialbd.ttf",
            "/usr/share/fonts/truetype/montserrat/Montserrat-Bold.ttf",
            "/usr/share/fonts/truetype/dejavu/DejaVuSans-Bold.ttf",
            "/usr/share/fonts/truetype/liberation/LiberationSans-Bold.ttf",
            "Montserrat-Bold.ttf",
            "arialbd.ttf",
            "DejaVuSans-Bold.ttf",
            "LiberationSans-Bold.ttf",
        ])
    else:
        candidates.extend([
            "C:\\Windows\\Fonts\\Montserrat-Regular.ttf",
            "C:\\Windows\\Fonts\\arial.ttf",
            "/usr/share/fonts/truetype/montserrat/Montserrat-Regular.ttf",
            "/usr/share/fonts/truetype/dejavu/DejaVuSans.ttf",
            "/usr/share/fonts/truetype/liberation/LiberationSans-Regular.ttf",
            "Montserrat-Regular.ttf",
            "arial.ttf",
            "DejaVuSans.ttf",
            "LiberationSans-Regular.ttf",
        ])

    for path in candidates:
        if not path:
            continue
        try:
            return ImageFont.truetype(path, point_size)
        except Exception:
            continue

    try:
        return ImageFont.load_default()
    except Exception:
        return None


def _lms_text_size(draw, text, font):
    value = str(text or "")
    if not value:
        return 0, 0
    bbox = draw.textbbox((0, 0), value, font=font)
    return max(0, int(bbox[2] - bbox[0])), max(0, int(bbox[3] - bbox[1]))


def _lms_wrap_text(draw, text, font, max_width):
    words = str(text or "").split()
    if not words:
        return []
    lines = []
    current = words[0]
    for word in words[1:]:
        candidate = f"{current} {word}"
        width, _ = _lms_text_size(draw, candidate, font)
        if width <= max_width:
            current = candidate
        else:
            lines.append(current)
            current = word
    lines.append(current)
    return lines


def _lms_draw_dot_grid(draw, x, y, width, height, step, radius, color):
    x0 = int(x)
    y0 = int(y)
    x1 = int(x + width)
    y1 = int(y + height)
    spacing = max(4, int(step))
    r = max(1, int(radius))
    yy = y0 + r
    while yy < y1:
        xx = x0 + r
        while xx < x1:
            draw.ellipse((xx - r, yy - r, xx + r, yy + r), fill=color)
            xx += spacing
        yy += spacing


def _lms_format_certificate_ru_date(issue_dt):
    dt_value = issue_dt if isinstance(issue_dt, datetime) else _lms_now()
    month_names = [
        "января", "февраля", "марта", "апреля", "мая", "июня",
        "июля", "августа", "сентября", "октября", "ноября", "декабря"
    ]
    month_idx = max(1, min(12, int(dt_value.month))) - 1
    return f"{int(dt_value.day)} {month_names[month_idx]} {int(dt_value.year)}"


def _lms_fit_font(draw, text, max_width, start_size, min_size, bold=False):
    size = max(int(min_size), int(start_size))
    while size >= int(min_size):
        font = _lms_certificate_font(size, bold=bold)
        width, _ = _lms_text_size(draw, text, font)
        if width <= max_width or size == int(min_size):
            return font
        size -= 1
    return _lms_certificate_font(min_size, bold=bold)


@lru_cache(maxsize=1)
def _lms_certificate_logo_path():
    custom_logo_path = str(os.getenv("LMS_CERTIFICATE_LOGO_PATH") or "").strip()
    base_dir = os.path.dirname(os.path.abspath(__file__))
    candidates = []
    if custom_logo_path:
        candidates.append(custom_logo_path)
    candidates.extend([
        os.path.join(base_dir, "src", "components", "lms", "iGroup-logo-300-249px.png"),
        os.path.join(base_dir, "lms", "iGroup-logo-300-249px.png"),
        os.path.join(os.getcwd(), "src", "components", "lms", "iGroup-logo-300-249px.png"),
    ])

    for candidate in candidates:
        try:
            if candidate and os.path.isfile(candidate):
                return candidate
        except Exception:
            continue
    return None


