def _lms_build_bold_split_certificate_pdf(certificate_number, learner_name, course_title, issued_at):
    if Image is None or ImageDraw is None or ImageFont is None:
        return None

    cert_number = str(certificate_number or "-").strip() or "-"
    learner = str(learner_name or "-").strip() or "-"
    course = str(course_title or "-").strip() or "-"
    issue_dt = issued_at if isinstance(issued_at, datetime) else _lms_now()
    issue_date_ru = _lms_format_certificate_ru_date(issue_dt)
    issue_date_short = issue_dt.strftime("%d.%m.%Y")
    course_label = course if any(token in course for token in ("«", "»", "\"", "'")) else f"«{course}»"

    raster_scale = max(3, min(8, int(LMS_CERTIFICATE_RASTER_SCALE or 4)))

    def S(value):
        return int(round(float(value) * float(raster_scale)))

    canvas_w, canvas_h = S(1123), S(794)
    left_w = S(340)
    right_x = left_w
    image = Image.new("RGBA", (canvas_w, canvas_h), (255, 255, 255, 255))
    draw = ImageDraw.Draw(image, "RGBA")

    col_y = (253, 183, 0, 255)
    col_k = (0, 0, 0, 255)
    col_w = (255, 255, 255, 255)
    col_g2 = (238, 236, 230, 255)
    col_g4 = (155, 152, 144, 255)
    col_g5 = (74, 72, 69, 255)

    draw.rectangle((0, 0, left_w, canvas_h), fill=col_k)
    draw.rectangle((0, 0, left_w, S(6)), fill=col_y)
    draw.ellipse((S(-120), S(554), S(240), S(914)), outline=(90, 80, 60, 15), width=max(1, S(1)))
    draw.ellipse((S(-50), S(624), S(170), S(844)), outline=(90, 80, 60, 26), width=max(1, S(1)))
    _lms_draw_dot_grid(draw, left_w - S(120), S(10), S(120), S(140), S(16), S(1), (90, 80, 60, 26))

    draw.ellipse((S(853), S(-190), S(1273), S(230)), outline=(185, 185, 185, 56), width=max(1, S(1)))
    draw.ellipse((S(933), S(-110), S(1193), S(150)), outline=(185, 185, 185, 46), width=max(1, S(1)))
    _lms_draw_dot_grid(draw, canvas_w - S(160), canvas_h - S(160), S(160), S(160), S(18), S(1), (253, 183, 0, 56))

    logo_path = _lms_certificate_logo_path()
    if logo_path:
        try:
            with Image.open(logo_path) as logo_source:
                logo_rgba = logo_source.convert("RGBA")
                resample = Image.Resampling.LANCZOS if hasattr(Image, "Resampling") else Image.LANCZOS
                logo_rgba = logo_rgba.resize((S(430), S(357)), resample=resample)
                alpha_mask = logo_rgba.split()[3].point(lambda px: int(px * 0.14))
                logo_overlay = Image.new("RGBA", logo_rgba.size, (150, 150, 150, 0))
                logo_overlay.putalpha(alpha_mask)
                image.alpha_composite(logo_overlay, (right_x + S(130), S(215)))
        except Exception:
            logging.exception("LMS certificate background logo render failed")

    left_pad_x = S(44)
    top_pad = S(52)

    full_logo_path = _lms_certificate_full_logo_path()
    if full_logo_path:
        try:
            with Image.open(full_logo_path) as full_logo_source:
                full_logo_rgba = full_logo_source.convert("RGBA")
                resample = Image.Resampling.LANCZOS if hasattr(Image, "Resampling") else Image.LANCZOS
                src_w, src_h = full_logo_rgba.size
                max_w = S(230)
                max_h = S(80)
                scale = min(max_w / float(max(1, src_w)), max_h / float(max(1, src_h)))
                dst_w = max(1, int(round(src_w * scale)))
                dst_h = max(1, int(round(src_h * scale)))
                full_logo_rgba = full_logo_rgba.resize((dst_w, dst_h), resample=resample)
                logo_x = max(0, int(round((left_w - dst_w) / 2.0)))
                image.alpha_composite(full_logo_rgba, (logo_x, top_pad - S(4)))
        except Exception:
            logging.exception("LMS certificate full logo render failed")

    left_label_font = _lms_certificate_font(S(9), bold=True)
    left_title_font = _lms_certificate_font(S(36), bold=True)
    left_sub_font = _lms_certificate_font(S(10), bold=False)
    info_label_font = _lms_certificate_font(S(9), bold=True)
    info_value_font = _lms_certificate_font(S(11), bold=True)

    block_y = canvas_h - S(280)
    draw.text((left_pad_x, block_y), "ВНУТРЕНИИЙ", font=left_label_font, fill=col_y)
    draw.text((left_pad_x, block_y + S(22)), "Сертификат", font=left_title_font, fill=col_w)
    draw.text((left_pad_x, block_y + S(88)), "о прохождении обучения", font=left_sub_font, fill=(255, 255, 255, 89))
    draw.rectangle((left_pad_x, block_y + S(116), left_pad_x + S(40), block_y + S(119)), fill=col_y)

    info_y = block_y + S(140)
    draw.text((left_pad_x, info_y), "НОМЕР СЕРТИФИКАТА", font=info_label_font, fill=(255, 255, 255, 77))
    draw.text((left_pad_x, info_y + S(14)), cert_number, font=info_value_font, fill=(255, 255, 255, 181))
    draw.text((left_pad_x, info_y + S(42)), "ДАТА ВЫДАЧИ", font=info_label_font, fill=(255, 255, 255, 77))
    draw.text((left_pad_x, info_y + S(56)), issue_date_ru, font=info_value_font, fill=(255, 255, 255, 181))

    rp_left = right_x + S(60)
    rp_right = canvas_w - S(60)
    rp_top = S(52)
    rp_bottom = canvas_h - S(48)

    cert_label_font = _lms_certificate_font(S(8), bold=True)
    cert_value_font = _lms_certificate_font(S(11), bold=True)
    cert_label = "Выдан"
    cert_value = "iGroup Education"
    cert_label_w, _ = _lms_text_size(draw, cert_label, cert_label_font)
    cert_value_w, _ = _lms_text_size(draw, cert_value, cert_value_font)
    draw.text((rp_right - cert_label_w, rp_top), cert_label, font=cert_label_font, fill=col_g4)
    draw.text((rp_right - cert_value_w, rp_top + S(15)), cert_value, font=cert_value_font, fill=col_k)

    recipient_hint_font = _lms_certificate_font(S(9), bold=True)
    recipient_font = _lms_fit_font(draw, learner, rp_right - rp_left, S(52), S(30), bold=True)
    recipient_hint_y = S(312)
    draw.text((rp_left, recipient_hint_y), "ВРУЧАЕТСЯ", font=recipient_hint_font, fill=col_g4)
    draw.text((rp_left, recipient_hint_y + S(20)), learner, font=recipient_font, fill=col_k)
    _, recip_h = _lms_text_size(draw, learner, recipient_font)

    bar_y = recipient_hint_y + S(20) + recip_h + S(14)
    draw.rectangle((rp_left, bar_y, rp_left + S(52), bar_y + S(5)), fill=col_y)

    desc_font = _lms_certificate_font(S(13), bold=False)
    desc_bold_font = _lms_certificate_font(S(13), bold=True)
    course_tag_font = _lms_certificate_font(S(13), bold=True)
    desc_segments = [
        {"kind": "text", "text": "Настоящий сертификат подтверждает, что ", "font": desc_font, "fill": col_g5},
        {"kind": "text", "text": learner, "font": desc_bold_font, "fill": col_k},
        {"kind": "text", "text": " успешно прошел(а) курс ", "font": desc_font, "fill": col_g5},
        {"kind": "tag", "text": course_label, "font": course_tag_font, "fill": col_k, "bg": col_y, "pad_x": S(9), "pad_y": S(2)},
        {"kind": "text", "text": ", продемонстрировав высокий уровень профессиональных компетенций в соответствии с программой обучения iGroup.", "font": desc_font, "fill": col_g5},
    ]
    desc_y = bar_y + S(24)
    _, desc_line_h = _lms_text_size(draw, "Ag", desc_bold_font)
    desc_step = max(S(18), desc_line_h + S(7))
    max_desc_lines = 7
    max_desc_width = rp_right - rp_left
    cursor_x = rp_left
    cursor_y = desc_y
    line_index = 0

    def _desc_new_line():
        nonlocal cursor_x, cursor_y, line_index
        line_index += 1
        cursor_x = rp_left
        cursor_y += desc_step

    for segment in desc_segments:
        if line_index >= max_desc_lines:
            break

        kind = str(segment.get("kind") or "text")
        font = segment.get("font") or desc_font
        fill = segment.get("fill") or col_g5

        if kind == "tag":
            tag_text = str(segment.get("text") or "").strip()
            if not tag_text:
                continue
            tag_bg = segment.get("bg") or col_y
            pad_x = int(segment.get("pad_x") or S(9))
            pad_y = int(segment.get("pad_y") or S(2))
            tag_w, tag_h = _lms_text_size(draw, tag_text, font)
            box_w = tag_w + pad_x * 2

            if cursor_x > rp_left and (cursor_x - rp_left + box_w > max_desc_width):
                _desc_new_line()
            if line_index >= max_desc_lines:
                break

            if box_w > max_desc_width:
                fit_font = _lms_fit_font(
                    draw,
                    tag_text,
                    max(1, max_desc_width - (pad_x * 2)),
                    S(13),
                    S(9),
                    bold=True
                )
                font = fit_font
                tag_w, tag_h = _lms_text_size(draw, tag_text, fit_font)
                box_w = tag_w + pad_x * 2

            rect_top = cursor_y - S(1)
            rect_bottom = cursor_y + tag_h + S(3)
            draw.rectangle((cursor_x, rect_top, cursor_x + box_w, rect_bottom), fill=tag_bg)
            draw.text((cursor_x + pad_x, cursor_y), tag_text, font=font, fill=fill)
            cursor_x += box_w
            continue

        tokens = re.findall(r"\S+|\s+", str(segment.get("text") or ""))
        for token in tokens:
            if line_index >= max_desc_lines:
                break
            token_width, _ = _lms_text_size(draw, token, font)
            if not token_width:
                continue
            if token.strip() and cursor_x > rp_left and (cursor_x - rp_left + token_width > max_desc_width):
                _desc_new_line()
                if line_index >= max_desc_lines:
                    break
            if not token.strip() and cursor_x == rp_left:
                continue
            draw.text((cursor_x, cursor_y), token, font=font, fill=fill)
            cursor_x += token_width

    bottom_divider_y = rp_bottom - S(95)
    sig_top = bottom_divider_y + S(24)

    sig_name_font = _lms_certificate_font(S(11), bold=True)
    sig_role_font = _lms_certificate_font(S(9), bold=False)
    sig_line_w = S(130)
    sig_gap = S(44)
    sig1_x = rp_left
    sig2_x = rp_left + sig_line_w + sig_gap
    sig_name_1 = str(os.getenv("LMS_CERTIFICATE_SIGNER_1_NAME") or "Мулдир Юсупова").strip()
    sig_role_1 = str(os.getenv("LMS_CERTIFICATE_SIGNER_1_ROLE") or "РУКОВОДИТЕЛЬ ПРОГРАММ").strip()
    sig_name_2 = str(os.getenv("LMS_CERTIFICATE_SIGNER_2_NAME") or "Рамазан Алдияр").strip()
    sig_role_2 = str(os.getenv("LMS_CERTIFICATE_SIGNER_2_ROLE") or "ТРЕНЕР").strip()

    signer_1_signature_path = _lms_certificate_signer_1_signature_path()
    if signer_1_signature_path:
        try:
            with Image.open(signer_1_signature_path) as signer_1_sig_source:
                signer_1_sig_rgba = signer_1_sig_source.convert("RGBA")
                resample = Image.Resampling.LANCZOS if hasattr(Image, "Resampling") else Image.LANCZOS
                src_w, src_h = signer_1_sig_rgba.size
                max_sig_w = max(1, sig_line_w + S(10))
                max_sig_h = S(44)
                sig_scale = min(max_sig_w / float(max(1, src_w)), max_sig_h / float(max(1, src_h)))
                dst_sig_w = max(1, int(round(src_w * sig_scale)))
                dst_sig_h = max(1, int(round(src_h * sig_scale)))
                signer_1_sig_rgba = signer_1_sig_rgba.resize((dst_sig_w, dst_sig_h), resample=resample)
                signer_1_sig_alpha = signer_1_sig_rgba.split()[3]
                signer_1_sig_rgba = Image.new("RGBA", (dst_sig_w, dst_sig_h), (0, 0, 0, 0))
                signer_1_sig_rgba.putalpha(signer_1_sig_alpha)
                sig_img_x = sig1_x + int(round((sig_line_w - dst_sig_w) / 2.0))
                sig_img_y = sig_top - dst_sig_h - S(4)
                image.alpha_composite(signer_1_sig_rgba, (sig_img_x, sig_img_y))
        except Exception:
            logging.exception("LMS certificate signer 1 signature render failed")

    draw.line((sig1_x, sig_top, sig1_x + sig_line_w, sig_top), fill=col_k, width=max(1, S(1)))
    draw.text((sig1_x, sig_top + S(8)), sig_name_1, font=sig_name_font, fill=col_k)
    draw.text((sig1_x, sig_top + S(24)), sig_role_1.upper(), font=sig_role_font, fill=col_g4)

    trainer_signature_path = _lms_certificate_trainer_signature_path()
    if trainer_signature_path:
        try:
            with Image.open(trainer_signature_path) as trainer_sig_source:
                trainer_sig_rgba = trainer_sig_source.convert("RGBA")
                resample = Image.Resampling.LANCZOS if hasattr(Image, "Resampling") else Image.LANCZOS
                src_w, src_h = trainer_sig_rgba.size
                max_sig_w = max(1, sig_line_w - S(8))
                max_sig_h = S(34)
                sig_scale = min(max_sig_w / float(max(1, src_w)), max_sig_h / float(max(1, src_h)))
                dst_sig_w = max(1, int(round(src_w * sig_scale)))
                dst_sig_h = max(1, int(round(src_h * sig_scale)))
                trainer_sig_rgba = trainer_sig_rgba.resize((dst_sig_w, dst_sig_h), resample=resample)
                sig_img_x = sig2_x + int(round((sig_line_w - dst_sig_w) / 2.0))
                sig_img_y = sig_top - dst_sig_h - S(4)
                image.alpha_composite(trainer_sig_rgba, (sig_img_x, sig_img_y))
        except Exception:
            logging.exception("LMS certificate trainer signature render failed")

    draw.line((sig2_x, sig_top, sig2_x + sig_line_w, sig_top), fill=col_k, width=max(1, S(1)))
    draw.text((sig2_x, sig_top + S(8)), sig_name_2, font=sig_name_font, fill=col_k)
    draw.text((sig2_x, sig_top + S(24)), sig_role_2.upper(), font=sig_role_font, fill=col_g4)

    date_label_font = _lms_certificate_font(S(8), bold=True)
    date_value_font = _lms_certificate_font(S(18), bold=True)
    date_label = "ДАТА ВЫДАЧИ"
    date_value = issue_date_ru
    date_label_w, _ = _lms_text_size(draw, date_label, date_label_font)
    date_value_w, date_value_h = _lms_text_size(draw, date_value, date_value_font)
    date_x = rp_right - max(date_label_w, date_value_w)
    draw.text((date_x, sig_top), date_label, font=date_label_font, fill=col_g4)
    draw.text((rp_right - date_value_w, sig_top + S(15)), date_value, font=date_value_font, fill=col_k)
    draw.rectangle(
        (rp_right - S(36), sig_top + S(15) + date_value_h + S(7), rp_right, sig_top + S(15) + date_value_h + S(10)),
        fill=col_y
    )

    out = BytesIO()
    image.convert("RGB").save(
        out,
        format="PDF",
        resolution=float(120 * raster_scale),
        quality=100
    )
    return out.getvalue()


def _lms_generate_certificate_pdf(certificate_number, learner_name, course_title, issued_at, score_percent, verify_token):
    issue_dt = issued_at if isinstance(issued_at, datetime) else _lms_now()
    try:
        bold_split_pdf = _lms_build_bold_split_certificate_pdf(
            certificate_number=certificate_number,
            learner_name=learner_name,
            course_title=course_title,
            issued_at=issue_dt
        )
        if bold_split_pdf:
            return bold_split_pdf
    except Exception:
        logging.exception("LMS raster certificate render failed")

    if LMS_CERTIFICATE_ENABLE_HTML_RENDER:
        try:
            html_markup = _lms_build_bold_split_certificate_html(
                certificate_number=certificate_number,
                learner_name=learner_name,
                course_title=course_title,
                issued_at=issue_dt
            )
            html_pdf = _lms_build_pdf_from_html(html_markup)
            if html_pdf:
                return html_pdf
        except Exception:
            logging.exception("LMS HTML certificate render fallback")

    verify_url = _lms_verify_url(verify_token)
    lines = [
        "OTP LMS CERTIFICATE",
        f"Certificate: {certificate_number}",
        f"Learner: {learner_name or '-'}",
        f"Course: {course_title or '-'}",
        f"Issued at: {issue_dt.strftime('%Y-%m-%d %H:%M:%S')}",
        f"Score: {float(score_percent or 0):.2f}%",
        f"QR verify token: {verify_token}",
        f"Verify URL: {verify_url}",
    ]
    return _lms_build_simple_pdf(lines)


def _lms_resolve_request(required_scope='learner'):
    requester_id, requester, error = _resolve_requester()
    if error:
        message, status_code = error
        return None, None, None, jsonify({"error": message}), status_code

    requester_role = _normalize_user_role(requester[3])
    if not _lms_is_allowed_account(requester_id, requester_role):
        return None, None, None, jsonify({"error": "LMS section is restricted for this account"}), 403

    if required_scope == 'learner':
        if requester_role not in LMS_LEARNER_ROLES:
            return None, None, None, jsonify({"error": "Learner role required"}), 403
    elif required_scope == 'manager':
        if requester_role not in LMS_MANAGER_ROLES:
            return None, None, None, jsonify({"error": "Manager role required"}), 403
    elif required_scope == 'full_admin':
        if requester_role not in LMS_FULL_ADMIN_ROLES:
            return None, None, None, jsonify({"error": "Admin role required"}), 403
    elif required_scope == 'manager_or_learner':
        if requester_role not in LMS_MANAGER_ROLES and requester_role not in LMS_LEARNER_ROLES:
            return None, None, None, jsonify({"error": "LMS role required"}), 403

    return requester_id, requester, requester_role, None, None


def _lms_visible_learner_ids(requester_id, requester_role):
    try:
        return db.get_visible_lms_learner_ids_for_requester(requester_id, requester_role)
    except Exception:
        return []


def _lms_material_row_to_payload(row):
    bucket = row[5]
    blob_path = row[6]
    material_type = row[3]
    mime_type = row[8]
    is_video = str(material_type or '').strip().lower() == 'video'
    signed_url = _lms_signed_url(
        bucket,
        blob_path,
        expires_minutes=240,
        response_disposition='inline' if is_video else None,
        response_type=mime_type if is_video and mime_type else None
    )
    return {
        "id": int(row[0]),
        "lesson_id": int(row[1]),
        "title": row[2],
        "material_type": material_type,
        "content_text": row[4],
        "url": signed_url or row[7],
        "content_url": row[7],
        "signed_url": signed_url,
        "bucket": bucket,
        "blob_path": blob_path,
        "gcs_bucket": bucket,
        "gcs_blob_path": blob_path,
        "mime_type": mime_type,
        "metadata": _lms_parse_json(row[9], {}),
        "position": int(row[10] or 1)
    }


def _lms_resolve_lesson_type(raw_lesson_type, materials=None, has_video=None, has_text=None, has_combined_block=None):
    raw = str(raw_lesson_type or '').strip().lower()
    explicit = raw if raw in ('video', 'text', 'combined', 'quiz') else ''

    material_items = materials if isinstance(materials, list) else []
    if has_video is None:
        has_video = any(
            str(item.get('material_type') or item.get('type') or '').strip().lower() == 'video'
            for item in material_items
            if isinstance(item, dict)
        )
    if has_text is None:
        has_text = any(
            str(item.get('material_type') or item.get('type') or '').strip().lower() == 'text'
            for item in material_items
            if isinstance(item, dict)
        )
    if has_combined_block is None:
        has_combined_block = any(
            isinstance(item, dict)
            and isinstance(item.get('metadata'), dict)
            and str(item.get('metadata', {}).get('combined_block') or '').strip().lower() in ('1', 'true', 't', 'yes', 'y')
            for item in material_items
        )

    has_video = bool(has_video)
    has_text = bool(has_text)
    combined_by_structure = bool(has_combined_block) and has_video and has_text

    if explicit == 'quiz':
        return 'quiz'
    if explicit == 'combined':
        return 'combined'
    if combined_by_structure:
        return 'combined'
    if explicit == 'text':
        return 'text'
    if explicit == 'video':
        if (not has_video) and has_text:
            return 'text'
        return 'video'
    if has_video:
        return 'video'
    if has_text:
        return 'text'
    return 'video'


def _lms_close_learning_session_tx(cursor, session_id, ended_at=None):
    resolved_ended_at = ended_at if isinstance(ended_at, datetime) else _lms_now()
    cursor.execute("""
        UPDATE lms_learning_sessions
        SET is_active = FALSE,
            ended_at = COALESCE(ended_at, %s)
        WHERE id = %s
          AND COALESCE(is_active, FALSE) = TRUE
        RETURNING id
    """, (resolved_ended_at, session_id))
    return cursor.fetchone()


def _lms_close_stale_learning_sessions_tx(cursor, assignment_id, lesson_id, user_id, except_session_id=None, stale_before=None):
    params = [assignment_id, lesson_id, user_id]
    where_parts = [
        "assignment_id = %s",
        "lesson_id = %s",
        "user_id = %s",
        "COALESCE(is_active, FALSE) = TRUE",
    ]
    if except_session_id:
        where_parts.append("id <> %s")
        params.append(except_session_id)
    if isinstance(stale_before, datetime):
        where_parts.append("COALESCE(last_heartbeat_at, started_at) < %s")
        params.append(stale_before)
    cursor.execute(f"""
        UPDATE lms_learning_sessions
        SET is_active = FALSE,
            ended_at = COALESCE(ended_at, %s)
        WHERE {" AND ".join(where_parts)}
        RETURNING id
    """, [_lms_now(), *params])
    return [int(row[0]) for row in cursor.fetchall() if row and row[0] is not None]


def _lms_ensure_progress_and_session_tx(cursor, assignment_id, lesson_id, user_id, client_session_key=None):
    now = _lms_now()
    client_session_key = _lms_normalize_client_session_key(client_session_key)
    cursor.execute("""
        SELECT
            id, status, max_position_seconds, confirmed_seconds, completion_ratio,
            active_seconds, last_heartbeat_at, tab_hidden_count, stale_gap_count, started_at, completed_at
        FROM lms_lesson_progress
        WHERE assignment_id = %s AND lesson_id = %s AND user_id = %s
        LIMIT 1
    """, (assignment_id, lesson_id, user_id))
    progress = cursor.fetchone()
    if not progress:
        cursor.execute("""
            INSERT INTO lms_lesson_progress (
                assignment_id, lesson_id, user_id, status, started_at, updated_at
            )
            VALUES (%s, %s, %s, 'in_progress', %s, %s)
            RETURNING
                id, status, max_position_seconds, confirmed_seconds, completion_ratio,
                active_seconds, last_heartbeat_at, tab_hidden_count, stale_gap_count, started_at, completed_at
        """, (assignment_id, lesson_id, user_id, now, now))
        progress = cursor.fetchone()
    elif progress[1] == 'not_started':
        cursor.execute("""
            UPDATE lms_lesson_progress
            SET status = 'in_progress',
                started_at = COALESCE(started_at, %s),
                updated_at = %s
            WHERE id = %s
            RETURNING
                id, status, max_position_seconds, confirmed_seconds, completion_ratio,
                active_seconds, last_heartbeat_at, tab_hidden_count, stale_gap_count, started_at, completed_at
        """, (now, now, progress[0]))
        progress = cursor.fetchone()

    session_where = [
        "assignment_id = %s",
        "lesson_id = %s",
        "user_id = %s",
        "is_active = TRUE",
    ]
    session_params = [assignment_id, lesson_id, user_id]
    if client_session_key:
        session_where.append("client_fingerprint = %s")
        session_params.append(client_session_key)
    else:
        session_where.append("client_fingerprint IS NULL")
    cursor.execute(f"""
        SELECT
            id, started_at, ended_at, last_heartbeat_at, is_active, max_position_seconds,
            confirmed_seconds, active_seconds, tab_hidden_count, stale_gap_count
        FROM lms_learning_sessions
        WHERE {" AND ".join(session_where)}
        ORDER BY id DESC
        LIMIT 1
    """, session_params)
    session = cursor.fetchone()
    if not session:
        stale_before = now - timedelta(seconds=max(int(LMS_STALE_GAP_SECONDS or 0) * 2, int(LMS_HEARTBEAT_SECONDS or 0) * 3, 90))
        _lms_close_stale_learning_sessions_tx(
            cursor,
            assignment_id=assignment_id,
            lesson_id=lesson_id,
            user_id=user_id,
            stale_before=stale_before
        )
        cursor.execute("""
            INSERT INTO lms_learning_sessions (
                assignment_id, lesson_id, user_id, started_at, last_heartbeat_at, last_visible_at, is_active, client_fingerprint
            )
            VALUES (%s, %s, %s, %s, %s, %s, TRUE, %s)
            RETURNING
                id, started_at, ended_at, last_heartbeat_at, is_active, max_position_seconds,
                confirmed_seconds, active_seconds, tab_hidden_count, stale_gap_count
        """, (assignment_id, lesson_id, user_id, now, now, now, client_session_key))
        session = cursor.fetchone()

    return progress, session


def _lms_get_lesson_context_tx(cursor, user_id, lesson_id, client_session_key=None):
    cursor.execute("""
        SELECT
            a.id as assignment_id,
            a.course_id,
            a.course_version_id,
            a.status,
            a.due_at,
            l.id as lesson_id,
            l.title,
            l.description,
            l.duration_seconds,
            COALESCE(l.allow_fast_forward, FALSE),
            COALESCE(l.completion_threshold, %s),
            m.title as module_title,
            COALESCE(NULLIF(TRIM(LOWER(l.lesson_type)), ''), 'video') AS lesson_type,
            COALESCE(ms.has_video, FALSE) AS has_video_material,
            COALESCE(ms.has_text, FALSE) AS has_text_material,
            COALESCE(ms.has_combined_block, FALSE) AS has_combined_block,
            vm.metadata as video_metadata
        FROM lms_lessons l
        JOIN lms_modules m ON m.id = l.module_id
        JOIN lms_course_versions cv ON cv.id = m.course_version_id
           AND cv.status = 'published'
        JOIN lms_course_assignments a
            ON a.course_version_id = cv.id
           AND a.user_id = %s
        JOIN lms_courses c
            ON c.id = a.course_id
           AND c.status = 'published'
        LEFT JOIN LATERAL (
            SELECT metadata
            FROM lms_lesson_materials lm
            WHERE lm.lesson_id = l.id
              AND lm.material_type = 'video'
            ORDER BY lm.position ASC, lm.id ASC
            LIMIT 1
        ) vm ON TRUE
        LEFT JOIN LATERAL (
            SELECT
                BOOL_OR(lm.material_type = 'video') AS has_video,
                BOOL_OR(lm.material_type = 'text') AS has_text,
                BOOL_OR(
                    COALESCE(LOWER(lm.metadata->>'combined_block'), '') IN ('1', 'true', 't', 'yes', 'y')
                ) AS has_combined_block
            FROM lms_lesson_materials lm
            WHERE lm.lesson_id = l.id
        ) ms ON TRUE
        WHERE l.id = %s
        LIMIT 1
    """, (LMS_COMPLETION_THRESHOLD, user_id, lesson_id))
    row = cursor.fetchone()
    if not row:
        return None

    assignment_id = int(row[0])
    lesson_id = int(row[5])
    lesson_duration_seconds = max(0.0, _lms_to_float(row[8], 0.0))
    lesson_type = _lms_resolve_lesson_type(
        row[12],
        has_video=bool(row[13]),
        has_text=bool(row[14]),
        has_combined_block=bool(row[15]),
    )
    video_metadata = _lms_parse_json(row[16], {})
    if isinstance(video_metadata, dict):
        video_duration_seconds = max(0.0, _lms_to_float(video_metadata.get("duration_seconds"), 0.0))
        if video_duration_seconds > 0:
            lesson_duration_seconds = video_duration_seconds
    progress, session = _lms_ensure_progress_and_session_tx(
        cursor,
        assignment_id,
        lesson_id,
        int(user_id),
        client_session_key=client_session_key
    )
    return {
        "assignment_id": assignment_id,
        "course_id": int(row[1]),
        "course_version_id": int(row[2]),
        "assignment_status": row[3],
        "due_at": row[4],
        "lesson_id": lesson_id,
        "lesson_title": row[6],
        "lesson_description": row[7],
        "duration_seconds": lesson_duration_seconds,
        "allow_fast_forward": bool(row[9]),
        "completion_threshold": float(row[10] or LMS_COMPLETION_THRESHOLD),
        "module_title": row[11],
        "lesson_type": lesson_type,
        "progress": progress,
        "session": session
    }


def _lms_try_issue_certificate_tx(cursor, assignment_id, user_id, score_percent=None, test_attempt_id=None):
    cursor.execute("""
        SELECT id, certificate_number, verify_token, status, issued_at, metadata, score_percent
        FROM lms_certificates
        WHERE assignment_id = %s
          AND user_id = %s
        ORDER BY id DESC
        LIMIT 1
    """, (assignment_id, user_id))
    existing = cursor.fetchone()
    if existing and existing[3] == 'active':
        existing_metadata = _lms_parse_json(existing[5], {})
        if not isinstance(existing_metadata, dict):
            existing_metadata = {}

        if _lms_certificate_metadata_needs_refresh(existing_metadata):
            cursor.execute("""
                SELECT a.course_id, c.title, u.name
                FROM lms_course_assignments a
                JOIN lms_courses c ON c.id = a.course_id
                JOIN users u ON u.id = a.user_id
                WHERE a.id = %s AND a.user_id = %s
                LIMIT 1
            """, (assignment_id, user_id))
            base = cursor.fetchone()
            if base:
                refresh_issued_at = existing[4] if isinstance(existing[4], datetime) else _lms_now()
                refresh_score = score_percent if score_percent is not None else existing[6]
                refresh_pdf_bytes = _lms_generate_certificate_pdf(
                    certificate_number=existing[1],
                    learner_name=base[2],
                    course_title=base[1],
                    issued_at=refresh_issued_at,
                    score_percent=refresh_score,
                    verify_token=existing[2]
                )
                refreshed_metadata = dict(existing_metadata)
                refreshed_metadata["verify_url"] = _lms_verify_url(existing[2])
                refreshed_metadata["template_version"] = LMS_CERTIFICATE_TEMPLATE_VERSION
                _lms_update_certificate_pdf_tx(
                    cursor,
                    certificate_id=existing[0],
                    certificate_number=existing[1],
                    issued_at=refresh_issued_at,
                    pdf_bytes=refresh_pdf_bytes,
                    metadata=refreshed_metadata
                )
        return {
            "id": int(existing[0]),
            "certificate_number": existing[1],
            "verify_token": existing[2],
            "status": existing[3],
            "issued_at": existing[4]
        }

    cursor.execute("""
        SELECT a.course_id, c.title, u.name
        FROM lms_course_assignments a
        JOIN lms_courses c ON c.id = a.course_id
        JOIN users u ON u.id = a.user_id
        WHERE a.id = %s AND a.user_id = %s
        LIMIT 1
    """, (assignment_id, user_id))
    base = cursor.fetchone()
    if not base:
        return None

    course_id = int(base[0])
    course_title = base[1]
    learner_name = base[2]
    issued_at = _lms_now()

    certificate_number = None
    for _ in range(5):
        candidate = f"OTP-LMS-{issued_at.strftime('%Y%m%d')}-{secrets.token_hex(4).upper()}"
        cursor.execute("SELECT id FROM lms_certificates WHERE certificate_number = %s LIMIT 1", (candidate,))
        if not cursor.fetchone():
            certificate_number = candidate
            break
    if not certificate_number:
        certificate_number = f"OTP-LMS-{issued_at.strftime('%Y%m%d%H%M%S')}-{secrets.token_hex(3).upper()}"

    verify_token = secrets.token_urlsafe(24).replace('-', '').replace('_', '')
    pdf_bytes = _lms_generate_certificate_pdf(
        certificate_number=certificate_number,
        learner_name=learner_name,
        course_title=course_title,
        issued_at=issued_at,
        score_percent=score_percent,
        verify_token=verify_token
    )

    storage_type, pdf_data, gcs_bucket, gcs_blob_path = _lms_store_certificate_pdf_payload(
        certificate_number=certificate_number,
        issued_at=issued_at,
        pdf_bytes=pdf_bytes
    )

    cursor.execute("""
        INSERT INTO lms_certificates (
            assignment_id, course_id, user_id, test_attempt_id,
            certificate_number, verify_token, score_percent, status, issued_at,
            pdf_storage_type, pdf_data, gcs_bucket, gcs_blob_path, metadata
        )
        VALUES (%s, %s, %s, %s, %s, %s, %s, 'active', %s, %s, %s, %s, %s, %s::jsonb)
        RETURNING id
    """, (
        assignment_id,
        course_id,
        user_id,
        (int(test_attempt_id) if test_attempt_id is not None else None),
        certificate_number,
        verify_token,
        (float(score_percent) if score_percent is not None else None),
        issued_at,
        storage_type,
        pdf_data,
        gcs_bucket,
        gcs_blob_path,
        json.dumps({
            "verify_url": _lms_verify_url(verify_token),
            "template_version": LMS_CERTIFICATE_TEMPLATE_VERSION
        }, ensure_ascii=False)
    ))
    cert_id = int(cursor.fetchone()[0])

    _lms_emit_notification(
        cursor,
        user_id=user_id,
        notification_type='certificate',
        title='Сертификат сформирован',
        message=f"Курс «{course_title}» завершен. Сертификат #{certificate_number} доступен для скачивания.",
        payload={"certificate_id": cert_id, "verify_token": verify_token}
    )
    return {
        "id": cert_id,
        "certificate_number": certificate_number,
        "verify_token": verify_token,
        "status": "active",
        "issued_at": issued_at
    }


def _lms_try_complete_assignment_tx(cursor, assignment_id, user_id, score_percent=None, test_attempt_id=None):
    cursor.execute("""
        SELECT id, course_id, course_version_id, due_at, status, completed_at
        FROM lms_course_assignments
        WHERE id = %s AND user_id = %s
        LIMIT 1
    """, (assignment_id, user_id))
    assignment = cursor.fetchone()
    if not assignment:
        return {"completed": False, "reason": "ASSIGNMENT_NOT_FOUND"}

    course_version_id = assignment[2]
    due_at = assignment[3]
    existing_completed_at = assignment[5]

    cursor.execute("""
        SELECT COUNT(*)
        FROM lms_lessons l
        JOIN lms_modules m ON m.id = l.module_id
        WHERE m.course_version_id = %s
    """, (course_version_id,))
    total_lessons = int(cursor.fetchone()[0] or 0)

    cursor.execute("""
        SELECT COUNT(*)
        FROM lms_lesson_progress
        WHERE assignment_id = %s
          AND user_id = %s
          AND status = 'completed'
    """, (assignment_id, user_id))
    completed_lessons = int(cursor.fetchone()[0] or 0)

    if total_lessons > 0 and completed_lessons < total_lessons:
        return {
            "completed": False,
            "reason": "LESSONS_INCOMPLETE",
            "total_lessons": total_lessons,
            "completed_lessons": completed_lessons
        }

    cursor.execute("""
        SELECT
            COUNT(*) AS total_tests,
            COUNT(*) FILTER (WHERE COALESCE(is_final, FALSE) = TRUE) AS total_final_tests
        FROM lms_tests
        WHERE course_version_id = %s
          AND status <> 'archived'
    """, (course_version_id,))
    tests_count_row = cursor.fetchone() or (0, 0)
    total_tests = int(tests_count_row[0] or 0)
    total_final_tests = int(tests_count_row[1] or 0)
    require_final_only = total_final_tests > 0
    required_tests = total_final_tests if require_final_only else total_tests

    cursor.execute("""
        SELECT COUNT(DISTINCT ta.test_id)
        FROM lms_test_attempts ta
        JOIN lms_tests t ON t.id = ta.test_id
        WHERE ta.assignment_id = %s
          AND ta.user_id = %s
          AND ta.passed = TRUE
          AND t.course_version_id = %s
          AND (%s::boolean = FALSE OR COALESCE(t.is_final, FALSE) = TRUE)
    """, (assignment_id, user_id, course_version_id, require_final_only))
    passed_tests = int(cursor.fetchone()[0] or 0)

    if required_tests > 0 and passed_tests < required_tests:
        return {
            "completed": False,
            "reason": "TESTS_INCOMPLETE",
            "total_tests": required_tests,
            "passed_tests": passed_tests
        }

    completed_at = existing_completed_at or _lms_now()
    deadline_status = _lms_deadline_status(due_at, completed_at)
    cursor.execute("""
        UPDATE lms_course_assignments
        SET status = 'completed',
            completed_at = %s,
            completion_color_status = %s,
            updated_at = %s
        WHERE id = %s
    """, (completed_at, deadline_status, _lms_now(), assignment_id))

    certificate = _lms_try_issue_certificate_tx(
        cursor,
        assignment_id=assignment_id,
        user_id=user_id,
        score_percent=score_percent,
        test_attempt_id=test_attempt_id
    )

    return {
        "completed": True,
        "completed_at": completed_at,
        "deadline_status": deadline_status,
        "certificate": certificate
    }


def _lms_fetch_test_questions_tx(cursor, test_id, include_correct=False):
    cursor.execute("""
        SELECT id, question_type, prompt, points, position, required, metadata, correct_text_answers
        FROM lms_questions
        WHERE test_id = %s
        ORDER BY position ASC, id ASC
    """, (test_id,))
    question_rows = cursor.fetchall()
    questions = []
    for q in question_rows:
        q_id = int(q[0])
        q_type = str(q[1] or '').strip().lower()
        cursor.execute("""
            SELECT id, option_key, option_text, position, is_correct, match_key, metadata
            FROM lms_question_options
            WHERE question_id = %s
            ORDER BY position ASC, id ASC
        """, (q_id,))
        option_rows = cursor.fetchall()
        options = []
        for opt in option_rows:
            item = {
                "id": int(opt[0]),
                "key": opt[1],
                "text": opt[2],
                "position": int(opt[3] or 1),
                "metadata": _lms_parse_json(opt[6], {})
            }
            if include_correct:
                item["is_correct"] = bool(opt[4])
                item["match_key"] = opt[5]
            options.append(item)

        question_payload = {
            "id": q_id,
            "type": q_type,
            "prompt": q[2],
            "points": float(q[3] or 1.0),
            "position": int(q[4] or 1),
            "required": bool(q[5]),
            "metadata": _lms_parse_json(q[6], {}),
            "options": options
        }
        if include_correct:
            question_payload["correct_text_answers"] = _lms_parse_json(q[7], [])
        questions.append(question_payload)
    return questions


def _lms_parse_question_ids(raw_value):
    raw_list = _lms_parse_json(raw_value, [])
    if not isinstance(raw_list, list):
        return []
    out = []
    for value in raw_list:
        try:
            parsed = int(value)
        except Exception:
            continue
        if parsed > 0 and parsed not in out:
            out.append(parsed)
    return out


def _lms_extract_selected_option_ids(answer_payload):
    selected = []
    payload = answer_payload
    if isinstance(payload, dict):
        if isinstance(payload.get('option_ids'), list):
            selected.extend(payload.get('option_ids') or [])
        elif payload.get('option_id') is not None:
            selected.append(payload.get('option_id'))
        elif isinstance(payload.get('value'), list):
            selected.extend(payload.get('value') or [])
        elif payload.get('value') is not None:
            selected.append(payload.get('value'))
    elif isinstance(payload, list):
        selected.extend(payload)
    elif payload is not None:
        selected.append(payload)

    out = []
    for value in selected:
        try:
            parsed = int(value)
        except Exception:
            continue
        if parsed not in out:
            out.append(parsed)
    return out


def _lms_answer_to_matching_map(answer_payload):
    if isinstance(answer_payload, dict):
        pairs = answer_payload.get('pairs')
        if isinstance(pairs, dict):
            return {str(k): str(v) for k, v in pairs.items()}
        if isinstance(pairs, list):
            mapped = {}
            for item in pairs:
                if not isinstance(item, dict):
                    continue
                left = item.get('left')
                right = item.get('right')
                if left in (None, ''):
                    continue
                mapped[str(left)] = str(right) if right is not None else ''
            return mapped
    if isinstance(answer_payload, list):
        mapped = {}
        for item in answer_payload:
            if not isinstance(item, dict):
                continue
            left = item.get('left')
            right = item.get('right')
            if left in (None, ''):
                continue
            mapped[str(left)] = str(right) if right is not None else ''
        return mapped
    return {}


def _lms_finalize_attempt_tx(cursor, attempt_id, user_id):
    cursor.execute("""
        SELECT
            ta.id, ta.assignment_id, ta.test_id, ta.user_id, ta.status, ta.started_at, ta.question_ids,
            t.title, t.pass_threshold, t.attempt_limit
        FROM lms_test_attempts ta
        JOIN lms_tests t ON t.id = ta.test_id
        WHERE ta.id = %s AND ta.user_id = %s
        LIMIT 1
    """, (attempt_id, user_id))
    attempt = cursor.fetchone()
    if not attempt:
        return None

    if attempt[4] != 'in_progress':
        cursor.execute("""
            SELECT score_percent, passed, finished_at, status
            FROM lms_test_attempts
            WHERE id = %s
        """, (attempt_id,))
        ready = cursor.fetchone()
        return {
            "attempt_id": int(attempt_id),
            "assignment_id": int(attempt[1]),
            "test_id": int(attempt[2]),
            "status": ready[3] if ready else attempt[4],
            "score_percent": float(ready[0] or 0.0) if ready else 0.0,
            "passed": bool(ready[1]) if ready and ready[1] is not None else False,
            "finished_at": ready[2] if ready else None,
            "already_finished": True
        }

    questions = _lms_fetch_test_questions_tx(cursor, int(attempt[2]), include_correct=True)
    selected_question_ids = _lms_parse_question_ids(attempt[6])
    if selected_question_ids:
        question_map = {int(item.get('id')): item for item in questions}
        selected_questions = [question_map[qid] for qid in selected_question_ids if qid in question_map]
        if selected_questions:
            questions = selected_questions

    cursor.execute("""
        SELECT question_id, answer_payload
        FROM lms_test_attempt_answers
        WHERE attempt_id = %s
    """, (attempt_id,))
    raw_answers = cursor.fetchall()
    answer_by_q = {}
    for row in raw_answers:
        answer_by_q[int(row[0])] = _lms_parse_json(row[1], {})

    total_points = 0.0
    scored_points = 0.0
    breakdown = []

    for question in questions:
        q_id = int(question['id'])
        q_type = str(question.get('type') or '').strip().lower()
        q_points = float(question.get('points') or 1.0)
        total_points += q_points
        payload = answer_by_q.get(q_id, {})
        is_correct = False

        if q_type in ('single', 'multiple'):
            expected = [int(opt['id']) for opt in question.get('options', []) if opt.get('is_correct')]
            expected_set = set(expected)
            selected_set = set(_lms_extract_selected_option_ids(payload))
            is_correct = selected_set == expected_set and (q_type != 'single' or len(selected_set) == 1)
        elif q_type == 'true_false':
            expected_options = [opt for opt in question.get('options', []) if opt.get('is_correct')]
            expected_bool = None
            if expected_options:
                text = _lms_normalize_text(expected_options[0].get('text'))
                expected_bool = text in ('true', 'верно', 'истина', 'да')
            if expected_bool is None:
                expected_bool = _lms_parse_bool((question.get('metadata') or {}).get('correct'), False)

            selected_bool = None
            if isinstance(payload, dict):
                if 'value' in payload:
                    selected_bool = _lms_parse_bool(payload.get('value'), False)
                elif 'answer' in payload:
                    selected_bool = _lms_parse_bool(payload.get('answer'), False)
                elif payload.get('option_id') is not None:
                    selected = _lms_extract_selected_option_ids(payload)
                    if selected:
                        option_map = {int(opt['id']): opt for opt in question.get('options', [])}
                        selected_option = option_map.get(int(selected[0]))
                        if selected_option:
                            selected_bool = _lms_normalize_text(selected_option.get('text')) in ('true', 'верно', 'истина', 'да')
            elif isinstance(payload, bool):
                selected_bool = payload

            if selected_bool is not None:
                is_correct = (selected_bool == expected_bool)
        elif q_type == 'matching':
            expected_map = {}
            for opt in question.get('options', []):
                key = opt.get('key')
                match_key = opt.get('match_key')
                if key not in (None, '') and match_key not in (None, ''):
                    expected_map[str(key)] = str(match_key)
            if not expected_map:
                for pair in (question.get('metadata') or {}).get('pairs', []):
                    if not isinstance(pair, dict):
                        continue
                    left = pair.get('left')
                    right = pair.get('right')
                    if left in (None, '') or right in (None, ''):
                        continue
                    expected_map[str(left)] = str(right)
            answer_map = _lms_answer_to_matching_map(payload)
            is_correct = bool(expected_map) and answer_map == expected_map
        elif q_type == 'text':
            accepted = question.get('correct_text_answers') or []
            if not accepted:
                accepted = (question.get('metadata') or {}).get('accepted_answers') or []
            normalized_accepted = {_lms_normalize_answer_text(item) for item in accepted if str(item or '').strip()}
            submitted = ''
            if isinstance(payload, dict):
                submitted = payload.get('text') or payload.get('value') or payload.get('answer') or ''
            else:
                submitted = payload
            submitted_norm = _lms_normalize_answer_text(submitted)
            is_correct = bool(submitted_norm) and submitted_norm in normalized_accepted

        points_awarded = q_points if is_correct else 0.0
        scored_points += points_awarded
        cursor.execute("""
            INSERT INTO lms_test_attempt_answers (
                attempt_id, question_id, answer_payload, is_correct, points_awarded, answered_at
            )
            VALUES (%s, %s, %s::jsonb, %s, %s, %s)
            ON CONFLICT (attempt_id, question_id)
            DO UPDATE SET
                answer_payload = EXCLUDED.answer_payload,
                is_correct = EXCLUDED.is_correct,
                points_awarded = EXCLUDED.points_awarded,
                answered_at = EXCLUDED.answered_at
        """, (
            attempt_id,
            q_id,
            json.dumps(payload, ensure_ascii=False),
            is_correct,
            points_awarded,
            _lms_now()
        ))

        breakdown.append({
            "question_id": q_id,
            "type": q_type,
            "is_correct": is_correct,
            "points_awarded": points_awarded,
            "points_total": q_points
        })

    score_percent = 0.0
    if total_points > 0:
        score_percent = round((scored_points / total_points) * 100.0, 2)

    pass_threshold = float(attempt[8] if attempt[8] is not None else LMS_DEFAULT_PASS_THRESHOLD)
    passed = score_percent >= pass_threshold
    finished_at = _lms_now()
    started_at = attempt[5]
    duration_seconds = None
    if isinstance(started_at, datetime):
        duration_seconds = max(0, int((finished_at - started_at).total_seconds()))

    cursor.execute("""
        UPDATE lms_test_attempts
        SET status = 'finished',
            score_percent = %s,
            passed = %s,
            finished_at = %s,
            duration_seconds = %s
        WHERE id = %s
    """, (score_percent, passed, finished_at, duration_seconds, attempt_id))

    completion = _lms_try_complete_assignment_tx(
        cursor,
        assignment_id=int(attempt[1]),
        user_id=int(user_id),
        score_percent=score_percent if passed else None,
        test_attempt_id=int(attempt_id) if passed else None
    )

    title = 'Тест пройден' if passed else 'Тест не пройден'
    text = (
        f"Результат: {score_percent:.2f}% (порог {pass_threshold:.2f}%)."
        + (" Поздравляем!" if passed else " Можно попробовать снова, если есть попытки.")
    )
    _lms_emit_notification(
        cursor,
        user_id=user_id,
        notification_type='test_result',
        title=title,
        message=text,
        payload={
            "attempt_id": int(attempt_id),
            "test_id": int(attempt[2]),
            "score_percent": score_percent,
            "passed": passed
        }
    )

    return {
        "attempt_id": int(attempt_id),
        "assignment_id": int(attempt[1]),
        "test_id": int(attempt[2]),
        "status": "finished",
        "score_percent": score_percent,
        "pass_threshold": pass_threshold,
        "passed": passed,
        "finished_at": finished_at,
        "duration_seconds": duration_seconds,
        "total_points": round(total_points, 2),
        "scored_points": round(scored_points, 2),
        "breakdown": breakdown,
        "assignment_completion": completion
    }


def _lms_course_structure_tx(cursor, course_id, course_version_id, include_test_questions=False, include_correct_answers=False):
    cursor.execute("""
        SELECT
            c.id, c.title, c.description, c.category, c.status,
            c.default_pass_threshold, c.default_attempt_limit,
            cv.id, cv.version_number, cv.status, cv.pass_threshold, cv.attempt_limit,
            cv.anti_cheat_settings
        FROM lms_courses c
        JOIN lms_course_versions cv ON cv.id = %s AND cv.course_id = c.id
        WHERE c.id = %s
        LIMIT 1
    """, (course_version_id, course_id))
    header = cursor.fetchone()
    if not header:
        return None

    cursor.execute("""
        SELECT id, title, description, position
        FROM lms_modules
        WHERE course_version_id = %s
        ORDER BY position ASC, id ASC
    """, (course_version_id,))
    modules_rows = cursor.fetchall()

    cursor.execute("""
        SELECT
            l.id, l.module_id, l.title, l.description, l.position,
            l.duration_seconds, COALESCE(l.allow_fast_forward, FALSE), COALESCE(l.completion_threshold, %s),
            COALESCE(NULLIF(TRIM(LOWER(l.lesson_type)), ''), 'video') AS lesson_type
        FROM lms_lessons l
        JOIN lms_modules m ON m.id = l.module_id
        WHERE m.course_version_id = %s
        ORDER BY m.position ASC, l.position ASC, l.id ASC
    """, (LMS_COMPLETION_THRESHOLD, course_version_id))
    lessons_rows = cursor.fetchall()

    cursor.execute("""
        SELECT
            id, lesson_id, title, material_type, content_text, gcs_bucket, gcs_blob_path,
            content_url, mime_type, metadata, position
        FROM lms_lesson_materials
        WHERE lesson_id IN (
            SELECT l.id
            FROM lms_lessons l
            JOIN lms_modules m ON m.id = l.module_id
            WHERE m.course_version_id = %s
        )
        ORDER BY position ASC, id ASC
    """, (course_version_id,))
    material_rows = cursor.fetchall()

    cursor.execute("""
        SELECT
            id, module_id, position, source_lesson_id, title, description, pass_threshold, attempt_limit,
            time_limit_minutes, question_count, random_order, is_final, status
        FROM lms_tests
        WHERE course_version_id = %s
          AND status <> 'archived'
        ORDER BY module_id ASC NULLS LAST, COALESCE(position, 2147483647) ASC, id ASC
    """, (course_version_id,))
    tests_rows = cursor.fetchall()

    material_by_lesson = {}
    for row in material_rows:
        material_by_lesson.setdefault(int(row[1]), []).append(_lms_material_row_to_payload(row))

    lessons_by_module = {}
    for row in lessons_rows:
        lesson_id = int(row[0])
        module_id = int(row[1])
        lesson_materials = material_by_lesson.get(lesson_id, [])
        lesson_type = _lms_resolve_lesson_type(row[8], materials=lesson_materials)
        combined_blocks = []
        if lesson_type == 'combined':
            for material in lesson_materials:
                block_type = str(material.get("material_type") or "").strip().lower()
                if block_type not in ("text", "video"):
                    continue
                combined_blocks.append({
                    "id": int(material.get("id") or 0) or None,
                    "type": block_type,
                    "title": material.get("title"),
                    "content_text": material.get("content_text"),
                    "content_url": material.get("content_url") or material.get("url"),
                    "url": material.get("url"),
                    "signed_url": material.get("signed_url"),
                    "mime_type": material.get("mime_type"),
                    "bucket": material.get("bucket"),
                    "blob_path": material.get("blob_path"),
                    "metadata": material.get("metadata") if isinstance(material.get("metadata"), dict) else {},
                    "position": int(material.get("position") or 1),
                })
        lessons_by_module.setdefault(module_id, []).append({
            "id": lesson_id,
            "module_id": module_id,
            "title": row[2],
            "description": row[3],
            "position": int(row[4] or 1),
            "duration_seconds": int(row[5] or 0),
            "allow_fast_forward": bool(row[6]),
            "completion_threshold": float(row[7] or LMS_COMPLETION_THRESHOLD),
            "lesson_type": lesson_type,
            "materials": lesson_materials,
            "blocks": combined_blocks
        })

    modules = []
    for row in modules_rows:
        module_id = int(row[0])
        modules.append({
            "id": module_id,
            "title": row[1],
            "description": row[2],
            "position": int(row[3] or 1),
            "lessons": lessons_by_module.get(module_id, [])
        })

    tests = []
    for row in tests_rows:
        test_id = int(row[0])
        questions = []
        question_type_breakdown = {}
        if include_test_questions:
            questions = _lms_fetch_test_questions_tx(cursor, test_id, include_correct=include_correct_answers)
            question_bank_count = len(questions)
            for question in questions:
                q_type = str(question.get("type") or "").strip().lower() or "single"
                question_type_breakdown[q_type] = int(question_type_breakdown.get(q_type, 0)) + 1
        else:
            cursor.execute("""
                SELECT question_type, COUNT(*)
                FROM lms_questions
                WHERE test_id = %s
                GROUP BY question_type
            """, (test_id,))
            question_rows = cursor.fetchall()
            question_bank_count = 0
            for q_row in question_rows:
                q_type = str(q_row[0] or "").strip().lower() or "single"
                q_count = int(q_row[1] or 0)
                question_bank_count += q_count
                question_type_breakdown[q_type] = q_count
        configured_question_count = _lms_to_int(row[9], 0)
        effective_question_count = question_bank_count
        if configured_question_count > 0:
            effective_question_count = min(question_bank_count, configured_question_count)
        test_payload = {
            "id": test_id,
            "module_id": int(row[1]) if row[1] is not None else None,
            "position": int(row[2]) if row[2] is not None else None,
            "source_lesson_id": int(row[3]) if row[3] is not None else None,
            "title": row[4],
            "description": row[5],
            "pass_threshold": float(row[6] if row[6] is not None else LMS_DEFAULT_PASS_THRESHOLD),
            "attempt_limit": int(row[7] if row[7] is not None else LMS_DEFAULT_ATTEMPT_LIMIT),
            "time_limit_minutes": int(row[8]) if row[8] is not None else None,
            "question_count": effective_question_count,
            "question_bank_count": question_bank_count,
            "question_type_breakdown": question_type_breakdown,
            "question_types": [q_type for q_type, q_count in question_type_breakdown.items() if int(q_count or 0) > 0],
            "random_order": _lms_parse_bool(row[10], True),
            "is_final": bool(row[11]),
            "status": row[12]
        }
        if include_test_questions:
            test_payload["questions"] = questions
        tests.append(test_payload)

    version_settings = _lms_parse_json(header[12], {})
    cover_payload = _lms_resolve_cover_payload(version_settings)
    return {
        "id": int(header[0]),
        "title": header[1],
        "description": header[2],
        "category": header[3],
        "status": header[4],
        "default_pass_threshold": float(header[5] if header[5] is not None else LMS_DEFAULT_PASS_THRESHOLD),
        "default_attempt_limit": int(header[6] if header[6] is not None else LMS_DEFAULT_ATTEMPT_LIMIT),
        "course_version": {
            "id": int(header[7]),
            "version_number": int(header[8] or 1),
            "status": header[9],
            "pass_threshold": float(header[10] if header[10] is not None else LMS_DEFAULT_PASS_THRESHOLD),
            "attempt_limit": int(header[11] if header[11] is not None else LMS_DEFAULT_ATTEMPT_LIMIT),
            "cover_url": cover_payload["cover_url"],
            "cover_bucket": cover_payload["cover_bucket"],
            "cover_blob_path": cover_payload["cover_blob_path"],
            "skills": _lms_normalize_skills(version_settings.get("skills"))
        },
        "modules": modules,
        "tests": tests
    }


def _lms_course_versions_history_tx(cursor, course_id, current_version_id=None):
    cursor.execute("""
        SELECT
            cv.id,
            cv.version_number,
            cv.status,
            cv.created_by,
            cv.created_at,
            cv.published_by,
            cv.published_at,
            cv.pass_threshold,
            cv.attempt_limit,
            COALESCE(mods.module_count, 0) AS modules_count,
            COALESCE(lessons.lesson_count, 0) AS lessons_count,
            COALESCE(tests.test_count, 0) AS tests_count,
            COALESCE(questions.question_count, 0) AS questions_count
        FROM lms_course_versions cv
        LEFT JOIN (
            SELECT m.course_version_id, COUNT(*) AS module_count
            FROM lms_modules m
            GROUP BY m.course_version_id
        ) mods ON mods.course_version_id = cv.id
        LEFT JOIN (
            SELECT m.course_version_id, COUNT(*) AS lesson_count
            FROM lms_lessons l
            JOIN lms_modules m ON m.id = l.module_id
            GROUP BY m.course_version_id
        ) lessons ON lessons.course_version_id = cv.id
        LEFT JOIN (
            SELECT t.course_version_id, COUNT(*) FILTER (WHERE t.status <> 'archived') AS test_count
            FROM lms_tests t
            GROUP BY t.course_version_id
        ) tests ON tests.course_version_id = cv.id
        LEFT JOIN (
            SELECT t.course_version_id, COUNT(*) AS question_count
            FROM lms_questions q
            JOIN lms_tests t ON t.id = q.test_id
            WHERE t.status <> 'archived'
            GROUP BY t.course_version_id
        ) questions ON questions.course_version_id = cv.id
        WHERE cv.course_id = %s
        ORDER BY cv.version_number DESC, cv.id DESC
    """, (course_id,))
    rows = cursor.fetchall()
    normalized_current_version_id = int(current_version_id) if current_version_id is not None else None
    items = []
    for row in rows:
        version_id = int(row[0])
        items.append({
            "id": version_id,
            "version_number": int(row[1] or 1),
            "status": row[2],
            "is_current": normalized_current_version_id is not None and version_id == normalized_current_version_id,
            "created_by": int(row[3]) if row[3] is not None else None,
            "created_at": row[4].isoformat() if row[4] else None,
            "published_by": int(row[5]) if row[5] is not None else None,
            "published_at": row[6].isoformat() if row[6] else None,
            "pass_threshold": float(row[7] if row[7] is not None else LMS_DEFAULT_PASS_THRESHOLD),
            "attempt_limit": int(row[8] if row[8] is not None else LMS_DEFAULT_ATTEMPT_LIMIT),
            "modules_count": int(row[9] or 0),
            "lessons_count": int(row[10] or 0),
            "tests_count": int(row[11] or 0),
            "questions_count": int(row[12] or 0)
        })
    return items


def _lms_insert_course_structure_tx(cursor, requester_id, version_id, modules, tests, pass_threshold, attempt_limit, now):
    created_module_ids = []
    module_by_source_id = {}
    module_by_position = {}
    lesson_by_source_id = {}

    for module_index, module in enumerate(modules, start=1):
        if not isinstance(module, dict):
            continue
        module_title = str(module.get('title') or '').strip()
        if not module_title:
            continue
        module_desc = str(module.get('description') or '').strip() or None
        module_pos = max(1, _lms_to_int(module.get('position'), module_index))
        cursor.execute("""
            INSERT INTO lms_modules (course_version_id, title, description, position, created_at)
            VALUES (%s, %s, %s, %s, %s)
            RETURNING id
        """, (version_id, module_title, module_desc, module_pos, now))
        module_id = int(cursor.fetchone()[0])
        created_module_ids.append(module_id)
        module_by_position[module_pos] = module_id

        source_module_id = _lms_to_int(module.get('id'), 0)
        if source_module_id > 0:
            module_by_source_id[source_module_id] = module_id

        lessons = module.get('lessons') if isinstance(module.get('lessons'), list) else []
        for lesson_index, lesson in enumerate(lessons, start=1):
            if not isinstance(lesson, dict):
                continue
            lesson_title = str(lesson.get('title') or '').strip()
            if not lesson_title:
                continue
            lesson_desc = str(lesson.get('description') or '').strip() or None
            lesson_type = str(lesson.get('lesson_type') or lesson.get('type') or '').strip().lower()
            if lesson_type not in ('video', 'text', 'combined'):
                lesson_type = 'video'
            lesson_materials = lesson.get('materials') if isinstance(lesson.get('materials'), list) else []
            lesson_blocks = lesson.get('blocks') if isinstance(lesson.get('blocks'), list) else []
            if lesson_type == 'combined':
                combined_materials = []
                for block_index, block in enumerate(lesson_blocks, start=1):
                    if not isinstance(block, dict):
                        continue
                    block_type = str(block.get('type') or block.get('material_type') or '').strip().lower()
                    if block_type not in ('text', 'video'):
                        continue
                    block_title = str(block.get('title') or '').strip()
                    if not block_title:
                        block_title = "Текстовый блок" if block_type == 'text' else f"Видео блок {block_index}"
                    block_content_text = str(block.get('content_text') or '').strip() or None
                    block_content_url = str(block.get('content_url') or block.get('signed_url') or block.get('url') or '').strip() or None
                    block_mime = str(block.get('mime_type') or block.get('content_type') or '').strip() or None
                    block_bucket = str(block.get('bucket') or block.get('gcs_bucket') or '').strip() or None
                    block_blob = str(block.get('blob_path') or block.get('gcs_blob_path') or '').strip() or None
                    block_meta = block.get('metadata') if isinstance(block.get('metadata'), dict) else {}
                    if not block_content_text and not block_content_url:
                        continue
                    combined_materials.append({
                        "title": block_title,
                        "material_type": block_type,
                        "content_text": block_content_text,
                        "content_url": block_content_url,
                        "mime_type": block_mime,
                        "bucket": block_bucket,
                        "blob_path": block_blob,
                        "metadata": {**block_meta, "combined_block": True},
                        "position": max(1, _lms_to_int(block.get('position'), block_index)),
                    })

                extra_materials = []
                for material in lesson_materials:
                    if not isinstance(material, dict):
                        continue
                    material_type = str(material.get('material_type') or material.get('type') or '').strip().lower()
                    if material_type in ('text', 'video'):
                        continue
                    extra_materials.append(material)

                if not combined_materials:
                    fallback_text = str(lesson.get('content_text') or lesson_desc or '').strip()
                    if fallback_text:
                        combined_materials.append({
                            "title": "Текстовый блок",
                            "material_type": "text",
                            "content_text": fallback_text,
                            "content_url": None,
                            "mime_type": "text/html",
                            "bucket": None,
                            "blob_path": None,
                            "metadata": {"combined_block": True},
                            "position": 1,
                        })

                lesson_materials = [*combined_materials, *extra_materials]
            lesson_position = max(1, _lms_to_int(lesson.get('position'), lesson_index))
            cursor.execute("""
                INSERT INTO lms_lessons (
                    module_id, title, description, lesson_type, position, duration_seconds,
                    allow_fast_forward, completion_threshold, created_at
                )
                VALUES (%s, %s, %s, %s, %s, %s, %s, %s, %s)
                RETURNING id
            """, (
                module_id,
                lesson_title,
                lesson_desc,
                lesson_type,
                lesson_position,
                max(0, _lms_to_int(lesson.get('duration_seconds'), 0)),
                _lms_parse_bool(lesson.get('allow_fast_forward'), False),
                min(100.0, max(0.0, _lms_to_float(lesson.get('completion_threshold'), LMS_COMPLETION_THRESHOLD))),
                now
            ))
            lesson_id = int(cursor.fetchone()[0])
            source_lesson_id = _lms_to_int(lesson.get('id'), 0)
            if source_lesson_id > 0:
                lesson_by_source_id[source_lesson_id] = lesson_id

            material_position = 1
            has_text_material = False
            for material in lesson_materials:
                if not isinstance(material, dict):
                    continue
                material_type = str(material.get('material_type') or material.get('type') or 'file').strip().lower()
                if material_type not in ('video', 'pdf', 'link', 'text', 'file'):
                    material_type = 'file'
                content_url = str(material.get('content_url') or material.get('signed_url') or material.get('url') or '').strip() or None
                content_text = str(material.get('content_text') or '').strip() or None
                if material_type == 'text' and content_text:
                    has_text_material = True
                if not content_url and not content_text:
                    continue
                title_raw = str(material.get('title') or '').strip()
                material_title = title_raw or ("Текстовый материал" if material_type == 'text' else f"Материал {material_position}")
                mime_type = str(material.get('mime_type') or material.get('content_type') or '').strip() or None
                gcs_bucket = str(material.get('bucket') or material.get('gcs_bucket') or '').strip() or None
                gcs_blob_path = str(material.get('blob_path') or material.get('gcs_blob_path') or '').strip() or None
                metadata = material.get('metadata') if isinstance(material.get('metadata'), dict) else {}
                uploaded_name = str(material.get('file_name') or material.get('uploaded_file_name') or '').strip()
                if uploaded_name:
                    metadata["uploaded_file_name"] = uploaded_name
                position = max(1, _lms_to_int(material.get('position'), material_position))
                cursor.execute("""
                    INSERT INTO lms_lesson_materials (
                        lesson_id, title, material_type, content_text, content_url,
                        gcs_bucket, gcs_blob_path, mime_type, metadata, position, created_by, created_at
                    )
                    VALUES (%s, %s, %s, %s, %s, %s, %s, %s, %s::jsonb, %s, %s, %s)
                """, (
                    lesson_id,
                    material_title,
                    material_type,
                    content_text,
                    content_url,
                    gcs_bucket,
                    gcs_blob_path,
                    mime_type,
                    json.dumps(metadata, ensure_ascii=False),
                    position,
                    requester_id,
                    now
                ))
                material_position += 1

            if lesson_type == 'text' and not has_text_material:
                fallback_text = str(lesson.get('content_text') or lesson_desc or '').strip()
                if fallback_text:
                    cursor.execute("""
                        INSERT INTO lms_lesson_materials (
                            lesson_id, title, material_type, content_text, content_url,
                            gcs_bucket, gcs_blob_path, mime_type, metadata, position, created_by, created_at
                        )
                        VALUES (%s, %s, 'text', %s, NULL, NULL, NULL, 'text/plain', %s::jsonb, %s, %s, %s)
                    """, (
                        lesson_id,
                        "Текстовый материал",
                        fallback_text,
                        json.dumps({}, ensure_ascii=False),
                        material_position,
                        requester_id,
                        now
                    ))

    for test_index, test in enumerate(tests, start=1):
        if not isinstance(test, dict):
            continue
        test_title = str(test.get('title') or '').strip() or f"Тест {test_index}"
        requested_module_id = _lms_to_int(test.get('module_id'), 0)
        test_module_id = module_by_source_id.get(requested_module_id) if requested_module_id > 0 else None
        if not test_module_id:
            module_position = _lms_to_int(test.get('module_position'), 0)
            if module_position > 0:
                test_module_id = module_by_position.get(module_position)
        if not test_module_id:
            test_module_id = None

        test_metadata = test.get('metadata') if isinstance(test.get('metadata'), dict) else {}
        raw_time_limit_minutes = test.get('time_limit_minutes')
        if raw_time_limit_minutes in (None, ''):
            raw_time_limit_minutes = test.get('time_limit')
        parsed_time_limit_minutes = _lms_to_int(raw_time_limit_minutes, 0)
        test_time_limit_minutes = parsed_time_limit_minutes if parsed_time_limit_minutes > 0 else None
        raw_question_count = test.get('question_count')
        if raw_question_count in (None, ''):
            raw_question_count = test_metadata.get('questions_per_test')
        parsed_question_count = _lms_to_int(raw_question_count, 0)
        test_question_count = parsed_question_count if parsed_question_count > 0 else None
        raw_random_order = test.get('random_order')
        if raw_random_order in (None, ''):
            raw_random_order = test_metadata.get('random_order')
        test_random_order = _lms_parse_bool(raw_random_order, True)
        test_position = max(1, _lms_to_int(test.get('position'), test_index))
        source_lesson_id = None
        requested_source_lesson_id = _lms_to_int(test.get('source_lesson_id'), 0)
        if requested_source_lesson_id > 0:
            source_lesson_id = lesson_by_source_id.get(requested_source_lesson_id)
        cursor.execute("""
            INSERT INTO lms_tests (
                course_version_id, module_id, position, source_lesson_id, title, description, pass_threshold,
                attempt_limit, time_limit_minutes, question_count, random_order,
                is_final, status, created_at
            )
            VALUES (%s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, 'draft', %s)
            RETURNING id
        """, (
            version_id,
            test_module_id,
            test_position,
            source_lesson_id,
            test_title,
            str(test.get('description') or '').strip() or None,
            min(100.0, max(0.0, _lms_to_float(test.get('pass_threshold'), pass_threshold))),
            max(1, _lms_to_int(test.get('attempt_limit'), attempt_limit)),
            test_time_limit_minutes,
            test_question_count,
            test_random_order,
            _lms_parse_bool(test.get('is_final'), True),
            now
        ))
        test_id = int(cursor.fetchone()[0])

        questions = test.get('questions') if isinstance(test.get('questions'), list) else []
        for q_index, question in enumerate(questions, start=1):
            if not isinstance(question, dict):
                continue
            prompt = str(question.get('prompt') or question.get('text') or '').strip()
            if not prompt:
                continue
            q_type = str(question.get('type') or 'single').strip().lower()
            if q_type in ('single_choice',):
                q_type = 'single'
            if q_type in ('multiple_choice', 'multi'):
                q_type = 'multiple'
            if q_type in ('boolean', 'truefalse'):
                q_type = 'true_false'
            if q_type not in ('single', 'multiple', 'true_false', 'matching', 'text'):
                q_type = 'single'

            cursor.execute("""
                INSERT INTO lms_questions (
                    test_id, question_type, prompt, points, position, required, metadata, correct_text_answers, created_at
                )
                VALUES (%s, %s, %s, %s, %s, %s, %s::jsonb, %s::jsonb, %s)
                RETURNING id
            """, (
                test_id,
                q_type,
                prompt,
                max(0.1, _lms_to_float(question.get('points'), 1.0)),
                max(1, _lms_to_int(question.get('position'), q_index)),
                _lms_parse_bool(question.get('required'), True),
                json.dumps(question.get('metadata') if isinstance(question.get('metadata'), dict) else {}, ensure_ascii=False),
                json.dumps(question.get('correct_text_answers') if isinstance(question.get('correct_text_answers'), list) else [], ensure_ascii=False),
                now
            ))
            question_id = int(cursor.fetchone()[0])

            options = question.get('options') if isinstance(question.get('options'), list) else []
            if q_type == 'true_false' and not options:
                correct_bool = _lms_parse_bool(question.get('correct'), True)
                options = [
                    {"text": "True", "is_correct": correct_bool, "key": "true"},
                    {"text": "False", "is_correct": (not correct_bool), "key": "false"}
                ]

            for o_index, option in enumerate(options, start=1):
                if isinstance(option, dict):
                    opt_text = str(option.get('text') or option.get('label') or '').strip()
                    opt_key = str(option.get('key') or '').strip() or None
                    is_correct = _lms_parse_bool(option.get('is_correct'), False)
                    match_key = str(option.get('match_key') or option.get('right') or '').strip() or None
                    opt_meta = option.get('metadata') if isinstance(option.get('metadata'), dict) else {}
                    opt_position = max(1, _lms_to_int(option.get('position'), o_index))
                else:
                    opt_text = str(option or '').strip()
                    opt_key = None
                    is_correct = False
                    match_key = None
                    opt_meta = {}
                    opt_position = o_index
                if not opt_text:
                    continue
                cursor.execute("""
                    INSERT INTO lms_question_options (
                        question_id, option_key, option_text, position, is_correct, match_key, metadata
                    )
                    VALUES (%s, %s, %s, %s, %s, %s, %s::jsonb)
                """, (
                    question_id,
                    opt_key,
                    opt_text,
                    opt_position,
                    is_correct,
                    match_key,
                    json.dumps(opt_meta, ensure_ascii=False)
                ))

    return {
        "module_ids": created_module_ids
    }


def _lms_combined_video_progress_tx(cursor, lesson_id, user_id):
    cursor.execute("""
        SELECT id
        FROM lms_lesson_materials
        WHERE lesson_id = %s
          AND material_type = 'video'
        ORDER BY position ASC, id ASC
    """, (lesson_id,))
    material_ids = [int(row[0]) for row in cursor.fetchall() if row and row[0] is not None]
    if not material_ids:
        return [], {}

    cursor.execute("""
        SELECT
            material_id,
            MAX(progress_ratio) AS max_ratio
        FROM (
            SELECT
                CASE
                    WHEN COALESCE(payload->>'material_id', '') ~ '^[0-9]+$'
                        THEN (payload->>'material_id')::INTEGER
                    ELSE NULL
                END AS material_id,
                CASE
                    WHEN COALESCE(payload->>'progress_ratio', '') ~ '^[0-9]+(\\.[0-9]+)?$'
                        THEN (payload->>'progress_ratio')::NUMERIC
                    ELSE 0
                END AS progress_ratio
            FROM lms_learning_events
            WHERE lesson_id = %s
              AND user_id = %s
              AND event_type = 'combined_video_progress'
        ) ev
        WHERE material_id = ANY(%s)
        GROUP BY material_id
    """, (lesson_id, user_id, material_ids))
    rows = cursor.fetchall()
    ratio_by_material = {}
    for row in rows:
        material_id = int(row[0])
        ratio_raw = float(row[1] or 0.0)
        ratio_by_material[material_id] = min(100.0, max(0.0, ratio_raw))
    return material_ids, ratio_by_material


def _lms_lesson_linked_test_state_tx(cursor, assignment_id, user_id, course_version_id, lesson_id):
    cursor.execute("""
        SELECT
            t.id,
            t.title,
            t.description,
            t.pass_threshold,
            t.attempt_limit,
            t.time_limit_minutes,
            t.question_count,
            t.random_order,
            t.is_final,
            t.status
        FROM lms_tests t
        WHERE t.course_version_id = %s
          AND t.source_lesson_id = %s
          AND t.status <> 'archived'
        ORDER BY COALESCE(t.is_final, FALSE) ASC, COALESCE(t.position, 2147483647) ASC, t.id ASC
        LIMIT 1
    """, (course_version_id, lesson_id))
    row = cursor.fetchone()
    if not row:
        return None

    test_id = int(row[0])
    cursor.execute("""
        SELECT
            MAX(score_percent) FILTER (WHERE status = 'finished') AS best_score,
            BOOL_OR(COALESCE(passed, FALSE)) FILTER (WHERE status = 'finished') AS passed_any,
            COUNT(*) AS attempts_used
        FROM lms_test_attempts
        WHERE assignment_id = %s
          AND user_id = %s
          AND test_id = %s
    """, (assignment_id, user_id, test_id))
    progress_row = cursor.fetchone() or (None, False, 0)
    attempts_used = int(progress_row[2] or 0)
    pass_threshold = float(row[3] if row[3] is not None else LMS_DEFAULT_PASS_THRESHOLD)
    attempt_limit = int(row[4] if row[4] is not None else LMS_DEFAULT_ATTEMPT_LIMIT)
    passed_any = bool(progress_row[1]) if progress_row[1] is not None else False
    can_start = not passed_any and attempts_used < attempt_limit

    return {
        "id": test_id,
        "title": row[1],
        "description": row[2],
        "pass_threshold": pass_threshold,
        "attempt_limit": attempt_limit,
        "time_limit_minutes": int(row[5]) if row[5] is not None else None,
        "question_count": int(row[6]) if row[6] is not None else None,
        "random_order": _lms_parse_bool(row[7], True),
        "is_final": bool(row[8]),
        "status": row[9],
        "best_score": float(progress_row[0]) if progress_row[0] is not None else None,
        "passed_any": passed_any,
        "attempts_used": attempts_used,
        "can_start": can_start
    }


@app.route('/api/lms/home', methods=['GET'])
@require_api_key
def lms_home():
    requester_id, requester, requester_role, error_response, status_code = _lms_resolve_request('learner')
    if error_response:
        return error_response, status_code

    try:
        with db._get_cursor() as cursor:
            cursor.execute("""
                WITH assignments AS (
                    SELECT
                        a.id, a.course_id, a.course_version_id, a.status, a.due_at,
                        a.started_at, a.completed_at, a.created_at,
                        c.title, c.description, c.category,
                        cv.anti_cheat_settings
                    FROM lms_course_assignments a
                    JOIN lms_courses c ON c.id = a.course_id
                    LEFT JOIN lms_course_versions cv ON cv.id = a.course_version_id
                    WHERE a.user_id = %(uid)s
                      AND c.status = 'published'
                ),
                lesson_stats AS (
                    SELECT
                        m.course_version_id,
                        COUNT(l.id) AS total_lessons,
                        COALESCE(SUM(l.duration_seconds), 0) AS lessons_duration_seconds
                    FROM lms_modules m
                    JOIN lms_lessons l ON l.module_id = m.id
                    WHERE m.course_version_id IN (
                        SELECT DISTINCT course_version_id FROM assignments
                        WHERE course_version_id IS NOT NULL
                    )
                    GROUP BY m.course_version_id
                ),
                test_stats AS (
                    SELECT
                        t.course_version_id,
                        COUNT(*) AS total_tests,
                        COUNT(*) FILTER (WHERE COALESCE(t.is_final, FALSE) = FALSE) AS total_intermediate_tests,
                        COALESCE(SUM(
                            COALESCE(
                                NULLIF(to_jsonb(t) ->> 'time_limit_seconds', '')::INTEGER,
                                t.time_limit_minutes * 60,
                                0
                            )
                        ), 0) AS tests_duration_seconds
                    FROM lms_tests t
                    WHERE t.course_version_id IN (
                        SELECT DISTINCT course_version_id FROM assignments
                        WHERE course_version_id IS NOT NULL
                    )
                      AND t.status <> 'archived'
                    GROUP BY t.course_version_id
                ),
                completed_lessons AS (
                    SELECT lp.assignment_id, COUNT(*) AS completed_count
                    FROM lms_lesson_progress lp
                    WHERE lp.assignment_id IN (SELECT id FROM assignments)
                      AND lp.user_id = %(uid)s
                      AND lp.status = 'completed'
                    GROUP BY lp.assignment_id
                ),
                passed_tests AS (
                    SELECT
                        ta.assignment_id,
                        COUNT(DISTINCT ta.test_id) AS completed_tests,
                        COUNT(DISTINCT ta.test_id) FILTER (
                            WHERE COALESCE(t.is_final, FALSE) = FALSE
                        ) AS completed_intermediate_tests
                    FROM lms_test_attempts ta
                    JOIN lms_tests t ON t.id = ta.test_id
                    JOIN assignments ass ON ass.id = ta.assignment_id
                        AND t.course_version_id = ass.course_version_id
                    WHERE ta.user_id = %(uid)s
                      AND ta.status = 'finished'
                      AND ta.passed = TRUE
                      AND t.status <> 'archived'
                    GROUP BY ta.assignment_id
                ),
                best_scores AS (
                    SELECT ta.assignment_id, MAX(ta.score_percent) AS best_score
                    FROM lms_test_attempts ta
                    WHERE ta.assignment_id IN (SELECT id FROM assignments)
                      AND ta.user_id = %(uid)s
                      AND ta.status = 'finished'
                    GROUP BY ta.assignment_id
                ),
                latest_certs AS (
                    SELECT DISTINCT ON (cert.assignment_id)
                        cert.assignment_id, cert.id AS cert_id, cert.status AS cert_status
                    FROM lms_certificates cert
                    WHERE cert.assignment_id IN (SELECT id FROM assignments)
                    ORDER BY cert.assignment_id, cert.id DESC
                )
                SELECT
                    ass.id, ass.course_id, ass.course_version_id, ass.status,
                    ass.due_at, ass.started_at, ass.completed_at,
                    ass.title, ass.description, ass.category, ass.anti_cheat_settings,
                    COALESCE(ls.total_lessons, 0),
                    COALESCE(ls.lessons_duration_seconds, 0),
                    COALESCE(ts.tests_duration_seconds, 0),
                    COALESCE(cl.completed_count, 0),
                    COALESCE(ts.total_tests, 0),
                    COALESCE(pt.completed_tests, 0),
                    COALESCE(ts.total_intermediate_tests, 0),
                    COALESCE(pt.completed_intermediate_tests, 0),
                    bs.best_score,
                    lc.cert_id, lc.cert_status
                FROM assignments ass
                LEFT JOIN lesson_stats ls ON ls.course_version_id = ass.course_version_id
                LEFT JOIN test_stats ts ON ts.course_version_id = ass.course_version_id
                LEFT JOIN completed_lessons cl ON cl.assignment_id = ass.id
                LEFT JOIN passed_tests pt ON pt.assignment_id = ass.id
                LEFT JOIN best_scores bs ON bs.assignment_id = ass.id
                LEFT JOIN latest_certs lc ON lc.assignment_id = ass.id
                ORDER BY COALESCE(ass.due_at, ass.created_at) ASC, ass.id DESC
            """, {"uid": requester_id})
            combined_rows = cursor.fetchall()

            courses = []
            for row in combined_rows:
                assignment_id = int(row[0])
                course_version_id = int(row[2]) if row[2] is not None else None
                total_lessons = int(row[11])
                lessons_duration_seconds = int(row[12])
                tests_duration_seconds = int(row[13])
                total_duration_seconds = lessons_duration_seconds + tests_duration_seconds
                completed_lessons = int(row[14])
                total_tests = int(row[15])
                completed_tests = int(row[16])
                total_intermediate_tests = int(row[17])
                completed_intermediate_tests = int(row[18])
                best_score_raw = row[19]
                cert_id = row[20]
                cert_status = row[21]

                progress_total_items = total_lessons + total_tests
                progress_completed_items = completed_lessons + completed_tests

                progress_percent = 0.0
                if row[3] == 'completed':
                    progress_percent = 100.0
                elif progress_total_items > 0:
                    progress_percent = round((progress_completed_items / progress_total_items) * 100.0, 2)

                deadline_status = _lms_deadline_status(row[4], row[6])
                version_settings = _lms_parse_json(row[10], {})
                cover_payload = _lms_resolve_cover_payload(version_settings)
                courses.append({
                    "assignment_id": assignment_id,
                    "course_id": int(row[1]),
                    "course_version_id": course_version_id,
                    "title": row[7],
                    "description": row[8],
                    "category": row[9],
                    "cover_url": cover_payload["cover_url"],
                    "cover_bucket": cover_payload["cover_bucket"],
                    "cover_blob_path": cover_payload["cover_blob_path"],
                    "skills": _lms_normalize_skills(version_settings.get("skills")),
                    "status": row[3],
                    "due_at": row[4].isoformat() if row[4] else None,
                    "started_at": row[5].isoformat() if row[5] else None,
                    "completed_at": row[6].isoformat() if row[6] else None,
                    "deadline_status": deadline_status,
                    "progress_percent": progress_percent,
                    "completed_lessons": completed_lessons,
                    "total_lessons": total_lessons,
                    "total_duration_seconds": total_duration_seconds,
                    "completed_tests": completed_tests,
                    "total_tests": total_tests,
                    "completed_intermediate_tests": completed_intermediate_tests,
                    "total_intermediate_tests": total_intermediate_tests,
                    "best_score": float(best_score_raw) if best_score_raw is not None else None,
                    "certificate": (
                        {
                            "id": int(cert_id),
                            "status": cert_status
                        } if cert_id else None
                    )
                })

            cursor.execute("""
                SELECT COUNT(*)
                FROM lms_notifications
                WHERE user_id = %s
                  AND is_read = FALSE
            """, (requester_id,))
            unread_count = int(cursor.fetchone()[0] or 0)

        return jsonify({
            "status": "success",
            "role": requester_role,
            "heartbeat_seconds": LMS_HEARTBEAT_SECONDS,
            "stale_gap_seconds": LMS_STALE_GAP_SECONDS,
            "completion_threshold_percent": LMS_COMPLETION_THRESHOLD,
            "unread_notifications": unread_count,
            "courses": courses
        }), 200
    except Exception as e:
        logging.exception("Error in /api/lms/home")
        return jsonify({"error": "Failed to load LMS home"}), 500


@app.route('/api/lms/courses', methods=['GET'])
@require_api_key
def lms_courses():
    requester_id, _, _, error_response, status_code = _lms_resolve_request('learner')
    if error_response:
        return error_response, status_code

    try:
        with db._get_cursor() as cursor:
            cursor.execute("""
                SELECT
                    a.id, a.course_id, a.course_version_id, a.status, a.due_at, a.started_at, a.completed_at,
                    c.title, c.description, c.category
                FROM lms_course_assignments a
                JOIN lms_courses c ON c.id = a.course_id
                WHERE a.user_id = %s
                  AND c.status = 'published'
                ORDER BY c.title ASC
            """, (requester_id,))
            rows = cursor.fetchall()

            items = []
            for row in rows:
                due_at = row[4]
                completed_at = row[6]
                items.append({
                    "assignment_id": int(row[0]),
                    "course_id": int(row[1]),
                    "course_version_id": int(row[2]) if row[2] is not None else None,
                    "status": row[3],
                    "title": row[7],
                    "description": row[8],
                    "category": row[9],
                    "due_at": due_at.isoformat() if due_at else None,
                    "started_at": row[5].isoformat() if row[5] else None,
                    "completed_at": completed_at.isoformat() if completed_at else None,
                    "deadline_status": _lms_deadline_status(due_at, completed_at)
                })

        return jsonify({"status": "success", "courses": items}), 200
    except Exception as e:
        logging.exception("Error in /api/lms/courses")
        return jsonify({"error": "Internal server error"}), 500


@app.route('/api/lms/courses/<int:course_id>', methods=['GET'])
@require_api_key
def lms_course_detail(course_id):
    requester_id, _, _, error_response, status_code = _lms_resolve_request('learner')
    if error_response:
        return error_response, status_code

    try:
        with db._get_cursor() as cursor:
            cursor.execute("""
                SELECT a.id, a.course_version_id, a.status, a.due_at, a.started_at, a.completed_at
                FROM lms_course_assignments a
                JOIN lms_courses c ON c.id = a.course_id
                WHERE a.user_id = %s
                  AND a.course_id = %s
                  AND c.status = 'published'
                LIMIT 1
            """, (requester_id, course_id))
            assignment = cursor.fetchone()
            if not assignment:
                return jsonify({"error": "Course is not assigned to learner"}), 404

            assignment_id = int(assignment[0])
            course_version_id = int(assignment[1]) if assignment[1] is not None else None
            if course_version_id is None:
                cursor.execute("SELECT current_version_id FROM lms_courses WHERE id = %s", (course_id,))
                row = cursor.fetchone()
                if not row or row[0] is None:
                    return jsonify({"error": "Course version is not available"}), 404
                course_version_id = int(row[0])

            structure = _lms_course_structure_tx(cursor, course_id, course_version_id)
            if not structure:
                return jsonify({"error": "Course not found"}), 404

            cursor.execute("""
                SELECT
                    lesson_id, status, completion_ratio, max_position_seconds,
                    confirmed_seconds, active_seconds, completed_at, content_completed_at
                FROM lms_lesson_progress
                WHERE assignment_id = %s
                  AND user_id = %s
            """, (assignment_id, requester_id))
            progress_rows = cursor.fetchall()
            lesson_progress = {}
            for row in progress_rows:
                lesson_progress[int(row[0])] = {
                    "status": row[1],
                    "completion_ratio": float(row[2] or 0.0),
                    "max_position_seconds": float(row[3] or 0.0),
                    "confirmed_seconds": float(row[4] or 0.0),
                    "active_seconds": int(row[5] or 0),
                    "completed_at": row[6].isoformat() if row[6] else None,
                    "content_completed_at": row[7].isoformat() if row[7] else None
                }

            cursor.execute("""
                SELECT
                    test_id,
                    MAX(score_percent) FILTER (WHERE status = 'finished') AS best_score,
                    BOOL_OR(COALESCE(passed, FALSE)) FILTER (WHERE status = 'finished') AS passed_any,
                    COUNT(*) AS attempts_used
                FROM lms_test_attempts
                WHERE assignment_id = %s
                  AND user_id = %s
                GROUP BY test_id
            """, (assignment_id, requester_id))
            attempts = {}
            for row in cursor.fetchall():
                attempts[int(row[0])] = {
                    "best_score": float(row[1]) if row[1] is not None else None,
                    "passed_any": bool(row[2]) if row[2] is not None else False,
                    "attempts_used": int(row[3] or 0)
                }

            structure["assignment"] = {
                "id": assignment_id,
                "status": assignment[2],
                "due_at": assignment[3].isoformat() if assignment[3] else None,
                "started_at": assignment[4].isoformat() if assignment[4] else None,
                "completed_at": assignment[5].isoformat() if assignment[5] else None,
                "deadline_status": _lms_deadline_status(assignment[3], assignment[5]),
                "lesson_progress": lesson_progress,
                "tests": attempts
            }

        return jsonify({"status": "success", "course": structure}), 200
    except Exception as e:
        logging.exception("Error in /api/lms/courses/<course_id>")
        return jsonify({"error": "Internal server error"}), 500


@app.route('/api/lms/courses/<int:course_id>/start', methods=['POST'])
@require_api_key
def lms_start_course(course_id):
    requester_id, _, _, error_response, status_code = _lms_resolve_request('learner')
    if error_response:
        return error_response, status_code

    try:
        now = _lms_now()
        with db._get_cursor() as cursor:
            cursor.execute("""
                UPDATE lms_course_assignments a
                SET status = CASE WHEN a.status = 'assigned' THEN 'in_progress' ELSE a.status END,
                    started_at = COALESCE(a.started_at, %s),
                    updated_at = %s
                FROM lms_courses c
                WHERE a.user_id = %s
                  AND a.course_id = %s
                  AND c.id = a.course_id
                  AND c.status = 'published'
                RETURNING a.id, a.status, a.started_at, a.due_at
            """, (now, now, requester_id, course_id))
            updated = cursor.fetchone()
            if not updated:
                return jsonify({"error": "Course is not assigned to learner"}), 404

        return jsonify({
            "status": "success",
            "assignment_id": int(updated[0]),
            "assignment_status": updated[1],
            "started_at": updated[2].isoformat() if updated[2] else None,
            "due_at": updated[3].isoformat() if updated[3] else None
        }), 200
    except Exception as e:
        logging.exception("Error in /api/lms/courses/<course_id>/start")
        return jsonify({"error": "Internal server error"}), 500


@app.route('/api/lms/courses/<int:course_id>/open', methods=['POST'])
@require_api_key
def lms_course_open(course_id):
    """Combined start + detail in a single call.
    Accepts ?skip_start=1 to skip the start step (for refresh/reload)."""
    requester_id, _, _, error_response, status_code = _lms_resolve_request('learner')
    if error_response:
        return error_response, status_code

    skip_start = request.args.get('skip_start', '') in ('1', 'true')

    try:
        with db._get_cursor() as cursor:
            if not skip_start:
                now = _lms_now()
                cursor.execute("""
                    UPDATE lms_course_assignments a
                    SET status = CASE WHEN a.status = 'assigned' THEN 'in_progress' ELSE a.status END,
                        started_at = COALESCE(a.started_at, %s),
                        updated_at = %s
                    FROM lms_courses c
                    WHERE a.user_id = %s
                      AND a.course_id = %s
                      AND c.id = a.course_id
                      AND c.status = 'published'
                """, (now, now, requester_id, course_id))

            cursor.execute("""
                SELECT a.id, a.course_version_id, a.status, a.due_at, a.started_at, a.completed_at
                FROM lms_course_assignments a
                JOIN lms_courses c ON c.id = a.course_id
                WHERE a.user_id = %s
                  AND a.course_id = %s
                  AND c.status = 'published'
                LIMIT 1
            """, (requester_id, course_id))
            assignment = cursor.fetchone()
            if not assignment:
                return jsonify({"error": "Course is not assigned to learner"}), 404

            assignment_id = int(assignment[0])
            course_version_id = int(assignment[1]) if assignment[1] is not None else None
            if course_version_id is None:
                cursor.execute("SELECT current_version_id FROM lms_courses WHERE id = %s", (course_id,))
                row = cursor.fetchone()
                if not row or row[0] is None:
                    return jsonify({"error": "Course version is not available"}), 404
                course_version_id = int(row[0])

            structure = _lms_course_structure_tx(cursor, course_id, course_version_id)
            if not structure:
                return jsonify({"error": "Course not found"}), 404

            cursor.execute("""
                SELECT
                    lesson_id, status, completion_ratio, max_position_seconds,
                    confirmed_seconds, active_seconds, completed_at, content_completed_at
                FROM lms_lesson_progress
                WHERE assignment_id = %s
                  AND user_id = %s
            """, (assignment_id, requester_id))
            lesson_progress = {}
            for row in cursor.fetchall():
                lesson_progress[int(row[0])] = {
                    "status": row[1],
                    "completion_ratio": float(row[2] or 0.0),
                    "max_position_seconds": float(row[3] or 0.0),
                    "confirmed_seconds": float(row[4] or 0.0),
                    "active_seconds": int(row[5] or 0),
                    "completed_at": row[6].isoformat() if row[6] else None,
                    "content_completed_at": row[7].isoformat() if row[7] else None
                }

            cursor.execute("""
                SELECT
                    test_id,
                    MAX(score_percent) FILTER (WHERE status = 'finished') AS best_score,
                    BOOL_OR(COALESCE(passed, FALSE)) FILTER (WHERE status = 'finished') AS passed_any,
                    COUNT(*) AS attempts_used
                FROM lms_test_attempts
                WHERE assignment_id = %s
                  AND user_id = %s
                GROUP BY test_id
            """, (assignment_id, requester_id))
            attempts = {}
            for row in cursor.fetchall():
                attempts[int(row[0])] = {
                    "best_score": float(row[1]) if row[1] is not None else None,
                    "passed_any": bool(row[2]) if row[2] is not None else False,
                    "attempts_used": int(row[3] or 0)
                }

            structure["assignment"] = {
                "id": assignment_id,
                "status": assignment[2],
                "due_at": assignment[3].isoformat() if assignment[3] else None,
                "started_at": assignment[4].isoformat() if assignment[4] else None,
                "completed_at": assignment[5].isoformat() if assignment[5] else None,
                "deadline_status": _lms_deadline_status(assignment[3], assignment[5]),
                "lesson_progress": lesson_progress,
                "tests": attempts
            }

        return jsonify({"status": "success", "course": structure}), 200
    except Exception as e:
        logging.exception("Error in /api/lms/courses/<course_id>/open")
        return jsonify({"error": "Internal server error"}), 500


@app.route('/api/lms/lessons/<int:lesson_id>', methods=['GET'])
@require_api_key
def lms_lesson_detail(lesson_id):
    requester_id, _, _, error_response, status_code = _lms_resolve_request('learner')
    if error_response:
        return error_response, status_code

    try:
        client_session_key = _lms_resolve_client_session_key()
        with db._get_cursor() as cursor:
            context = _lms_get_lesson_context_tx(
                cursor,
                requester_id,
                lesson_id,
                client_session_key=client_session_key
            )
            if not context:
                return jsonify({"error": "Lesson is not available for learner"}), 404

            cursor.execute("""
                UPDATE lms_course_assignments
                SET status = CASE WHEN status = 'assigned' THEN 'in_progress' ELSE status END,
                    started_at = COALESCE(started_at, %s),
                    updated_at = %s
                WHERE id = %s
            """, (_lms_now(), _lms_now(), context["assignment_id"]))

            cursor.execute("""
                SELECT
                    id, lesson_id, title, material_type, content_text, gcs_bucket, gcs_blob_path,
                    content_url, mime_type, metadata, position
                FROM lms_lesson_materials
                WHERE lesson_id = %s
                ORDER BY position ASC, id ASC
            """, (lesson_id,))
            materials = [_lms_material_row_to_payload(row) for row in cursor.fetchall()]

            progress = context["progress"]
            session = context["session"]
            completion_ratio = float(progress[4] or 0.0)
            required_ratio = max(float(context["completion_threshold"]), float(LMS_COMPLETION_THRESHOLD))
            lesson_type = str(context.get("lesson_type") or "video").strip().lower() or "video"
            linked_test = _lms_lesson_linked_test_state_tx(
                cursor,
                assignment_id=int(context["assignment_id"]),
                user_id=int(requester_id),
                course_version_id=int(context["course_version_id"]),
                lesson_id=int(lesson_id)
            )
            progress_status = str(progress[1] or '').strip().lower()
            content_completed = progress_status == 'completed'
            if linked_test:
                linked_test["content_completed"] = content_completed
                linked_test["can_start"] = bool(linked_test.get("can_start")) and content_completed
            combined_video_progress = None
            if lesson_type == 'combined':
                material_ids, ratio_by_material = _lms_combined_video_progress_tx(
                    cursor,
                    lesson_id=int(lesson_id),
                    user_id=int(requester_id)
                )
                combined_video_progress = [
                    {
                        "material_id": material_id,
                        "progress_ratio": float(ratio_by_material.get(material_id, 0.0))
                    }
                    for material_id in material_ids
                ]
                if material_ids:
                    can_complete = all(float(ratio_by_material.get(material_id, 0.0)) >= required_ratio for material_id in material_ids)
                else:
                    can_complete = True
            else:
                can_complete = completion_ratio >= required_ratio

        return jsonify({
            "status": "success",
            "lesson": {
                "id": context["lesson_id"],
                "title": context["lesson_title"],
                "description": context["lesson_description"],
                "module_title": context["module_title"],
                "lesson_type": lesson_type,
                "duration_seconds": context["duration_seconds"],
                "allow_fast_forward": context["allow_fast_forward"],
                "completion_threshold": required_ratio
            },
            "assignment_id": context["assignment_id"],
            "session": {
                "id": int(session[0]),
                "started_at": session[1].isoformat() if session[1] else None,
                "last_heartbeat_at": session[3].isoformat() if session[3] else None,
                "is_active": bool(session[4]),
                "max_position_seconds": float(session[5] or 0.0),
                "confirmed_seconds": float(session[6] or 0.0),
                "active_seconds": int(session[7] or 0),
                "tab_hidden_count": int(session[8] or 0),
                "stale_gap_count": int(session[9] or 0)
            },
            "progress": {
                "id": int(progress[0]),
                "status": progress[1],
                "max_position_seconds": float(progress[2] or 0.0),
                "confirmed_seconds": float(progress[3] or 0.0),
                "completion_ratio": completion_ratio,
                "active_seconds": int(progress[5] or 0),
                "last_heartbeat_at": progress[6].isoformat() if progress[6] else None,
                "tab_hidden_count": int(progress[7] or 0),
                "stale_gap_count": int(progress[8] or 0),
                "can_complete": can_complete
            },
            "anti_cheat": {
                "heartbeat_seconds": LMS_HEARTBEAT_SECONDS,
                "stale_gap_seconds": LMS_STALE_GAP_SECONDS,
                "completion_threshold_percent": required_ratio
            },
            "materials": materials,
            "linked_test": linked_test,
            "combined_video_progress": combined_video_progress
        }), 200
    except Exception as e:
        logging.exception("Error in /api/lms/lessons/<lesson_id>")
        return jsonify({"error": "Internal server error"}), 500


@app.route('/api/lms/lessons/<int:lesson_id>/event', methods=['POST'])
@require_api_key
def lms_lesson_event(lesson_id):
    requester_id, _, _, error_response, status_code = _lms_resolve_request('learner')
    if error_response:
        return error_response, status_code

    data = request.get_json(silent=True) or {}
    event_type = str(data.get('event_type') or '').strip().lower() or 'unknown'
    payload = data.get('payload') if isinstance(data.get('payload'), dict) else {}
    client_ts = _lms_parse_datetime(data.get('client_ts'))
    client_session_key = _lms_resolve_client_session_key(data)

    try:
        with db._get_cursor() as cursor:
            context = _lms_get_lesson_context_tx(
                cursor,
                requester_id,
                lesson_id,
                client_session_key=client_session_key
            )
            if not context:
                return jsonify({"error": "Lesson is not available for learner"}), 404

            progress = context["progress"]
            session = context["session"]
            progress_id = int(progress[0])
            session_id = int(session[0])
            allow_fast_forward = bool(context["allow_fast_forward"])
            progress_max = float(progress[2] or 0.0)
            now = _lms_now()

            blocked_seek = False
            allowed_position = None
            if event_type == 'seek':
                to_seconds = _lms_to_float(
                    payload.get('to_seconds')
                    if isinstance(payload, dict) else None,
                    default=_lms_to_float(data.get('to_seconds'), default=0.0)
                )
                from_seconds = _lms_to_float(
                    payload.get('from_seconds')
                    if isinstance(payload, dict) else None,
                    default=_lms_to_float(data.get('from_seconds'), default=0.0)
                )
                payload = {
                    **(payload or {}),
                    "from_seconds": from_seconds,
                    "to_seconds": to_seconds
                }

                if not allow_fast_forward:
                    allowed_position = progress_max + max(3.0, float(LMS_HEARTBEAT_SECONDS) * 2.0)
                    if to_seconds > allowed_position:
                        blocked_seek = True

            if event_type in ('visibility', 'tab_hidden', 'tab_visible'):
                if event_type == 'tab_hidden':
                    is_visible = False
                elif event_type == 'tab_visible':
                    is_visible = True
                else:
                    is_visible = _lms_parse_bool(payload.get('is_visible') if isinstance(payload, dict) else None, True)
                payload = {**(payload or {}), "is_visible": bool(is_visible)}
                event_type = 'tab_visible' if is_visible else 'tab_hidden'
                if is_visible:
                    cursor.execute("""
                        UPDATE lms_lesson_progress
                        SET last_event_at = %s,
                            updated_at = %s
                        WHERE id = %s
                    """, (now, now, progress_id))
                    cursor.execute("""
                        UPDATE lms_learning_sessions
                        SET last_visible_at = %s
                        WHERE id = %s
                    """, (now, session_id))
                else:
                    cursor.execute("""
                        UPDATE lms_lesson_progress
                        SET tab_hidden_count = COALESCE(tab_hidden_count, 0) + 1,
                            last_event_at = %s,
                            updated_at = %s
                        WHERE id = %s
                    """, (now, now, progress_id))
                    cursor.execute("""
                        UPDATE lms_learning_sessions
                        SET tab_hidden_count = COALESCE(tab_hidden_count, 0) + 1
                        WHERE id = %s
                    """, (session_id,))

            if event_type == 'combined_video_progress':
                lesson_duration = max(0.0, float(context["duration_seconds"] or 0.0))
                progress_confirmed = float(progress[3] or 0.0)
                progress_active = int(progress[5] or 0)
                progress_tab_hidden = int(progress[7] or 0)
                progress_stale = int(progress[8] or 0)
                tab_visible = _lms_parse_bool(payload.get('tab_visible') if isinstance(payload, dict) else None, True)
                last_heartbeat = session[3] or progress[6]
                gap_seconds = None
                stale_gap = False
                if isinstance(last_heartbeat, datetime):
                    gap_seconds = max(0.0, (now - last_heartbeat).total_seconds())
                    stale_gap = gap_seconds > float(LMS_STALE_GAP_SECONDS)

                active_increment = _lms_resolve_active_increment_seconds(
                    payload,
                    gap_seconds=gap_seconds,
                    tab_visible=tab_visible,
                    stale_gap=stale_gap
                )
                next_confirmed = progress_confirmed + active_increment
                if lesson_duration > 0.0:
                    next_confirmed = min(lesson_duration, next_confirmed)
                    next_completion_ratio = min(100.0, round((next_confirmed / lesson_duration) * 100.0, 2))
                else:
                    next_completion_ratio = float(progress[4] or 0.0)
                next_active = progress_active + active_increment
                next_tab_hidden = progress_tab_hidden + (0 if tab_visible else 1)
                next_stale = progress_stale + (1 if stale_gap else 0)
                payload = {
                    **(payload or {}),
                    "tab_visible": tab_visible,
                    "stale_gap": stale_gap,
                    "active_increment_seconds": active_increment
                }
                cursor.execute("""
                    UPDATE lms_lesson_progress
                    SET status = CASE WHEN status = 'not_started' THEN 'in_progress' ELSE status END,
                        confirmed_seconds = %s,
                        completion_ratio = %s,
                        active_seconds = %s,
                        last_heartbeat_at = %s,
                        last_event_at = %s,
                        tab_hidden_count = %s,
                        stale_gap_count = %s,
                        started_at = COALESCE(started_at, %s),
                        updated_at = %s
                    WHERE id = %s
                """, (
                    next_confirmed,
                    next_completion_ratio,
                    next_active,
                    now,
                    now,
                    next_tab_hidden,
                    next_stale,
                    now,
                    now,
                    progress_id
                ))
                cursor.execute("""
                    UPDATE lms_learning_sessions
                    SET last_heartbeat_at = %s,
                        last_visible_at = CASE WHEN %s THEN %s ELSE last_visible_at END,
                        confirmed_seconds = GREATEST(confirmed_seconds, %s),
                        active_seconds = COALESCE(active_seconds, 0) + %s,
                        tab_hidden_count = %s,
                        stale_gap_count = %s
                    WHERE id = %s
                """, (
                    now,
                    tab_visible,
                    now,
                    next_confirmed,
                    active_increment,
                    int(session[8] or 0) + (0 if tab_visible else 1),
                    int(session[9] or 0) + (1 if stale_gap else 0),
                    session_id
                ))

            if event_type == 'session_end':
                reason = str(payload.get('reason') if isinstance(payload, dict) else '' or '').strip().lower() or 'client_close'
                payload = {**(payload or {}), "reason": reason}
                cursor.execute("""
                    UPDATE lms_lesson_progress
                    SET last_event_at = %s,
                        updated_at = %s
                    WHERE id = %s
                """, (now, now, progress_id))

            if blocked_seek:
                payload = {**(payload or {}), "blocked": True, "allowed_position": allowed_position}
                event_name = 'seek_blocked'
            else:
                event_name = event_type

            cursor.execute("""
                INSERT INTO lms_learning_events (
                    session_id, lesson_id, user_id, event_type, payload, client_ts, created_at
                )
                VALUES (%s, %s, %s, %s, %s::jsonb, %s, %s)
            """, (
                session_id,
                lesson_id,
                requester_id,
                event_name,
                json.dumps(payload or {}, ensure_ascii=False),
                client_ts,
                now
            ))

            if event_name == 'session_end':
                _lms_close_learning_session_tx(cursor, session_id, ended_at=now)

            if blocked_seek:
                return jsonify({
                    "status": "blocked",
                    "reason": "FORWARD_SEEK_NOT_ALLOWED",
                    "allowed_position": allowed_position
                }), 409

        return jsonify({"status": "success"}), 200
    except Exception as e:
        logging.exception("Error in /api/lms/lessons/<lesson_id>/event")
        return jsonify({"error": "Internal server error"}), 500


@app.route('/api/lms/lessons/<int:lesson_id>/heartbeat', methods=['POST'])
@require_api_key
def lms_lesson_heartbeat(lesson_id):
    requester_id, _, _, error_response, status_code = _lms_resolve_request('learner')
    if error_response:
        return error_response, status_code

    data = request.get_json(silent=True) or {}
    raw_position = data.get('position_seconds')
    raw_media_duration = data.get('media_duration_seconds')
    tab_visible = _lms_parse_bool(data.get('tab_visible'), True)
    client_session_key = _lms_resolve_client_session_key(data)

    try:
        with db._get_cursor() as cursor:
            context = _lms_get_lesson_context_tx(
                cursor,
                requester_id,
                lesson_id,
                client_session_key=client_session_key
            )
            if not context:
                return jsonify({"error": "Lesson is not available for learner"}), 404

            progress = context["progress"]
            session = context["session"]

            progress_id = int(progress[0])
            session_id = int(session[0])
            lesson_duration = float(context["duration_seconds"] or 0.0)
            media_duration = max(0.0, _lms_to_float(raw_media_duration, default=0.0))
            allow_fast_forward = bool(context["allow_fast_forward"])

            # Use effective media duration from player when available.
            # This prevents inflated lesson durations from skewing completion ratio.
            if media_duration > 0.0:
                lesson_duration = media_duration if lesson_duration <= 0.0 else min(lesson_duration, media_duration)

            now = _lms_now()
            requested_position = max(0.0, _lms_to_float(raw_position, default=0.0))
            progress_max = float(progress[2] or 0.0)
            progress_confirmed = float(progress[3] or 0.0)
            progress_active = int(progress[5] or 0)
            progress_tab_hidden = int(progress[7] or 0)
            progress_stale = int(progress[8] or 0)

            last_heartbeat = session[3] or progress[6]
            gap_seconds = None
            stale_gap = False
            if isinstance(last_heartbeat, datetime):
                gap_seconds = max(0.0, (now - last_heartbeat).total_seconds())
                stale_gap = gap_seconds > float(LMS_STALE_GAP_SECONDS)

            blocked_forward_seek = False
            allowed_position = None
            effective_position = requested_position
            if not allow_fast_forward:
                allowed_position = progress_max + max(3.0, float(LMS_HEARTBEAT_SECONDS) * 2.0)
                if effective_position > allowed_position:
                    effective_position = allowed_position
                    blocked_forward_seek = True

            next_max = max(progress_max, effective_position)
            next_confirmed = progress_confirmed
            active_increment = 0

            if tab_visible and not stale_gap:
                next_confirmed = max(next_confirmed, effective_position)
            active_increment = _lms_resolve_active_increment_seconds(
                data,
                gap_seconds=gap_seconds,
                tab_visible=tab_visible,
                stale_gap=stale_gap
            )

            next_active = progress_active + active_increment
            next_tab_hidden = progress_tab_hidden + (0 if tab_visible else 1)
            next_stale = progress_stale + (1 if stale_gap else 0)
            completion_ratio = 100.0 if lesson_duration <= 0 else min(100.0, round((next_confirmed / lesson_duration) * 100.0, 2))

            cursor.execute("""
                UPDATE lms_lesson_progress
                SET status = CASE WHEN status = 'not_started' THEN 'in_progress' ELSE status END,
                    max_position_seconds = %s,
                    confirmed_seconds = %s,
                    completion_ratio = %s,
                    active_seconds = %s,
                    last_heartbeat_at = %s,
                    last_event_at = %s,
                    tab_hidden_count = %s,
                    stale_gap_count = %s,
                    started_at = COALESCE(started_at, %s),
                    updated_at = %s
                WHERE id = %s
            """, (
                next_max,
                next_confirmed,
                completion_ratio,
                next_active,
                now,
                now,
                next_tab_hidden,
                next_stale,
                now,
                now,
                progress_id
            ))

            cursor.execute("""
                UPDATE lms_learning_sessions
                SET
                    last_heartbeat_at = %s,
                    last_visible_at = CASE WHEN %s THEN %s ELSE last_visible_at END,
                    max_position_seconds = %s,
                    confirmed_seconds = %s,
                    active_seconds = %s,
                    tab_hidden_count = %s,
                    stale_gap_count = %s
                WHERE id = %s
            """, (
                now,
                tab_visible,
                now,
                max(float(session[5] or 0.0), next_max),
                max(float(session[6] or 0.0), next_confirmed),
                int(session[7] or 0) + active_increment,
                int(session[8] or 0) + (0 if tab_visible else 1),
                int(session[9] or 0) + (1 if stale_gap else 0),
                session_id
            ))

            cursor.execute("""
                INSERT INTO lms_learning_events (
                    session_id, lesson_id, user_id, event_type, payload, client_ts, created_at
                )
                VALUES (%s, %s, %s, 'heartbeat', %s::jsonb, %s, %s)
            """, (
                session_id,
                lesson_id,
                requester_id,
                json.dumps({
                    "requested_position_seconds": requested_position,
                    "effective_position_seconds": effective_position,
                    "effective_duration_seconds": lesson_duration,
                    "media_duration_seconds": media_duration,
                    "tab_visible": tab_visible,
                    "active_delta_seconds": data.get('active_delta_seconds'),
                    "stale_gap": stale_gap,
                    "blocked_forward_seek": blocked_forward_seek,
                    "client_session_key": client_session_key
                }, ensure_ascii=False),
                _lms_parse_datetime(data.get('client_ts')),
                now
            ))

        return jsonify({
            "status": "success",
            "position_seconds": effective_position,
            "completion_ratio": completion_ratio,
            "effective_duration_seconds": lesson_duration,
            "active_seconds": next_active,
            "stale_gap": stale_gap,
            "blocked_forward_seek": blocked_forward_seek,
            "allowed_position": allowed_position if blocked_forward_seek else None
        }), 200
    except Exception as e:
        logging.exception("Error in /api/lms/lessons/<lesson_id>/heartbeat")
        return jsonify({"error": "Internal server error"}), 500


@app.route('/api/lms/lessons/<int:lesson_id>/complete', methods=['POST'])
@require_api_key
def lms_lesson_complete(lesson_id):
    requester_id, _, _, error_response, status_code = _lms_resolve_request('learner')
    if error_response:
        return error_response, status_code

    try:
        data = request.get_json(silent=True) or {}
        client_session_key = _lms_resolve_client_session_key(data)
        with db._get_cursor() as cursor:
            context = _lms_get_lesson_context_tx(
                cursor,
                requester_id,
                lesson_id,
                client_session_key=client_session_key
            )
            if not context:
                return jsonify({"error": "Lesson is not available for learner"}), 404

            progress = context["progress"]
            progress_id = int(progress[0])
            current_ratio = float(progress[4] or 0.0)
            last_heartbeat_at = progress[6]
            required_ratio = max(float(context["completion_threshold"]), float(LMS_COMPLETION_THRESHOLD))
            lesson_type = str(context.get("lesson_type") or "video").strip().lower() or "video"
            cursor.execute("""
                SELECT EXISTS(
                    SELECT 1
                    FROM lms_lesson_materials
                    WHERE lesson_id = %s
                      AND material_type = 'video'
                )
            """, (lesson_id,))
            has_video_material = bool((cursor.fetchone() or [False])[0])

            if lesson_type == 'combined' and has_video_material:
                material_ids, ratio_by_material = _lms_combined_video_progress_tx(
                    cursor,
                    lesson_id=int(lesson_id),
                    user_id=int(requester_id)
                )
                incomplete_videos = [
                    {
                        "material_id": material_id,
                        "progress_ratio": float(ratio_by_material.get(material_id, 0.0))
                    }
                    for material_id in material_ids
                    if float(ratio_by_material.get(material_id, 0.0)) < required_ratio
                ]
                if incomplete_videos:
                    return jsonify({
                        "error": "Combined lesson videos are not fully watched",
                        "required_ratio": required_ratio,
                        "incomplete_videos": incomplete_videos
                    }), 409

            enforce_video_watch = has_video_material and lesson_type != 'combined'

            if enforce_video_watch and current_ratio < required_ratio:
                return jsonify({
                    "error": "Lesson completion threshold is not reached",
                    "required_ratio": required_ratio,
                    "current_ratio": current_ratio
                }), 409

            if enforce_video_watch and isinstance(last_heartbeat_at, datetime):
                gap = (_lms_now() - last_heartbeat_at).total_seconds()
                if gap > float(LMS_STALE_GAP_SECONDS):
                    return jsonify({
                        "error": "Heartbeat is stale, lesson completion denied",
                        "stale_gap_seconds": LMS_STALE_GAP_SECONDS,
                        "current_gap_seconds": round(gap, 2)
                    }), 409

            now = _lms_now()
            cursor.execute("""
                UPDATE lms_lesson_progress
                SET status = 'completed',
                    completion_ratio = GREATEST(completion_ratio, %s),
                    content_completed_at = COALESCE(content_completed_at, %s),
                    completed_at = COALESCE(completed_at, %s),
                    updated_at = %s
                WHERE id = %s
                RETURNING completed_at, completion_ratio, content_completed_at
            """, (required_ratio, now, now, now, progress_id))
            updated = cursor.fetchone()

            completion = _lms_try_complete_assignment_tx(
                cursor,
                assignment_id=context["assignment_id"],
                user_id=requester_id
            )

            _lms_emit_notification(
                cursor,
                user_id=requester_id,
                notification_type='lesson_completed',
                title='Урок завершен',
                message=f"Урок «{context['lesson_title']}» отмечен как завершенный.",
                payload={"lesson_id": lesson_id, "assignment_id": context["assignment_id"]}
            )

        return jsonify({
            "status": "success",
            "lesson_id": lesson_id,
            "completed_at": updated[0].isoformat() if updated and updated[0] else None,
            "completion_ratio": float(updated[1] or required_ratio) if updated else required_ratio,
            "content_completed_at": updated[2].isoformat() if updated and updated[2] else None,
            "assignment_completion": completion
        }), 200
    except Exception as e:
        logging.exception("Error in /api/lms/lessons/<lesson_id>/complete")
        return jsonify({"error": "Internal server error"}), 500


@app.route('/api/lms/tests/<int:test_id>/start', methods=['POST'])
@require_api_key
def lms_test_start(test_id):
    requester_id, _, _, error_response, status_code = _lms_resolve_request('learner')
    if error_response:
        return error_response, status_code

    try:
        with db._get_cursor() as cursor:
            cursor.execute("""
                SELECT
                    a.id as assignment_id,
                    a.course_id,
                    a.course_version_id,
                    a.status as assignment_status,
                    t.id as test_id,
                    t.title,
                    COALESCE(t.pass_threshold, cv.pass_threshold, c.default_pass_threshold, %s),
                    COALESCE(t.attempt_limit, cv.attempt_limit, c.default_attempt_limit, %s),
                    t.time_limit_minutes,
                    t.question_count,
                    COALESCE(t.random_order, TRUE),
                    t.module_id,
                    t.position,
                    t.source_lesson_id
                FROM lms_tests t
                JOIN lms_course_versions cv ON cv.id = t.course_version_id
                JOIN lms_courses c ON c.id = cv.course_id
                JOIN lms_course_assignments a
                    ON a.course_version_id = cv.id
                   AND a.user_id = %s
                WHERE t.id = %s
                  AND t.status <> 'archived'
                  AND cv.status = 'published'
                  AND c.status = 'published'
                LIMIT 1
            """, (
                LMS_DEFAULT_PASS_THRESHOLD,
                LMS_DEFAULT_ATTEMPT_LIMIT,
                requester_id,
                test_id
            ))
            row = cursor.fetchone()
            if not row:
                return jsonify({"error": "Test is not available for learner"}), 404

            assignment_id = int(row[0])
            course_version_id = int(row[2])
            pass_threshold = float(row[6] or LMS_DEFAULT_PASS_THRESHOLD)
            attempt_limit = int(row[7] or LMS_DEFAULT_ATTEMPT_LIMIT)
            test_module_id = int(row[11]) if row[11] is not None else None
            test_position = _lms_to_int(row[12], 0)
            source_lesson_id = _lms_to_int(row[13], 0)

            total_lessons = 0
            completed_lessons = 0
            if source_lesson_id > 0:
                total_lessons = 1
                cursor.execute("""
                    SELECT COUNT(*)
                    FROM lms_lesson_progress
                    WHERE assignment_id = %s
                      AND user_id = %s
                      AND lesson_id = %s
                      AND status = 'completed'
                """, (assignment_id, requester_id, source_lesson_id))
                completed_lessons = int(cursor.fetchone()[0] or 0)
            elif test_module_id is not None and test_position > 0:
                cursor.execute("""
                    SELECT COUNT(*)
                    FROM lms_lessons l
                    JOIN lms_modules m ON m.id = l.module_id
                    JOIN lms_modules tm ON tm.id = %s
                    WHERE m.course_version_id = %s
                      AND (
                        m.position < tm.position
                        OR (m.position = tm.position AND l.position < %s)
                      )
                """, (test_module_id, course_version_id, test_position))
                total_lessons = int(cursor.fetchone()[0] or 0)

                if total_lessons > 0:
                    cursor.execute("""
                        SELECT COUNT(*)
                        FROM lms_lesson_progress lp
                        JOIN lms_lessons l ON l.id = lp.lesson_id
                        JOIN lms_modules m ON m.id = l.module_id
                        JOIN lms_modules tm ON tm.id = %s
                        WHERE lp.assignment_id = %s
                          AND lp.user_id = %s
                          AND lp.status = 'completed'
                          AND m.course_version_id = %s
                          AND (
                            m.position < tm.position
                            OR (m.position = tm.position AND l.position < %s)
                          )
                    """, (test_module_id, assignment_id, requester_id, course_version_id, test_position))
                    completed_lessons = int(cursor.fetchone()[0] or 0)
            else:
                cursor.execute("""
                    SELECT COUNT(*)
                    FROM lms_lessons l
                    JOIN lms_modules m ON m.id = l.module_id
                    WHERE m.course_version_id = %s
                """, (course_version_id,))
                total_lessons = int(cursor.fetchone()[0] or 0)

                if total_lessons > 0:
                    cursor.execute("""
                        SELECT COUNT(*)
                        FROM lms_lesson_progress
                        WHERE assignment_id = %s
                          AND user_id = %s
                          AND status = 'completed'
                    """, (assignment_id, requester_id))
                    completed_lessons = int(cursor.fetchone()[0] or 0)

            if total_lessons > 0 and completed_lessons < total_lessons:
                return jsonify({
                    "error": "Lessons must be completed before test start",
                    "completed_lessons": completed_lessons,
                    "total_lessons": total_lessons
                }), 409

            cursor.execute("""
                SELECT id, attempt_no, question_ids
                FROM lms_test_attempts
                WHERE assignment_id = %s
                  AND test_id = %s
                  AND user_id = %s
                  AND status = 'in_progress'
                ORDER BY id DESC
                LIMIT 1
            """, (assignment_id, test_id, requester_id))
            active_attempt = cursor.fetchone()
            if active_attempt:
                attempt_id = int(active_attempt[0])
                attempt_no = int(active_attempt[1])
                stored_question_ids = _lms_parse_question_ids(active_attempt[2])
            else:
                cursor.execute("""
                    SELECT COUNT(*)
                    FROM lms_test_attempts
                    WHERE assignment_id = %s
                      AND test_id = %s
                      AND user_id = %s
                """, (assignment_id, test_id, requester_id))
                attempts_used = int(cursor.fetchone()[0] or 0)
                if attempts_used >= attempt_limit:
                    return jsonify({
                        "error": "Attempt limit reached",
                        "attempt_limit": attempt_limit,
                        "attempts_used": attempts_used
                    }), 409

                attempt_no = attempts_used + 1
                cursor.execute("""
                    INSERT INTO lms_test_attempts (
                        assignment_id, test_id, user_id, attempt_no, status, started_at, question_ids
                    )
                    VALUES (%s, %s, %s, %s, 'in_progress', %s, '[]'::jsonb)
                    RETURNING id
                """, (assignment_id, test_id, requester_id, attempt_no, _lms_now()))
                attempt_id = int(cursor.fetchone()[0])
                stored_question_ids = []

            all_questions = _lms_fetch_test_questions_tx(cursor, test_id, include_correct=False)
            questions = []
            if stored_question_ids:
                question_map = {int(item.get('id')): item for item in all_questions}
                questions = [question_map[qid] for qid in stored_question_ids if qid in question_map]

            if not questions:
                configured_question_count = _lms_to_int(row[9], 0)
                random_order = _lms_parse_bool(row[10], True)

                # Preserve behavior for already-active attempts from legacy versions:
                # if user has started answering, keep full bank to avoid hidden answered items.
                cursor.execute("""
                    SELECT COUNT(*)
                    FROM lms_test_attempt_answers
                    WHERE attempt_id = %s
                """, (attempt_id,))
                has_any_legacy_answers = int(cursor.fetchone()[0] or 0) > 0

                selected_questions = list(all_questions)
                if not has_any_legacy_answers:
                    if random_order and len(selected_questions) > 1:
                        random.shuffle(selected_questions)
                    if configured_question_count > 0:
                        selected_questions = selected_questions[:configured_question_count]
                questions = selected_questions
                selected_ids = [int(item.get('id')) for item in selected_questions if int(item.get('id') or 0) > 0]
                cursor.execute("""
                    UPDATE lms_test_attempts
                    SET question_ids = %s::jsonb
                    WHERE id = %s
                """, (json.dumps(selected_ids, ensure_ascii=False), attempt_id))

        return jsonify({
            "status": "success",
            "attempt": {
                "id": attempt_id,
                "attempt_no": attempt_no,
                "assignment_id": assignment_id,
                "test_id": int(test_id),
                "pass_threshold": pass_threshold,
                "attempt_limit": attempt_limit,
                "time_limit_minutes": int(row[8]) if row[8] is not None else None,
                "question_count": len(questions),
                "configured_question_count": (int(row[9]) if row[9] is not None else None),
                "random_order": _lms_parse_bool(row[10], True)
            },
            "questions": questions
        }), 200
    except Exception as e:
        logging.exception("Error in /api/lms/tests/<test_id>/start")
        return jsonify({"error": "Internal server error"}), 500


@app.route('/api/lms/tests/attempts/<int:attempt_id>/answer', methods=['PATCH'])
@require_api_key
def lms_test_answer(attempt_id):
    requester_id, _, _, error_response, status_code = _lms_resolve_request('learner')
    if error_response:
        return error_response, status_code

    data = request.get_json(silent=True) or {}
    question_id = data.get('question_id')
    if question_id in (None, ''):
        return jsonify({"error": "question_id is required"}), 400
    try:
        question_id = int(question_id)
    except Exception:
        return jsonify({"error": "Invalid question_id"}), 400

    raw_answer = data.get('answer_payload', data.get('answer'))
    if raw_answer is None:
        raw_answer = {}

    try:
        with db._get_cursor() as cursor:
            cursor.execute("""
                SELECT id, test_id, status, question_ids
                FROM lms_test_attempts
                WHERE id = %s AND user_id = %s
                LIMIT 1
            """, (attempt_id, requester_id))
            attempt = cursor.fetchone()
            if not attempt:
                return jsonify({"error": "Attempt not found"}), 404
            if attempt[2] != 'in_progress':
                return jsonify({"error": "Attempt is not in progress"}), 409
            selected_question_ids = _lms_parse_question_ids(attempt[3])
            if selected_question_ids and question_id not in set(selected_question_ids):
                return jsonify({"error": "Question does not belong to this attempt"}), 404

            cursor.execute("""
                SELECT id
                FROM lms_questions
                WHERE id = %s AND test_id = %s
                LIMIT 1
            """, (question_id, int(attempt[1])))
            qrow = cursor.fetchone()
            if not qrow:
                return jsonify({"error": "Question does not belong to this attempt"}), 404

            cursor.execute("""
                INSERT INTO lms_test_attempt_answers (
                    attempt_id, question_id, answer_payload, answered_at
                )
                VALUES (%s, %s, %s::jsonb, %s)
                ON CONFLICT (attempt_id, question_id)
                DO UPDATE SET
                    answer_payload = EXCLUDED.answer_payload,
                    answered_at = EXCLUDED.answered_at
            """, (
                attempt_id,
                question_id,
                json.dumps(raw_answer, ensure_ascii=False),
                _lms_now()
            ))

        return jsonify({"status": "success", "attempt_id": attempt_id, "question_id": question_id}), 200
    except Exception as e:
        logging.exception("Error in /api/lms/tests/attempts/<attempt_id>/answer")
        return jsonify({"error": "Internal server error"}), 500


@app.route('/api/lms/tests/attempts/<int:attempt_id>/answers', methods=['PATCH'])
@require_api_key
def lms_test_answers_bulk(attempt_id):
    requester_id, _, _, error_response, status_code = _lms_resolve_request('learner')
    if error_response:
        return error_response, status_code

    data = request.get_json(silent=True) or {}
    answers_raw = data.get('answers')
    if isinstance(answers_raw, dict):
        answers_raw = [{"question_id": qid, "answer_payload": payload} for qid, payload in answers_raw.items()]
    if not isinstance(answers_raw, list):
        return jsonify({"error": "answers must be a list"}), 400

    normalized_items = []
    by_question_id = {}
    for item in answers_raw:
        if not isinstance(item, dict):
            continue
        raw_question_id = item.get('question_id', item.get('id'))
        if raw_question_id in (None, ''):
            continue
        try:
            question_id = int(raw_question_id)
        except Exception:
            return jsonify({"error": f"Invalid question_id: {raw_question_id}"}), 400

        raw_answer = item.get('answer_payload', item.get('answer'))
        if raw_answer is None:
            raw_answer = {}

        by_question_id[question_id] = raw_answer

    for question_id, answer_payload in by_question_id.items():
        normalized_items.append((question_id, answer_payload))

    if not normalized_items:
        return jsonify({"status": "success", "attempt_id": attempt_id, "updated_count": 0}), 200

    try:
        with db._get_cursor() as cursor:
            cursor.execute("""
                SELECT id, test_id, status, question_ids
                FROM lms_test_attempts
                WHERE id = %s AND user_id = %s
                LIMIT 1
            """, (attempt_id, requester_id))
            attempt = cursor.fetchone()
            if not attempt:
                return jsonify({"error": "Attempt not found"}), 404
            if attempt[2] != 'in_progress':
                return jsonify({"error": "Attempt is not in progress"}), 409

            selected_question_ids = _lms_parse_question_ids(attempt[3])
            if selected_question_ids:
                allowed_set = set(selected_question_ids)
                invalid_selected = [qid for qid, _ in normalized_items if qid not in allowed_set]
                if invalid_selected:
                    return jsonify({"error": "Some questions do not belong to this attempt", "question_ids": invalid_selected}), 404

            candidate_question_ids = [qid for qid, _ in normalized_items]
            cursor.execute("""
                SELECT id
                FROM lms_questions
                WHERE test_id = %s
                  AND id = ANY(%s)
            """, (int(attempt[1]), candidate_question_ids))
            valid_question_ids = {int(row[0]) for row in cursor.fetchall()}
            missing_question_ids = [qid for qid in candidate_question_ids if qid not in valid_question_ids]
            if missing_question_ids:
                return jsonify({"error": "Some questions do not belong to this test", "question_ids": missing_question_ids}), 404

            now = _lms_now()
            for question_id, answer_payload in normalized_items:
                cursor.execute("""
                    INSERT INTO lms_test_attempt_answers (
                        attempt_id, question_id, answer_payload, answered_at
                    )
                    VALUES (%s, %s, %s::jsonb, %s)
                    ON CONFLICT (attempt_id, question_id)
                    DO UPDATE SET
                        answer_payload = EXCLUDED.answer_payload,
                        answered_at = EXCLUDED.answered_at
                """, (
                    attempt_id,
                    question_id,
                    json.dumps(answer_payload, ensure_ascii=False),
                    now
                ))

        return jsonify({
            "status": "success",
            "attempt_id": attempt_id,
            "updated_count": len(normalized_items),
            "question_ids": [qid for qid, _ in normalized_items]
        }), 200
    except Exception as e:
        logging.exception("Error in /api/lms/tests/attempts/<attempt_id>/answers")
        return jsonify({"error": "Internal server error"}), 500


