@dp.callback_query_handler(lambda c: c.data and c.data.startswith('reject_reval:'))
async def handle_reject_reval(callback_query: types.CallbackQuery, state: FSMContext):
    cq = callback_query
    user = cq.from_user
    data = cq.data

    try:
        _, call_id_str = data.split(':', 1)
        call_id = int(call_id_str)
    except Exception:
        await cq.answer("Неверный идентификатор звонка", show_alert=True)
        return

    try:
        is_admin = await _is_admin_user(user.id)
    except Exception as e:
        logging.exception("Ошибка проверки администратора: %s", e)
        is_admin = False

    if not is_admin:
        await cq.answer("Только администратор может отклонять переоценку", show_alert=True)
        return

    await _prompt_reevaluation_decision_comment(cq, call_id, 'rejected', state)


@dp.callback_query_handler(lambda c: c.data == 'reval_skip_comment', state=ReevalDecision.waiting_comment)
async def handle_reval_skip_comment(callback_query: types.CallbackQuery, state: FSMContext):
    """Админ решил не добавлять комментарий. Решение уже зафиксировано — просто закрываем шаг."""
    cq = callback_query
    await state.finish()

    try:
        await cq.answer()
    except Exception:
        pass
    try:
        if cq.message:
            await cq.bot.edit_message_reply_markup(
                chat_id=cq.message.chat.id, message_id=cq.message.message_id, reply_markup=None
            )
    except Exception as e:
        logging.debug("Не удалось убрать reply_markup у запроса комментария: %s", e)


@dp.message_handler(state=ReevalDecision.waiting_comment, content_types=types.ContentTypes.TEXT)
async def handle_reval_decision_comment(message: types.Message, state: FSMContext):
    """Админ ввёл комментарий — дописываем его к уже принятому решению по переоценке."""
    fsm_data = await state.get_data()
    call_id = fsm_data.get('reval_call_id')
    decision = fsm_data.get('reval_decision')
    await state.finish()

    if not call_id or not decision:
        return
    comment = (message.text or '').strip() or None
    if not comment:
        return
    try:
        saved = await _apply_call_reevaluation_comment_for_telegram(int(call_id), decision, comment)
    except Exception as e:
        logging.exception("Не удалось сохранить комментарий к решению по переоценке: %s", e)
        saved = False
    logging.info("Call %s %s comment by tg_user %s (saved=%s)", call_id, decision, message.from_user.id, saved)
    try:
        if saved:
            await message.reply("💬 Комментарий сохранён.")
        else:
            await message.reply("ℹ️ Не удалось сохранить комментарий: решение по запросу изменилось.")
    except Exception as e:
        logging.debug("Не удалось подтвердить сохранение комментария: %s", e)


def _register_it_ticket_chat_discovery():
    """Авто-обнаружение чатов/каналов для IT-заявок.

    Когда бота добавляют в группу/канал, мы запоминаем чат, чтобы супервайзер
    мог выбрать его в интерфейсе. Регистрация защищена на случай отсутствия
    обработчика my_chat_member в установленной версии aiogram.
    """
    handler_decorator = getattr(dp, 'my_chat_member_handler', None)
    if not callable(handler_decorator):
        logging.warning("aiogram my_chat_member_handler недоступен — авто-обнаружение IT-каналов отключено")
        return

    @handler_decorator()
    async def _on_my_chat_member_update(update):
        try:
            chat = getattr(update, 'chat', None)
            new_member = getattr(update, 'new_chat_member', None)
            new_status = getattr(new_member, 'status', None) if new_member else None
            if chat is None or getattr(chat, 'type', None) not in ('group', 'supergroup', 'channel'):
                return
            loop = asyncio.get_event_loop()
            if new_status in ('member', 'administrator', 'creator'):
                await loop.run_in_executor(
                    executor_pool, db.record_discovered_chat,
                    chat.id, getattr(chat, 'title', None), getattr(chat, 'type', None), getattr(chat, 'username', None),
                )
                logging.info(f"IT-ticket: бот добавлен в чат {chat.id} ({getattr(chat, 'title', '')})")
            elif new_status in ('left', 'kicked'):
                await loop.run_in_executor(
                    executor_pool, db.deactivate_it_ticket_channel_by_chat_id, chat.id,
                )
                logging.info(f"IT-ticket: бот удалён из чата {chat.id}")
        except Exception as e:
            logging.error(f"Ошибка обработки my_chat_member для IT-заявок: {e}", exc_info=True)


_register_it_ticket_chat_discovery()


